 68→/// Extract preview text from a single message JSON value.
 69→fn extract_preview_from_value(msg: &Value) -> Option<String> {
 70→    fn message_text(msg: &Value) -> Option<String> {
 71→        let text = if let Some(s) = msg.get("content").and_then(|v| v.as_str()) {
 72→            s.to_string()
 73→        } else if let Some(blocks) = msg.get("content").and_then(|v| v.as_array()) {
 74→            blocks
 75→                .iter()
 76→                .filter_map(|b| {
 77→                    if b.get("type").and_then(|v| v.as_str()) == Some("text") {
 78→                        b.get("text").and_then(|v| v.as_str())
 79→                    } else {
 80→                        None
 81→                    }
 82→                })
 83→                .collect::<Vec<_>>()
 84→                .join(" ")
 85→        } else {
 86→            return None;
 87→        };
 88→        let trimmed = text.trim();
 89→        if trimmed.is_empty() {
 90→            None
 91→        } else {
 92→            Some(trimmed.to_string())
 93→        }
 94→    }
 95→    fn truncate_preview(s: &str, max: usize) -> String {
 96→        if s.len() <= max {
 97→            s.to_string()
 98→        } else {
 99→            format!("{}…", &s[..s.floor_char_boundary(max)])
100→        }
101→    }
102→    message_text(msg).map(|t| truncate_preview(&t, 200))
103→}
