129→/// Convert session-crate `MessageContent` to agents-crate `UserContent`.
130→///
131→/// The two types have different image representations:
132→/// - `ContentBlock::ImageUrl` stores a data URI string
133→/// - `ContentPart::Image` stores separated `media_type` + `data` fields
134→fn format_user_documents_context(documents: &[UserDocument]) -> Option<String> {
135→    if documents.is_empty() {
136→        return None;
137→    }
138→
139→    let mut sections = Vec::with_capacity(documents.len() + 1);
140→    sections.push("[Inbound documents available]".to_string());
141→    for document in documents {
142→        sections.push(format!(
143→            "filename: {}\nmime_type: {}\nlocal_path: {}\nmedia_ref: {}",
144→            document.display_name,
145→            document.mime_type,
146→            document
147→                .absolute_path
148→                .as_deref()
149→                .unwrap_or(&document.media_ref),
150→            document.media_ref
151→        ));
152→    }
153→
154→    Some(sections.join("\n\n"))
155→}
156→
157→fn append_user_documents_to_text(text: &str, documents: &[UserDocument]) -> String {
158→    if let Some(context) = format_user_documents_context(documents) {
159→        if text.trim().is_empty() {
160→            context
161→        } else {
162→            format!("{text}\n\n{context}")
163→        }
164→    } else {
165→        text.to_string()
166→    }
167→}
168→
169→fn to_user_content(mc: &MessageContent, documents: &[UserDocument]) -> UserContent {
170→    match mc {
171→        MessageContent::Text(text) => {
172→            UserContent::Text(append_user_documents_to_text(text, documents))
173→        },
174→        MessageContent::Multimodal(blocks) => {
175→            let mut parts: Vec<ContentPart> = blocks
176→                .iter()
177→                .filter_map(|block| match block {
178→                    ContentBlock::Text { text } => Some(ContentPart::Text(text.clone())),
179→                    ContentBlock::ImageUrl { image_url } => match parse_data_uri(&image_url.url) {
180→                        Some((media_type, data)) => {
181→                            debug!(
182→                                media_type,
183→                                data_len = data.len(),
184→                                "to_user_content: parsed image from data URI"
185→                            );
186→                            Some(ContentPart::Image {
187→                                media_type: media_type.to_string(),
188→                                data: data.to_string(),
189→                            })
190→                        },
191→                        None => {
192→                            warn!(
193→                                url_prefix = truncate_at_char_boundary(&image_url.url, 80),
194→                                "to_user_content: failed to parse data URI, dropping image"
195→                            );
196→                            None
197→                        },
198→                    },
199→                })
200→                .collect();

200→                .collect();
201→            if let Some(context) = format_user_documents_context(documents) {
202→                if let Some(ContentPart::Text(text)) = parts
203→                    .iter_mut()
204→                    .find(|part| matches!(part, ContentPart::Text(_)))
205→                {
206→                    if !text.trim().is_empty() {
207→                        text.push_str("\n\n");
208→                    }
209→                    text.push_str(&context);
210→                } else {
211→                    parts.insert(0, ContentPart::Text(context));
212→                }
213→            }
214→            let text_count = parts
215→                .iter()
216→                .filter(|p| matches!(p, ContentPart::Text(_)))
217→                .count();
218→            let image_count = parts
219→                .iter()
220→                .filter(|p| matches!(p, ContentPart::Image { .. }))
221→                .count();
222→            debug!(
223→                text_count,
224→                image_count,
225→                total_blocks = blocks.len(),
226→                "to_user_content: converted multimodal content"
227→            );
228→            UserContent::Multimodal(parts)
229→        },
230→    }
231→}
