233→fn rewrite_multimodal_text_blocks(blocks: &[ContentBlock], new_text: &str) -> Vec<ContentBlock> {
234→    let mut rewritten = Vec::with_capacity(blocks.len().max(1));
235→    let mut inserted_text = false;
236→
237→    for block in blocks {
238→        match block {
239→            ContentBlock::Text { .. } if !inserted_text => {
240→                rewritten.push(ContentBlock::Text {
241→                    text: new_text.to_string(),
242→                });
243→                inserted_text = true;
244→            },
245→            ContentBlock::Text { .. } => {},
246→            _ => rewritten.push(block.clone()),
247→        }
248→    }
249→
250→    if !inserted_text {
251→        rewritten.insert(0, ContentBlock::Text {
252→            text: new_text.to_string(),
253→        });
254→    }
255→
256→    rewritten
257→}
