259→fn apply_message_received_rewrite(
260→    message_content: &mut MessageContent,
261→    params: &mut Value,
262→    new_text: &str,
263→) {
264→    match message_content {
265→        MessageContent::Text(text) => {
266→            *text = new_text.to_string();
267→            if let Some(params_obj) = params.as_object_mut() {
268→                params_obj.insert("text".to_string(), serde_json::json!(new_text));
269→                params_obj.remove("content");
270→            }
271→        },
272→        MessageContent::Multimodal(blocks) => {
273→            let rewritten_blocks = rewrite_multimodal_text_blocks(blocks, new_text);
274→            match serde_json::to_value(&rewritten_blocks) {
275→                Ok(content_value) => {
276→                    *blocks = rewritten_blocks;
277→                    if let Some(params_obj) = params.as_object_mut() {
278→                        params_obj.insert("content".to_string(), content_value);
279→                        params_obj.remove("text");
280→                        params_obj.remove("message");
281→                    }
282→                },
283→                Err(e) => {
284→                    warn!(error = %e, "failed to serialize rewritten multimodal content");
285→                },
286→            }
287→        },
288→    }
289→}
