400→#[must_use]
401→fn session_token_usage_from_messages(messages: &[Value]) -> SessionTokenUsage {
402→    let session_input_tokens = messages
403→        .iter()
404→        .filter_map(|m| m.get("inputTokens").and_then(|v| v.as_u64()))
405→        .sum();
406→    let session_output_tokens = messages
407→        .iter()
408→        .filter_map(|m| m.get("outputTokens").and_then(|v| v.as_u64()))
409→        .sum();
410→
411→    let (current_request_input_tokens, current_request_output_tokens) = messages
412→        .iter()
413→        .rev()
414→        .find(|m| m.get("role").and_then(|v| v.as_str()) == Some("assistant"))
415→        .map_or((0, 0), |m| {
416→            let input = m
417→                .get("requestInputTokens")
418→                .and_then(|v| v.as_u64())
419→                .or_else(|| m.get("inputTokens").and_then(|v| v.as_u64()))
420→                .unwrap_or(0);
421→            let output = m
422→                .get("requestOutputTokens")
423→                .and_then(|v| v.as_u64())
424→                .or_else(|| m.get("outputTokens").and_then(|v| v.as_u64()))
425→                .unwrap_or(0);
426→            (input, output)
427→        });
428→
429→    SessionTokenUsage {
430→        session_input_tokens,
431→        session_output_tokens,
432→        current_request_input_tokens,
433→        current_request_output_tokens,
434→    }
435→}
