461→/// Compute the auto-compact trigger threshold for a given context window
462→/// and user-configured `chat.compaction.threshold_percent`.
463→///
464→/// The returned value is the number of estimated next-request input
465→/// tokens at or above which `send()` fires a pre-emptive compaction.
466→/// The fraction is clamped to `[0.1, 0.95]` so a typo'd config can't
467→/// disable auto-compact or spam it on every message, and the result is
468→/// floored at `1` so zero-context windows still get a non-zero check.
469→#[must_use]
470→fn compute_auto_compact_threshold(context_window_tokens: u64, threshold_percent: f32) -> u64 {
471→    let fraction = f64::from(threshold_percent.clamp(0.1, 0.95));
472→    ((context_window_tokens as f64) * fraction).round().max(1.0) as u64
473→}
