482→pub fn normalize_model_key(value: &str) -> String {
483→    let mut normalized = String::with_capacity(value.len());
484→    let mut last_was_separator = true;
485→
486→    for ch in value.trim().chars() {
487→        if ch.is_ascii_alphanumeric() {
488→            normalized.push(ch.to_ascii_lowercase());
489→            last_was_separator = false;
490→            continue;
491→        }
492→
493→        if !last_was_separator {
494→            normalized.push(' ');
495→            last_was_separator = true;
496→        }
497→    }
498→
499→    normalized.trim().to_string()
500→}
