521→/// Returns `true` if the model matches the allowlist patterns.
522→/// An empty pattern list means all models are allowed.
523→/// Matching is case-insensitive against the full model ID, raw model ID, and
524→/// display name:
525→/// - patterns with digits use exact-or-suffix matching (boundary aware)
526→/// - patterns without digits use substring matching
527→///
528→/// This keeps precise model pins like "gpt 5.2" from matching variants such as
529→/// "gpt-5.2-chat-latest", while still allowing broad buckets like "mini".
530→#[allow(dead_code)]
531→fn allowlist_pattern_matches_key(pattern: &str, key: &str) -> bool {
532→    if pattern.chars().any(|ch| ch.is_ascii_digit()) {
533→        if key == pattern {
534→            return true;
535→        }
536→        return key
537→            .strip_suffix(pattern)
538→            .is_some_and(|prefix| prefix.ends_with(' '));
539→    }
540→    key.contains(pattern)
541→}
542→
543→#[allow(dead_code)]
544→pub fn model_matches_allowlist(model: &moltis_providers::ModelInfo, patterns: &[String]) -> bool {
545→    if patterns.is_empty() {
546→        return true;
547→    }
548→    if is_allowlist_exempt_provider(&model.provider) {
549→        return true;
550→    }
551→    let full = normalize_model_key(&model.id);
552→    let raw = normalize_model_key(raw_model_id(&model.id));
553→    let display = normalize_model_key(&model.display_name);
554→    patterns.iter().any(|p| {
555→        allowlist_pattern_matches_key(p, &full)
556→            || allowlist_pattern_matches_key(p, &raw)
557→            || allowlist_pattern_matches_key(p, &display)
558→    })
559→}
