615→const PROBE_RATE_LIMIT_INITIAL_BACKOFF_MS: u64 = 1_000;
616→const PROBE_RATE_LIMIT_MAX_BACKOFF_MS: u64 = 30_000;
617→
618→#[derive(Debug, Clone, Copy)]
619→struct ProbeRateLimitState {
620→    backoff_ms: u64,
621→    until: Instant,
622→}
623→
624→#[derive(Debug, Default)]
625→struct ProbeRateLimiter {
626→    by_provider: Mutex<HashMap<String, ProbeRateLimitState>>,
627→}
628→
629→impl ProbeRateLimiter {
630→    async fn remaining_backoff(&self, provider: &str) -> Option<Duration> {
631→        let map = self.by_provider.lock().await;
632→        map.get(provider).and_then(|state| {
633→            let now = Instant::now();
634→            (state.until > now).then_some(state.until - now)
635→        })
636→    }
637→
638→    async fn mark_rate_limited(&self, provider: &str) -> Duration {
639→        let mut map = self.by_provider.lock().await;
640→        let next_backoff_ms =
641→            next_probe_rate_limit_backoff_ms(map.get(provider).map(|s| s.backoff_ms));
642→        let delay = Duration::from_millis(next_backoff_ms);
643→        let state = ProbeRateLimitState {
644→            backoff_ms: next_backoff_ms,
645→            until: Instant::now() + delay,
646→        };
647→        let _ = map.insert(provider.to_string(), state);
648→        delay
649→    }
650→
651→    async fn clear(&self, provider: &str) {
652→        let mut map = self.by_provider.lock().await;
653→        let _ = map.remove(provider);
654→    }
655→}
