657→fn next_probe_rate_limit_backoff_ms(previous_ms: Option<u64>) -> u64 {
658→    previous_ms
659→        .map(|ms| ms.saturating_mul(2))
660→        .unwrap_or(PROBE_RATE_LIMIT_INITIAL_BACKOFF_MS)
661→        .clamp(
662→            PROBE_RATE_LIMIT_INITIAL_BACKOFF_MS,
663→            PROBE_RATE_LIMIT_MAX_BACKOFF_MS,
664→        )
665→}
