667→fn is_probe_rate_limited_error(error_obj: &Value, error_text: &str) -> bool {
668→    if error_obj.get("type").and_then(|v| v.as_str()) == Some("rate_limit_exceeded") {
669→        return true;
670→    }
671→
672→    let lower = error_text.to_ascii_lowercase();
673→    lower.contains("status=429")
674→        || lower.contains("http 429")
675→        || lower.contains("too many requests")
676→        || lower.contains("rate limit")
677→        || lower.contains("quota exceeded")
678→}
