683→    by_provider: Mutex<HashMap<String, Arc<Semaphore>>>,
684→}
685→
686→impl ProbeProviderLimiter {
687→    fn new(permits_per_provider: usize) -> Self {
688→        Self {
689→            permits_per_provider,
690→            by_provider: Mutex::new(HashMap::new()),
691→        }
692→    }
