711→enum ProbeStatus {
712→    Supported,
713→    Unsupported { detail: String, provider: String },
714→    Error { message: String },
715→}
716→
717→#[derive(Debug)]
718→struct ProbeOutcome {
719→    model_id: String,
720→    display_name: String,
721→    provider_name: String,
722→    status: ProbeStatus,
723→}
724→
725→/// Run a single model probe: acquire concurrency permits, respect rate-limit
726→/// backoff, send a "ping" completion, and classify the result.
727→async fn run_single_probe(
728→    model_id: String,
729→    display_name: String,
730→    provider_name: String,
731→    provider: Arc<dyn moltis_agents::model::LlmProvider>,
732→    limiter: Arc<Semaphore>,
733→    provider_limiter: Arc<ProbeProviderLimiter>,
734→    rate_limiter: Arc<ProbeRateLimiter>,
735→) -> ProbeOutcome {
736→    let _permit = match limiter.acquire_owned().await {
737→        Ok(permit) => permit,
738→        Err(_) => {
739→            return ProbeOutcome {
740→                model_id,
741→                display_name,
742→                provider_name,
743→                status: ProbeStatus::Error {
744→                    message: "probe limiter closed".to_string(),
745→                },
746→            };
747→        },
748→    };
749→    let _provider_permit = match provider_limiter.acquire(&provider_name).await {
750→        Ok(permit) => permit,
751→        Err(_) => {
752→            return ProbeOutcome {
753→                model_id,
754→                display_name,
755→                provider_name,
756→                status: ProbeStatus::Error {
757→                    message: "provider probe limiter closed".to_string(),
758→                },
759→            };
760→        },
761→    };
762→
763→    if let Some(wait_for) = rate_limiter.remaining_backoff(&provider_name).await {
764→        debug!(
765→            provider = %provider_name,
766→            model = %model_id,
767→            wait_ms = wait_for.as_millis() as u64,
768→            "skipping model probe while provider is in rate-limit backoff"
769→        );
770→        return ProbeOutcome {
771→            model_id,
772→            display_name,
773→            provider_name,
774→            status: ProbeStatus::Error {
775→                message: format!(
776→                    "probe skipped due provider backoff ({}ms remaining)",
777→                    wait_for.as_millis()
778→                ),
779→            },
780→        };
781→    }
782→
783→    let completion = tokio::time::timeout(Duration::from_secs(20), provider.probe()).await;
784→
785→    match completion {
786→        Ok(Ok(_)) => {
787→            rate_limiter.clear(&provider_name).await;
788→            ProbeOutcome {
789→                model_id,
790→                display_name,
791→                provider_name,
792→                status: ProbeStatus::Supported,
793→            }
794→        },
795→        Ok(Err(err)) => {
796→            let error_text = err.to_string();
797→            let error_obj = parse_chat_error(&error_text, Some(provider_name.as_str()));
798→            if is_probe_rate_limited_error(&error_obj, &error_text) {
799→                let backoff = rate_limiter.mark_rate_limited(&provider_name).await;
800→                let detail = error_obj
801→                    .get("detail")
802→                    .and_then(|v| v.as_str())
803→                    .unwrap_or("Too many requests while probing model support");
804→                warn!(
805→                    provider = %provider_name,
806→                    model = %model_id,
807→                    backoff_ms = backoff.as_millis() as u64,
808→                    "model probe rate limited, applying provider backoff"
809→                );
810→                return ProbeOutcome {
811→                    model_id,
812→                    display_name,
813→                    provider_name,
814→                    status: ProbeStatus::Error {
815→                        message: format!("{detail} (probe backoff {}ms)", backoff.as_millis()),
816→                    },
817→                };
818→            }
819→
820→            rate_limiter.clear(&provider_name).await;
821→            let is_unsupported =
822→                error_obj.get("type").and_then(|v| v.as_str()) == Some("unsupported_model");
823→
824→            if is_unsupported {
825→                let detail = error_obj
826→                    .get("detail")
827→                    .and_then(|v| v.as_str())
828→                    .unwrap_or("Model is not supported for this account/provider")
829→                    .to_string();
830→                let parsed_provider = error_obj
831→                    .get("provider")
832→                    .and_then(|v| v.as_str())
833→                    .unwrap_or(provider_name.as_str())
834→                    .to_string();
835→                ProbeOutcome {
836→                    model_id,
837→                    display_name,
838→                    provider_name,
839→                    status: ProbeStatus::Unsupported {
840→                        detail,
841→                        provider: parsed_provider,
842→                    },
843→                }
844→            } else {
845→                ProbeOutcome {
846→                    model_id,
847→                    display_name,
848→                    provider_name,
849→                    status: ProbeStatus::Error {
850→                        message: error_text,
851→                    },
852→                }
853→            }
854→        },
855→        Err(_) => ProbeOutcome {
856→            model_id,
857→            display_name,
858→            provider_name,
859→            status: ProbeStatus::Error {
860→                message: "probe timeout after 20s".to_string(),
861→            },
862→        },
863→    }
864→}
