909→fn infer_reply_medium(params: &Value, text: &str) -> ReplyMedium {
910→    if let Some(explicit) = explicit_reply_medium_override(text) {
911→        return explicit;
912→    }
913→
914→    if let Some(input_medium) = parse_input_medium(params) {
915→        return input_medium;
916→    }
917→
918→    if let Some(channel) = params
919→        .get("channel")
920→        .cloned()
921→        .and_then(|v| serde_json::from_value::<InputChannelMeta>(v).ok())
922→        && channel.message_kind == Some(InputMessageKind::Voice)
923→    {
924→        return ReplyMedium::Voice;
925→    }
926→
927→    ReplyMedium::Text
928→}
