 50→/// Sanitize a tool name from model output.
 51→///
 52→/// Handles quirks from various LLM providers:
 53→/// 1. Trims whitespace
 54→/// 2. Strips surrounding double quotes (some models quote tool names)
 55→/// 3. Strips `functions_` prefix (OpenAI legacy artifact from some models)
 56→/// 4. Strips trailing `_\d+` suffix (parallel-call indexing from some models,
 57→///    e.g. Kimi K2.5 via OpenRouter sends `exec_2`, `browser_4`)
 58→fn sanitize_tool_name(name: &str) -> Cow<'_, str> {
 59→    let trimmed = name.trim();
 60→    let unquoted = trimmed
 61→        .strip_prefix('"')
 62→        .and_then(|s| s.strip_suffix('"'))
 63→        .unwrap_or(trimmed);
 64→
 65→    // Strip `functions_` prefix (OpenAI legacy artifact from some models).
 66→    // INVARIANT: no registered tool name starts with "functions_".
 67→    let without_prefix = unquoted.strip_prefix("functions_").unwrap_or(unquoted);
 68→
 69→    // Strip trailing `_\d+` suffix (parallel-call indexing from some models).
 70→    // INVARIANT: no registered tool name ends with `_\d+` (a purely numeric segment after the last underscore).
 71→    let cleaned = without_prefix
 72→        .rfind('_')
 73→        .and_then(|pos| {
 74→            let suffix = &without_prefix[pos + 1..];
 75→            if !suffix.is_empty() && suffix.bytes().all(|b| b.is_ascii_digit()) && pos > 0 {
 76→                Some(&without_prefix[..pos])
 77→            } else {
 78→                None
 79→            }
 80→        })
 81→        .unwrap_or(without_prefix);
 82→
 83→    if cleaned == name {
 84→        Cow::Borrowed(name)
 85→    } else {
 86→        Cow::Owned(cleaned.to_string())
 87→    }
 88→}
