216→        }
217→
218→        let tool_call_id = tool_call_id.clone();
219→        let original = content.clone();
220→        let before = estimate_message_tokens(&ChatMessage::tool(&tool_call_id, &original));
221→        *content = TOOL_RESULT_COMPACTION_PLACEHOLDER.to_string();
222→        let after = estimate_message_tokens(&ChatMessage::tool(
223→            &tool_call_id,
224→            TOOL_RESULT_COMPACTION_PLACEHOLDER,
225→        ));
226→        let saved = before.saturating_sub(after);
227→        if saved == 0 {
228→            *content = original;
229→            continue;
230→        }
231→
232→        reduced = reduced.saturating_add(saved);
233→    }
234→
235→    reduced
236→}
