238→fn enforce_tool_result_context_budget(
239→    messages: &mut [ChatMessage],
240→    tool_schemas: &[serde_json::Value],
241→    context_window: u32,
242→) -> Result<(), AgentRunError> {
243→    let context_window = context_window as usize;
244→    if context_window == 0 || !has_tool_result_messages(messages) {
245→        return Ok(());
246→    }
247→
248→    let compaction_budget =
249→        context_window.saturating_mul(TOOL_RESULT_COMPACTION_RATIO_PERCENT) / 100;
250→    let overflow_budget = context_window.saturating_mul(PREEMPTIVE_OVERFLOW_RATIO_PERCENT) / 100;
251→    let current_tokens = estimate_prompt_tokens(messages, tool_schemas);
252→
253→    if current_tokens > compaction_budget {
254→        let needed = current_tokens.saturating_sub(compaction_budget);
255→        let reduced = compact_tool_results_newest_first_in_place(messages, needed);
256→        debug!(
257→            current_tokens,
258→            compaction_budget,
259→            overflow_budget,
260→            needed,
261→            reduced,
262→            "compacted newest tool results to preserve prompt budget"
263→        );
264→    }
265→
266→    let post_compaction_tokens = estimate_prompt_tokens(messages, tool_schemas);
267→    if post_compaction_tokens > overflow_budget {
268→        return Err(AgentRunError::ContextWindowExceeded(format!(
269→            "preemptive context overflow: estimated prompt size {post_compaction_tokens} tokens exceeds {overflow_budget} token budget after tool-result compaction"
270→        )));
271→    }
272→
273→    Ok(())
274→}
