352→/// Base delay for non-rate-limit transient retries.
353→const SERVER_RETRY_DELAY: std::time::Duration = std::time::Duration::from_secs(2);
354→
355→/// Rate-limit retries use exponential backoff with a cap.
356→const RATE_LIMIT_INITIAL_RETRY_MS: u64 = 2_000;
357→const RATE_LIMIT_MAX_RETRY_MS: u64 = 60_000;
358→const RATE_LIMIT_MAX_RETRIES: u8 = 10;
359→
360→fn next_rate_limit_retry_ms(previous_ms: Option<u64>) -> u64 {
361→    previous_ms
362→        .map(|ms| ms.saturating_mul(2))
363→        .unwrap_or(RATE_LIMIT_INITIAL_RETRY_MS)
364→        .clamp(RATE_LIMIT_INITIAL_RETRY_MS, RATE_LIMIT_MAX_RETRY_MS)
365→}
366→
367→fn parse_retry_delay_ms_from_fragment(
368→    fragment: &str,
369→    unit_default_ms: bool,
370→    max_ms: u64,
371→) -> Option<u64> {
372→    let start = fragment.find(|c: char| c.is_ascii_digit())?;
373→    let tail = &fragment[start..];
374→    let digits_len = tail.chars().take_while(|c| c.is_ascii_digit()).count();
375→    if digits_len == 0 {
376→        return None;
377→    }
378→    let amount = tail[..digits_len].parse::<u64>().ok()?;
379→    let unit = tail[digits_len..].trim_start();
380→
381→    let ms = if unit.starts_with("ms") || unit.starts_with("millisecond") {
382→        amount
383→    } else if unit.starts_with("sec") || unit.starts_with("second") || unit.starts_with('s') {
384→        amount.saturating_mul(1_000)
385→    } else if unit.starts_with("min") || unit.starts_with("minute") || unit.starts_with('m') {
386→        amount.saturating_mul(60_000)
387→    } else if unit_default_ms {
388→        amount
389→    } else {
390→        amount.saturating_mul(1_000)
391→    };
392→
393→    Some(ms.clamp(1, max_ms))
394→}
395→
396→/// Extract retry delay hints embedded in provider error messages.
397→///
398→/// Supports patterns like:
399→/// - `retry_after_ms=1234`
400→/// - `Retry-After: 30`
401→/// - `retry after 30s`
402→/// - `retry in 45 seconds`
403→fn extract_retry_after_ms(msg: &str, max_ms: u64) -> Option<u64> {
404→    let lower = msg.to_ascii_lowercase();
405→    for (needle, default_ms) in [
406→        ("retry_after_ms=", true),
407→        ("retry-after-ms=", true),
408→        ("retry_after=", false),
409→        ("retry-after:", false),
410→        ("retry after ", false),
411→        ("retry in ", false),
412→    ] {
413→        if let Some(idx) = lower.find(needle) {
414→            let fragment = &lower[idx + needle.len()..];
415→            if let Some(ms) = parse_retry_delay_ms_from_fragment(fragment, default_ms, max_ms) {
416→                return Some(ms);
417→            }
418→        }
419→    }
420→    None
421→}
422→
423→fn next_retry_delay_ms(
424→    msg: &str,
425→    server_retries_remaining: &mut u8,
426→    rate_limit_retries_remaining: &mut u8,
427→    rate_limit_backoff_ms: &mut Option<u64>,
428→) -> Option<u64> {
429→    // Account/billing quota exhaustion is not transient; don't auto-retry.
430→    if is_billing_quota_error(msg) {
431→        return None;
432→    }
433→
434→    if is_rate_limit_error(msg) {
435→        if *rate_limit_retries_remaining == 0 {
436→            return None;
437→        }
438→        *rate_limit_retries_remaining -= 1;
439→
440→        // Keep exponential state advancing even when the provider gives a
441→        // Retry-After hint, so future retries remain bounded and predictable.
442→        let current_backoff = *rate_limit_backoff_ms;
443→        *rate_limit_backoff_ms = Some(next_rate_limit_retry_ms(current_backoff));
444→
445→        let hinted_ms = extract_retry_after_ms(msg, RATE_LIMIT_MAX_RETRY_MS);
446→        let delay_ms = hinted_ms
447→            .or(*rate_limit_backoff_ms)
448→            .unwrap_or(RATE_LIMIT_INITIAL_RETRY_MS);
449→        return Some(delay_ms.clamp(1, RATE_LIMIT_MAX_RETRY_MS));
450→    }
451→
452→    if is_retryable_server_error(msg) {
453→        if *server_retries_remaining == 0 {
454→            return None;
455→        }
456→        *server_retries_remaining -= 1;
457→        return Some(SERVER_RETRY_DELAY.as_millis() as u64);
458→    }
459→
460→    None
461→}
