556→/// Detect an explicit shell command in the latest user turn.
557→///
558→/// Only `/sh ...` commands are treated as explicit shell execution requests.
559→/// This keeps normal chat turns (`hey`, `hello`, etc.) out of the forced-exec path.
560→///
561→/// Supported forms:
562→/// - `/sh pwd`
563→/// - `/sh@mybot uname -a`
564→fn explicit_shell_command_from_user_content(user_content: &UserContent) -> Option<String> {
565→    let text = match user_content {
566→        UserContent::Text(text) => text.trim(),
567→        UserContent::Multimodal(_) => return None,
568→    };
569→
570→    if text.is_empty() || text.len() > 4096 || text.contains('\n') || text.contains('\r') {
571→        return None;
572→    }
573→
574→    let rest = text.strip_prefix('/')?;
575→    let split_idx = rest.find(char::is_whitespace)?;
576→    let head = &rest[..split_idx];
577→    let command = rest[split_idx..].trim_start();
578→    if command.is_empty() {
579→        return None;
580→    }
581→
582→    let head_lower = head.to_ascii_lowercase();
583→    let is_sh_prefix = if head_lower == "sh" {
584→        true
585→    } else {
586→        head_lower
587→            .strip_prefix("sh@")
588→            .is_some_and(|mention| !mention.is_empty())
589→    };
590→
591→    if !is_sh_prefix {
592→        return None;
593→    }
594→
595→    Some(command.to_string())
596→}
