 73→    let mut sanitized = String::new();
 74→    let mut previous_was_separator = false;
 75→    for character in root.to_string_lossy().chars() {
 76→        let normalized = character.to_ascii_lowercase();
 77→        if normalized.is_ascii_alphanumeric() {
 78→            sanitized.push(normalized);
 79→            previous_was_separator = false;
 80→        } else if !previous_was_separator {
 81→            sanitized.push('_');
 82→            previous_was_separator = true;
 83→        }
 84→    }
 85→    let sanitized = sanitized.trim_matches('_').to_string();
 86→    if sanitized.is_empty() {
 87→        "moltis".into()
 88→    } else {
 89→        format!("moltis-{sanitized}")
