 94→fn build_qmd_collections(
 95→    data_dir: &FsPath,
 96→    config: &moltis_config::schema::QmdConfig,
 97→) -> HashMap<String, moltis_qmd::QmdCollection> {
 98→    if config.collections.is_empty() {
 99→        return HashMap::from([
100→            ("moltis-root-memory".into(), moltis_qmd::QmdCollection {
101→                path: data_dir.to_path_buf(),
102→                glob: "MEMORY.md".into(),
103→            }),
104→            (
105→                "moltis-root-memory-lower".into(),
106→                moltis_qmd::QmdCollection {
107→                    path: data_dir.to_path_buf(),
108→                    glob: "memory.md".into(),
109→                },
110→            ),
111→            ("moltis-memory".into(), moltis_qmd::QmdCollection {
112→                path: data_dir.join("memory"),
113→                glob: "**/*.md".into(),
114→            }),
115→            ("moltis-agents".into(), moltis_qmd::QmdCollection {
116→                path: data_dir.join("agents"),
117→                glob: "**/*.md".into(),
118→            }),
119→        ]);
120→    }
121→
122→    let mut collections = HashMap::new();
123→    for (name, collection) in &config.collections {
124→        let globs = if collection.globs.is_empty() {
125→            vec!["**/*.md".to_string()]
126→        } else {
127→            collection.globs.clone()
128→        };
129→
130→        for (path_index, path) in collection.paths.iter().enumerate() {
131→            let root = FsPath::new(path);
132→            let root = if root.is_absolute() {
133→                root.to_path_buf()
134→            } else {
135→                data_dir.join(root)
136→            };
137→
138→            for (glob_index, glob) in globs.iter().enumerate() {
139→                let key = if collection.paths.len() == 1 && globs.len() == 1 {
140→                    name.clone()
141→                } else {
142→                    format!("{name}-{path_index}-{glob_index}")
143→                };
144→                collections.insert(key, moltis_qmd::QmdCollection {
145→                    path: root.clone(),
146→                    glob: glob.clone(),
147→                });
148→            }
149→        }
150→    }
151→
152→    collections
153→}
