1006→                line.to_string()
1007→            } else {
1008→                // Step 2: truncate individual lines exceeding 160 chars.
1009→                line[..line.floor_char_boundary(SUMMARY_MAX_LINE_CHARS)].to_string()
1010→            });
1011→        }
1012→    }
1013→    drop(seen);
1014→
1015→    // Step 3: check if already within budget.
1016→    let joined = deduped.join("\n");
1017→    if deduped.len() <= SUMMARY_MAX_LINES && joined.len() <= SUMMARY_MAX_CHARS {
1018→        return joined;
1019→    }
1020→
1021→    // Step 4: priority-based line dropping.
1022→    // Headers (starting with #) get highest priority, then bullets (- * •), then rest.
1023→    fn is_header(line: &str) -> bool {
1024→        line.trim_start().starts_with('#')
1025→    }
1026→    fn is_bullet(line: &str) -> bool {
1027→        let trimmed = line.trim_start();
1028→        trimmed.starts_with("- ") || trimmed.starts_with("* ") || trimmed.starts_with("• ")
1029→    }
1030→
1031→    let mut headers: Vec<String> = Vec::new();
1032→    let mut bullet_lines: Vec<String> = Vec::new();
1033→    let mut other_lines: Vec<String> = Vec::new();
1034→
1035→    for line in deduped {
1036→        if is_header(&line) {
1037→            headers.push(line);
1038→        } else if is_bullet(&line) {
1039→            bullet_lines.push(line);
1040→        } else {
1041→            other_lines.push(line);
1042→        }
1043→    }
1044→
1045→    // Build ordered candidate list: bullets first, then others.
1046→    // Headers are always kept.
1047→    let mut candidates: Vec<String> = Vec::new();
1048→    candidates.extend(bullet_lines);
1049→    candidates.extend(other_lines);
1050→
1051→    let header_count = headers.len();
1052→
1053→    // Check if keeping all candidates fits.
1054→    if header_count + candidates.len() <= SUMMARY_MAX_LINES {
1055→        let total_len = headers.iter().chain(candidates.iter()).fold(0, |acc, l| {
1056→            acc + l.len() + 1 // +1 for newline
1057→        })
1058→        // fold overcounts by 1 (N newlines vs N-1 for join); subtract to correct.
1059→        .saturating_sub(1);
1060→        if total_len <= SUMMARY_MAX_CHARS {
1061→            let mut result = headers;
1062→            result.extend(candidates);
1063→            return result.join("\n");
1064→        }
1065→    }
1066→
1067→    // Need to drop lines from the end of candidates.
1068→    // Account for omission notice in budget.
1069→    fn make_notice(n: usize) -> String {
1070→        format!("[... {n} lines omitted for brevity]")
1071→    }
1072→
1073→    for drop_count in 1..=candidates.len() {
1074→        let keep_count = candidates.len() - drop_count;
1075→        let line_count = header_count + keep_count + 1; // +1 for omission notice
1076→        if line_count > SUMMARY_MAX_LINES {
1077→            continue;
1078→        }
1079→
1080→        let notice = make_notice(drop_count);
1081→        let kept_candidates = &candidates[..keep_count];
1082→        let total_len = headers
1083→            .iter()
1084→            .chain(kept_candidates.iter())
1085→            .fold(0, |acc, l| acc + l.len() + 1)
1086→            // fold overcounts by 1 (N newlines vs N-1 for join); subtract to correct.
1087→            .saturating_sub(1)
1088→            + notice.len()
1089→            + 1; // +1 for newline before notice
1090→
1091→        if total_len <= SUMMARY_MAX_CHARS {
1092→            let mut result = headers;
1093→            result.extend(kept_candidates.iter().cloned());
1094→            result.push(notice);
1095→            return result.join("\n");
1096→        }
1097→    }
1098→
1099→    // Edge case: even dropping all candidates, headers alone are too long.
1100→    // Force-truncate headers from the end.  Run two passes so the notice
1101→    // length is exact: first pass counts dropped headers, second pass
1102→    // builds the result with the correct budget.
1103→    let base_dropped = candidates.len();
1104→    let mut header_drop_count = 0usize;
1105→    {
1106→        // First pass: determine how many headers must be dropped.
1107→        let mut budget = SUMMARY_MAX_CHARS.saturating_sub(make_notice(base_dropped).len() + 1);
1108→        let mut kept = 0usize;
1109→        for line in &headers {
1110→            let needed = line.len()
1111→                + if kept == 0 {
1112→                    0
1113→                } else {
1114→                    1
1115→                };
1116→            if needed > budget || kept + 1 >= SUMMARY_MAX_LINES {
1117→                header_drop_count += 1;
1118→            } else {
1119→                budget -= needed;
1120→                kept += 1;
1121→            }
1122→        }
1123→    }
1124→
1125→    let notice = make_notice(base_dropped + header_drop_count);
1126→    // Second pass: rebuild with exact budget including final notice length.
1127→    let mut char_budget = SUMMARY_MAX_CHARS.saturating_sub(notice.len() + 1);
1128→    let mut result: Vec<String> = Vec::new();
1129→    for line in &headers {
1130→        let needed = line.len()
1131→            + if result.is_empty() {
1132→                0
1133→            } else {
1134→                1
1135→            };
1136→        if needed > char_budget || result.len() + 1 >= SUMMARY_MAX_LINES {
1137→            continue;
1138→        }
1139→        char_budget -= needed;
1140→        result.push(line.clone());
1141→    }
1142→    result.push(notice);
1143→    result.join("\n")
1144→}
