1146→/// Apply [`compress_summary`] to any `[Conversation Summary]` or
1147→/// `[Conversation Compacted]` message in a compacted history.
1148→///
1149→/// Walks each message, detects the summary prefix, compresses the body, and
1150→/// replaces the content in place. Non-summary messages are passed through
1151→/// unchanged, preserving the head/tail structure of modes like
1152→/// `recency_preserving`.
1153→fn compress_summary_in_history(mut history: Vec<Value>) -> Vec<Value> {
1154→    for msg in &mut history {
1155→        let Some(content) = msg.get("content").and_then(Value::as_str).map(String::from) else {
1156→            continue;
1157→        };
1158→        for prefix in ["[Conversation Summary]\n\n", "[Conversation Compacted]\n\n"] {
1159→            if let Some(body) = content.strip_prefix(prefix) {
1160→                let compressed = compress_summary(body);
1161→                if compressed.len() < body.len()
1162→                    && let Some(obj) = msg.as_object_mut()
1163→                {
1164→                    obj.insert(
1165→                        "content".into(),
1166→                        Value::String(format!("{prefix}{compressed}")),
1167→                    );
1168→                }
1169→                break;
1170→            }
1171→        }
1172→    }
1173→    history
1174→}
