1176→fn shell_reply_text_from_exec_result(result: &Value) -> String {
1177→    let stdout = result
1178→        .get("stdout")
1179→        .and_then(Value::as_str)
1180→        .map(str::trim_end)
1181→        .unwrap_or("");
1182→    if !stdout.is_empty() {
1183→        return stdout.to_string();
1184→    }
1185→
1186→    let stderr = result
1187→        .get("stderr")
1188→        .and_then(Value::as_str)
1189→        .map(str::trim_end)
1190→        .unwrap_or("");
1191→    if !stderr.is_empty() {
1192→        return stderr.to_string();
1193→    }
1194→
1195→    let exit_code = result.get("exit_code").and_then(Value::as_i64).or_else(|| {
1196→        result
1197→            .get("exit_code")
1198→            .and_then(Value::as_u64)
1199→            .and_then(|code| i64::try_from(code).ok())
1200→    });
1201→    match exit_code {
1202→        Some(code) if code != 0 => format!("Command failed (exit {code})."),
1203→        _ => String::new(),
1204→    }
1205→}
