1256→            continue;
1257→        };
1258→        let stored_filename = document.stored_filename.trim();
1259→        let mime_type = document.mime_type.trim();
1260→        if !is_safe_user_audio_filename(stored_filename) || mime_type.is_empty() {
1261→            continue;
1262→        }
1263→
1264→        let display_name = sanitize_user_document_display_name(&document.display_name)
1265→            .unwrap_or_else(|| stored_filename.to_string());
1266→        parsed.push(UserDocument {
1267→            display_name,
1268→            stored_filename: stored_filename.to_string(),
1269→            mime_type: mime_type.to_string(),
1270→            media_ref: format!("media/{media_dir_key}/{stored_filename}"),
1271→            absolute_path: Some(
1272→                session_store
1273→                    .media_path_for(session_key, stored_filename)
1274→                    .to_string_lossy()
1275→                    .to_string(),
1276→            ),
1277→        });
1278→    }
1279→
1280→    if parsed.is_empty() {
1281→        None
1282→    } else {
1283→        Some(parsed)
1284→    }
1285→}
