1324→async fn detect_host_sudo_access() -> (Option<bool>, Option<String>) {
1325→    #[cfg(not(unix))]
1326→    {
1327→        return (None, Some("unsupported".to_string()));
1328→    }
1329→
1330→    #[cfg(unix)]
1331→    {
1332→        let output = tokio::process::Command::new("sudo")
1333→            .arg("-n")
1334→            .arg("true")
1335→            .stdin(Stdio::null())
1336→            .stdout(Stdio::null())
1337→            .stderr(Stdio::piped())
1338→            .output()
1339→            .await;
1340→
1341→        match output {
1342→            Ok(out) if out.status.success() => (Some(true), Some("passwordless".to_string())),
1343→            Ok(out) => {
1344→                let stderr = String::from_utf8_lossy(&out.stderr).to_lowercase();
1345→                if stderr.contains("a password is required") {
1346→                    (Some(false), Some("requires_password".to_string()))
1347→                } else if stderr.contains("not in the sudoers")
1348→                    || stderr.contains("is not in the sudoers")
1349→                    || stderr.contains("is not allowed to run sudo")
1350→                    || stderr.contains("may not run sudo")
1351→                {
1352→                    (Some(false), Some("denied".to_string()))
1353→                } else {
1354→                    (None, Some("unknown".to_string()))
1355→                }
1356→            },
1357→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
1358→                (None, Some("not_installed".to_string()))
1359→            },
1360→            Err(_) => (None, Some("unknown".to_string())),
1361→        }
1362→    }
1363→}
