1365→async fn detect_host_root_user() -> Option<bool> {
1366→    #[cfg(not(unix))]
1367→    {
1368→        return None;
1369→    }
1370→
1371→    #[cfg(unix)]
1372→    {
1373→        if let Some(uid) = std::env::var("EUID")
1374→            .ok()
1375→            .or_else(|| std::env::var("UID").ok())
1376→            .and_then(|raw| raw.trim().parse::<u32>().ok())
1377→        {
1378→            return Some(uid == 0);
1379→        }
1380→        if let Ok(user) = std::env::var("USER") {
1381→            let trimmed = user.trim();
1382→            if !trimmed.is_empty() {
1383→                return Some(trimmed == "root");
1384→            }
1385→        }
1386→        let output = tokio::process::Command::new("id")
1387→            .arg("-u")
1388→            .stdin(Stdio::null())
1389→            .stdout(Stdio::piped())
1390→            .stderr(Stdio::null())
1391→            .output()
1392→            .await
1393→            .ok()?;
1394→        if !output.status.success() {
1395→            return None;
1396→        }
1397→        let uid_text = String::from_utf8_lossy(&output.stdout);
1398→        uid_text.trim().parse::<u32>().ok().map(|uid| uid == 0)
1399→    }
1400→}
