598→// ── Tool result sanitization ────────────────────────────────────────────
599→
600→/// Tag that starts a base64 data URI.
601→const BASE64_TAG: &str = "data:";
602→/// Marker between MIME type and base64 payload.
603→const BASE64_MARKER: &str = ";base64,";
604→/// Minimum length of a blob payload (base64 or hex) to be worth stripping.
605→const BLOB_MIN_LEN: usize = 200;
606→
607→fn is_base64_byte(b: u8) -> bool {
608→    b.is_ascii_alphanumeric() || b == b'+' || b == b'/' || b == b'='
609→}
610→
611→/// Strip base64 data-URI blobs (e.g. `data:image/png;base64,AAAA...`) and
612→/// replace them with a short placeholder. Only targets payloads ≥ 200 chars.
613→fn strip_base64_blobs(input: &str) -> String {
614→    let mut result = String::with_capacity(input.len());
615→    let mut rest = input;
616→
617→    while let Some(start) = rest.find(BASE64_TAG) {
618→        result.push_str(&rest[..start]);
619→        let after_tag = &rest[start + BASE64_TAG.len()..];
620→
621→        if let Some(marker_pos) = after_tag.find(BASE64_MARKER) {
622→            let mime_part = &after_tag[..marker_pos];
623→            let payload_start = marker_pos + BASE64_MARKER.len();
624→            let payload = &after_tag[payload_start..];
625→            let payload_len = payload.bytes().take_while(|b| is_base64_byte(*b)).count();
626→
627→            if payload_len >= BLOB_MIN_LEN {
628→                let total_uri_len = BASE64_TAG.len() + payload_start + payload_len;
629→                // Provide a descriptive message based on MIME type
630→                if mime_part.starts_with("image/") {
631→                    result.push_str("[screenshot captured and displayed in UI]");
632→                } else {
633→                    let _ = write!(result, "[{mime_part} data removed — {total_uri_len} bytes]");
634→                }
635→                rest = &rest[start + total_uri_len..];
636→                continue;
637→            }
638→        }
639→
640→        result.push_str(BASE64_TAG);
641→        rest = after_tag;
642→    }
643→    result.push_str(rest);
644→    result
645→}
646→
647→/// Strip long hex sequences (≥ 200 hex chars) that look like binary dumps.
648→fn strip_hex_blobs(input: &str) -> String {
649→    let mut result = String::with_capacity(input.len());
650→    let mut chars = input.char_indices().peekable();
651→
652→    while let Some(&(start, ch)) = chars.peek() {
653→        if ch.is_ascii_hexdigit() {
654→            let mut end = start;
655→            while let Some(&(i, c)) = chars.peek() {
656→                if c.is_ascii_hexdigit() {
657→                    end = i + c.len_utf8();
658→                    chars.next();
659→                } else {
660→                    break;
661→                }
662→            }
663→            let run = end - start;
664→            if run >= BLOB_MIN_LEN {
665→                let _ = write!(result, "[hex data removed — {run} chars]");
666→            } else {
667→                result.push_str(&input[start..end]);
668→            }
669→        } else {
670→            result.push(ch);
671→            chars.next();
672→        }
673→    }
674→    result
675→}
676→
677→/// Sanitize a tool result string before feeding it to the LLM.
678→///
679→/// 1. Strips base64 data URIs (≥ 200 char payloads).
680→/// 2. Strips long hex sequences (≥ 200 hex chars).
681→/// 3. Truncates the result to `max_bytes` (at a char boundary), appending a
682→///    truncation marker.
683→pub fn sanitize_tool_result(input: &str, max_bytes: usize) -> String {
684→    let mut result = strip_base64_blobs(input);
685→    result = strip_hex_blobs(&result);
686→
687→    if result.len() <= max_bytes {
688→        return result;
689→    }
690→
691→    let original_len = result.len();
692→    let mut end = max_bytes;
693→    while end > 0 && !result.is_char_boundary(end) {
694→        end -= 1;
695→    }
696→    result.truncate(end);
697→    let _ = write!(result, "\n\n[truncated — {original_len} bytes total]");
698→    result
699→}
