701→// ── Multimodal tool result helpers ─────────────────────────────────────────
702→
703→/// Image extracted from a tool result for multimodal handling.
704→#[derive(Debug)]
705→pub struct ExtractedImage {
706→    /// MIME type (e.g., "image/png", "image/jpeg")
707→    pub media_type: String,
708→    /// Base64-encoded image data
709→    pub data: String,
710→}
711→
712→/// Extract image data URIs from text, returning the images and remaining text.
713→///
714→/// Searches for patterns like `data:image/png;base64,AAAA...` and extracts them.
715→/// Returns the list of images found and the text with images removed.
716→fn extract_images_from_text_impl(input: &str) -> (Vec<ExtractedImage>, String) {
717→    let mut images = Vec::new();
718→    let mut remaining = String::with_capacity(input.len());
719→    let mut rest = input;
720→
721→    while let Some(start) = rest.find(BASE64_TAG) {
722→        remaining.push_str(&rest[..start]);
723→        let after_tag = &rest[start + BASE64_TAG.len()..];
724→
725→        // Check for image MIME type
726→        if let Some(marker_pos) = after_tag.find(BASE64_MARKER) {
727→            let mime_part = &after_tag[..marker_pos];
728→
729→            // Only extract image/* MIME types
730→            if let Some(image_subtype) = mime_part.strip_prefix("image/") {
731→                let payload_start = marker_pos + BASE64_MARKER.len();
732→                let payload = &after_tag[payload_start..];
733→                let payload_len = payload.bytes().take_while(|b| is_base64_byte(*b)).count();
734→
735→                if payload_len >= BLOB_MIN_LEN {
736→                    // Extract the image
737→                    let media_type = format!("image/{image_subtype}");
738→                    let data = payload[..payload_len].to_string();
739→                    images.push(ExtractedImage { media_type, data });
740→
741→                    // Skip past the full data URI
742→                    let total_uri_len = BASE64_TAG.len() + payload_start + payload_len;
743→                    rest = &rest[start + total_uri_len..];
744→                    continue;
745→                }
746→            }
747→        }
748→
749→        // Not an extractable image, keep the tag and continue
750→        remaining.push_str(BASE64_TAG);
751→        rest = after_tag;
752→    }
753→    remaining.push_str(rest);
754→
755→    (images, remaining)
756→}
