758→/// Test alias for extract_images_from_text_impl
759→#[allow(clippy::unwrap_used, clippy::expect_used)]
760→#[cfg(test)]
761→fn extract_images_from_text(input: &str) -> (Vec<ExtractedImage>, String) {
762→    extract_images_from_text_impl(input)
763→}
