765→/// Convert a tool result to multimodal content for vision-capable providers.
766→///
767→/// For providers with `supports_vision() == true`, this extracts images from
768→/// the tool result and returns them as OpenAI-style content blocks:
769→/// ```json
770→/// [
771→///   { "type": "text", "text": "..." },
772→///   { "type": "image_url", "image_url": { "url": "data:image/png;base64,..." } }
773→/// ]
774→/// ```
775→///
776→/// For non-vision providers, returns a simple string with images stripped.
777→///
778→/// Note: Browser screenshots are pre-stripped by the browser tool to avoid
779→/// the LLM outputting the raw base64 in its response (the UI already displays
780→/// screenshots via WebSocket events).
781→pub fn tool_result_to_content(
782→    result: &str,
783→    max_bytes: usize,
784→    supports_vision: bool,
785→) -> serde_json::Value {
786→    if !supports_vision {
787→        // Non-vision provider: strip images and return string
788→        return serde_json::Value::String(sanitize_tool_result(result, max_bytes));
789→    }
790→
791→    // Vision provider: extract images and create multimodal content
792→    let (images, text) = extract_images_from_text_impl(result);
793→
794→    if images.is_empty() {
795→        // No images found, just sanitize and return string
796→        return serde_json::Value::String(sanitize_tool_result(result, max_bytes));
797→    }
798→
799→    // Build multimodal content array
800→    let mut content_blocks = Vec::new();
801→
802→    // Sanitize remaining text (strips any remaining hex blobs, truncates if needed)
803→    let sanitized_text = sanitize_tool_result(&text, max_bytes);
804→    if !sanitized_text.trim().is_empty() {
805→        content_blocks.push(serde_json::json!({
806→            "type": "text",
807→            "text": sanitized_text
808→        }));
809→    }
810→
811→    // Add image blocks
812→    for image in images {
813→        // Reconstruct data URI for OpenAI format
814→        let data_uri = format!("data:{};base64,{}", image.media_type, image.data);
815→        content_blocks.push(serde_json::json!({
816→            "type": "image_url",
817→            "image_url": { "url": data_uri }
818→        }));
819→    }
820→
821→    serde_json::json!(content_blocks)
822→}
