849→fn channel_binding_from_tool_context(
850→    session_key: &str,
851→    tool_context: Option<&serde_json::Value>,
852→) -> Option<ChannelBinding> {
853→    let channel_value = tool_context.and_then(|ctx| ctx.get("_channel"))?;
854→    match serde_json::from_value(channel_value.clone()) {
855→        Ok(binding) => Some(binding),
856→        Err(error) => {
857→            warn!(
858→                error = %error,
859→                session = %session_key,
860→                "failed to parse _channel tool context for hooks; ignoring channel provenance"
861→            );
862→            None
863→        },
864→    }
865→}
