867→/// Like `run_agent_loop` but accepts optional context values that are injected
868→/// into every tool call's parameters (e.g. `_session_key`).
869→pub async fn run_agent_loop_with_context(
870→    provider: Arc<dyn LlmProvider>,
871→    tools: &ToolRegistry,
872→    system_prompt: &str,
873→    user_content: &UserContent,
874→    on_event: Option<&OnEvent>,
875→    history: Option<Vec<ChatMessage>>,
876→    tool_context: Option<serde_json::Value>,
877→    hook_registry: Option<Arc<HookRegistry>>,
878→) -> Result<AgentRunResult, AgentRunError> {
879→    let native_tools = provider.supports_tools();
880→    let config = moltis_config::discover_and_load();
881→    let max_tool_result_bytes = config.tools.max_tool_result_bytes;
882→    let max_auto_continues = config.tools.agent_max_auto_continues;
883→    let auto_continue_min_tool_calls = config.tools.agent_auto_continue_min_tool_calls;
884→    let base_max_iterations = resolve_agent_max_iterations(config.tools.agent_max_iterations);
885→    // Lazy mode needs extra iterations for tool_search discovery round-trips.
886→    let max_iterations = if config.tools.registry_mode == moltis_config::ToolRegistryMode::Lazy {
887→        base_max_iterations * 3
888→    } else {
889→        base_max_iterations
890→    };
891→
892→    let is_multimodal = matches!(user_content, UserContent::Multimodal(_));
893→    info!(
894→        provider = provider.name(),
895→        model = provider.id(),
896→        native_tools,
897→        tools_count = tools.list_names().len(),
898→        is_multimodal,
899→        "starting agent loop"
900→    );
901→
902→    let mut messages: Vec<ChatMessage> = vec![ChatMessage::system(system_prompt)];
903→
904→    // Insert conversation history before the current user message.
905→    if let Some(hist) = history {
906→        messages.extend(hist);
907→    }
908→
909→    messages.push(ChatMessage::User {
910→        content: user_content.clone(),
911→    });
912→    let explicit_shell_command = explicit_shell_command_from_user_content(user_content);
913→
914→    // Extract session key once for hook payloads.
915→    let session_key_for_hooks = tool_context
916→        .as_ref()
917→        .and_then(|ctx| ctx.get("_session_key"))
918→        .and_then(|v| v.as_str())
919→        .unwrap_or("")
920→        .to_string();
921→    let channel_for_hooks =
922→        channel_binding_from_tool_context(&session_key_for_hooks, tool_context.as_ref());
923→
924→    let mut iterations = 0;
925→    let mut total_tool_calls = 0;
926→    let mut total_input_tokens: u32 = 0;
927→    let mut total_output_tokens: u32 = 0;
928→    let mut server_retries_remaining: u8 = 1;
929→    let mut rate_limit_retries_remaining: u8 = RATE_LIMIT_MAX_RETRIES;
930→    let mut rate_limit_backoff_ms: Option<u64> = None;
931→    let mut last_answer_text = String::new();
932→    let mut malformed_retry_count: u8 = 0;
933→    let mut empty_tool_name_retry_count: u8 = 0;
934→    let mut auto_continue_count: usize = 0;
935→    let mut loop_detector = ToolLoopDetector::new(
936→        config.tools.agent_loop_detector_window,
937→        config.tools.agent_loop_detector_strip_tools_on_second_fire,
938→    );
939→    let mut strip_tools_next_iter = false;
940→
941→    loop {
942→        iterations += 1;
943→        if iterations > max_iterations {
944→            warn!("agent loop exceeded max iterations ({})", max_iterations);
945→            return Err(AgentRunError::Other(anyhow::anyhow!(
946→                "agent loop exceeded max iterations ({})",
947→                max_iterations
948→            )));
949→        }
950→
951→        // Re-compute schemas each iteration so activated tools appear immediately.
952→        // When the loop detector has escalated to stage 2, pass an empty tool
953→        // list for this single turn so the model is forced to respond in text.
954→        let schemas_for_api = if native_tools && !strip_tools_next_iter {
955→            tools.list_schemas()
956→        } else {
957→            vec![]
958→        };
959→        if strip_tools_next_iter {
960→            strip_tools_next_iter = false;
961→            loop_detector.clear_strip_tools();
962→        }
963→
964→        enforce_tool_result_context_budget(
965→            &mut messages,
966→            &schemas_for_api,
967→            provider.context_window(),
968→        )?;
969→
970→        if let Some(cb) = on_event {
971→            cb(RunnerEvent::Iteration(iterations));
972→        }
973→
974→        info!(
975→            iteration = iterations,
976→            messages_count = messages.len(),
977→            "calling LLM"
978→        );
979→        trace!(iteration = iterations, messages = ?messages, "LLM request messages");
980→
981→        // Dispatch BeforeLLMCall hook — may block the LLM call.
982→        if let Some(ref hooks) = hook_registry {
983→            let msgs_json: Vec<serde_json::Value> =
984→                messages.iter().map(|m| m.to_openai_value()).collect();
985→            let payload = HookPayload::BeforeLLMCall {
986→                session_key: session_key_for_hooks.clone(),
987→                provider: provider.name().to_string(),
988→                model: provider.id().to_string(),
989→                messages: serde_json::Value::Array(msgs_json),
990→                tool_count: schemas_for_api.len(),
991→                iteration: iterations,
992→            };
993→            match hooks.dispatch(&payload).await {
994→                Ok(HookAction::Block(reason)) => {
995→                    warn!(reason = %reason, "LLM call blocked by BeforeLLMCall hook");
996→                    return Err(AgentRunError::Other(anyhow::anyhow!(
997→                        "blocked by BeforeLLMCall hook: {reason}"

200→        {
201→            let mut inner_w = self.state.inner.write().await;
202→            let invokes = &mut inner_w.pending_invokes;
203→            invokes.insert(request_id.clone(), crate::state::PendingInvoke {
204→                request_id: request_id.clone(),
205→                sender: tx,
206→                created_at: std::time::Instant::now(),
207→            });
208→        }
209→
210→        // Wait up to 30 seconds for the user to grant/deny permission.
211→        let result = match tokio::time::timeout(std::time::Duration::from_secs(30), rx).await {
212→            Ok(Ok(value)) => value,
213→            Ok(Err(_)) => {
214→                // Sender dropped — clean up.
215→                self.state
216→                    .inner
217→                    .write()
218→                    .await
219→                    .pending_invokes
220→                    .remove(&request_id);
221→                return Ok(LocationResult {
222→                    location: None,
223→                    error: Some(LocationError::Timeout),
224→                });
225→            },
226→            Err(_) => {
227→                // Timeout — clean up.
228→                self.state
229→                    .inner
230→                    .write()
231→                    .await
232→                    .pending_invokes
233→                    .remove(&request_id);
234→                return Ok(LocationResult {
235→                    location: None,
236→                    error: Some(LocationError::Timeout),
237→                });
238→            },
239→        };
240→
241→        // Parse the result from the browser.
242→        if let Some(loc) = result.get("location") {
243→            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
244→            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
245→            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
246→            Ok(LocationResult {
247→                location: Some(moltis_tools::location::BrowserLocation {
248→                    latitude: lat,
249→                    longitude: lon,
250→                    accuracy,
251→                }),
252→                error: None,
253→            })
254→        } else if let Some(err) = result.get("error") {
255→            let code = err.get("code").and_then(|v| v.as_u64()).unwrap_or(0);
256→            let error = match code {
257→                1 => LocationError::PermissionDenied,
258→                2 => LocationError::PositionUnavailable,
259→                3 => LocationError::Timeout,
260→                _ => LocationError::NotSupported,
261→            };
262→            Ok(LocationResult {
263→                location: None,
264→                error: Some(error),
265→            })
266→        } else {
267→            Ok(LocationResult {
268→                location: None,
269→                error: Some(LocationError::PositionUnavailable),
270→            })
271→        }
272→    }
