278→    async fn request_channel_location(
279→        &self,
280→        session_key: &str,
281→    ) -> moltis_tools::Result<moltis_tools::location::LocationResult> {
282→        use moltis_tools::location::{LocationError, LocationResult};
283→
284→        // Look up channel binding from session metadata.
285→        let session_meta = self
286→            .state
287→            .services
288→            .session_metadata
289→            .as_ref()
290→            .ok_or_else(|| moltis_tools::Error::message("session metadata not available"))?;
291→        let entry = session_meta.get(session_key).await.ok_or_else(|| {
292→            moltis_tools::Error::message(format!("no session metadata for key {session_key}"))
293→        })?;
294→        let binding_json = entry.channel_binding.ok_or_else(|| {
295→            moltis_tools::Error::message(format!("no channel binding for session {session_key}"))
296→        })?;
297→        let reply_target: moltis_channels::ChannelReplyTarget =
298→            serde_json::from_str(&binding_json)?;
299→
300→        // Send a message asking the user to share their location.
301→        let outbound = self
302→            .state
303→            .services
304→            .channel_outbound_arc()
305→            .ok_or_else(|| moltis_tools::Error::message("no channel outbound available"))?;
306→        outbound
307→            .send_text(
308→                &reply_target.account_id,
309→                &reply_target.outbound_to(),
310→                "Please share your location in this chat, or paste a geo: link / map pin.",
311→                None,
312→            )
313→            .await
314→            .map_err(|e| moltis_tools::Error::external("send location request", e))?;
315→
316→        // Create a pending invoke keyed by session.
317→        let pending_key = format!("channel_location:{session_key}");
318→        let (tx, rx) = tokio::sync::oneshot::channel();
319→        {
320→            let mut inner = self.state.inner.write().await;
321→            inner
322→                .pending_invokes
323→                .insert(pending_key.clone(), crate::state::PendingInvoke {
324→                    request_id: pending_key.clone(),
325→                    sender: tx,
326→                    created_at: std::time::Instant::now(),
327→                });
328→        }
329→
330→        // Wait up to 60 seconds — user needs to navigate Telegram's UI.
331→        let result = match tokio::time::timeout(std::time::Duration::from_secs(60), rx).await {
332→            Ok(Ok(value)) => value,
333→            Ok(Err(_)) => {
334→                self.state
335→                    .inner
336→                    .write()
337→                    .await
338→                    .pending_invokes
339→                    .remove(&pending_key);
340→                return Ok(LocationResult {
341→                    location: None,
342→                    error: Some(LocationError::Timeout),
343→                });
344→            },
345→            Err(_) => {
346→                self.state
347→                    .inner
348→                    .write()
349→                    .await
350→                    .pending_invokes
351→                    .remove(&pending_key);
352→                return Ok(LocationResult {
353→                    location: None,
354→                    error: Some(LocationError::Timeout),
355→                });
356→            },
357→        };
358→
359→        // Parse the result (same format as update_location sends).
360→        if let Some(loc) = result.get("location") {
361→            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
362→            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
363→            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
364→            Ok(LocationResult {
365→                location: Some(moltis_tools::location::BrowserLocation {
366→                    latitude: lat,
367→                    longitude: lon,
368→                    accuracy,
369→                }),
370→                error: None,
371→            })
372→        } else {
373→            Ok(LocationResult {
374→                location: None,
375→                error: Some(LocationError::PositionUnavailable),
376→            })
377→        }
378→    }
379→}
