388→fn instance_slug(config: &moltis_config::MoltisConfig) -> String {
389→    let mut raw_name = config.identity.name.clone();
390→    if let Some(file_identity) = moltis_config::load_identity_for_agent("main")
391→        && file_identity.name.is_some()
392→    {
393→        raw_name = file_identity.name;
394→    }
395→
396→    let base = raw_name
397→        .unwrap_or_else(|| "moltis".to_string())
398→        .to_lowercase();
399→    let mut out = String::new();
400→    let mut last_dash = false;
401→    for ch in base.chars() {
402→        let mapped = if ch.is_ascii_alphanumeric() {
403→            ch
404→        } else {
405→            '-'
406→        };
407→        if mapped == '-' {
408→            if !last_dash {
409→                out.push(mapped);
410→            }
411→            last_dash = true;
412→        } else {
413→            out.push(mapped);
414→            last_dash = false;
415→        }
416→    }
417→    let out = out.trim_matches('-').to_string();
418→    if out.is_empty() {
419→        "moltis".to_string()
420→    } else {
421→        out
422→    }
423→}
