445→fn summarize_model_ids_for_logs(sorted_model_ids: &[String], max_items: usize) -> Vec<String> {
446→    if max_items == 0 {
447→        return Vec::new();
448→    }
449→
450→    if sorted_model_ids.len() <= max_items || max_items < 3 {
451→        return sorted_model_ids.iter().take(max_items).cloned().collect();
452→    }
453→
454→    let head_count = max_items / 2;
455→    let tail_count = max_items - head_count - 1;
456→    let mut sample = Vec::with_capacity(max_items);
457→    sample.extend(sorted_model_ids.iter().take(head_count).cloned());
458→    sample.push("...".to_string());
459→    sample.extend(
460→        sorted_model_ids
461→            .iter()
462→            .skip(sorted_model_ids.len().saturating_sub(tail_count))
463→            .cloned(),
464→    );
465→    sample
466→}
