139→/// Reasoning effort suffixes appended to model IDs.
140→const REASONING_SUFFIXES: &[(&str, moltis_agents::model::ReasoningEffort)] = &[
141→    ("reasoning-low", moltis_agents::model::ReasoningEffort::Low),
142→    (
143→        "reasoning-medium",
144→        moltis_agents::model::ReasoningEffort::Medium,
