152→/// Split a model ID into (base_id, optional reasoning effort).
153→///
154→/// Examples:
155→/// - `"anthropic::claude-opus-4-5@reasoning-high"` → `("anthropic::claude-opus-4-5", Some(High))`
156→/// - `"gpt-4o"` → `("gpt-4o", None)`
157→#[must_use]
158→pub fn split_reasoning_suffix(
159→    model_id: &str,
160→) -> (&str, Option<moltis_agents::model::ReasoningEffort>) {
161→    if let Some((base, suffix)) = model_id.rsplit_once(REASONING_SUFFIX_SEP) {
162→        for &(tag, effort) in REASONING_SUFFIXES {
163→            if suffix == tag {
164→                return (base, Some(effort));
165→            }
166→        }
167→    }
168→    (model_id, None)
169→}
