511→async fn ollama_has_model(base_url: &str, model: &str) -> bool {
512→    let url = format!("{}/api/tags", base_url.trim_end_matches('/'));
513→    let response = match reqwest::Client::new().get(url).send().await {
514→        Ok(resp) => resp,
515→        Err(_) => return false,
516→    };
517→    if !response.status().is_success() {
518→        return false;
519→    }
520→    let value: serde_json::Value = match response.json().await {
521→        Ok(v) => v,
522→        Err(_) => return false,
523→    };
524→    value
525→        .get("models")
526→        .and_then(|m| m.as_array())
527→        .map(|models| {
528→            models.iter().any(|m| {
529→                let name = m.get("name").and_then(|n| n.as_str()).unwrap_or_default();
530→                name == model || name.starts_with(&format!("{model}:"))
531→            })
532→        })
533→        .unwrap_or(false)
534→}
