621→fn process_rss_bytes() -> u64 {
622→    let mut sys = sysinfo::System::new();
623→    let Some(pid) = sysinfo::get_current_pid().ok() else {
624→        return 0;
625→    };
626→    sys.refresh_memory();
627→    sys.refresh_processes_specifics(
628→        sysinfo::ProcessesToUpdate::Some(&[pid]),
629→        false,
630→        sysinfo::ProcessRefreshKind::nothing().with_memory(),
631→    );
632→    sys.process(pid).map(|p| p.memory()).unwrap_or(0)
633→}
