635→struct StartupMemProbe {
636→    enabled: bool,
637→    last_rss_bytes: u64,
638→}
639→
640→impl StartupMemProbe {
641→    fn new() -> Self {
642→        let enabled = env_flag_enabled("MOLTIS_STARTUP_MEM_TRACE");
643→        let last_rss_bytes = if enabled {
644→            process_rss_bytes()
645→        } else {
646→            0
647→        };
648→        Self {
649→            enabled,
650→            last_rss_bytes,
651→        }
652→    }
653→
654→    fn checkpoint(&mut self, stage: &str) {
655→        if !self.enabled {
656→            return;
657→        }
658→        let rss_bytes = process_rss_bytes();
659→        let delta_bytes = rss_bytes as i128 - self.last_rss_bytes as i128;
660→        self.last_rss_bytes = rss_bytes;
661→
662→        info!(
663→            stage,
664→            rss_bytes,
665→            delta_bytes = delta_bytes as i64,
666→            "startup memory checkpoint"
667→        );
668→    }
669→}
