243→fn merge_preferred_and_discovered_models(
244→    preferred: Vec<String>,
245→    discovered: Vec<DiscoveredModel>,
246→) -> Vec<DiscoveredModel> {
247→    let discovered_by_id: HashMap<String, &DiscoveredModel> =
248→        discovered.iter().map(|m| (m.id.clone(), m)).collect();
249→    let mut merged = Vec::new();
250→    let mut seen = HashSet::new();
251→
252→    for model_id in preferred {
