263→            }
264→        } else {
265→            DiscoveredModel::new(model_id.clone(), model_id)
266→        };
267→        merged.push(model);
268→    }
269→
270→    for model in discovered {
271→        if !seen.insert(model.id.clone()) {
272→            continue;
273→        }
274→        merged.push(model);
275→    }
276→
277→    merged
