321→/// Parse `Retry-After` header as milliseconds.
322→///
323→/// `Retry-After` may be either delta-seconds or an HTTP date. We currently
324→/// consume delta-seconds, which is what providers typically return for 429.
325→pub(crate) fn retry_after_ms_from_headers(headers: &reqwest::header::HeaderMap) -> Option<u64> {
326→    let value = headers.get(reqwest::header::RETRY_AFTER)?;
327→    let text = value.to_str().ok()?.trim();
328→    let seconds = text.parse::<u64>().ok()?;
329→    seconds.checked_mul(1_000)
330→}
