351→async fn discover_ollama_models_from_api(base_url: String) -> anyhow::Result<Vec<DiscoveredModel>> {
352→    let api_base = normalize_ollama_api_base_url(&base_url);
353→    let endpoint = format!("{}/api/tags", api_base.trim_end_matches('/'));
354→    let response = reqwest::Client::builder()
355→        .timeout(std::time::Duration::from_secs(2))
356→        .build()?
357→        .get(&endpoint)
358→        .send()
359→        .await?;
360→
361→    let status = response.status();
362→    if !status.is_success() {
363→        anyhow::bail!("ollama model discovery failed HTTP {status}");
364→    }
365→
366→    let payload: OllamaTagsPayload = response.json().await?;
367→    let mut models: Vec<DiscoveredModel> = payload
368→        .models
369→        .into_iter()
370→        .map(|entry| entry.name.trim().to_string())
371→        .filter(|model| !model.is_empty())
372→        .map(|model| DiscoveredModel::new(model.clone(), model))
373→        .collect();
374→    models.sort_by(|left, right| left.id.cmp(&right.id));
375→    models.dedup_by(|left, right| left.id == right.id);
376→    Ok(models)
377→}
