379→/// Spawn Ollama model discovery in a background thread and return the receiver
380→/// immediately, without blocking. Call `.recv()` later to collect the result.
381→fn start_ollama_discovery(
382→    base_url: &str,
383→) -> std::sync::mpsc::Receiver<anyhow::Result<Vec<DiscoveredModel>>> {
384→    let (tx, rx) = std::sync::mpsc::sync_channel(1);
385→    let base_url = base_url.to_string();
386→    std::thread::spawn(move || {
387→        let result = tokio::runtime::Builder::new_current_thread()
388→            .enable_all()
389→            .build()
390→            .map_err(anyhow::Error::from)
391→            .and_then(|rt| rt.block_on(discover_ollama_models_from_api(base_url)));
392→        let _ = tx.send(result);
393→    });
394→    rx
395→}
