417→/// Asynchronously fetch models from all discoverable provider APIs.
418→///
419→/// Runs `/v1/models` (or Ollama `/api/tags`) for each eligible provider
420→/// concurrently, then batch-probes any discovered Ollama models via
421→/// `/api/show` for tool-mode metadata. Returns everything needed for
422→/// lock-free registration.
423→///
424→/// `provider_filter` narrows the scope to a single provider name (case-
425→/// insensitive comparison against config name or alias).
426→pub async fn fetch_discoverable_models(
427→    config: &ProvidersConfig,
428→    env_overrides: &HashMap<String, String>,
429→    provider_filter: Option<&str>,
430→) -> RediscoveryResult {
431→    use futures::future::join_all;
432→
433→    let filter_matches =
434→        |name: &str| -> bool { provider_filter.is_none_or(|f| f.eq_ignore_ascii_case(name)) };
435→
436→    let mut tasks: Vec<(
437→        String,
438→        Pin<Box<dyn Future<Output = anyhow::Result<Vec<DiscoveredModel>>> + Send>>,
439→    )> = Vec::new();
440→
441→    // ── OpenAI builtin ────────────────────────────────────────────────
442→    if filter_matches("openai")
443→        && config.is_enabled("openai")
444→        && !cfg!(test)
445→        && let Some(key) = resolve_api_key(config, "openai", "OPENAI_API_KEY", env_overrides)
446→        && should_fetch_models(config, "openai")
447→    {
448→        let base_url = config
449→            .get("openai")
450→            .and_then(|e| e.base_url.clone())
451→            .or_else(|| env_value(env_overrides, "OPENAI_BASE_URL"))
452→            .unwrap_or_else(|| "https://api.openai.com/v1".into());
453→        tasks.push((
454→            "openai".into(),
455→            Box::pin(openai::fetch_models_from_api(key, base_url)),
456→        ));
457→    }
458→
459→    // ── Anthropic builtin ─────────────────────────────────────────────
460→    if filter_matches("anthropic")
461→        && config.is_enabled("anthropic")
462→        && !cfg!(test)
463→        && let Some(key) = resolve_api_key(config, "anthropic", "ANTHROPIC_API_KEY", env_overrides)
464→        && should_fetch_models(config, "anthropic")
465→    {
466→        let base_url = config
467→            .get("anthropic")
468→            .and_then(|e| e.base_url.clone())
469→            .or_else(|| env_value(env_overrides, "ANTHROPIC_BASE_URL"))
470→            .unwrap_or_else(|| "https://api.anthropic.com".into());
471→        tasks.push((
472→            "anthropic".into(),
473→            Box::pin(anthropic::fetch_models_from_api(key, base_url)),
474→        ));
475→    }
476→
477→    // ── OpenAI-compatible providers ───────────────────────────────────
478→    for def in OPENAI_COMPAT_PROVIDERS {
479→        if !filter_matches(def.config_name) || !config.is_enabled(def.config_name) {
480→            continue;
481→        }
482→
483→        let key = resolve_api_key(config, def.config_name, def.env_key, env_overrides);
484→        let key = if !def.requires_api_key {
485→            key.or_else(|| Some(secrecy::Secret::new(def.config_name.into())))
486→        } else if def.config_name == "gemini" {
487→            key.or_else(|| env_value(env_overrides, "GOOGLE_API_KEY").map(secrecy::Secret::new))
488→        } else {
489→            key
490→        };
491→        let Some(key) = key else {
492→            continue;
493→        };
494→
495→        let base_url = config
496→            .get(def.config_name)
497→            .and_then(|e| e.base_url.clone())
498→            .or_else(|| env_value(env_overrides, def.env_base_url_key))
