 73→
 74→        // Open the shared SQLite database (same moltis.db used by the gateway).
 75→        // WAL mode + synchronous=NORMAL avoids multi-second write contention.
 76→        let db_path = data_dir.join("moltis.db");
 77→        let db_pool = runtime.block_on(async {
 78→            use {
 79→                sqlx::sqlite::{SqliteConnectOptions, SqliteJournalMode, SqliteSynchronous},
 80→                std::str::FromStr,
 81→            };
 82→            let opts = SqliteConnectOptions::from_str(&format!("sqlite:{}", db_path.display()))
 83→                .expect("invalid moltis.db path")
 84→                .create_if_missing(true)
 85→                .journal_mode(SqliteJournalMode::Wal)
 86→                .synchronous(SqliteSynchronous::Normal);
 87→            let pool = sqlx::SqlitePool::connect_with(opts)
 88→                .await
 89→                .unwrap_or_else(|e| panic!("failed to open moltis.db: {e}"));
 90→            // Run migrations so the sessions table exists even if the gateway
 91→            // hasn't been started yet. Order: projects first (FK dependency).
 92→            if let Err(e) = moltis_projects::run_migrations(&pool).await {
 93→                emit_log("WARN", "bridge", &format!("projects migration: {e}"));
 94→            }
 95→            if let Err(e) = moltis_sessions::run_migrations(&pool).await {
 96→                emit_log("WARN", "bridge", &format!("sessions migration: {e}"));
 97→            }
 98→            if let Err(e) = moltis_gateway::run_migrations(&pool).await {
 99→                emit_log("WARN", "bridge", &format!("gateway migration: {e}"));
100→            }
101→            pool
102→        });
103→        let event_bus = SessionEventBus::new();
104→        let session_metadata = SqliteSessionMetadata::with_event_bus(db_pool.clone(), event_bus);
105→        let credential_store = runtime.block_on(async {
106→            // Keep vault metadata up to date so env var encryption status works
107→            // even when the full gateway server is not running.
108→            if let Err(e) = moltis_gateway::auth::moltis_vault::run_migrations(&db_pool).await {
109→                emit_log("WARN", "bridge", &format!("vault migration: {e}"));
110→            }
111→
112→            let vault = match moltis_gateway::auth::moltis_vault::Vault::new(db_pool.clone()).await
113→            {
114→                Ok(vault) => Some(Arc::new(vault)),
115→                Err(e) => {
116→                    emit_log("WARN", "bridge", &format!("vault init failed: {e}"));
117→                    None
118→                },
119→            };
120→
121→            match moltis_gateway::auth::CredentialStore::with_vault(
122→                db_pool.clone(),
123→                &moltis_config::discover_and_load().auth,
124→                vault,
125→            )
126→            .await
127→            {
128→                Ok(store) => Arc::new(store),
129→                Err(e) => panic!("failed to init credential store: {e}"),
130→            }
131→        });
132→
133→        emit_log("INFO", "bridge", "Bridge initialized successfully");
134→        Self {
135→            runtime,
136→            registry: RwLock::new(registry),
137→            session_store,
138→            session_metadata,
139→            credential_store,
140→            sandbox_default_image_override: RwLock::new(None),
141→        }
142→    }
143→}
