108→fn normalize_model_list(models: impl IntoIterator<Item = String>) -> Vec<String> {
109→    let mut out = Vec::new();
110→    for model in models {
111→        let trimmed = model.trim();
112→        if trimmed.is_empty() {
113→            continue;
114→        }
115→        // Persist raw IDs so provider-local preferences don't collide with
116→        // another provider's namespace (e.g. "openai::gpt-5.2").
117→        let normalized = raw_model_id(trimmed).trim().to_string();
118→        if normalized.is_empty() {
119→            continue;
120→        }
121→        if out.iter().any(|existing| existing == &normalized) {
122→            continue;
123→        }
124→        out.push(normalized);
125→    }
126→    out
127→}
