129→fn parse_models_param(params: &Value) -> Vec<String> {
130→    let from_array = params
131→        .get("models")
132→        .and_then(Value::as_array)
133→        .map(|values| {
134→            values
135→                .iter()
136→                .filter_map(Value::as_str)
137→                .map(ToString::to_string)
138→                .collect::<Vec<String>>()
139→        })
140→        .unwrap_or_default();
141→
142→    let mut models = normalize_model_list(from_array);
143→    if models.is_empty()
144→        && let Some(model) = params.get("model").and_then(Value::as_str)
145→    {
146→        models = normalize_model_list([model.to_string()]);
147→    }
148→    models
149→}
