1535→fn resolve_prompt_agent_id(session_entry: Option<&SessionEntry>) -> String {
1536→    let Some(entry) = session_entry else {
1537→        return "main".to_string();
1538→    };
1539→    let Some(agent_id) = entry
1540→        .agent_id
1541→        .as_deref()
1542→        .map(str::trim)
1543→        .filter(|value| !value.is_empty())
1544→    else {
1545→        return "main".to_string();
1546→    };
1547→    if agent_id == "main" {
1548→        return "main".to_string();
1549→    }
1550→    if moltis_config::agent_workspace_dir(agent_id).exists() {
1551→        return agent_id.to_string();
1552→    }
1553→    warn!(
1554→        session = %entry.key,
1555→        agent_id,
1556→        "session references unknown agent workspace, falling back to main prompt persona"
1557→    );
1558→    "main".to_string()
1559→}
