1614→async fn load_prompt_memory_for_session(
1615→    session_key: &str,
1616→    agent_id: &str,
1617→    mode: PromptMemoryMode,
1618→    state_store: Option<&SessionStateStore>,
1619→) -> (Option<LoadedWorkspaceMarkdown>, bool) {
1620→    let live_memory = || moltis_config::load_memory_md_for_agent_with_source(agent_id);
1621→
1622→    if !matches!(mode, PromptMemoryMode::FrozenAtSessionStart) {
1623→        return (live_memory(), false);
1624→    }
1625→
1626→    let Some(store) = state_store else {
1627→        return (live_memory(), false);
1628→    };
1629→
1630→    let key = prompt_memory_snapshot_key(agent_id);
1631→    match store.get(session_key, PROMPT_MEMORY_NAMESPACE, &key).await {
1632→        Ok(Some(raw)) => match serde_json::from_str::<Option<LoadedWorkspaceMarkdown>>(&raw) {
1633→            Ok(snapshot) => return (snapshot, true),
1634→            Err(error) => warn!(
1635→                session = %session_key,
1636→                agent_id,
1637→                error = %error,
1638→                "failed to deserialize prompt memory snapshot, rebuilding"
1639→            ),
1640→        },
1641→        Ok(None) => {},
1642→        Err(error) => warn!(
1643→            session = %session_key,
1644→            agent_id,
1645→            error = %error,
1646→            "failed to read prompt memory snapshot, falling back to live memory"
1647→        ),
1648→    }
1649→
1650→    let memory = live_memory();
1651→    match serde_json::to_string(&memory) {
1652→        Ok(serialized) => {
1653→            if let Err(error) = store
1654→                .set(session_key, PROMPT_MEMORY_NAMESPACE, &key, &serialized)
1655→                .await
1656→            {
1657→                warn!(
1658→                    session = %session_key,
1659→                    agent_id,
1660→                    error = %error,
1661→                    "failed to persist prompt memory snapshot"
1662→                );
1663→                return (memory, false);
1664→            }
1665→            (memory, true)
1666→        },
1667→        Err(error) => {
1668→            warn!(
1669→                session = %session_key,
1670→                agent_id,
1671→                error = %error,
1672→                "failed to serialize prompt memory snapshot"
1673→            );
1674→            (memory, false)
1675→        },
1676→    }
1677→}
