1679→async fn load_prompt_persona_for_session(
1680→    session_key: &str,
1681→    session_entry: Option<&SessionEntry>,
1682→    state_store: Option<&SessionStateStore>,
1683→) -> PromptPersona {
1684→    let agent_id = resolve_prompt_agent_id(session_entry);
