1718→    let discoverer = moltis_skills::discover::FsSkillDiscoverer::new(search_paths);
1719→    match discoverer.discover().await {
1720→        Ok(skills) => skills,
1721→        Err(e) => {
1722→            warn!("failed to discover skills: {e}");
1723→            Vec::new()
