1764→fn build_tool_context(
1765→    session_key: &str,
1766→    accept_language: Option<&str>,
1767→    conn_id: Option<&str>,
1768→    runtime_context: Option<&PromptRuntimeContext>,
1769→) -> Value {
1770→    let mut tool_context = serde_json::json!({
1771→        "_session_key": session_key,
1772→    });
1773→    if let Some(channel_binding) = channel_binding_from_runtime_context(runtime_context)
1774→        && let Ok(channel_value) = serde_json::to_value(channel_binding)
1775→    {
1776→        tool_context["_channel"] = channel_value;
1777→    }
1778→    if let Some(lang) = accept_language {
1779→        tool_context["_accept_language"] = serde_json::json!(lang);
1780→    }
1781→    if let Some(cid) = conn_id {
1782→        tool_context["_conn_id"] = serde_json::json!(cid);
1783→    }
1784→    tool_context
