1787→async fn build_prompt_runtime_context(
1788→    state: &Arc<dyn ChatRuntime>,
1789→    provider: &Arc<dyn moltis_agents::model::LlmProvider>,
1790→    session_key: &str,
1791→    session_entry: Option<&SessionEntry>,
1792→) -> PromptRuntimeContext {
1793→    let data_dir = moltis_config::data_dir();
1794→    let data_dir_display = data_dir.display().to_string();
1795→
1796→    let sudo_fut = detect_host_sudo_access();
1797→    let sandbox_fut = async {
1798→        if let Some(router) = state.sandbox_router() {
1799→            let is_sandboxed = router.is_sandboxed(session_key).await;
1800→            // Only include sandbox context when sandbox is actually enabled for
1801→            // this session.  When disabled, omitting it prevents the LLM from
1802→            // hallucinating sandbox usage (see #360).  This intentionally
1803→            // discards `session_override` — its only consumer is the prompt
1804→            // line we are omitting, and no other code reads it from
1805→            // `PromptSandboxRuntimeContext`.
1806→            if !is_sandboxed {
1807→                return None;
1808→            }
1809→            let config = router.config();
1810→            let backend_name = router.backend_name();
1811→            let workspace_mount = config.workspace_mount.to_string();
1812→            let workspace_path = (workspace_mount != "none").then(|| data_dir_display.clone());
1813→            Some(PromptSandboxRuntimeContext {
1814→                exec_sandboxed: true,
1815→                mode: Some(config.mode.to_string()),
1816→                backend: Some(backend_name.to_string()),
1817→                scope: Some(config.scope.to_string()),
1818→                image: Some(router.resolve_image(session_key, None).await),
1819→                home: Some("/home/sandbox".to_string()),
1820→                workspace_mount: Some(workspace_mount),
1821→                workspace_path,
1822→                no_network: prompt_sandbox_no_network_state(backend_name, config.no_network),
1823→                session_override: session_entry.and_then(|entry| entry.sandbox_enabled),
1824→            })
1825→        } else {
1826→            None
1827→        }
1828→    };
1829→
1830→    let ((sudo_non_interactive, sudo_status), sandbox_ctx) = tokio::join!(sudo_fut, sandbox_fut);
1831→
1832→    let configured_timezone = state
1833→        .sandbox_router()
1834→        .and_then(|r| r.config().timezone.clone());
1835→    let timezone = Some(server_prompt_timezone(configured_timezone.as_deref()));
1836→
1837→    let location = state
1838→        .cached_location()
1839→        .await
1840→        .as_ref()
1841→        .map(|loc| loc.to_string());
1842→    let channel_context = resolve_channel_runtime_context(session_key, session_entry);
1843→
1844→    let mut host_ctx = PromptHostRuntimeContext {
1845→        host: Some(state.hostname().to_string()),
1846→        os: Some(std::env::consts::OS.to_string()),
1847→        arch: Some(std::env::consts::ARCH.to_string()),
1848→        shell: detect_runtime_shell(),
1849→        time: None,
1850→        provider: Some(provider.name().to_string()),
1851→        model: Some(provider.id().to_string()),
1852→        session_key: Some(session_key.to_string()),
1853→        surface: channel_context.surface,
1854→        session_kind: channel_context.session_kind,
1855→        channel_type: channel_context.channel_type,
1856→        channel_account_id: channel_context.account_id,
1857→        channel_chat_id: channel_context.chat_id,
1858→        channel_chat_type: channel_context.chat_type,
1859→        data_dir: Some(data_dir_display),
1860→        sudo_non_interactive,
1861→        sudo_status,
1862→        timezone,
1863→        location,
1864→        ..Default::default()
1865→    };
1866→    refresh_runtime_prompt_time(&mut host_ctx);
1867→
1868→    // Build nodes context from connected remote nodes.
1869→    let connected = state.connected_nodes().await;
1870→    let nodes_ctx = if connected.is_empty() {
1871→        None
1872→    } else {
1873→        let default_node_id = session_entry.and_then(|e| e.node_id.clone());
1874→        Some(PromptNodesRuntimeContext {
1875→            nodes: connected
1876→                .into_iter()
1877→                .map(|n| PromptNodeInfo {
1878→                    node_id: n.node_id,
1879→                    display_name: n.display_name,
1880→                    platform: n.platform,
1881→                    capabilities: n.capabilities,
1882→                    cpu_count: n.cpu_count,
1883→                    mem_total: n.mem_total,
1884→                    runtimes: n.runtimes,
1885→                    providers: n.providers,
1886→                })
1887→                .collect(),
1888→            default_node_id,
1889→        })
1890→    };
1891→
1892→    PromptRuntimeContext {
1893→        host: host_ctx,
1894→        sandbox: sandbox_ctx,
1895→        nodes: nodes_ctx,
1896→    }
1897→}
