1899→fn refresh_runtime_prompt_time(host: &mut PromptHostRuntimeContext) {
1900→    host.time = Some(prompt_now_for_timezone(host.timezone.as_deref()));
1901→    host.today = Some(prompt_today_for_timezone(host.timezone.as_deref()));
