1904→fn server_prompt_timezone(configured_timezone: Option<&str>) -> String {
1905→    if let Some(timezone) = configured_timezone
1906→        .map(str::trim)
1907→        .filter(|value| !value.is_empty())
1908→    {
1909→        return timezone.to_string();
1910→    }
1911→    "server-local".to_string()
1912→}
1913→
1914→fn prompt_now_for_timezone(timezone: Option<&str>) -> String {
1915→    #[cfg(any(feature = "web-ui", feature = "push-notifications"))]
1916→    {
1917→        use chrono::{Local, Utc};
1918→
1919→        let trimmed_timezone = timezone.map(str::trim).filter(|value| !value.is_empty());
1920→
1921→        if let Some(tz) = trimmed_timezone.and_then(|name| name.parse::<chrono_tz::Tz>().ok()) {
1922→            return Utc::now()
1923→                .with_timezone(&tz)
1924→                .format("%Y-%m-%d %H:%M:%S %Z")
1925→                .to_string();
1926→        }
1927→
1928→        // Fallback to server local clock when timezone is unknown/non-IANA.
1929→        Local::now().format("%Y-%m-%d %H:%M:%S %Z").to_string()
1930→    }
1931→
1932→    #[cfg(not(any(feature = "web-ui", feature = "push-notifications")))]
1933→    {
1934→        let unix_secs = std::time::SystemTime::now()
1935→            .duration_since(std::time::UNIX_EPOCH)
1936→            .unwrap_or_default()
1937→            .as_secs();
1938→        let tz = timezone.unwrap_or("server-local");
1939→        format!("unix={unix_secs} {tz}")
1940→    }
1941→}
1942→
1943→fn prompt_today_for_timezone(timezone: Option<&str>) -> String {
1944→    #[cfg(any(feature = "web-ui", feature = "push-notifications"))]
1945→    {
1946→        use chrono::{Local, Utc};
1947→
1948→        let trimmed_timezone = timezone.map(str::trim).filter(|value| !value.is_empty());
1949→
1950→        if let Some(tz) = trimmed_timezone.and_then(|name| name.parse::<chrono_tz::Tz>().ok()) {
1951→            return Utc::now().with_timezone(&tz).format("%Y-%m-%d").to_string();
1952→        }
1953→
1954→        Local::now().format("%Y-%m-%d").to_string()
1955→    }
1956→
1957→    #[cfg(not(any(feature = "web-ui", feature = "push-notifications")))]
1958→    {
1959→        let _ = timezone;
1960→        let unix_days = std::time::SystemTime::now()
1961→            .duration_since(std::time::UNIX_EPOCH)
1962→            .unwrap_or_default()
1963→            .as_secs()
1964→            / 86_400;
1965→        format!("unix-day={unix_days}")
1966→    }
1967→}
1968→
1969→fn normalized_iana_timezone(timezone: Option<&str>) -> Option<String> {
1970→    timezone
1971→        .map(str::trim)
1972→        .filter(|value| !value.is_empty())
1973→        .and_then(|value| value.parse::<chrono_tz::Tz>().ok())
1974→        .map(|tz| tz.to_string())
1975→}
1976→
1977→fn default_user_prompt_timezone() -> Option<String> {
1978→    moltis_config::resolve_user_profile()
1979→        .timezone
1980→        .as_ref()
1981→        .map(|timezone| timezone.name().to_string())
1982→        .and_then(|timezone| normalized_iana_timezone(Some(&timezone)))
1983→}
