1985→fn apply_request_runtime_context(host: &mut PromptHostRuntimeContext, params: &Value) {
1986→    host.accept_language = params
1987→        .get("_accept_language")
1988→        .and_then(|v| v.as_str())
1989→        .map(String::from);
1990→    host.remote_ip = params
1991→        .get("_remote_ip")
1992→        .and_then(|v| v.as_str())
1993→        .map(String::from);
1994→
1995→    // Extract sender_id from channel metadata (set by channel handlers).
1996→    if host.channel_sender_id.is_none() {
1997→        host.channel_sender_id = params
1998→            .get("channel")
1999→            .and_then(|ch| ch.get("sender_id"))
2000→            .and_then(|v| v.as_str())
2001→            .map(String::from);
2002→    }
2003→
2004→    if let Some(timezone) =
2005→        normalized_iana_timezone(params.get("_timezone").and_then(|v| v.as_str()))
2006→            .or_else(default_user_prompt_timezone)
2007→    {
2008→        host.timezone = Some(timezone);
2009→    }
2010→
2011→    refresh_runtime_prompt_time(host);
2012→}
