2014→fn prompt_sandbox_no_network_state(backend: &str, configured_no_network: bool) -> Option<bool> {
2015→    match backend {
2016→        // Docker supports `--network=none`, so this value is reliable.
2017→        "docker" => Some(configured_no_network),
2018→        // Apple Container currently has no equivalent runtime toggle, and
2019→        // failover wrappers may switch backends dynamically.
2020→        _ => None,
2021→    }
2022→}
