2024→fn apply_runtime_tool_filters(
2025→    base: &ToolRegistry,
2026→    config: &moltis_config::MoltisConfig,
2027→    _skills: &[moltis_skills::types::SkillMetadata],
2028→    mcp_disabled: bool,
2029→    policy_context: &PolicyContext,
2030→) -> ToolRegistry {
2031→    let base_registry = if mcp_disabled {
2032→        base.clone_without_mcp()
2033→    } else {
2034→        base.clone_without(&[])
2035→    };
2036→
2037→    let policy = resolve_effective_policy(config, policy_context);
2038→    // NOTE: Do not globally restrict tools by discovered skill `allowed_tools`.
2039→    // Skills are always discovered for prompt injection; applying those lists at
2040→    // runtime can unintentionally remove unrelated tools (for example, leaving
2041→    // only `web_fetch` and preventing `create_skill` from being called).
2042→    // Tool availability here is controlled by configured runtime policy.
2043→    base_registry.clone_allowed_by(|name| policy.is_allowed(name))
2044→}
