2046→/// Build a `PolicyContext` from runtime context and request parameters.
2047→fn build_policy_context(
2048→    agent_id: &str,
2049→    runtime_context: Option<&PromptRuntimeContext>,
2050→    params: Option<&Value>,
2051→) -> PolicyContext {
2052→    let host = runtime_context.map(|rc| &rc.host);
2053→    // sender_id: prefer params["channel"]["sender_id"] (fresh from channel
2054→    // dispatch), fall back to host.channel_sender_id (set by
2055→    // apply_request_runtime_context earlier in the call chain).
2056→    let sender_id = params
2057→        .and_then(|p| p.get("channel"))
2058→        .and_then(|ch| ch.get("sender_id"))
2059→        .and_then(|v| v.as_str())
2060→        .map(String::from)
2061→        .or_else(|| host.and_then(|h| h.channel_sender_id.clone()));
2062→    PolicyContext {
2063→        agent_id: agent_id.to_string(),
2064→        provider: host.and_then(|h| h.provider.clone()),
2065→        channel: host.and_then(|h| h.channel_type.clone()),
2066→        channel_account_id: host.and_then(|h| h.channel_account_id.clone()),
2067→        group_id: host.and_then(|h| h.channel_chat_type.clone()),
2068→        sender_id,
2069→        sandboxed: runtime_context
2070→            .and_then(|rc| rc.sandbox.as_ref())
2071→            .is_some_and(|s| s.exec_sandboxed),
2072→    }
2073→}
