2234→    fn build_priority_order(models: &[String]) -> HashMap<String, usize> {
2235→        let mut order = HashMap::new();
2236→        for (idx, model) in models.iter().enumerate() {
2237→            let key = normalize_model_key(model);
2238→            if !key.is_empty() {
2239→                let _ = order.entry(key).or_insert(idx);
2240→            }
2241→        }
2242→        order
2243→    }
2244→
2245→    fn priority_rank(order: &HashMap<String, usize>, model: &moltis_providers::ModelInfo) -> usize {
2246→        let full = normalize_model_key(&model.id);
2247→        if let Some(rank) = order.get(&full) {
2248→            return *rank;
2249→        }
2250→        let raw = normalize_model_key(raw_model_id(&model.id));
2251→        if let Some(rank) = order.get(&raw) {
2252→            return *rank;
2253→        }
2254→        let display = normalize_model_key(&model.display_name);
2255→        if let Some(rank) = order.get(&display) {
2256→            return *rank;
2257→        }
2258→        usize::MAX
2259→    }
2260→
2261→    fn prioritize_models<'a>(
2262→        order: &HashMap<String, usize>,
2263→        models: impl Iterator<Item = &'a moltis_providers::ModelInfo>,
2264→    ) -> Vec<&'a moltis_providers::ModelInfo> {
2265→        let mut ordered: Vec<(usize, &'a moltis_providers::ModelInfo)> =
2266→            models.enumerate().collect();
2267→        ordered.sort_by(|(idx_a, a), (idx_b, b)| {
2268→            let rank_a = Self::priority_rank(order, a);
2269→            let rank_b = Self::priority_rank(order, b);
2270→            // Preferred (rank != MAX) first, then non-preferred
2271→            let bucket_a = if rank_a == usize::MAX {
2272→                1u8
2273→            } else {
2274→                0
2275→            };
2276→            let bucket_b = if rank_b == usize::MAX {
2277→                1u8
2278→            } else {
2279→                0
2280→            };
2281→            bucket_a
2282→                .cmp(&bucket_b)
2283→                .then_with(|| {
2284→                    if bucket_a == 0 {
2285→                        rank_a.cmp(&rank_b)
2286→                    } else {
2287→                        Ordering::Equal
2288→                    }
2289→                })
2290→                .then_with(|| {
2291→                    a.display_name
2292→                        .to_lowercase()
2293→                        .cmp(&b.display_name.to_lowercase())
2294→                })
2295→                .then_with(|| {
