2297→                        .cmp(&subscription_provider_rank(&b.provider))
2298→                })
2299→                .then_with(|| idx_a.cmp(idx_b))
2300→        });
2301→        ordered.into_iter().map(|(_, model)| model).collect()
2302→    }
