2342→fn levenshtein_distance(a: &str, b: &str) -> usize {
2343→    if a.is_empty() {
2344→        return b.chars().count();
2345→    }
2346→    if b.is_empty() {
2347→        return a.chars().count();
2348→    }
2349→
2350→    let b_chars: Vec<char> = b.chars().collect();
2351→    let a_chars: Vec<char> = a.chars().collect();
2352→    let mut prev: Vec<usize> = (0..=b_chars.len()).collect();
2353→    let mut curr = vec![0; b_chars.len() + 1];
2354→
2355→    for (i, a_ch) in a_chars.iter().enumerate() {
2356→        curr[0] = i + 1;
2357→        for (j, b_ch) in b_chars.iter().enumerate() {
2358→            let cost = usize::from(a_ch != b_ch);
2359→            let deletion = prev[j + 1] + 1;
2360→            let insertion = curr[j] + 1;
2361→            let substitution = prev[j] + cost;
2362→            curr[j + 1] = deletion.min(insertion).min(substitution);
2363→        }
2364→        std::mem::swap(&mut prev, &mut curr);
2365→    }
2366→
2367→    prev[b_chars.len()]
2368→}
2369→
2370→fn suggest_model_ids(
2371→    requested_model_id: &str,
2372→    available_model_ids: &[String],
2373→    limit: usize,
2374→) -> Vec<String> {
2375→    if requested_model_id.trim().is_empty() || available_model_ids.is_empty() || limit == 0 {
2376→        return Vec::new();
2377→    }
2378→
2379→    let requested_provider = model_id_provider(requested_model_id).map(str::to_ascii_lowercase);
2380→    let requested_raw = raw_model_id(requested_model_id);
2381→    let requested_norm = normalize_model_lookup_key(requested_model_id);
2382→    let requested_raw_norm = normalize_model_lookup_key(requested_raw);
2383→
2384→    let mut ranked: Vec<(String, bool, usize, usize, usize)> = available_model_ids
2385→        .iter()
2386→        .filter_map(|candidate| {
2387→            let candidate_provider = model_id_provider(candidate).map(str::to_ascii_lowercase);
2388→            let provider_match = requested_provider
2389→                .as_deref()
2390→                .zip(candidate_provider.as_deref())
2391→                .is_some_and(|(left, right)| left == right);
2392→
2393→            let candidate_raw = raw_model_id(candidate);
2394→            let candidate_norm = normalize_model_lookup_key(candidate);
2395→            let candidate_raw_norm = normalize_model_lookup_key(candidate_raw);
2396→
2397→            let raw_distance = levenshtein_distance(&requested_raw_norm, &candidate_raw_norm);
2398→            let full_distance = levenshtein_distance(&requested_norm, &candidate_norm);
2399→            let contains = requested_raw_norm.contains(&candidate_raw_norm)
2400→                || candidate_raw_norm.contains(&requested_raw_norm)
2401→                || requested_norm.contains(&candidate_norm)
2402→                || candidate_norm.contains(&requested_norm);
2403→
2404→            // Keep nearest neighbors and strong substring matches. This trims
2405→            // unrelated model IDs from suggestion logs/responses.
2406→            let distance_cap = requested_raw_norm
2407→                .len()
2408→                .max(candidate_raw_norm.len())
2409→                .max(3)
2410→                / 2
2411→                + 2;
2412→            if !contains && raw_distance > distance_cap {
2413→                return None;
2414→            }
2415→
2416→            Some((
2417→                candidate.clone(),
2418→                provider_match,
2419→                raw_distance,
2420→                full_distance,
2421→                requested_raw_norm.len().abs_diff(candidate_raw_norm.len()),
2422→            ))
2423→        })
2424→        .collect();
2425→
2426→    ranked.sort_by(|left, right| {
2427→        right
2428→            .1
2429→            .cmp(&left.1) // provider match first
2430→            .then(left.2.cmp(&right.2)) // nearest raw model id
2431→            .then(left.3.cmp(&right.3)) // nearest full model id
2432→            .then(left.4.cmp(&right.4)) // similar length
2433→            .then(left.0.cmp(&right.0))
2434→    });
2435→
2436→    ranked.into_iter().map(|(id, ..)| id).take(limit).collect()
2437→}
