2444→        let order = self.priority_order().await;
2445→        let all_models = reg.list_models_with_reasoning_variants();
2446→
2447→        // Hide models older than 1 year from the chat selector unless the
2448→        // user opted in via `providers.show_legacy_models`.  Preferred models
2449→        // and models without a timestamp are never hidden.
2450→        let legacy_cutoff: Option<i64> = if self.show_legacy_models {
2451→            None
2452→        } else {
2453→            let one_year_ago = std::time::SystemTime::now()
2454→                .duration_since(std::time::UNIX_EPOCH)
2455→                .unwrap_or_default()
2456→                .as_secs() as i64
2457→                - 365 * 24 * 60 * 60;
2458→            Some(one_year_ago)
2459→        };
2460→
2461→        let prioritized = Self::prioritize_models(
2462→            &order,
2463→            all_models
2464→                .iter()
2465→                .filter(|m| moltis_providers::is_chat_capable_model(&m.id))
2466→                .filter(|m| !disabled.is_disabled(&m.id))
2467→                .filter(|m| disabled.unsupported_info(&m.id).is_none()),
2468→        );
2469→        debug!(model_count = prioritized.len(), "models.list response");
2470→        let models: Vec<_> = prioritized
2471→            .iter()
2472→            .copied()
2473→            .filter(|m| {
2474→                let preferred = Self::priority_rank(&order, m) != usize::MAX;
2475→                if preferred {
2476→                    return true;
2477→                }
2478→                match (legacy_cutoff, m.created_at) {
2479→                    (Some(cutoff), Some(ts)) => ts >= cutoff,
2480→                    _ => true, // no cutoff or no timestamp → keep
2481→                }
2482→            })
2483→            .map(|m| {
2484→                let preferred = Self::priority_rank(&order, m) != usize::MAX;
2485→                serde_json::json!({
2486→                    "id": m.id,
2487→                    "provider": m.provider,
2488→                    "displayName": m.display_name,
2489→                    "supportsTools": m.capabilities.tools,
2490→                    "supportsVision": m.capabilities.vision,
2491→                    "supportsReasoning": m.capabilities.reasoning,
2492→                    "preferred": preferred,
2493→                    "recommended": m.recommended,
2494→                    "createdAt": m.created_at,
2495→                    "unsupported": false,
2496→                    "unsupportedReason": Value::Null,
2497→                    "unsupportedProvider": Value::Null,
2498→                    "unsupportedUpdatedAt": Value::Null,
2499→                })
