2591→    async fn detect_supported(&self, params: Value) -> ServiceResult {
2592→        let background = params
2593→            .get("background")
2594→            .and_then(|v| v.as_bool())
2595→            .unwrap_or(false);
2596→        let reason = params
2597→            .get("reason")
2598→            .and_then(|v| v.as_str())
2599→            .unwrap_or("manual")
2600→            .to_string();
2601→        let max_parallel = params
2602→            .get("maxParallel")
2603→            .and_then(|v| v.as_u64())
2604→            .map(|v| v.clamp(1, 32) as usize)
2605→            .unwrap_or(8);
2606→        let max_parallel_per_provider = probe_max_parallel_per_provider(&params);
2607→        let provider_filter = provider_filter_from_params(&params);
2608→
2609→        let _run_permit: OwnedSemaphorePermit = if background {
2610→            match Arc::clone(&self.detect_gate).try_acquire_owned() {
2611→                Ok(permit) => permit,
2612→                Err(_) => {
2613→                    return Ok(serde_json::json!({
2614→                        "ok": true,
2615→                        "background": true,
2616→                        "reason": reason,
2617→                        "skipped": true,
2618→                        "message": "model probe already running",
2619→                    }));
2620→                },
2621→            }
2622→        } else {
2623→            Arc::clone(&self.detect_gate)
2624→                .acquire_owned()
2625→                .await
2626→                .map_err(|_| ServiceError::message("model probe gate closed"))?
2627→        };
2628→
2629→        // Install a cancellation token for this run so cancel_detect() can stop it.
2630→        let cancel_token = CancellationToken::new();
2631→        {
2632→            let mut guard = self.detect_cancel.write().await;
2633→            *guard = Some(cancel_token.clone());
2634→        }
2635→
2636→        let state = self.state.get().cloned();
2637→
2638→        // Phase 0: re-discover models from provider APIs so that newly
2639→        // added models (e.g. a model loaded into llama.cpp after startup)
2640→        // are found before probing.
2641→        //
2642→        // HTTP fetches and Ollama `/api/show` probes run outside the
2643→        // registry lock; only the fast in-memory registration takes it.
2644→        {
2645→            let env_snapshot = self.env_overrides.read().await.clone();
2646→            let result = moltis_providers::fetch_discoverable_models(
2647→                &self.providers_config,
2648→                &env_snapshot,
2649→                provider_filter.as_deref(),
2650→            )
2651→            .await;
2652→            if !result.is_empty() {
2653→                let mut reg = self.providers.write().await;
2654→                let new_count = reg.register_rediscovered_models(
2655→                    &self.providers_config,
2656→                    &env_snapshot,
2657→                    &result,
2658→                );
2659→                if new_count > 0 {
2660→                    tracing::info!(
2661→                        new_models = new_count,
2662→                        "rediscovery registered new models before probe"
2663→                    );
2664→                }
2665→            }
2666→        }
2667→
2668→        // Phase 1: notify clients to refresh and show the full current model list first.
2669→        if let Some(state) = state.as_ref() {
2670→            broadcast(
2671→                state,
2672→                "models.updated",
2673→                serde_json::json!({
2674→                    "phase": "catalog",
2675→                    "background": background,
2676→                    "reason": reason,
2677→                    "provider": provider_filter.as_deref(),
2678→                }),

2679→                BroadcastOpts::default(),
2680→            )
2681→            .await;
2682→        }
2683→
2684→        let checks = {
2685→            let reg = self.providers.read().await;
2686→            let disabled = self.disabled.read().await;
2687→            reg.list_models()
2688→                .iter()
2689→                .filter(|m| !disabled.is_disabled(&m.id))
2690→                .filter(|m| provider_matches_filter(&m.provider, provider_filter.as_deref()))
2691→                .filter_map(|m| {
2692→                    reg.get(&m.id).map(|provider| {
2693→                        (
2694→                            m.id.clone(),
2695→                            m.display_name.clone(),
2696→                            provider.name().to_string(),
2697→                            provider,
2698→                        )
2699→                    })
2700→                })
2701→                .collect::<Vec<_>>()
2702→        };
2703→
2704→        let total = checks.len();
2705→        if let Some(state) = state.as_ref() {
2706→            broadcast(
2707→                state,
2708→                "models.updated",
2709→                serde_json::json!({
2710→                    "phase": "start",
2711→                    "background": background,
2712→                    "reason": reason,
2713→                    "provider": provider_filter.as_deref(),
2714→                    "maxParallelPerProvider": max_parallel_per_provider,
2715→                    "total": total,
2716→                    "checked": 0,
2717→                    "supported": 0,
2718→                    "unsupported": 0,
2719→                    "errors": 0,
2720→                }),
2721→                BroadcastOpts::default(),
2722→            )
2723→            .await;
2724→        }
2725→
2726→        let limiter = Arc::new(Semaphore::new(max_parallel));
2727→        let provider_limiter = Arc::new(ProbeProviderLimiter::new(max_parallel_per_provider));
2728→        let rate_limiter = Arc::new(ProbeRateLimiter::default());
2729→        let mut tasks = tokio::task::JoinSet::new();
2730→        for (model_id, display_name, provider_name, provider) in checks {
2731→            let limiter = Arc::clone(&limiter);
2732→            let provider_limiter = Arc::clone(&provider_limiter);
2733→            let rate_limiter = Arc::clone(&rate_limiter);
2734→            tasks.spawn(run_single_probe(
2735→                model_id,
2736→                display_name,
2737→                provider_name,
2738→                provider,
2739→                limiter,
2740→                provider_limiter,
2741→                rate_limiter,
2742→            ));
2743→        }
2744→
2745→        let mut results = Vec::with_capacity(total);
2746→        let mut checked = 0usize;
2747→        let mut supported = 0usize;
2748→        let mut unsupported = 0usize;
2749→        let mut flagged = 0usize;
2750→        let mut cleared = 0usize;
2751→        let mut errors = 0usize;
2752→        let mut supported_by_provider: BTreeMap<String, Vec<Value>> = BTreeMap::new();
2753→        let mut unsupported_by_provider: BTreeMap<String, Vec<Value>> = BTreeMap::new();
2754→        let mut errors_by_provider: BTreeMap<String, Vec<Value>> = BTreeMap::new();
2755→
2756→        let mut cancelled = false;
2757→        loop {
2758→            let joined = tokio::select! {
2759→                biased;
2760→                () = cancel_token.cancelled() => {
2761→                    tasks.abort_all();
2762→                    cancelled = true;
2763→                    break;
2764→                }
2765→                next = tasks.join_next() => match next {
2766→                    Some(joined) => joined,
2767→                    None => break,
2768→                },
2769→            };
2770→            checked += 1;
2771→            let outcome = match joined {
2772→                Ok(outcome) => outcome,
2773→                Err(err) => {
2774→                    errors += 1;
2775→                    results.push(serde_json::json!({
2776→                        "modelId": "",
2777→                        "displayName": "",
2778→                        "provider": "",
2779→                        "status": "error",
2780→                        "error": format!("probe task failed: {err}"),
2781→                    }));
2782→                    if let Some(state) = state.as_ref() {
2783→                        broadcast(
2784→                            state,
2785→                            "models.updated",
2786→                            serde_json::json!({
2787→                                "phase": "progress",
2788→                                "background": background,
2789→                                "reason": reason,
2790→                                "provider": provider_filter.as_deref(),
2791→                                "total": total,
2792→                                "checked": checked,
2793→                                "supported": supported,
2794→                                "unsupported": unsupported,
2795→                                "errors": errors,
2796→                            }),
2797→                            BroadcastOpts::default(),
2798→                        )
2799→                        .await;
2800→                    }
2801→                    continue;
2802→                },
2803→            };
2804→
2805→            match outcome.status {
2806→                ProbeStatus::Supported => {
2807→                    supported += 1;
2808→                    push_provider_model(
2809→                        &mut supported_by_provider,
2810→                        &outcome.provider_name,
2811→                        &outcome.model_id,
2812→                        &outcome.display_name,
2813→                    );
2814→                    let mut changed = false;
2815→                    {
2816→                        let mut store = self.disabled.write().await;
2817→                        if store.clear_unsupported(&outcome.model_id) {
2818→                            changed = true;
2819→                            if let Err(err) = store.save() {
2820→                                warn!(
2821→                                    model = %outcome.model_id,
2822→                                    error = %err,
2823→                                    "failed to persist unsupported model clear"
2824→                                );
2825→                            }
2826→                        }
2827→                    }
2828→                    if changed {
2829→                        cleared += 1;
2830→                        if let Some(state) = state.as_ref() {
2831→                            broadcast(
2832→                                state,
2833→                                "models.updated",
2834→                                serde_json::json!({
2835→                                    "modelId": outcome.model_id,
2836→                                    "unsupported": false,
2837→                                }),
2838→                                BroadcastOpts::default(),
2839→                            )
2840→                            .await;
2841→                        }
2842→                    }
2843→
2844→                    results.push(serde_json::json!({
2845→                        "modelId": outcome.model_id,
2846→                        "displayName": outcome.display_name,
2847→                        "provider": outcome.provider_name,
2848→                        "status": "supported",
2849→                    }));
2850→                },
2851→                ProbeStatus::Unsupported { detail, provider } => {
2852→                    unsupported += 1;
2853→                    push_provider_model(
2854→                        &mut unsupported_by_provider,
2855→                        &outcome.provider_name,
2856→                        &outcome.model_id,
2857→                        &outcome.display_name,
2858→                    );
2859→                    let mut changed = false;
2860→                    let mut updated_at_ms = now_ms();
2861→                    {
2862→                        let mut store = self.disabled.write().await;
2863→                        if store.mark_unsupported(&outcome.model_id, &detail, Some(&provider)) {
2864→                            changed = true;
2865→                            if let Some(info) = store.unsupported_info(&outcome.model_id) {
2866→                                updated_at_ms = info.updated_at_ms;
2867→                            }
2868→                            if let Err(save_err) = store.save() {
2869→                                warn!(
2870→                                    model = %outcome.model_id,
2871→                                    provider = provider,
2872→                                    error = %save_err,
2873→                                    "failed to persist unsupported model flag"
2874→                                );
2875→                            }
2876→                        }
2877→                    }
2878→                    if changed {
2879→                        flagged += 1;
2880→                        if let Some(state) = state.as_ref() {
2881→                            broadcast(
2882→                                state,
2883→                                "models.updated",
2884→                                serde_json::json!({
2885→                                    "modelId": outcome.model_id,
2886→                                    "unsupported": true,
2887→                                    "unsupportedReason": detail,
2888→                                    "unsupportedProvider": provider,
2889→                                    "unsupportedUpdatedAt": updated_at_ms,
2890→                                }),
2891→                                BroadcastOpts::default(),
2892→                            )
2893→                            .await;
2894→                        }
2895→                    }
2896→
2897→                    results.push(serde_json::json!({
2898→                        "modelId": outcome.model_id,
2899→                        "displayName": outcome.display_name,
2900→                        "provider": outcome.provider_name,
2901→                        "status": "unsupported",
2902→                        "error": detail,
