2936→                        "errors": errors,
2937→                    }),
2938→                    BroadcastOpts::default(),
2939→                )
2940→                .await;
2941→            }
2942→        }
2943→
2944→        // Clear the cancellation token now that the loop has exited.
2945→        {
2946→            let mut guard = self.detect_cancel.write().await;
2947→            *guard = None;
2948→        }
2949→
2950→        let phase = if cancelled {
2951→            "cancelled"
2952→        } else {
2953→            "complete"
