2972→            "unsupportedByProvider": unsupported_by_provider,
2973→            "errorsByProvider": errors_by_provider,
2974→            "results": results,
2975→        });
2976→
2977→        // Final refresh event to ensure clients are in sync after the full pass.
2978→        if let Some(state) = state.as_ref() {
2979→            broadcast(
2980→                state,
2981→                "models.updated",
2982→                serde_json::json!({
