638→/// Determine whether an Ollama model supports native tool calling based on its
639→/// model name and family metadata from `/api/show`.
640→fn ollama_model_supports_native_tools(model_name: &str, details: &OllamaModelDetails) -> bool {
641→    let name_lower = model_name.to_ascii_lowercase();
642→
643→    // Check all family strings from the model details.
644→    let families_iter = details
645→        .family
646→        .iter()
647→        .chain(details.families.iter().flatten());
648→    for family in families_iter {
649→        let fam_lower = family.to_ascii_lowercase();
650→        if OLLAMA_NATIVE_TOOL_FAMILIES
651→            .iter()
652→            .any(|known| fam_lower.contains(known))
653→        {
654→            return true;
655→        }
656→    }
657→
658→    // Heuristic: check model name for known families.
659→    OLLAMA_NATIVE_TOOL_FAMILIES
660→        .iter()
661→        .any(|known| name_lower.contains(known))
662→}
663→
664→/// Check if Ollama's `capabilities` list indicates native tool support.
665→///
666→/// Returns `Some(true)` if `"tools"` is present, `Some(false)` if capabilities
667→/// exist but don't include tools, and `None` if the list is empty (pre-0.5.x
668→/// Ollama versions that don't report capabilities).
669→fn ollama_capabilities_support_tools(capabilities: &[String]) -> Option<bool> {
670→    if capabilities.is_empty() {
671→        return None;
672→    }
673→    Some(capabilities.iter().any(|c| c == "tools"))
674→}
