676→/// Probe the Ollama `/api/show` endpoint for a specific model to get its family
677→/// and details. Returns `Ok(response)` on success, error on timeout/failure.
678→async fn probe_ollama_model_info(
679→    base_url: &str,
680→    model_name: &str,
681→) -> anyhow::Result<OllamaShowResponse> {
682→    let api_base = normalize_ollama_api_base_url(base_url);
683→    let endpoint = format!("{}/api/show", api_base.trim_end_matches('/'));
684→    let response = reqwest::Client::builder()
685→        .timeout(std::time::Duration::from_secs(3))
686→        .build()?
687→        .post(&endpoint)
688→        .json(&serde_json::json!({ "name": model_name }))
689→        .send()
690→        .await?;
691→
692→    let status = response.status();
693→    if !status.is_success() {
694→        anyhow::bail!("ollama /api/show for {model_name} failed HTTP {status}");
695→    }
696→    Ok(response.json().await?)
697→}
