699→/// Resolve the effective tool mode for an Ollama model.
700→///
701→/// - If the user configured an explicit `tool_mode`, use that.
702→/// - Otherwise, check the model's `capabilities` list from Ollama (>= 0.5.x).
703→/// - Fall back to the hardcoded family whitelist only when capabilities are
704→///   unavailable (pre-0.5.x Ollama).
705→fn resolve_ollama_tool_mode(
706→    config_tool_mode: moltis_config::ToolMode,
707→    model_name: &str,
708→    probe_result: Option<&OllamaShowResponse>,
709→) -> moltis_config::ToolMode {
710→    use moltis_config::ToolMode;
711→
712→    match config_tool_mode {
713→        ToolMode::Native | ToolMode::Text | ToolMode::Off => config_tool_mode,
714→        ToolMode::Auto => {
715→            // Prefer Ollama's own capabilities field when available.
716→            if let Some(resp) = probe_result
717→                && let Some(supports) = ollama_capabilities_support_tools(&resp.capabilities)
718→            {
719→                return if supports {
720→                    ToolMode::Native
721→                } else {
722→                    ToolMode::Text
723→                };
724→            }
725→            // Fallback: family whitelist (pre-0.5.x Ollama without capabilities).
726→            let details = probe_result
727→                .map(|r| &r.details)
728→                .cloned()
729→                .unwrap_or_default();
730→            if ollama_model_supports_native_tools(model_name, &details) {
731→                ToolMode::Native
732→            } else {
733→                ToolMode::Text
734→            }
735→        },
736→    }
