739→/// Batch-probe Ollama `/api/show` for a list of models.
740→/// Runs probes in a dedicated thread with its own tokio runtime (same pattern
741→/// as `discover_ollama_models`). Returns a map from model ID to show response;
742→/// failures are silently dropped.
743→fn probe_ollama_models_batch(
744→    base_url: &str,
745→    models: &[DiscoveredModel],
746→) -> HashMap<String, OllamaShowResponse> {
747→    if models.is_empty() {
748→        return HashMap::new();
749→    }
750→    let base_url = base_url.to_string();
751→    let model_ids: Vec<String> = models.iter().map(|m| m.id.clone()).collect();
752→    let (tx, rx) = std::sync::mpsc::sync_channel(1);
753→
754→    std::thread::spawn(move || {
755→        let result = tokio::runtime::Builder::new_current_thread()
756→            .enable_all()
757→            .build()
758→            .map(|rt| {
759→                rt.block_on(async {
760→                    let futs: Vec<_> = model_ids
761→                        .iter()
762→                        .map(|id| {
763→                            let base = base_url.clone();
764→                            let model_id = id.clone();
765→                            async move {
766→                                let resp = probe_ollama_model_info(&base, &model_id).await;
767→                                (model_id, resp)
768→                            }
769→                        })
770→                        .collect();
771→                    futures::future::join_all(futs).await
772→                })
773→            });
774→        let _ = tx.send(result);
775→    });
776→
777→    match rx.recv() {
778→        Ok(Ok(results)) => results
779→            .into_iter()
780→            .filter_map(|(id, r)| r.ok().map(|resp| (id, resp)))
781→            .collect(),
782→        _ => HashMap::new(),
783→    }
784→}
