 800→fn spawn_openclaw_background_init(data_dir: PathBuf) {
 801→    tokio::spawn(async move {
 802→        #[cfg_attr(not(feature = "file-watcher"), allow(unused_variables))]
 803→        let detection = match tokio::task::spawn_blocking(detect_openclaw_with_startup_logs).await {
 804→            Ok(detection) => detection,
 805→            Err(error) => {
 806→                warn!(
 807→                    error = %error,
 808→                    "startup OpenClaw background detection worker failed"
 809→                );
 810→                return;
 811→            },
 812→        };
 813→
 814→        #[cfg(feature = "file-watcher")]
 815→        if let Some(detection) = detection {
 816→            let import_agent = if detection.agent_ids.contains(&"main".to_string()) {
 817→                "main"
 818→            } else {
 819→                detection
 820→                    .agent_ids
 821→                    .first()
 822→                    .map(|s| s.as_str())
 823→                    .unwrap_or("main")
 824→            };
 825→            let sessions_dir = detection
 826→                .home_dir
 827→                .join("agents")
 828→                .join(import_agent)
 829→                .join("agent")
 830→                .join("sessions");
 831→            if sessions_dir.is_dir() {
 832→                match moltis_openclaw_import::watcher::ImportWatcher::start(sessions_dir) {
 833→                    Ok((_watcher, mut rx)) => {
 834→                        info!("openclaw: session watcher started");
 835→                        let watcher_data_dir = data_dir;
 836→                        tokio::spawn(async move {
 837→                            let _watcher = _watcher; // keep alive
 838→                            let mut interval =
 839→                                tokio::time::interval(std::time::Duration::from_secs(60));
 840→                            interval.tick().await; // skip first immediate tick
 841→                            loop {
 842→                                tokio::select! {
 843→                                    Some(_event) = rx.recv() => {
 844→                                        debug!("openclaw: session change detected, running incremental import");
 845→                                        let report = moltis_openclaw_import::import_sessions_only(
 846→                                            &detection, &watcher_data_dir,
 847→                                        );
 848→                                        if report.items_imported > 0 || report.items_updated > 0 {
 849→                                            info!(
 850→                                                imported = report.items_imported,
 851→                                                updated = report.items_updated,
 852→                                                skipped = report.items_skipped,
 853→                                                "openclaw: incremental session sync complete"
 854→                                            );
 855→                                        }
 856→                                    }
 857→                                    _ = interval.tick() => {
 858→                                        debug!("openclaw: periodic session sync");
 859→                                        let report = moltis_openclaw_import::import_sessions_only(
 860→                                            &detection, &watcher_data_dir,
 861→                                        );
 862→                                        if report.items_imported > 0 || report.items_updated > 0 {
 863→                                            info!(
 864→                                                imported = report.items_imported,
 865→                                                updated = report.items_updated,
 866→                                                skipped = report.items_skipped,
 867→                                                "openclaw: periodic session sync complete"
 868→                                            );
 869→                                        }
 870→                                    }
 871→                                }
 872→                            }
 873→                        });
 874→                    },
 875→                    Err(error) => {
 876→                        warn!("openclaw: failed to start session watcher: {error}");
 877→                    },
 878→                }
 879→            }
 880→        }
 881→    });
 882→}
