 925→/// Register a runtime-discovered host in the WebAuthn registry.
 926→///
 927→/// Returns a user-facing warning when the host is newly registered and
 928→/// existing passkeys may need to be re-added for that hostname.
 929→pub async fn sync_runtime_webauthn_host_and_notice(
 930→    gateway: &GatewayState,
 931→    registry: Option<&SharedWebAuthnRegistry>,
 932→    hostname: Option<&str>,
 933→    origin_override: Option<&str>,
 934→    source: &str,
 935→) -> Option<String> {
 936→    let hostname = hostname?;
 937→    let normalized = crate::auth_webauthn::normalize_host(hostname);
 938→    if normalized.is_empty() {
 939→        return None;
 940→    }
 941→
 942→    let registry = registry?;
 943→    if registry.read().await.contains_host(&normalized) {
 944→        return None;
 945→    }
 946→
 947→    let origin = if let Some(origin_override) = origin_override {
 948→        origin_override.to_string()
 949→    } else {
 950→        let scheme = if gateway.tls_active {
 951→            "https"
 952→        } else {
 953→            "http"
 954→        };
 955→        format!("{scheme}://{normalized}:{}", gateway.port)
 956→    };
 957→
 958→    let origin_url = match webauthn_rs::prelude::Url::parse(&origin) {
 959→        Ok(url) => url,
 960→        Err(error) => {
 961→            warn!(
 962→                host = %normalized,
 963→                origin = %origin,
 964→                %error,
 965→                "invalid runtime WebAuthn origin from {source}"
 966→            );
 967→            return None;
 968→        },
 969→    };
 970→    let webauthn = match crate::auth_webauthn::WebAuthnState::new(&normalized, &origin_url, &[]) {
 971→        Ok(webauthn) => webauthn,
 972→        Err(error) => {
 973→            warn!(
 974→                host = %normalized,
 975→                origin = %origin,
 976→                %error,
 977→                "failed to initialize runtime WebAuthn RP from {source}"
 978→            );
 979→            return None;
 980→        },
 981→    };
 982→
 983→    {
 984→        let mut reg = registry.write().await;
 985→        if reg.contains_host(&normalized) {
 986→            return None;
 987→        }
 988→        reg.add(normalized.clone(), webauthn);
 989→        info!(
 990→            host = %normalized,
 991→            origin = %origin,
 992→            origins = ?reg.get_all_origins(),
 993→            "WebAuthn RP registered from {source}"
 994→        );
 995→    }
 996→
 997→    let has_passkeys = if let Some(store) = gateway.credential_store.as_ref() {
 998→        store.has_passkeys().await.unwrap_or(false)
 999→    } else {
1000→        false
1001→    };
1002→
1003→    if has_passkeys {
1004→        gateway.add_passkey_host_update_pending(&normalized).await;
1005→        Some(format!(
1006→            "New host detected ({normalized}). Existing passkeys may not work on this host. Sign in with password, then add a new passkey in Settings > Authentication."
1007→        ))
1008→    } else {
1009→        None
1010→    }
1011→}
