1014→fn spawn_webauthn_tailscale_registration(
1015→    gateway: Arc<GatewayState>,
1016→    registry: SharedWebAuthnRegistry,
1017→) {
1018→    tokio::spawn(async move {
1019→        let started = std::time::Instant::now();
1020→        match CliTailscaleManager::new().hostname().await {
1021→            Ok(Some(ts_hostname)) => {
1022→                let registered = sync_runtime_webauthn_host_and_notice(
1023→                    &gateway,
1024→                    Some(&registry),
1025→                    Some(&ts_hostname),
1026→                    None,
1027→                    "tailscale hostname",
1028→                )
1029→                .await
1030→                .is_some()
1031→                    || registry
1032→                        .read()
1033→                        .await
1034→                        .contains_host(&crate::auth_webauthn::normalize_host(&ts_hostname));
1035→                if registered {
1036→                    info!(
1037→                        hostname = %ts_hostname,
1038→                        elapsed_ms = started.elapsed().as_millis(),
1039→                        "processed Tailscale WebAuthn hostname"
1040→                    );
1041→                } else {
1042→                    debug!(
1043→                        hostname = %ts_hostname,
1044→                        elapsed_ms = started.elapsed().as_millis(),
1045→                        "tailscale hostname did not add a new WebAuthn RP"
1046→                    );
1047→                }
1048→            },
1049→            Ok(None) => {
1050→                debug!(
1051→                    elapsed_ms = started.elapsed().as_millis(),
1052→                    "tailscale hostname unavailable, skipping WebAuthn RP registration"
1053→                );
1054→            },
1055→            Err(error) => {
1056→                debug!(
1057→                    %error,
1058→                    elapsed_ms = started.elapsed().as_millis(),
1059→                    "tailscale hostname lookup failed, skipping WebAuthn RP registration"
1060→                );
1061→            },
1062→        }
1063→    });
