243→// ── Log callback for Swift ───────────────────────────────────────────────
244→
245→/// Callback type for forwarding log events to Swift. Rust owns the
246→/// `log_json` pointer — the callback must copy the data before returning.
247→#[allow(unsafe_code)]
248→type LogCallback = unsafe extern "C" fn(log_json: *const c_char);
249→
250→static LOG_CALLBACK: OnceLock<LogCallback> = OnceLock::new();
251→
252→/// JSON-serializable log event sent to Swift.
253→#[derive(Debug, Serialize)]
254→struct BridgeLogEvent<'a> {
255→    level: &'a str,
256→    target: &'a str,
257→    message: &'a str,
258→    #[serde(skip_serializing_if = "Option::is_none")]
259→    fields: Option<&'a HashMap<&'a str, String>>,
260→}
261→
262→fn emit_log(level: &str, target: &str, message: &str) {
263→    emit_log_with_fields(level, target, message, None);
264→}
265→
266→#[allow(unsafe_code)]
267→fn emit_log_with_fields(
268→    level: &str,
269→    target: &str,
270→    message: &str,
271→    fields: Option<&HashMap<&str, String>>,
272→) {
273→    if let Some(callback) = LOG_CALLBACK.get() {
274→        let event = BridgeLogEvent {
275→            level,
276→            target,
277→            message,
278→            fields,
279→        };
280→        if let Ok(json) = serde_json::to_string(&event)
281→            && let Ok(c_str) = CString::new(json)
282→        {
283→            // SAFETY: c_str is valid NUL-terminated, callback copies
284→            // before returning, and we drop c_str afterwards.
285→            unsafe {
286→                callback(c_str.as_ptr());
287→            }
288→        }
289→    }
290→}
