1503→                if rejected {
1504→                    cb(RunnerEvent::ToolCallRejected {
1505→                        id: tc.id.clone(),
1506→                        name: tc.name.clone(),
1507→                        arguments: tc.arguments.clone(),
1508→                        error: error.clone().unwrap_or_default(),
1509→                    });
1510→                } else {
1511→                    cb(RunnerEvent::ToolCallEnd {
1512→                        id: tc.id.clone(),
1513→                        name: tc.name.clone(),
1514→                        success,
1515→                        error,
1516→                        result: if success {
1517→                            result.get("result").cloned()
1518→                        } else {
1519→                            None
1520→                        },
1521→                    });
1522→                }
1523→            }
1524→
1525→            // Dispatch ToolResultPersist hook — the last opportunity for a handler
1526→            // to sanitize, redact, or block attacker-controlled tool output before
1527→            // it enters the messages array and is reasoned on by the next LLM
1528→            // iteration. Block substitutes an error marker instead of aborting the
1529→            // run, so a single hostile tool result cannot kill a long-running
1530→            // autonomous agent.
1531→            if let Some(ref hooks) = hook_registry {
1532→                let payload = HookPayload::ToolResultPersist {
1533→                    session_key: session_key_for_hooks.clone(),
1534→                    tool_name: sanitize_tool_name(&tc.name).into_owned(),
1535→                    result: result.clone(),
1536→                    channel: channel_for_hooks.clone(),
1537→                };
1538→                match hooks.dispatch(&payload).await {
1539→                    Ok(HookAction::ModifyPayload(v)) => {
1540→                        debug!(tool = %tc.name, "ToolResultPersist replaced tool result");
1541→                        result = v;
1542→                    },
1543→                    Ok(HookAction::Block(reason)) => {
1544→                        warn!(tool = %tc.name, reason = %reason, "ToolResultPersist blocked result — substituting error marker");
1545→                        result = serde_json::json!({
1546→                            "error": format!("blocked by hook: {reason}")
1547→                        });
1548→                    },
1549→                    Ok(HookAction::Continue) => {},
1550→                    Err(e) => {
1551→                        warn!(tool = %tc.name, error = %e, "ToolResultPersist hook dispatch failed");
1552→                    },
1553→                }
1554→            }
1555→
1556→            // Always sanitize tool results as strings - most LLM APIs don't support
1557→            // multimodal content in tool results. Images are stripped but the UI
1558→            // still receives them via ToolCallEnd event.
1559→            let tool_result_str = sanitize_tool_result(&result.to_string(), max_tool_result_bytes);
1560→            debug!(
1561→                tool = %tc.name,
1562→                id = %tc.id,
1563→                result_len = tool_result_str.len(),
1564→                "appending tool result to messages"
1565→            );
1566→            trace!(tool = %tc.name, content = %tool_result_str, "tool result message content");
1567→
1568→            messages.push(ChatMessage::tool(&tc.id, &tool_result_str));
1569→        }
1570→
1571→        // Apply loop-detector intervention if one fired during this batch.
1572→        apply_loop_detector_intervention(
1573→            &mut loop_detector,
1574→            &mut messages,
1575→            &mut strip_tools_next_iter,
1576→            on_event,
1577→        );
1578→    }
1579→}
