1581→/// Consume the detector's post-batch action (if any) and apply it to the
1582→/// runner state: push the directive user message into `messages`, emit the
1583→/// `LoopInterventionFired` UI event, and set `strip_tools_next_iter` when
1584→/// stage 2 fires. Shared by the streaming and non-streaming loops (issue
1585→/// #658).
1586→fn apply_loop_detector_intervention(
1587→    loop_detector: &mut ToolLoopDetector,
1588→    messages: &mut Vec<ChatMessage>,
1589→    strip_tools_next_iter: &mut bool,
1590→    on_event: Option<&OnEvent>,
1591→) {
1592→    if !loop_detector.is_enabled() {
1593→        return;
1594→    }
1595→    match loop_detector.consume_pending_action() {
1596→        LoopDetectorAction::None => {},
1597→        LoopDetectorAction::InjectNudge => {
1598→            let window = loop_detector.window_snapshot();
1599→            let stuck_tool = window
1600→                .first()
1601→                .map(|fp| fp.tool_name.clone())
1602→                .unwrap_or_default();
1603→            let intervention = format_intervention_message(&window);
1604→            info!(
1605→                tool = %stuck_tool,
1606→                "loop detector fired (stage 1): injecting directive intervention"
1607→            );
1608→            if let Some(cb) = on_event {
1609→                cb(RunnerEvent::LoopInterventionFired {
1610→                    stage: 1,
1611→                    tool_name: stuck_tool,
1612→                });
1613→            }
1614→            messages.push(ChatMessage::user(intervention));
1615→        },
1616→        LoopDetectorAction::StripTools => {
1617→            let stuck_tool = loop_detector
1618→                .window_snapshot()
1619→                .first()
1620→                .map(|fp| fp.tool_name.clone())
1621→                .unwrap_or_default();
1622→            info!(
1623→                tool = %stuck_tool,
1624→                "loop detector fired (stage 2): stripping tools for next iteration"
1625→            );
1626→            if let Some(cb) = on_event {
1627→                cb(RunnerEvent::LoopInterventionFired {
1628→                    stage: 2,
1629→                    tool_name: stuck_tool,
1630→                });
1631→            }
1632→            messages.push(ChatMessage::user(format_strip_tools_message()));
1633→            *strip_tools_next_iter = true;
1634→        },
1635→    }
1636→}
