1643→/// Streaming variant of the agent loop.
1644→///
1645→/// Unlike `run_agent_loop_with_context`, this function uses streaming to send
1646→/// text deltas to the UI as they arrive, providing a much better UX.
1647→///
1648→/// Tool calls are accumulated from the stream and executed after the stream
1649→/// completes, then the loop continues with the next iteration.
1650→pub async fn run_agent_loop_streaming(
1651→    provider: Arc<dyn LlmProvider>,
1652→    tools: &ToolRegistry,
1653→    system_prompt: &str,
1654→    user_content: &UserContent,
1655→    on_event: Option<&OnEvent>,
1656→    history: Option<Vec<ChatMessage>>,
1657→    tool_context: Option<serde_json::Value>,
1658→    hook_registry: Option<Arc<HookRegistry>>,
1659→) -> Result<AgentRunResult, AgentRunError> {
1660→    let native_tools = provider.supports_tools();
1661→    let config = moltis_config::discover_and_load();
1662→    let max_tool_result_bytes = config.tools.max_tool_result_bytes;
1663→    let max_auto_continues = config.tools.agent_max_auto_continues;
1664→    let auto_continue_min_tool_calls = config.tools.agent_auto_continue_min_tool_calls;
1665→    let base_max_iterations = resolve_agent_max_iterations(config.tools.agent_max_iterations);
1666→    // Lazy mode needs extra iterations for tool_search discovery round-trips.
1667→    let max_iterations = if config.tools.registry_mode == moltis_config::ToolRegistryMode::Lazy {
1668→        base_max_iterations * 3
1669→    } else {
1670→        base_max_iterations
1671→    };
1672→
1673→    let is_multimodal = matches!(user_content, UserContent::Multimodal(_));
1674→    info!(
1675→        provider = provider.name(),
1676→        model = provider.id(),
1677→        native_tools,
1678→        tools_count = tools.list_names().len(),
1679→        is_multimodal,
1680→        "starting streaming agent loop"
1681→    );
1682→
1683→    let mut messages: Vec<ChatMessage> = vec![ChatMessage::system(system_prompt)];
1684→
1685→    // Insert conversation history before the current user message.
1686→    if let Some(hist) = history {
1687→        messages.extend(hist);
1688→    }
1689→
1690→    messages.push(ChatMessage::User {
1691→        content: user_content.clone(),
1692→    });
1693→    let explicit_shell_command = explicit_shell_command_from_user_content(user_content);
1694→
1695→    // Extract session key once for hook payloads.
1696→    let session_key_for_hooks = tool_context
1697→        .as_ref()
1698→        .and_then(|ctx| ctx.get("_session_key"))
1699→        .and_then(|v| v.as_str())
1700→        .unwrap_or("")
1701→        .to_string();
1702→    let channel_for_hooks =
1703→        channel_binding_from_tool_context(&session_key_for_hooks, tool_context.as_ref());
1704→
1705→    let mut iterations = 0;
1706→    let mut total_tool_calls = 0;
1707→    let mut total_input_tokens: u32 = 0;
1708→    let mut total_output_tokens: u32 = 0;
1709→    let mut server_retries_remaining: u8 = 1;
1710→    let mut rate_limit_retries_remaining: u8 = RATE_LIMIT_MAX_RETRIES;
1711→    let mut rate_limit_backoff_ms: Option<u64> = None;
1712→    let mut raw_llm_responses: Vec<serde_json::Value> = Vec::new();
1713→    // Track answer text from iterations that also contained tool calls.
1714→    // When the final iteration is empty (e.g. model stop after browser close),
1715→    // this is used as the final response text instead of returning silent.
1716→    let mut last_answer_text = String::new();
1717→    let mut malformed_retry_count: u8 = 0;
1718→    let mut empty_tool_name_retry_count: u8 = 0;
1719→    let mut auto_continue_count: usize = 0;
1720→    let mut loop_detector = ToolLoopDetector::new(
1721→        config.tools.agent_loop_detector_window,
1722→        config.tools.agent_loop_detector_strip_tools_on_second_fire,
1723→    );
1724→    let mut strip_tools_next_iter = false;
1725→
1726→    loop {
1727→        iterations += 1;
1728→        if iterations > max_iterations {
1729→            warn!(
1730→                "streaming agent loop exceeded max iterations ({})",
1731→                max_iterations
1732→            );
1733→            return Err(AgentRunError::Other(anyhow::anyhow!(
1734→                "agent loop exceeded max iterations ({})",
1735→                max_iterations
1736→            )));
1737→        }
1738→
1739→        // Re-compute schemas each iteration so activated tools appear immediately.
1740→        // When the loop detector has escalated to stage 2, pass an empty tool
1741→        // list for this single turn so the model is forced to respond in text
1742→        // (issue #658).
1743→        let schemas_for_api = if native_tools && !strip_tools_next_iter {
1744→            tools.list_schemas()
1745→        } else {
1746→            vec![]
1747→        };
1748→        if strip_tools_next_iter {
1749→            strip_tools_next_iter = false;
1750→            loop_detector.clear_strip_tools();
1751→        }
1752→
1753→        enforce_tool_result_context_budget(
1754→            &mut messages,
1755→            &schemas_for_api,
1756→            provider.context_window(),
1757→        )?;
1758→
1759→        if let Some(cb) = on_event {
1760→            cb(RunnerEvent::Iteration(iterations));
1761→        }
1762→
1763→        info!(
1764→            iteration = iterations,
1765→            messages_count = messages.len(),
1766→            "calling LLM (streaming)"
1767→        );
1768→        trace!(iteration = iterations, messages = ?messages, "LLM request messages");
1769→
1770→        // Dispatch BeforeLLMCall hook — may block the LLM call.
1771→        if let Some(ref hooks) = hook_registry {
1772→            let msgs_json: Vec<serde_json::Value> =
1773→                messages.iter().map(|m| m.to_openai_value()).collect();
1774→            let payload = HookPayload::BeforeLLMCall {
1775→                session_key: session_key_for_hooks.clone(),
1776→                provider: provider.name().to_string(),
1777→                model: provider.id().to_string(),
1778→                messages: serde_json::Value::Array(msgs_json),
1779→                tool_count: schemas_for_api.len(),
1780→                iteration: iterations,
1781→            };
1782→            match hooks.dispatch(&payload).await {
1783→                Ok(HookAction::Block(reason)) => {
1784→                    warn!(reason = %reason, "LLM call blocked by BeforeLLMCall hook");
1785→                    return Err(AgentRunError::Other(anyhow::anyhow!(
1786→                        "blocked by BeforeLLMCall hook: {reason}"
1787→                    )));
1788→                },
1789→                Ok(HookAction::ModifyPayload(_)) => {
1790→                    debug!("BeforeLLMCall ModifyPayload ignored (messages are typed)");
1791→                },
1792→                Ok(HookAction::Continue) => {},
1793→                Err(e) => {
1794→                    warn!(error = %e, "BeforeLLMCall hook dispatch failed");
1795→                },
1796→            }
1797→        }
1798→
1799→        if let Some(cb) = on_event {
1800→            cb(RunnerEvent::Thinking);
1801→        }
1802→
1803→        // Use streaming API.
1804→        #[cfg(feature = "metrics")]
1805→        let iter_start = std::time::Instant::now();
1806→        let mut stream = provider.stream_with_tools(messages.clone(), schemas_for_api.clone());
1807→
1808→        // Accumulate answer text, reasoning text, and tool calls from the stream.
1809→        let mut accumulated_text = String::new();
1810→        let mut accumulated_reasoning = String::new();
1811→        let mut tool_calls: Vec<ToolCall> = Vec::new();
1812→        // Map streaming index → accumulated JSON args string.
1813→        let mut tool_call_args: std::collections::HashMap<usize, String> =
1814→            std::collections::HashMap::new();
1815→        // Map streaming index → position in the `tool_calls` vec.
1816→        // The streaming index may not start at 0 (e.g. Copilot proxying
1817→        // Anthropic uses the content-block index, so a text block at index 0
1818→        // pushes the tool_use to index 1).
1819→        let mut stream_idx_to_vec_pos: std::collections::HashMap<usize, usize> =
1820→            std::collections::HashMap::new();
1821→        let mut input_tokens: u32 = 0;
1822→        let mut output_tokens: u32 = 0;
1823→        let mut stream_error: Option<String> = None;
1824→
1825→        while let Some(event) = stream.next().await {
1826→            match event {
1827→                StreamEvent::Delta(text) => {
1828→                    accumulated_text.push_str(&text);
1829→                    if let Some(cb) = on_event {
1830→                        cb(RunnerEvent::TextDelta(text));
1831→                    }
1832→                },
1833→                StreamEvent::ProviderRaw(raw) => {
1834→                    if raw_llm_responses.len() < 256 {
1835→                        raw_llm_responses.push(raw);
1836→                    }
1837→                },
1838→                StreamEvent::ReasoningDelta(text) => {
1839→                    accumulated_reasoning.push_str(&text);
1840→                    if let Some(cb) = on_event {
1841→                        cb(RunnerEvent::ThinkingText(accumulated_reasoning.clone()));
1842→                    }
1843→                },
1844→                StreamEvent::ToolCallStart { id, name, index } => {
1845→                    let vec_pos = tool_calls.len();
1846→                    debug!(tool = %name, id = %id, stream_index = index, vec_pos, "tool call started in stream");
1847→                    tool_calls.push(ToolCall {
1848→                        id,
1849→                        name,
1850→                        arguments: serde_json::json!({}),
1851→                    });
1852→                    stream_idx_to_vec_pos.insert(index, vec_pos);
1853→                    tool_call_args.insert(index, String::new());
1854→                },
1855→                StreamEvent::ToolCallArgumentsDelta { index, delta } => {
1856→                    if let Some(args) = tool_call_args.get_mut(&index) {
1857→                        args.push_str(&delta);
1858→                    }
1859→                },
1860→                StreamEvent::ToolCallComplete { index } => {
1861→                    // Arguments are finalized after stream completes.
1862→                    // Just log for now - we'll parse accumulated args later.
1863→                    debug!(index, "tool call arguments complete");
1864→                },
1865→                StreamEvent::Done(usage) => {
1866→                    input_tokens = usage.input_tokens;
1867→                    output_tokens = usage.output_tokens;
1868→                    debug!(input_tokens, output_tokens, "stream done");
1869→
1870→                    #[cfg(feature = "metrics")]
1871→                    {
1872→                        let provider_name = provider.name().to_string();
1873→                        let model_id = provider.id().to_string();
1874→                        let duration = iter_start.elapsed().as_secs_f64();
1875→                        counter!(
1876→                            llm_metrics::COMPLETIONS_TOTAL,
1877→                            labels::PROVIDER => provider_name.clone(),
1878→                            labels::MODEL => model_id.clone()
1879→                        )
1880→                        .increment(1);
1881→                        counter!(
1882→                            llm_metrics::INPUT_TOKENS_TOTAL,
1883→                            labels::PROVIDER => provider_name.clone(),
1884→                            labels::MODEL => model_id.clone()
1885→                        )
1886→                        .increment(u64::from(usage.input_tokens));
1887→                        counter!(
1888→                            llm_metrics::OUTPUT_TOKENS_TOTAL,
1889→                            labels::PROVIDER => provider_name.clone(),
1890→                            labels::MODEL => model_id.clone()
1891→                        )
1892→                        .increment(u64::from(usage.output_tokens));
1893→                        counter!(
1894→                            llm_metrics::CACHE_READ_TOKENS_TOTAL,
1895→                            labels::PROVIDER => provider_name.clone(),
1896→                            labels::MODEL => model_id.clone()
1897→                        )
1898→                        .increment(u64::from(usage.cache_read_tokens));
1899→                        counter!(
1900→                            llm_metrics::CACHE_WRITE_TOKENS_TOTAL,
1901→                            labels::PROVIDER => provider_name.clone(),
1902→                            labels::MODEL => model_id.clone()
1903→                        )
1904→                        .increment(u64::from(usage.cache_write_tokens));
1905→                        histogram!(
1906→                            llm_metrics::COMPLETION_DURATION_SECONDS,
1907→                            labels::PROVIDER => provider_name,
1908→                            labels::MODEL => model_id
1909→                        )
1910→                        .record(duration);
1911→                    }
1912→                },
1913→                StreamEvent::Error(msg) => {
1914→                    stream_error = Some(msg);
1915→                    break;
1916→                },
1917→            }
1918→        }
1919→
1920→        if let Some(cb) = on_event {
1921→            cb(RunnerEvent::ThinkingDone);
1922→        }
1923→
1924→        // Handle stream errors — retry on transient failures/rate limits.
1925→        if let Some(err) = stream_error {
1926→            if is_context_window_error(&err) {
1927→                return Err(AgentRunError::ContextWindowExceeded(err));
1928→            }
1929→            if let Some(delay_ms) = next_retry_delay_ms(
1930→                &err,
1931→                &mut server_retries_remaining,
1932→                &mut rate_limit_retries_remaining,
1933→                &mut rate_limit_backoff_ms,
1934→            ) {
1935→                // Don't count the failed attempt as an iteration.
1936→                iterations -= 1;
1937→                warn!(
1938→                    error = %err,
1939→                    delay_ms,
1940→                    server_retries_remaining,
1941→                    rate_limit_retries_remaining,
1942→                    "transient LLM error, retrying after delay"
1943→                );
1944→                if let Some(cb) = on_event {
1945→                    cb(RunnerEvent::RetryingAfterError {
1946→                        error: err,
1947→                        delay_ms,
1948→                    });
1949→                }
1950→                tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;
1951→                continue;
1952→            }
1953→            return Err(AgentRunError::Other(anyhow::anyhow!(err)));
1954→        }
1955→
1956→        total_input_tokens = total_input_tokens.saturating_add(input_tokens);
1957→        total_output_tokens = total_output_tokens.saturating_add(output_tokens);
1958→
1959→        // Finalize tool call arguments from accumulated strings.
1960→        // Use stream_idx_to_vec_pos to map streaming indices (which may not
1961→        // start at 0) to the actual position in the tool_calls vec.
1962→        for (stream_idx, args_str) in &tool_call_args {
1963→            // Emit raw accumulated string at debug level so future variants of
1964→            // "default to {} because no deltas arrived" can be diagnosed
1965→            // without a repro (issue #658).
1966→            debug!(
1967→                stream_idx,
1968→                args_str = %args_str,
1969→                "finalizing tool call args"
1970→            );
1971→            if let Some(&vec_pos) = stream_idx_to_vec_pos.get(stream_idx)
1972→                && vec_pos < tool_calls.len()
1973→                && !args_str.is_empty()
1974→                && let Ok(args) = serde_json::from_str::<serde_json::Value>(args_str)
1975→            {
1976→                tool_calls[vec_pos].arguments = args;
1977→            }
1978→        }
1979→
1980→        info!(
1981→            iteration = iterations,
1982→            has_text = !accumulated_text.is_empty(),
1983→            tool_calls_count = tool_calls.len(),
1984→            input_tokens,
1985→            output_tokens,
1986→            "streaming LLM response complete"
1987→        );
1988→
1989→        // Fallback: parse tool calls from model text if the provider returned
1990→        // no structured tool calls (some providers/models emit text-based calls).
1991→        if tool_calls.is_empty() && !accumulated_text.is_empty() {
1992→            let (parsed, remaining) = parse_tool_calls_from_text(&accumulated_text);
1993→            if !parsed.is_empty() {
1994→                info!(
1995→                    native_tools,
1996→                    count = parsed.len(),
1997→                    first_tool = %parsed[0].name,

