229→
230→    /// Load all provider configs. Handles migration from old format (string values).
231→    fn load_all_configs_from_path(path: &PathBuf) -> HashMap<String, ProviderConfig> {
232→        let content = match std::fs::read_to_string(path) {
233→            Ok(c) => c,
234→            Err(error) => {
235→                if error.kind() != std::io::ErrorKind::NotFound {
236→                    warn!(
237→                        path = %path.display(),
238→                        error = %error,
239→                        "failed to read provider key store"
240→                    );
241→                }
242→                return HashMap::new();
243→            },
244→        };
245→
246→        // Try parsing as new format first
247→        if let Ok(configs) = serde_json::from_str::<HashMap<String, ProviderConfig>>(&content) {
248→            return configs;
249→        }
250→
251→        // Fall back to old format migration: { "provider": "api-key-string" }
252→        if let Ok(old_format) = serde_json::from_str::<HashMap<String, String>>(&content) {
253→            return old_format
254→                .into_iter()
255→                .map(|(k, v)| {
256→                    (k, ProviderConfig {
257→                        api_key: Some(v),
258→                        base_url: None,
259→                        models: Vec::new(),
260→                        display_name: None,
261→                    })
262→                })
263→                .collect();
264→        }
265→
266→        warn!(
267→            path = %path.display(),
268→            "provider key store is invalid JSON and will be ignored"
269→        );
270→        HashMap::new()
271→    }
272→
273→    pub fn load_all_configs(&self) -> HashMap<String, ProviderConfig> {
274→        let guard = self.lock();
275→        Self::load_all_configs_from_path(&guard.path)
276→    }
277→
278→    /// Save all provider configs to disk.
279→    fn save_all_configs_to_path(
280→        path: &PathBuf,
281→        configs: &HashMap<String, ProviderConfig>,
282→    ) -> error::Result<()> {
283→        if let Some(parent) = path.parent() {
284→            std::fs::create_dir_all(parent).map_err(|error| {
285→                warn!(
286→                    path = %parent.display(),
287→                    error = %error,
288→                    "failed to create provider key store directory"
289→                );
290→                error::Error::external("failed to create provider key store directory", error)
291→            })?;
292→        }
293→        let data = serde_json::to_string_pretty(configs).map_err(|error| {
294→            warn!(error = %error, "failed to serialize provider key store");
295→            error
296→        })?;
297→
298→        // Write atomically via temp file + rename so readers never observe
299→        // partially-written JSON.
300→        let nanos = std::time::SystemTime::now()
301→            .duration_since(std::time::UNIX_EPOCH)
302→            .map(|d| d.as_nanos())
303→            .unwrap_or(0);
304→        let temp_path = path.with_extension(format!("json.tmp.{nanos}"));
305→        std::fs::write(&temp_path, &data).map_err(|error| {
306→            warn!(
307→                path = %temp_path.display(),
308→                error = %error,
309→                "failed to write provider key store temp file"
310→            );
311→            error::Error::external("failed to write provider key store temp file", error)
312→        })?;
313→        #[cfg(unix)]
314→        {
315→            use std::os::unix::fs::PermissionsExt;
316→            let _ = std::fs::set_permissions(&temp_path, std::fs::Permissions::from_mode(0o600));
317→        }
318→
319→        std::fs::rename(&temp_path, path).map_err(|error| {
320→            warn!(
321→                temp_path = %temp_path.display(),
322→                path = %path.display(),
323→                error = %error,
324→                "failed to atomically replace provider key store"
325→            );
326→            error::Error::external("failed to atomically replace provider key store", error)
327→        })?;
328→
329→        Ok(())
330→    }
