388→        base_url: Option<String>,
389→        models: Option<Vec<String>>,
390→        display_name: Option<String>,
391→    ) -> error::Result<()> {
392→        let guard = self.lock();
393→        let mut configs = Self::load_all_configs_from_path(&guard.path);
394→        let entry = configs.entry(provider.to_string()).or_default();
395→
396→        // Only update fields that are provided (Some), preserve existing for None
397→        if let Some(key) = api_key {
398→            entry.api_key = Some(key);
399→        }
400→        if let Some(url) = base_url {
401→            entry.base_url = if url.is_empty() {
402→                None
403→            } else {
404→                Some(url)
405→            };
406→        }
407→        if let Some(models) = models {
408→            entry.models = normalize_model_list(models);
409→        }
410→        if let Some(name) = display_name {
411→            entry.display_name = Some(name);
412→        }
413→
414→        Self::save_all_configs_to_path(&guard.path, &configs)
415→    }
416→}
