420→/// Merge persisted provider configs into a ProvidersConfig so the registry rebuild
421→/// picks them up without needing env vars.
422→pub fn config_with_saved_keys(
423→    base: &ProvidersConfig,
424→    key_store: &KeyStore,
425→    local_model_ids: &[String],
426→) -> ProvidersConfig {
427→    let mut config = base.clone();
428→    if let Some((home_config, _)) = home_provider_config() {
429→        for (name, entry) in home_config.providers {
430→            let dst = config.providers.entry(name).or_default();
431→            if dst
432→                .api_key
433→                .as_ref()
434→                .is_none_or(|k| k.expose_secret().is_empty())
435→                && let Some(api_key) = entry.api_key
436→                && !api_key.expose_secret().is_empty()
437→            {
438→                dst.api_key = Some(api_key);
439→            }
440→            if dst.base_url.is_none()
441→                && let Some(base_url) = entry.base_url
442→                && !base_url.trim().is_empty()
443→            {
444→                dst.base_url = Some(base_url);
445→            }
446→            if dst.models.is_empty() && !entry.models.is_empty() {
447→                dst.models = normalize_model_list(entry.models);
448→            }
449→        }
450→    }
451→
452→    // Merge home key store first, then current key store so current instance
453→    // values win when both have values.
454→    let mut saved_configs = HashMap::new();
455→    if let Some((home_store, _)) = home_key_store() {
456→        saved_configs.extend(home_store.load_all_configs());
457→    }
458→    for (name, saved) in key_store.load_all_configs() {
459→        let entry = saved_configs
460→            .entry(name)
461→            .or_insert_with(ProviderConfig::default);
462→        if saved.api_key.is_some() {
463→            entry.api_key = saved.api_key;
464→        }
465→        if saved.base_url.is_some() {
466→            entry.base_url = saved.base_url;
467→        }
468→        if !saved.models.is_empty() {
469→            entry.models = saved.models;
470→        }
471→    }
472→
473→    for (name, saved) in saved_configs {
474→        let entry = config.providers.entry(name).or_default();
475→
476→        // Only override API key if config doesn't already have one.
477→        if let Some(key) = saved.api_key
478→            && entry
479→                .api_key
480→                .as_ref()
481→                .is_none_or(|k| k.expose_secret().is_empty())
482→        {
483→            entry.api_key = Some(Secret::new(key));
484→        }
485→
486→        // Only override base_url if config doesn't already have one.
487→        if let Some(url) = saved.base_url
488→            && entry.base_url.is_none()
489→        {
490→            entry.base_url = Some(url);
491→        }
492→
493→        if !saved.models.is_empty() {
494→            // Merge: saved models (from "Choose model" UI) go first, then
495→            // config models. normalize_model_list deduplicates.
496→            let mut merged = saved.models;
497→            merged.append(&mut entry.models);
498→            entry.models = normalize_model_list(merged);
499→        }

