 906→/// Return the known context window size (in tokens) for a model ID.
 907→/// Falls back to 200,000 for unknown models.
 908→pub fn context_window_for_model(model_id: &str) -> u32 {
 909→    let model_id = capability_model_id(model_id);
 910→    // Codestral has the largest window at 256k.
 911→    if model_id.starts_with("codestral") {
 912→        return 256_000;
 913→    }
 914→    // Claude models: 200k.
 915→    if model_id.starts_with("claude-") {
 916→        return 200_000;
 917→    }
 918→    // OpenAI o3/o4-mini: 200k.
 919→    if model_id.starts_with("o3") || model_id.starts_with("o4-mini") {
 920→        return 200_000;
 921→    }
 922→    // GPT-4o, GPT-4-turbo, GPT-5 series: 128k.
 923→    if model_id.starts_with("gpt-4") || model_id.starts_with("gpt-5") {
 924→        return 128_000;
 925→    }
 926→    // Mistral Large: 128k.
 927→    if model_id.starts_with("mistral-large") {
 928→        return 128_000;
 929→    }
 930→    // Gemini: 1M context.
 931→    if model_id.starts_with("gemini-") {
 932→        return 1_000_000;
 933→    }
 934→    // Kimi K2.5: 128k.
 935→    if model_id.starts_with("kimi-") {
 936→        return 128_000;
 937→    }
 938→    // MiniMax M2/M2.1/M2.5/M2.7: 204,800.
 939→    if model_id.starts_with("MiniMax-") {
 940→        return 204_800;
 941→    }
 942→    // Z.AI GLM-4-32B: 128k.
 943→    if model_id == "glm-4-32b-0414-128k" {
 944→        return 128_000;
 945→    }
 946→    // Z.AI GLM-5/4.7/4.6/4.5 series: 128k.
 947→    if model_id.starts_with("glm-") {
 948→        return 128_000;
 949→    }
 950→    // Qwen3 series (Qwen3, Qwen3-Coder): 128k.
 951→    if model_id.starts_with("qwen3") {
 952→        return 128_000;
 953→    }
 954→    // Default fallback.
 955→    200_000
 956→}
 957→
 958→/// Returns `false` for model IDs that are clearly not chat-completion models
 959→/// (image generators, TTS, speech-to-text, embeddings, moderation, etc.).
 960→///
 961→/// Provider APIs like OpenAI's `/v1/models` return every model in the account.
 962→/// Since no capability metadata is exposed we filter by well-known prefixes and
 963→/// patterns. This is applied both at discovery time and at display time so that
 964→/// non-chat models never appear in the UI.
 965→pub fn is_chat_capable_model(model_id: &str) -> bool {
 966→    let id = capability_model_id(model_id);
 967→    const NON_CHAT_PREFIXES: &[&str] = &[
 968→        "dall-e",
 969→        "gpt-image",
 970→        "chatgpt-image",
 971→        "gpt-audio",
 972→        "tts-",
 973→        "whisper",
 974→        "text-embedding",
 975→        "claude-embedding",
 976→        "claude-embeddings",
 977→        "omni-moderation",
 978→        "moderation-",
 979→        "sora",
 980→        // Google Gemini non-chat models
 981→        "imagen-",
 982→        "gemini-embedding",
 983→        "learnlm-",
 984→        "gemma-3n-",
 985→        // Z.AI non-chat models
 986→        "glm-image",
 987→        "glm-asr",
 988→        "glm-ocr",
 989→        "cogvideo",
 990→        "cogview",
 991→        "vidu",
 992→        "autoglm-phone",
 993→    ];
 994→    for prefix in NON_CHAT_PREFIXES {
 995→        if id.starts_with(prefix) {
 996→            return false;
 997→        }
 998→    }
 999→    // TTS / audio-only / realtime / transcription variants
1000→    if id.contains("-tts") || id.contains("-audio-") || id.ends_with("-audio") {
1001→        return false;
1002→    }
1003→    if id.contains("-realtime-") || id.ends_with("-realtime") {
1004→        return false;
1005→    }
1006→    if id.contains("-transcribe") {
1007→        return false;
1008→    }
1009→    // Gemini live (real-time dialogue) and image-generation variants
1010→    if id.contains("-live-") || id.contains("-image-") {
1011→        return false;
1012→    }
1013→    true
1014→}
