1016→/// Check if a model supports tool/function calling.
1017→///
1018→/// Most modern chat models support tools, but legacy completions-only models
1019→/// (e.g. `babbage-002`, `davinci-002`) and non-chat models do not.
1020→/// This is checked per-model rather than per-provider so that providers
1021→/// exposing mixed catalogs report accurate tool support.
1022→pub fn supports_tools_for_model(model_id: &str) -> bool {
1023→    let id = capability_model_id(model_id);
1024→    // Legacy completions-only models — no tool support
1025→    if id.starts_with("babbage") || id.starts_with("davinci") {
1026→        return false;
1027→    }
1028→    // Non-chat model families — never support tools
1029→    if id.starts_with("dall-e")
1030→        || id.starts_with("gpt-image")
1031→        || id.starts_with("tts-")
1032→        || id.starts_with("whisper")
1033→        || id.starts_with("text-embedding")
1034→        || id.starts_with("claude-embedding")
1035→        || id.starts_with("claude-embeddings")
1036→        || id.starts_with("omni-moderation")
1037→    {
1038→        return false;
1039→    }
1040→    // Default: assume tool support for modern chat models
1041→    true
1042→}
1043→
1044→/// Check if a model supports vision (image inputs).
1045→///
1046→/// Vision-capable models can process images in tool results and user messages.
1047→/// When true, the runner sends images as multimodal content blocks rather than
1048→/// stripping them from the context.
1049→///
1050→/// Uses a deny-list approach: most modern LLMs support vision, so unknown
1051→/// models default to `true`. The consequence of a false positive (sending
1052→/// images to a text-only model) is an API error — visible and diagnosable.
1053→/// The consequence of a false negative (stripping images from a capable model)
1054→/// is a silent failure that confuses users.
1055→pub fn supports_vision_for_model(model_id: &str) -> bool {
1056→    let id = capability_model_id(model_id);
1057→
1058→    // ── Known text-only models ──────────────────────────────────────
1059→    // Code-focused models
1060→    if id.starts_with("codestral") {
1061→        return false;
1062→    }
1063→    // Legacy OpenAI models without vision
1064→    if id.starts_with("gpt-3.5") || id.starts_with("text-") || id.starts_with("gpt-4-") {
1065→        // gpt-4-turbo and gpt-4-vision variants support vision
1066→        if id.starts_with("gpt-4-turbo") || id.starts_with("gpt-4-vision") {
1067→            return true;
1068→        }
1069→        return false;
1070→    }
1071→    // Z.AI GLM text-only models (vision variants contain 'v' suffix)
1072→    if id.starts_with("glm-") && !id.contains('v') {
1073→        return false;
1074→    }
1075→
1076→    // ── Default: assume vision support ──────────────────────────────
1077→    true
1078→}
1079→
1080→/// Check if a model supports reasoning/extended thinking.
1081→///
1082→/// Reasoning-capable models can use the `reasoning_effort` configuration
1083→/// to control the depth of extended thinking. This is used by the UI and
1084→/// validation to inform users when reasoning_effort is set on a model
1085→/// that doesn't support it.
1086→pub fn supports_reasoning_for_model(model_id: &str) -> bool {
1087→    let id = capability_model_id(model_id);
1088→    // Anthropic Claude Opus 4.5+ and Sonnet 4.5+
1089→    if id.starts_with("claude-opus-4-5")
1090→        || id.starts_with("claude-sonnet-4-5")
1091→        || id.starts_with("claude-opus-4-6")
1092→        || id.starts_with("claude-sonnet-4-6")
1093→    {
1094→        return true;
1095→    }
1096→    // Claude 3.7 Sonnet supports extended thinking
1097→    if id.starts_with("claude-3-7-sonnet") {
1098→        return true;
1099→    }

