518→const CUSTOM_PROVIDER_PREFIX: &str = "custom-";
519→
520→fn is_custom_provider(name: &str) -> bool {
521→    name.starts_with(CUSTOM_PROVIDER_PREFIX)
522→}
523→
524→/// Derive a provider name from a URL, e.g. `https://api.together.ai/v1` → `custom-together-ai`.
525→fn derive_provider_name_from_url(raw: &str) -> Option<String> {
526→    let parsed = url::Url::parse(raw).ok()?;
527→    let host = parsed.host_str()?;
528→    let stripped = host.strip_prefix("api.").unwrap_or(host);
529→    let slug = stripped.replace('.', "-");
530→    Some(format!("{CUSTOM_PROVIDER_PREFIX}{slug}"))
531→}
532→
533→/// Return a unique provider name by appending `-2`, `-3`, etc. if the base
534→/// name is already taken.
535→fn make_unique_provider_name(base: &str, existing: &HashMap<String, ProviderConfig>) -> String {
536→    if !existing.contains_key(base) {
537→        return base.to_string();
538→    }
539→    for i in 2.. {
540→        let candidate = format!("{base}-{i}");
541→        if !existing.contains_key(&candidate) {
542→            return candidate;
543→        }
544→    }
545→    unreachable!()
546→}
547→
548→/// Extract a human-friendly display name from a URL.
549→/// `https://api.together.ai/v1` → `together.ai`
550→fn base_url_to_display_name(raw: &str) -> String {
551→    url::Url::parse(raw)
552→        .ok()
553→        .and_then(|u| u.host_str().map(ToOwned::to_owned))
554→        .map(|host| host.strip_prefix("api.").unwrap_or(&host).to_string())
555→        .unwrap_or_else(|| raw.to_string())
556→}
557→
558→fn normalize_base_url_for_compare(raw: &str) -> String {
559→    let trimmed = raw.trim();
560→    if trimmed.is_empty() {
561→        return String::new();
562→    }
563→
564→    if let Ok(parsed) = url::Url::parse(trimmed) {
565→        let scheme = parsed.scheme().to_ascii_lowercase();
566→        let host = parsed.host_str().unwrap_or_default().to_ascii_lowercase();
567→        let mut normalized = format!("{scheme}://{host}");
568→        if let Some(port) = parsed.port() {
569→            normalized.push(':');
570→            normalized.push_str(&port.to_string());
571→        }
572→        let path = parsed.path().trim_end_matches('/');
573→        normalized.push_str(path);
574→        return normalized;
575→    }
576→
577→    trimmed.trim_end_matches('/').to_ascii_lowercase()
578→}
579→
580→fn existing_custom_provider_for_base_url(
581→    base_url: &str,
582→    existing: &HashMap<String, ProviderConfig>,
583→) -> Option<String> {
584→    let target = normalize_base_url_for_compare(base_url);
585→    if target.is_empty() {
586→        return None;
587→    }
588→
589→    existing
590→        .iter()
591→        .filter_map(|(name, cfg)| {
592→            if !is_custom_provider(name) {
593→                return None;
594→            }
595→            let existing_url = cfg.base_url.as_deref()?;
596→            (normalize_base_url_for_compare(existing_url) == target).then_some(name.clone())
597→        })
598→        .min_by(|a, b| a.len().cmp(&b.len()).then(a.cmp(b)))
599→}
600→
601→fn validation_provider_name_for_endpoint(
602→    provider_name: &str,
603→    provider_default_base_url: Option<&str>,
604→    base_url: Option<&str>,
605→) -> String {
606→    if is_custom_provider(provider_name) {
607→        return provider_name.to_string();
608→    }
609→
610→    if provider_name != "openai" {
611→        return provider_name.to_string();
612→    }
613→
614→    let Some(endpoint) = base_url else {
615→        return provider_name.to_string();
616→    };
617→
618→    let normalized_endpoint = normalize_base_url_for_compare(endpoint);
619→    if normalized_endpoint.is_empty() {
620→        return provider_name.to_string();
621→    }
622→
623→    let normalized_default = normalize_base_url_for_compare(
624→        provider_default_base_url.unwrap_or("https://api.openai.com/v1"),
625→    );
626→    if normalized_default == normalized_endpoint {
627→        return provider_name.to_string();
628→    }
629→
630→    derive_provider_name_from_url(endpoint).unwrap_or_else(|| provider_name.to_string())
631→}
