677→async fn discover_ollama_models(base_url: &str) -> error::Result<Vec<String>> {
678→    let url = format!("{}/api/tags", base_url.trim_end_matches('/'));
679→    let response = reqwest::Client::new()
680→        .get(&url)
681→        .send()
682→        .await
683→        .map_err(|source| {
684→            error::Error::external("failed to query Ollama model discovery endpoint", source)
685→        })?;
686→
687→    if !response.status().is_success() {
688→        return Err(error::Error::message(format!(
689→            "Ollama model discovery failed at {url} (HTTP {}).",
690→            response.status(),
691→        )));
692→    }
693→
694→    let payload: OllamaTagsResponse = response.json().await.map_err(|source| {
695→        error::Error::external("invalid JSON from Ollama model discovery endpoint", source)
696→    })?;
697→
698→    let mut models: Vec<String> = payload
699→        .models
700→        .into_iter()
701→        .map(|m| m.name.trim().to_string())
702→        .filter(|name| !name.is_empty())
703→        .collect();
704→    models.sort();
705→    models.dedup();
706→    Ok(models)
707→}
