2047→            }];
2048→        }
2049→
2050→        if let Some(tc) = find_empty_tool_name_call(&tool_calls) {
2051→            if has_named_tool_call(&tool_calls) {
2052→                warn!(
2053→                    tool_call_id = %tc.id,
2054→                    "streamed tool call batch contains both empty and valid tool names; preserving valid sibling tool calls and falling back to normal tool error handling"
2055→                );
2056→            } else if empty_tool_name_retry_count == 0 {
2057→                empty_tool_name_retry_count += 1;
2058→                info!(tool_call_id = %tc.id, "detected structured tool call with empty name in stream, requesting retry");
2059→                let retry_text = streaming_tool_call_message_content(
2060→                    &mut last_answer_text,
2061→                    &accumulated_text,
2062→                    &accumulated_reasoning,
2063→                );
2064→                messages.push(ChatMessage::assistant(retry_text.unwrap_or_default()));
2065→                messages.push(ChatMessage::user(empty_tool_name_retry_prompt(tc)));
2066→                continue;
2067→            }
2068→            warn!(
2069→                tool_call_id = %tc.id,
2070→                "structured tool call in stream still has empty name after retry; falling back to normal tool error handling"
2071→            );
2072→        }
2073→
2074→        // Dispatch AfterLLMCall hook — may block tool execution.
2075→        if let Some(ref hooks) = hook_registry {
2076→            let tc_json: Vec<serde_json::Value> = tool_calls
2077→                .iter()
2078→                .map(|tc| {
2079→                    serde_json::json!({
2080→                        "id": tc.id,
2081→                        "name": tc.name,
2082→                        "arguments": tc.arguments,
2083→                    })
2084→                })
2085→                .collect();
2086→            let payload = HookPayload::AfterLLMCall {
2087→                session_key: session_key_for_hooks.clone(),
2088→                provider: provider.name().to_string(),
2089→                model: provider.id().to_string(),
2090→                text: if accumulated_text.is_empty() {
2091→                    None
2092→                } else {
2093→                    Some(accumulated_text.clone())
2094→                },
2095→                tool_calls: tc_json,
2096→                input_tokens,
2097→                output_tokens,
2098→                iteration: iterations,
2099→            };
2100→            match hooks.dispatch(&payload).await {
2101→                Ok(HookAction::Block(reason)) => {
2102→                    warn!(reason = %reason, "LLM response blocked by AfterLLMCall hook");
2103→                    return Err(AgentRunError::Other(anyhow::anyhow!(
2104→                        "blocked by AfterLLMCall hook: {reason}"
2105→                    )));
2106→                },
2107→                Ok(HookAction::ModifyPayload(_)) => {
2108→                    debug!("AfterLLMCall ModifyPayload ignored (response is typed)");
2109→                },
2110→                Ok(HookAction::Continue) => {},
2111→                Err(e) => {
2112→                    warn!(error = %e, "AfterLLMCall hook dispatch failed");
2113→                },
2114→            }
2115→        }
2116→
2117→        // If no tool calls, auto-continue or return the text response.
2118→        if tool_calls.is_empty() {
2119→            // Auto-continue: if the model made tool calls earlier in this run
2120→            // and we haven't exhausted nudges, ask it to keep going. Suppress
2121→            // the nudge when the model already produced a substantive final
2122→            // answer — nudging in that case risks losing the answer (GH #628).
2123→            if !is_substantive_answer_text(&accumulated_text)
2124→                && total_tool_calls > 0
2125→                && total_tool_calls >= auto_continue_min_tool_calls
2126→                && auto_continue_count < max_auto_continues
2127→            {
2128→                auto_continue_count += 1;
2129→                info!(
2130→                    iterations,
2131→                    auto_continue_count, "model stopped without tool calls, auto-continuing"
2132→                );
2133→                if let Some(cb) = on_event {
2134→                    cb(RunnerEvent::AutoContinue {
2135→                        iteration: iterations,
2136→                        max_iterations,
2137→                    });
2138→                }
2139→                if !accumulated_text.is_empty() {
2140→                    messages.push(ChatMessage::assistant(&accumulated_text));
2141→                }
2142→                messages.push(ChatMessage::user(AUTO_CONTINUE_NUDGE));
2143→                continue;
2144→            }
2145→
2146→            // When the final iteration produced no text but a previous iteration
2147→            // streamed answer text alongside tool calls, use that as the response.
2148→            let final_text = if accumulated_text.is_empty() && !last_answer_text.is_empty() {
2149→                std::mem::take(&mut last_answer_text)
2150→            } else {
2151→                accumulated_text
2152→            };
2153→            info!(
2154→                iterations,
2155→                tool_calls = total_tool_calls,
2156→                "streaming agent loop complete — returning text"
2157→            );
2158→            return Ok(AgentRunResult {
2159→                text: clean_response(&final_text),
2160→                iterations,
2161→                tool_calls_made: total_tool_calls,
2162→                usage: Usage {
2163→                    input_tokens: total_input_tokens,
2164→                    output_tokens: total_output_tokens,
2165→                    ..Default::default()
2166→                },
2167→                request_usage: Usage {
2168→                    input_tokens,
2169→                    output_tokens,
2170→                    ..Default::default()
2171→                },
2172→                raw_llm_responses,
2173→            });
2174→        }
2175→
2176→        // Append assistant message with tool calls.
2177→        //
2178→        // When the model emits explicit reasoning (extended thinking), use
2179→        // that as the planning text and emit it as ThinkingText for the UI.
2180→        // When there is only regular text alongside tool calls (no separate
2181→        // reasoning), preserve it on the message for history but do NOT emit
2182→        // it as ThinkingText — it was already streamed as TextDelta and is
2183→        // likely the actual answer (e.g. a search result table produced
2184→        // before a `browser close` cleanup call).
2185→        let (text_for_msg, is_actual_reasoning) = if !accumulated_reasoning.is_empty() {
2186→            (Some(accumulated_reasoning), true)
2187→        } else if !accumulated_text.is_empty() {
2188→            last_answer_text.clone_from(&accumulated_text);
2189→            (Some(accumulated_text), false)
2190→        } else {
2191→            (None, false)
2192→        };
2193→        if let Some(ref text) = text_for_msg
2194→            && is_actual_reasoning
2195→            && let Some(cb) = on_event
2196→        {
2197→            cb(RunnerEvent::ThinkingText(text.clone()));
2198→        }
2199→        messages.push(ChatMessage::assistant_with_tools(
2200→            text_for_msg,
2201→            tool_calls.clone(),
2202→        ));
2203→
2204→        // Execute tool calls concurrently.
2205→        total_tool_calls += tool_calls.len();
2206→
2207→        // Build futures for all tool calls (executed concurrently).
2208→        //
2209→        // Pre-dispatch schema validation runs synchronously against each
2210→        // tool's declared `parameters_schema`. Calls that fail validation
2211→        // are short-circuited to a directive error response without invoking
2212→        // `execute`, and the UI receives `ToolCallRejected` instead of the
2213→        // misleading "executing" status (issue #658).
2214→        let tool_futures: Vec<_> = tool_calls
2215→            .iter()
2216→            .map(|tc| {
2217→                let sanitized = sanitize_tool_name(&tc.name);
2218→                if *sanitized != tc.name {
2219→                    debug!(original = %tc.name, sanitized = %sanitized, "sanitized mangled tool name");
2220→                }
2221→                let tool = tools.get(&sanitized);
2222→                let mut args = tc.arguments.clone();
2223→
2224→                let hook_registry = hook_registry.clone();
2225→                let session_key = session_key_for_hooks.clone();
2226→                let channel_for_hooks = channel_for_hooks.clone();
2227→                let tc_name = sanitized.to_string();
2228→
2229→                if let Some(ref ctx) = tool_context
2230→                    && let (Some(args_obj), Some(ctx_obj)) = (args.as_object_mut(), ctx.as_object())
2231→                {
2232→                    for (k, v) in ctx_obj {
2233→                        args_obj.insert(k.clone(), v.clone());
2234→                    }
2235→                }
2236→
2237→                // Pre-dispatch validation against the tool's schema.
2238→                let validation_error: Option<String> = if let Some(ref t) = tool {
2239→                    let schema = t.parameters_schema();
2240→                    match validate_tool_args(&schema, &args) {
2241→                        Ok(()) => None,
2242→                        Err(e) => {
2243→                            warn!(
2244→                                tool = %tc_name,
2245→                                summary = %e.short_summary(),
2246→                                "tool call rejected by pre-dispatch schema validation"
2247→                            );
2248→                            Some(e.to_llm_error_message(&tc_name))
2249→                        },
2250→                    }
2251→                } else {
2252→                    None
2253→                };
2254→
2255→                if validation_error.is_none() {
2256→                    if let Some(cb) = on_event {
2257→                        cb(RunnerEvent::ToolCallStart {
2258→                            id: tc.id.clone(),
2259→                            name: tc.name.clone(),
2260→                            arguments: args.clone(),
2261→                        });
2262→                    }
2263→                    info!(tool = %tc_name, id = %tc.id, args = %args, "executing tool");
2264→                }
2265→
2266→                async move {
2267→                    if let Some(err_msg) = validation_error {
2268→                        return (
2269→                            false,
2270→                            serde_json::json!({ "error": err_msg.clone() }),
2271→                            Some(err_msg),
2272→                            true,
2273→                        );
2274→                    }
2275→                    // Run BeforeToolCall hook.
2276→                    if let Some(ref hooks) = hook_registry {
2277→                        let payload = HookPayload::BeforeToolCall {
2278→                            session_key: session_key.clone(),
2279→                            tool_name: tc_name.clone(),
2280→                            arguments: args.clone(),
2281→                            channel: channel_for_hooks.clone(),
2282→                        };
2283→                        match hooks.dispatch(&payload).await {
2284→                            Ok(HookAction::Block(reason)) => {
2285→                                warn!(tool = %tc_name, reason = %reason, "tool call blocked by hook");
2286→                                let err_str = format!("blocked by hook: {reason}");
2287→                                return (
2288→                                    false,
2289→                                    serde_json::json!({ "error": err_str }),
2290→                                    Some(err_str),
2291→                                    false,
2292→                                );
2293→                            }
2294→                            Ok(HookAction::ModifyPayload(v)) => {
2295→                                args = v;
2296→                            }
2297→                            Ok(HookAction::Continue) => {}
2298→                            Err(e) => {
2299→                                warn!(tool = %tc_name, error = %e, "BeforeToolCall hook dispatch failed");
2300→                            }
2301→                        }
2302→                    }
2303→
2304→                    if let Some(tool) = tool {
2305→                        match tool.execute(args).await {
2306→                            Ok(val) => {
2307→                                // Check if the result indicates a logical failure
2308→                                // (e.g., BrowserResponse with success: false)
2309→                                let has_error = val.get("error").is_some()
2310→                                    || val.get("success") == Some(&serde_json::json!(false));
2311→                                let error_msg = if has_error {
2312→                                    val.get("error")
2313→                                        .and_then(|e| e.as_str())
2314→                                        .map(String::from)
2315→                                } else {
2316→                                    None
2317→                                };
2318→
2319→                                if let Some(ref hooks) = hook_registry {
2320→                                    let payload = HookPayload::AfterToolCall {
2321→                                        session_key: session_key.clone(),
2322→                                        tool_name: tc_name.clone(),
2323→                                        success: !has_error,
2324→                                        result: Some(val.clone()),
2325→                                        channel: channel_for_hooks.clone(),
2326→                                    };
2327→                                    if let Err(e) = hooks.dispatch(&payload).await {
2328→                                        warn!(tool = %tc_name, error = %e, "AfterToolCall hook dispatch failed");
2329→                                    }
2330→                                }
2331→
2332→                                if has_error {
2333→                                    (false, serde_json::json!({ "result": val }), error_msg, false)
2334→                                } else {
2335→                                    (true, serde_json::json!({ "result": val }), None, false)
2336→                                }
2337→                            }
2338→                            Err(e) => {
2339→                                let err_str = e.to_string();
2340→                                if let Some(ref hooks) = hook_registry {
2341→                                    let payload = HookPayload::AfterToolCall {
2342→                                        session_key: session_key.clone(),
2343→                                        tool_name: tc_name.clone(),
2344→                                        success: false,
2345→                                        result: None,
2346→                                        channel: channel_for_hooks.clone(),
2347→                                    };
2348→                                    if let Err(e) = hooks.dispatch(&payload).await {
2349→                                        warn!(tool = %tc_name, error = %e, "AfterToolCall hook dispatch failed");
2350→                                    }
2351→                                }
2352→                                (
2353→                                    false,
2354→                                    serde_json::json!({ "error": err_str }),
2355→                                    Some(err_str),
2356→                                    false,
2357→                                )
2358→                            }
2359→                        }
2360→                    } else {
2361→                        let err_str = format!("unknown tool: {tc_name}");
2362→                        (
2363→                            false,
2364→                            serde_json::json!({ "error": err_str }),
2365→                            Some(err_str),
2366→                            false,
2367→                        )
2368→                    }
2369→                }
2370→            })
2371→            .collect();
2372→
2373→        // Execute all tools concurrently and collect results in order.
2374→        let results = futures::future::join_all(tool_futures).await;
2375→
2376→        // Process results in original order: emit events, append messages.
2377→        // Intervention is derived from the detector's post-batch state
2378→        // via `consume_pending_action()` below — see the non-streaming
2379→        // path for the rationale (issue #658).
2380→        for (tc, (success, mut result, error, rejected)) in tool_calls.iter().zip(results) {
2381→            if success {
2382→                info!(tool = %tc.name, id = %tc.id, "tool execution succeeded");
2383→                trace!(tool = %tc.name, result = %result, "tool result");
2384→            } else if rejected {
2385→                warn!(
2386→                    tool = %tc.name,
2387→                    id = %tc.id,
2388→                    "tool call rejected before execution by pre-dispatch validation"
2389→                );
2390→            } else {
2391→                warn!(tool = %tc.name, id = %tc.id, error = %error.as_deref().unwrap_or(""), "tool execution failed");
2392→            }
2393→
2394→            // Record outcome in the loop detector (issue #658).
2395→            if loop_detector.is_enabled() {
2396→                let fp = if success {
2397→                    ToolCallFingerprint::success(&tc.name, &tc.arguments)
2398→                } else {
2399→                    ToolCallFingerprint::failure(&tc.name, &tc.arguments, error.as_deref())
2400→                };
2401→                let _ = loop_detector.record(fp);
2402→            }
2403→
2404→            if let Some(cb) = on_event {
2405→                if rejected {
2406→                    cb(RunnerEvent::ToolCallRejected {
2407→                        id: tc.id.clone(),
2408→                        name: tc.name.clone(),
2409→                        arguments: tc.arguments.clone(),
2410→                        error: error.clone().unwrap_or_default(),
2411→                    });
2412→                } else {
2413→                    cb(RunnerEvent::ToolCallEnd {
2414→                        id: tc.id.clone(),
2415→                        name: tc.name.clone(),
2416→                        success,
2417→                        error,
2418→                        result: if success {
2419→                            result.get("result").cloned()
2420→                        } else {
2421→                            None
2422→                        },
2423→                    });
2424→                }
2425→            }
2426→
2427→            // Dispatch ToolResultPersist hook — the last opportunity for a handler
2428→            // to sanitize, redact, or block attacker-controlled tool output before
2429→            // it enters the messages array and is reasoned on by the next LLM
2430→            // iteration. Block substitutes an error marker instead of aborting the
2431→            // run, so a single hostile tool result cannot kill a long-running
2432→            // autonomous agent.
2433→            if let Some(ref hooks) = hook_registry {
2434→                let payload = HookPayload::ToolResultPersist {
2435→                    session_key: session_key_for_hooks.clone(),
2436→                    tool_name: sanitize_tool_name(&tc.name).into_owned(),
2437→                    result: result.clone(),
2438→                    channel: channel_for_hooks.clone(),
2439→                };
2440→                match hooks.dispatch(&payload).await {
2441→                    Ok(HookAction::ModifyPayload(v)) => {
2442→                        debug!(tool = %tc.name, "ToolResultPersist replaced tool result");
2443→                        result = v;
2444→                    },
2445→                    Ok(HookAction::Block(reason)) => {
2446→                        warn!(tool = %tc.name, reason = %reason, "ToolResultPersist blocked result — substituting error marker");
2447→                        result = serde_json::json!({
2448→                            "error": format!("blocked by hook: {reason}")
2449→                        });
2450→                    },
2451→                    Ok(HookAction::Continue) => {},
2452→                    Err(e) => {
2453→                        warn!(tool = %tc.name, error = %e, "ToolResultPersist hook dispatch failed");
2454→                    },
2455→                }
2456→            }
2457→
2458→            // Always sanitize tool results as strings - most LLM APIs don't support
2459→            // multimodal content in tool results. Images are stripped but the UI
2460→            // still receives them via ToolCallEnd event.
2461→            let tool_result_str = sanitize_tool_result(&result.to_string(), max_tool_result_bytes);
2462→            debug!(
2463→                tool = %tc.name,
2464→                id = %tc.id,
2465→                result_len = tool_result_str.len(),
2466→                "appending tool result to messages"
2467→            );
2468→            trace!(tool = %tc.name, content = %tool_result_str, "tool result message content");
2469→
2470→            messages.push(ChatMessage::tool(&tc.id, &tool_result_str));
2471→        }
2472→
2473→        // Apply loop-detector intervention if one fired during this batch.
2474→        apply_loop_detector_intervention(
2475→            &mut loop_detector,
2476→            &mut messages,
2477→            &mut strip_tools_next_iter,
2478→            on_event,
2479→        );
2480→    }
2481→}
