1161→async fn maybe_deliver_cron_output(
1162→    outbound: Option<Arc<dyn moltis_channels::ChannelOutbound>>,
1163→    req: &moltis_cron::service::AgentTurnRequest,
1164→    delivery_text: &str,
1165→) {
1166→    if !req.deliver || delivery_text.trim().is_empty() {
1167→        return;
1168→    }
1169→
1170→    let (Some(channel_account), Some(chat_id)) = (&req.channel, &req.to) else {
1171→        return;
1172→    };
1173→
1174→    if let Some(outbound) = outbound {
1175→        if let Err(error) = outbound
1176→            .send_text(channel_account, chat_id, delivery_text, None)
1177→            .await
1178→        {
1179→            tracing::warn!(
1180→                channel = %channel_account,
1181→                to = %chat_id,
1182→                error = %error,
1183→                "cron job channel delivery failed"
1184→            );
1185→        }
1186→    } else {
1187→        tracing::debug!("cron job delivery requested but no channel outbound configured");
1188→    }
1189→}
