1220→    /// scheduled jobs will not execute.
1221→    pub cron_service: Arc<moltis_cron::service::CronService>,
1222→    /// Log buffer for real-time log streaming.
1223→    pub log_buffer: Option<crate::logs::LogBuffer>,
1224→    /// Browser tool for warmup after listener is ready.
1225→    pub browser_tool_for_warmup: Option<Arc<dyn moltis_agents::tool_registry::AgentTool>>,
1226→    /// Loaded configuration snapshot.
1227→    pub config: moltis_config::schema::MoltisConfig,
1228→    /// Resolved data directory.
1229→    pub data_dir: PathBuf,
1230→    /// Human-readable provider summary for the startup banner.
1231→    pub provider_summary: String,
1232→    /// Number of configured MCP servers.
1233→    pub mcp_configured_count: usize,
1234→    /// OpenClaw detection status string.
1235→    pub openclaw_status: String,
1236→    /// One-time setup code (when auth setup is pending).
1237→    pub setup_code_display: Option<String>,
1238→    /// Resolved port.
1239→    pub port: u16,
1240→    /// Whether TLS is active for this gateway instance.
1241→    pub tls_enabled: bool,
1242→    /// Tailscale mode.
1243→    #[cfg(feature = "tailscale")]
1244→    pub tailscale_mode: TailscaleMode,
1245→    /// Whether to reset tailscale on exit.
1246→    #[cfg(feature = "tailscale")]
1247→    pub tailscale_reset_on_exit: bool,
1248→    /// Shutdown sender for the trusted-network proxy.  Retained here so the
1249→    /// proxy task is not cancelled when `prepare_gateway` returns (dropping
1250→    /// the sender closes the watch channel and triggers immediate shutdown).
1251→    #[cfg(feature = "trusted-network")]
1252→    pub _proxy_shutdown_tx: Option<tokio::sync::watch::Sender<bool>>,
1253→}
