1255→fn restore_saved_local_llm_models(
1256→    registry: &mut ProviderRegistry,
1257→    providers_config: &moltis_config::schema::ProvidersConfig,
1258→) {
1259→    #[cfg(feature = "local-llm")]
1260→    {
1261→        if !providers_config.is_enabled("local") {
1262→            return;
1263→        }
1264→
1265→        crate::local_llm_setup::register_saved_local_models(registry, providers_config);
1266→    }
1267→
1268→    #[cfg(not(feature = "local-llm"))]
1269→    {
1270→        let _ = (registry, providers_config);
1271→    }
1272→}
