1274→/// Prepare the core gateway: load config, run migrations, wire services,
1275→/// spawn background tasks, and return the core state without any HTTP layer.
1276→///
1277→/// This is the transport-agnostic initialisation. Non-HTTP consumers (TUI,
1278→/// tests) can stop here. HTTP consumers call [`prepare_gateway`] which
1279→/// delegates to this and then adds the router + middleware.
1280→#[allow(clippy::expect_used)] // Startup fail-fast: DB, migrations, credential store must succeed.
1281→pub async fn prepare_gateway_core(
1282→    bind: &str,
1283→    port: u16,
1284→    no_tls: bool,
1285→    log_buffer: Option<crate::logs::LogBuffer>,
1286→    config_dir: Option<PathBuf>,
1287→    data_dir: Option<PathBuf>,
1288→    tailscale_mode_override: Option<String>,
1289→    tailscale_reset_on_exit_override: Option<bool>,
1290→    session_event_bus: Option<SessionEventBus>,
1291→) -> anyhow::Result<PreparedGatewayCore> {
1292→    let session_event_bus = session_event_bus.unwrap_or_default();
1293→    #[cfg(not(feature = "tailscale"))]
1294→    let _ = (&tailscale_mode_override, &tailscale_reset_on_exit_override);
1295→
1296→    // Apply directory overrides before loading config.
1297→    if let Some(dir) = config_dir {
1298→        moltis_config::set_config_dir(dir);
1299→    }
1300→    if let Some(ref dir) = data_dir {
1301→        moltis_config::set_data_dir(dir.clone());
1302→    }
1303→
1304→    // Resolve auth from environment (MOLTIS_TOKEN / MOLTIS_PASSWORD).
1305→    let token = std::env::var("MOLTIS_TOKEN").ok();
1306→    let password = std::env::var("MOLTIS_PASSWORD").ok();
1307→
1308→    // Cloud deploy platform — hides local-only providers (local-llm, ollama).
1309→    let deploy_platform = std::env::var("MOLTIS_DEPLOY_PLATFORM").ok();
1310→    let resolved_auth = auth::resolve_auth(token, password.clone());
1311→
1312→    // Load config file (moltis.toml / .yaml / .json) if present.
1313→    let mut config = moltis_config::discover_and_load();
1314→    info!(
1315→        offered_channels = ?config.channels.offered,
1316→        "loaded offered channels from config"
1317→    );
1318→    let config_env_overrides = config.env.clone();
1319→    let instance_slug_value = instance_slug(&config);
1320→    let browser_container_prefix = browser_container_prefix(&instance_slug_value);
1321→    let sandbox_container_prefix = sandbox_container_prefix(&instance_slug_value);
1322→    let mut startup_mem_probe = StartupMemProbe::new();
1323→    startup_mem_probe.checkpoint("prepare_gateway.start");
1324→
1325→    // CLI --no-tls / MOLTIS_NO_TLS overrides config file TLS setting.
1326→    if no_tls {
1327→        config.tls.enabled = false;
1328→    }
1329→    let behind_proxy = env_flag_enabled("MOLTIS_BEHIND_PROXY");
1330→    let allow_tls_behind_proxy = env_flag_enabled("MOLTIS_ALLOW_TLS_BEHIND_PROXY");
1331→    #[cfg(feature = "tls")]
1332→    let tls_enabled_for_gateway = config.tls.enabled;
1333→    #[cfg(not(feature = "tls"))]
1334→    let tls_enabled_for_gateway = false;
1335→    validate_proxy_tls_configuration(
1336→        behind_proxy,
1337→        tls_enabled_for_gateway,
1338→        allow_tls_behind_proxy,
1339→    )?;
1340→    if behind_proxy && tls_enabled_for_gateway && allow_tls_behind_proxy {
1341→        warn!(
1342→            "MOLTIS_ALLOW_TLS_BEHIND_PROXY=true is set; ensure your proxy uses HTTPS upstream or TLS passthrough to avoid redirect loops"
1343→        );
1344→    }
1345→
1346→    let base_provider_config = config.providers.clone();
1347→
1348→    // Merge any previously saved API keys into the provider config so they
1349→    // survive gateway restarts without requiring env vars.
1350→    let key_store = crate::provider_setup::KeyStore::new();
1351→    // Collect local-llm model IDs (if the feature is enabled and models are configured).
1352→    #[cfg(feature = "local-llm")]
1353→    let local_model_ids: Vec<String> = crate::local_llm_setup::LocalLlmConfig::load()
1354→        .map(|c| c.models.iter().map(|m| m.model_id.clone()).collect())
1355→        .unwrap_or_default();
1356→    #[cfg(not(feature = "local-llm"))]
1357→    let local_model_ids: Vec<String> = Vec::new();
1358→
1359→    let effective_providers = crate::provider_setup::config_with_saved_keys(
1360→        &base_provider_config,
1361→        &key_store,
1362→        &local_model_ids,
1363→    );
1364→
1365→    let has_explicit_provider_settings =
1366→        crate::provider_setup::has_explicit_provider_settings(&config.providers);
1367→    let auto_detected_provider_sources = if has_explicit_provider_settings {
1368→        Vec::new()
1369→    } else {
1370→        crate::provider_setup::detect_auto_provider_sources_with_overrides(
1371→            &config.providers,
1372→            deploy_platform.as_deref(),
1373→            &config_env_overrides,
1374→        )
1375→    };
1376→
1377→    // Kick off discovery workers immediately, but build a static startup
1378→    // registry first so gateway startup does not block on network I/O.
1379→    let startup_discovery_pending =
1380→        ProviderRegistry::fire_discoveries(&effective_providers, &config_env_overrides);
1381→    let registry = Arc::new(tokio::sync::RwLock::new(
1382→        ProviderRegistry::from_config_with_static_catalogs(
1383→            &effective_providers,
1384→            &config_env_overrides,
1385→        ),
1386→    ));
1387→    {
1388→        let mut reg = registry.write().await;
1389→        restore_saved_local_llm_models(&mut reg, &effective_providers);
1390→    }
1391→    let (provider_summary, providers_available_at_startup) = {
1392→        let reg = registry.read().await;
1393→        log_startup_model_inventory(&reg);
1394→        (reg.provider_summary(), !reg.is_empty())
1395→    };
1396→    if !providers_available_at_startup {
1397→        let config_path = moltis_config::find_or_default_config_path();
1398→        let provider_keys_path = moltis_config::config_dir()
1399→            .unwrap_or_else(|| PathBuf::from(".moltis"))
1400→            .join("provider_keys.json");
1401→        warn!(
1402→            provider_summary = %provider_summary,
1403→            config_path = %config_path.display(),
1404→            provider_keys_path = %provider_keys_path.display(),
1405→            "no LLM providers in static startup catalog; model/chat services remain active and will pick up providers after credentials are saved or background discovery completes"
1406→        );
1407→    }
1408→
1409→    if !has_explicit_provider_settings {
1410→        if auto_detected_provider_sources.is_empty() {
1411→            info!("llm auto-detect: no providers detected from env/files");
1412→        } else {
1413→            for detected in &auto_detected_provider_sources {
1414→                info!(
1415→                    provider = %detected.provider,
1416→                    source = %detected.source,
1417→                    "llm auto-detected provider source"
1418→                );
1419→            }
1420→            // Import external tokens (e.g. Codex CLI auth.json) into the
1421→            // token store so all providers read from a single location.
1422→            let import_token_store = moltis_oauth::TokenStore::new();
1423→            crate::provider_setup::import_detected_oauth_tokens(
1424→                &auto_detected_provider_sources,
1425→                &import_token_store,
1426→            );
1427→        }
1428→    }
1429→    startup_mem_probe.checkpoint("providers.registry.initialized");
1430→
1431→    // Refresh dynamic provider model discovery daily so long-lived sessions
1432→    // pick up newly available models without requiring a restart.
1433→    const DYNAMIC_PROVIDER_MODEL_REFRESH_INTERVAL: std::time::Duration =
1434→        std::time::Duration::from_secs(24 * 60 * 60);
1435→    {
1436→        let registry_for_refresh = Arc::clone(&registry);
1437→        let provider_config_for_refresh = base_provider_config.clone();
1438→        tokio::spawn(async move {
1439→            let mut interval = tokio::time::interval(DYNAMIC_PROVIDER_MODEL_REFRESH_INTERVAL);
1440→            interval.tick().await;
1441→            loop {
1442→                interval.tick().await;
1443→                let mut reg = registry_for_refresh.write().await;
1444→                let refresh_results = reg.refresh_dynamic_models(&provider_config_for_refresh);
1445→                for (provider_name, refreshed) in refresh_results {
1446→                    if !refreshed {
1447→                        continue;
1448→                    }
1449→                    let model_count = reg
1450→                        .list_models()
1451→                        .iter()
1452→                        .filter(|m| m.provider == provider_name)
1453→                        .count();
1454→                    info!(
1455→                        provider = %provider_name,
1456→                        models = model_count,
1457→                        "daily dynamic provider model refresh complete"
1458→                    );
1459→                }
1460→            }
1461→        });
1462→    }
1463→
1464→    // Create shared approval manager from config.
1465→    let approval_manager = Arc::new(approval_manager_from_config(&config));
1466→
1467→    let mut services = GatewayServices::noop();
1468→
1469→    // Wire live logs service if a log buffer is available.
1470→    if let Some(ref buf) = log_buffer {
1471→        services.logs = Arc::new(crate::logs::LiveLogsService::new(buf.clone()));
1472→    }
1473→
1474→    services.exec_approval = Arc::new(LiveExecApprovalService::new(Arc::clone(&approval_manager)));
1475→
1476→    // Wire browser service if enabled.
1477→    if let Some(browser_svc) =
1478→        crate::services::RealBrowserService::from_config(&config, browser_container_prefix)
1479→    {
1480→        services.browser = Arc::new(browser_svc);
1481→    }
1482→
1483→    // Wire live onboarding service.
1484→    let onboarding_config_path = moltis_config::find_or_default_config_path();
1485→    let live_onboarding =
1486→        moltis_onboarding::service::LiveOnboardingService::new(onboarding_config_path);
1487→    // Wire live local-llm service when the feature is enabled.
1488→    #[cfg(feature = "local-llm")]
1489→    let local_llm_service: Option<Arc<crate::local_llm_setup::LiveLocalLlmService>> = {
1490→        let svc = Arc::new(crate::local_llm_setup::LiveLocalLlmService::new(
1491→            Arc::clone(&registry),
1492→        ));
1493→        services =
1494→            services.with_local_llm(Arc::clone(&svc) as Arc<dyn crate::services::LocalLlmService>);
1495→        Some(svc)
1496→    };
1497→    // When local-llm feature is disabled, this variable is not needed since
1498→    // the only usage is also feature-gated.
1499→

1500→    // Wire live voice services when the feature is enabled.
1501→    #[cfg(feature = "voice")]
1502→    {
1503→        use crate::voice::{LiveSttService, LiveTtsService, SttServiceConfig};
1504→
1505→        // Services read fresh config from disk on each operation,
1506→        // so we just need to create the instances here.
1507→        services.tts = Arc::new(LiveTtsService::new(moltis_voice::TtsConfig::default()));
1508→        services.stt = Arc::new(LiveSttService::new(SttServiceConfig::default()));
1509→    }
1510→
1511→    let model_store = Arc::new(tokio::sync::RwLock::new(
1512→        crate::chat::DisabledModelsStore::load(),
1513→    ));
1514→
1515→    let live_model_service = Arc::new(
1516→        LiveModelService::new(
1517→            Arc::clone(&registry),
1518→            Arc::clone(&model_store),
1519→            config.chat.priority_models.clone(),
1520→        )
1521→        .with_show_legacy_models(config.providers.show_legacy_models)
1522→        .with_discovery_config(effective_providers.clone(), config_env_overrides.clone()),
1523→    );
1524→    services = services
1525→        .with_model(Arc::clone(&live_model_service) as Arc<dyn crate::services::ModelService>);
1526→
1527→    // Create provider setup after model service so we can share the
1528→    // priority models handle for live dropdown reordering.
1529→    let mut provider_setup = LiveProviderSetupService::new(
1530→        Arc::clone(&registry),
1531→        config.providers.clone(),
1532→        deploy_platform.clone(),
1533→    )
1534→    .with_env_overrides(config_env_overrides.clone())
1535→    .with_error_parser(crate::chat_error::parse_chat_error)
1536→    .with_callback_bind_addr(bind.to_string());
1537→    provider_setup.set_priority_models(live_model_service.priority_models_handle());
1538→    let provider_setup_service = Arc::new(provider_setup);
1539→    services.provider_setup =
1540→        Arc::clone(&provider_setup_service) as Arc<dyn crate::services::ProviderSetupService>;
1541→
1542→    // Wire live MCP service.
1543→    let mcp_configured_count;
1544→    let live_mcp: Arc<crate::mcp_service::LiveMcpService>;
1545→    {
1546→        let mcp_registry_path = moltis_config::data_dir().join("mcp-servers.json");
1547→        let mcp_reg = moltis_mcp::McpRegistry::load(&mcp_registry_path).unwrap_or_default();
1548→        // Seed from config file servers that aren't already in the registry.
1549→        let mut merged = mcp_reg;
1550→        for (name, entry) in &config.mcp.servers {
1551→            if !merged.servers.contains_key(name) {
1552→                let transport = match entry.transport.as_str() {
1553→                    "sse" => moltis_mcp::registry::TransportType::Sse,
1554→                    "streamable_http" | "streamable-http" | "http" => {
1555→                        moltis_mcp::registry::TransportType::StreamableHttp
1556→                    },
1557→                    _ => moltis_mcp::registry::TransportType::Stdio,
1558→                };
1559→                let oauth = entry
1560→                    .oauth
1561→                    .as_ref()
1562→                    .map(|o| moltis_mcp::registry::McpOAuthConfig {
1563→                        client_id: o.client_id.clone(),
1564→                        auth_url: o.auth_url.clone(),
1565→                        token_url: o.token_url.clone(),
1566→                        scopes: o.scopes.clone(),
1567→                    });
1568→                merged
1569→                    .servers
1570→                    .insert(name.clone(), moltis_mcp::McpServerConfig {
1571→                        command: entry.command.clone(),
1572→                        args: entry.args.clone(),
1573→                        env: entry.env.clone(),
1574→                        enabled: entry.enabled,
1575→                        request_timeout_secs: entry.request_timeout_secs,
1576→                        transport,
1577→                        url: entry.url.clone().map(Secret::new),
1578→                        headers: entry
1579→                            .headers
1580→                            .iter()
1581→                            .map(|(key, value)| (key.clone(), Secret::new(value.clone())))
1582→                            .collect(),
1583→                        oauth,
1584→                        display_name: entry.display_name.clone(),
1585→                    });
1586→            }
1587→        }
1588→        mcp_configured_count = merged.servers.values().filter(|s| s.enabled).count();
1589→        let mcp_manager = Arc::new(moltis_mcp::McpManager::new_with_env_overrides(
1590→            merged,
1591→            config_env_overrides.clone(),
1592→            std::time::Duration::from_secs(config.mcp.request_timeout_secs.max(1)),
1593→        ));
1594→        live_mcp = Arc::new(crate::mcp_service::LiveMcpService::new(
1595→            Arc::clone(&mcp_manager),
1596→            config_env_overrides.clone(),
1597→            None,
1598→        ));
1599→        services.mcp = live_mcp.clone() as Arc<dyn crate::services::McpService>;
1600→    }
1601→    startup_mem_probe.checkpoint("services.core_wired");
1602→
1603→    // Initialize data directory and SQLite database.
1604→    let data_dir = data_dir.unwrap_or_else(moltis_config::data_dir);
1605→    std::fs::create_dir_all(&data_dir).unwrap_or_else(|e| {
1606→        panic!(
1607→            "failed to create data directory {}: {e}",
1608→            data_dir.display()
1609→        )
1610→    });
1611→
1612→    let config_dir = moltis_config::config_dir().unwrap_or_else(|| PathBuf::from(".moltis"));
1613→    std::fs::create_dir_all(&config_dir).unwrap_or_else(|e| {
1614→        panic!(
1615→            "failed to create config directory {}: {e}",
1616→            config_dir.display()
1617→        )
1618→    });
1619→    log_startup_config_storage_diagnostics();
1620→
1621→    let openclaw_startup_status = deferred_openclaw_status();
1622→
1623→    // Enable log persistence so entries survive restarts.
1624→    if let Some(ref buf) = log_buffer {
1625→        let log_buffer_for_persistence = buf.clone();
1626→        let persistence_path = data_dir.join("logs.jsonl");
1627→        tokio::spawn(async move {
1628→            let started = std::time::Instant::now();
1629→            match tokio::task::spawn_blocking(move || {
1630→                log_buffer_for_persistence.enable_persistence(persistence_path.clone());
1631→                persistence_path
1632→            })
1633→            .await
1634→            {
1635→                Ok(path) => {
1636→                    debug!(
1637→                        path = %path.display(),
1638→                        elapsed_ms = started.elapsed().as_millis(),
1639→                        "startup log persistence initialized"
1640→                    );
1641→                },
1642→                Err(error) => {
1643→                    warn!(
1644→                        %error,
1645→                        "startup log persistence initialization worker failed"
1646→                    );
1647→                },
1648→            }
1649→        });
1650→    }
1651→    let db_path = data_dir.join("moltis.db");
1652→    let db_pool = {
1653→        use {
1654→            sqlx::sqlite::{SqliteConnectOptions, SqliteJournalMode, SqliteSynchronous},
1655→            std::str::FromStr,
1656→        };
1657→        let db_exists = db_path.exists();
1658→        let mut options = SqliteConnectOptions::from_str(&format!("sqlite:{}", db_path.display()))
1659→            .expect("invalid database path")
1660→            .create_if_missing(true)
1661→            .foreign_keys(true)
1662→            .synchronous(SqliteSynchronous::Normal)
1663→            .busy_timeout(std::time::Duration::from_secs(5));
1664→        if !db_exists {
1665→            // Setting journal_mode can briefly require an exclusive lock.
1666→            // For existing databases, preserve current mode to avoid startup stalls.
1667→            options = options.journal_mode(SqliteJournalMode::Wal);
1668→        }
1669→
1670→        let started = std::time::Instant::now();
1671→        let pool = sqlx::pool::PoolOptions::new()
1672→            .max_connections(config.server.db_pool_max_connections)
1673→            .connect_with(options)
1674→            .await
1675→            .expect("failed to open moltis.db");
1676→        debug!(
1677→            path = %db_path.display(),
1678→            db_exists,
1679→            elapsed_ms = started.elapsed().as_millis(),
1680→            "startup sqlite pool connected"
1681→        );
1682→        pool
1683→    };
1684→
1685→    // Run database migrations from each crate in dependency order.
1686→    // Order matters: sessions depends on projects (FK reference).
1687→    moltis_projects::run_migrations(&db_pool)
1688→        .await
1689→        .expect("failed to run projects migrations");
1690→    moltis_sessions::run_migrations(&db_pool)
1691→        .await
1692→        .expect("failed to run sessions migrations");
1693→    moltis_cron::run_migrations(&db_pool)
1694→        .await
1695→        .expect("failed to run cron migrations");
1696→    moltis_webhooks::run_migrations(&db_pool)
1697→        .await
1698→        .expect("failed to run webhooks migrations");
1699→    // Gateway's own tables (auth, message_log, channels).
1700→    crate::run_migrations(&db_pool)
1701→        .await
1702→        .expect("failed to run gateway migrations");
1703→
1704→    // Vault migrations (vault_metadata table).
1705→    #[cfg(feature = "vault")]
1706→    moltis_vault::run_migrations(&db_pool)
1707→        .await
1708→        .expect("failed to run vault migrations");
1709→
1710→    // Migrate plugins data into unified skills system (idempotent, non-fatal).
1711→    moltis_skills::migration::migrate_plugins_to_skills(&data_dir).await;
1712→    startup_mem_probe.checkpoint("sqlite.migrations.complete");
1713→
1714→    // Initialize vault for encryption-at-rest.
1715→    #[cfg(feature = "vault")]
1716→    let vault: Option<Arc<moltis_vault::Vault>> = {
1717→        match moltis_vault::Vault::new(db_pool.clone()).await {
1718→            Ok(v) => {
1719→                info!(status = ?v.status().await, "vault ready");
1720→                Some(Arc::new(v))
1721→            },
1722→            Err(e) => {
1723→                warn!(error = %e, "vault init failed, encryption disabled");
1724→                None
1725→            },
1726→        }
1727→    };
1728→
1729→    // Initialize credential store (auth tables).
1730→    #[cfg(feature = "vault")]
1731→    let credential_store = Arc::new(
1732→        auth::CredentialStore::with_vault(db_pool.clone(), &config.auth, vault.clone())
