 880→
 881→fn encode_json<T: Serialize>(value: &T) -> String {
 882→    match serde_json::to_string(value) {
 883→        Ok(json) => json,
 884→        Err(_) => {
 885→            "{\"error\":{\"code\":\"serialization_error\",\"message\":\"failed to serialize response\"}}"
 886→                .to_owned()
 887→        }
 888→    }
 889→}
 890→
 891→fn encode_error(code: &str, message: &str) -> String {
 892→    encode_json(&ErrorEnvelope {
 893→        error: ErrorPayload { code, message },
 894→    })
 895→}
 896→
 897→fn into_c_ptr(payload: String) -> *mut c_char {
 898→    match CString::new(payload) {
 899→        Ok(value) => value.into_raw(),
 900→        Err(_) => std::ptr::null_mut(),
 901→    }
 902→}
 903→
 904→fn with_ffi_boundary<F>(work: F) -> *mut c_char
 905→where
 906→    F: FnOnce() -> String,
 907→{
 908→    match catch_unwind(AssertUnwindSafe(work)) {
 909→        Ok(payload) => into_c_ptr(payload),
 910→        Err(_) => into_c_ptr(encode_error(
 911→            "panic",
 912→            "unexpected panic occurred in Rust FFI boundary",
 913→        )),
 914→    }
 915→}
