 922→    ptr: *const c_char,
 923→) -> Result<T, String> {
 924→    let raw = read_c_string(ptr).map_err(|message| {
 925→        record_error(function, "null_pointer_or_invalid_utf8");
 926→        encode_error("null_pointer_or_invalid_utf8", &message)
 927→    })?;
 928→    serde_json::from_str::<T>(&raw).map_err(|error| {
 929→        record_error(function, "invalid_json");
 930→        encode_error("invalid_json", &error.to_string())
 931→    })
 932→}
 933→
 934→#[allow(unsafe_code)]
 935→fn read_c_string(ptr: *const c_char) -> Result<String, String> {
 936→    if ptr.is_null() {
 937→        return Err("request_json pointer was null".to_owned());
 938→    }
 939→
 940→    // SAFETY: pointer nullability is checked above, and callers guarantee a
 941→    // valid NUL-terminated C string for the duration of the call.
 942→    let c_str = unsafe { CStr::from_ptr(ptr) };
 943→    match c_str.to_str() {
 944→        Ok(text) => Ok(text.to_owned()),
 945→        Err(_) => Err("request_json was not valid UTF-8".to_owned()),
 946→    }
 947→}
