 949→fn format_bytes(bytes: u64) -> String {
 950→    const KB: u64 = 1024;
 951→    const MB: u64 = 1024 * KB;
 952→    const GB: u64 = 1024 * MB;
 953→    match bytes {
 954→        b if b >= GB => format!("{:.1} GB", b as f64 / GB as f64),
 955→        b if b >= MB => format!("{:.1} MB", b as f64 / MB as f64),
 956→        b if b >= KB => format!("{:.1} KB", b as f64 / KB as f64),
 957→        b => format!("{b} B"),
 958→    }
 959→}
