1062→fn resolve_provider_for_model(model: Option<&str>) -> Option<std::sync::Arc<dyn LlmProvider>> {
1063→    let registry = BRIDGE.registry.read().unwrap_or_else(|e| e.into_inner());
1064→
1065→    // Try explicit model first
1066→    if let Some(model_id) = model
1067→        && let Some(provider) = registry.get(model_id)
1068→    {
1069→        emit_log(
1070→            "DEBUG",
1071→            "bridge",
1072→            &format!(
1073→                "Resolved provider for model={}: {}",
1074→                model_id,
1075→                provider.name()
1076→            ),
1077→        );
1078→        return Some(provider);
1079→    }
1080→
1081→    // Fall back to first available provider
1082→    let result = registry.first();
1083→    if let Some(ref p) = result {
1084→        emit_log(
1085→            "DEBUG",
1086→            "bridge",
1087→            &format!("Using first available provider: {} ({})", p.name(), p.id()),
1088→        );
1089→    } else {
1090→        emit_log("WARN", "bridge", "No provider available in registry");
1091→    }
1092→    result
1093→}
