1095→fn build_chat_response(request: ChatRequest) -> String {
1096→    emit_log(
1097→        "INFO",
1098→        "bridge.chat",
1099→        &format!(
1100→            "Chat request: model={:?} msg_len={}",
1101→            request.model,
1102→            request.message.len()
1103→        ),
1104→    );
1105→    let validation = build_validation_summary(request.config_toml.as_deref());
1106→
1107→    let (reply, model, provider_name, input_tokens, output_tokens, duration_ms) =
1108→        match resolve_provider(&request) {
1109→            Some(provider) => {
1110→                let model_id = provider.id().to_string();
1111→                let provider_name = provider.name().to_string();
1112→                let messages = vec![AgentChatMessage::User {
1113→                    content: UserContent::text(&request.message),
1114→                }];
1115→
1116→                emit_log(
1117→                    "DEBUG",
1118→                    "bridge.chat",
1119→                    &format!("Calling {}/{}", provider_name, model_id),
1120→                );
1121→                let start = std::time::Instant::now();
1122→                match BRIDGE.runtime.block_on(provider.complete(&messages, &[])) {
1123→                    Ok(response) => {
1124→                        let elapsed = start.elapsed().as_millis() as u64;
1125→                        let text = response
1126→                            .text
1127→                            .unwrap_or_else(|| "(empty response)".to_owned());
1128→                        let in_tok = response.usage.input_tokens;
1129→                        let out_tok = response.usage.output_tokens;
1130→                        emit_log(
1131→                            "INFO",
1132→                            "bridge.chat",
1133→                            &format!(
1134→                                "Response: {}ms in={} out={} provider={}",
1135→                                elapsed, in_tok, out_tok, provider_name
1136→                            ),
1137→                        );
1138→                        (
1139→                            text,
1140→                            Some(model_id),
1141→                            Some(provider_name),
1142→                            Some(in_tok),
1143→                            Some(out_tok),
1144→                            Some(elapsed),
1145→                        )
1146→                    },
1147→                    Err(error) => {
1148→                        let msg = format!("LLM error: {error}");
1149→                        emit_log("ERROR", "bridge.chat", &msg);
1150→                        (msg, Some(model_id), Some(provider_name), None, None, None)
1151→                    },
1152→                }
1153→            },
1154→            None => {
1155→                let msg = "No LLM provider configured".to_owned();
1156→                emit_log("WARN", "bridge.chat", &msg);
1157→                (
1158→                    format!("{msg}. Rust bridge received: {}", request.message),
1159→                    None,
1160→                    None,
1161→                    None,
1162→                    None,
1163→                    None,
1164→                )
1165→            },
1166→        };
1167→
1168→    let response = ChatResponse {
1169→        reply,
1170→        model,
1171→        provider: provider_name,
1172→        config_dir: config_dir_string(),
1173→        default_soul: moltis_config::DEFAULT_SOUL.to_owned(),
1174→        validation,
1175→        input_tokens,
1176→        output_tokens,
1177→        duration_ms,
1178→    };
1179→    encode_json(&response)
1180→}
