3336→    /// Return the per-session semaphore, creating one if absent.
3337→    async fn session_semaphore(&self, key: &str) -> Arc<Semaphore> {
3338→        // Fast path: read lock.
3339→        {
3340→            let locks = self.session_locks.read().await;
3341→            if let Some(sem) = locks.get(key) {
3342→                return Arc::clone(sem);
3343→            }
3344→        }
3345→        // Slow path: write lock, insert.
3346→        let mut locks = self.session_locks.write().await;
3347→        Arc::clone(
3348→            locks
3349→                .entry(key.to_string())
3350→                .or_insert_with(|| Arc::new(Semaphore::new(1))),
3351→        )
3352→    }
