3354→    async fn abort_run_handle(
3355→        active_runs: &Arc<RwLock<HashMap<String, AbortHandle>>>,
3356→        active_runs_by_session: &Arc<RwLock<HashMap<String, String>>>,
3357→        terminal_runs: &Arc<RwLock<HashSet<String>>>,
3358→        run_id: Option<&str>,
3359→        session_key: Option<&str>,
3360→    ) -> (Option<String>, bool) {
3361→        let resolved_run_id = if let Some(id) = run_id {
3362→            Some(id.to_string())
3363→        } else if let Some(key) = session_key {
3364→            active_runs_by_session.read().await.get(key).cloned()
3365→        } else {
3366→            None
3367→        };
3368→
3369→        let Some(target_run_id) = resolved_run_id.clone() else {
3370→            return (None, false);
3371→        };
3372→
3373→        if terminal_runs.read().await.contains(&target_run_id) {
3374→            return (resolved_run_id, false);
3375→        }
3376→
3377→        let aborted = if let Some(handle) = active_runs.write().await.remove(&target_run_id) {
3378→            handle.abort();
3379→            true
3380→        } else {
3381→            false
3382→        };
3383→
3384→        let mut by_session = active_runs_by_session.write().await;
3385→        if let Some(key) = session_key
3386→            && by_session.get(key).is_some_and(|id| id == &target_run_id)
3387→        {
3388→            by_session.remove(key);
3389→        }
3390→        by_session.retain(|_, id| id != &target_run_id);
3391→
3392→        (resolved_run_id, aborted)
3393→    }
