3433→    async fn persist_partial_assistant_on_abort(
3434→        &self,
3435→        session_key: &str,
3436→    ) -> Option<(Value, Option<u32>)> {
3437→        let partial = self
3438→            .active_partial_assistant
3439→            .write()
3440→            .await
3441→            .remove(session_key)?;
3442→        if !partial.has_visible_content() {
3443→            return None;
3444→        }
3445→
3446→        let partial_message = partial.to_persisted_message();
3447→        let partial_value = partial_message.to_value();
3448→        let mut message_index = None;
3449→
3450→        if let Err(e) = self.session_store.append(session_key, &partial_value).await {
3451→            warn!(session = %session_key, error = %e, "failed to persist aborted partial assistant message");
3452→            return Some((partial_value, None));
3453→        }
3454→
3455→        match self.session_store.count(session_key).await {
3456→            Ok(count) => {
3457→                self.session_metadata.touch(session_key, count).await;
3458→                message_index = Some(count.saturating_sub(1));
3459→            },
3460→            Err(e) => {
3461→                warn!(session = %session_key, error = %e, "failed to count session after persisting aborted partial assistant message");
3462→            },
3463→        }
3464→
3465→        Some((partial_value, message_index))
3466→    }
