1207→/// Bundle of callback + user_data that can cross the `tokio::spawn` boundary.
1208→///
1209→/// # Safety
1210→///
1211→/// The Swift side guarantees that `user_data` remains valid until a terminal
1212→/// event (done/error) is received, and the callback function pointer is
1213→/// stable for the lifetime of the stream. The callback dispatches to the
1214→/// main thread so there is no concurrent access.
1215→struct StreamCallbackCtx {
1216→    callback: StreamCallback,
1217→    user_data: *mut c_void,
1218→}
1219→
1220→// SAFETY: See struct doc — Swift retains `StreamContext` via
1221→// `Unmanaged.passRetained` and the callback itself is a plain function pointer.
1222→#[allow(unsafe_code)]
1223→unsafe impl Send for StreamCallbackCtx {}
1224→
1225→#[allow(unsafe_code)]
1226→impl StreamCallbackCtx {
1227→    fn send(&self, event: &BridgeStreamEvent) {
1228→        let json = encode_json(event);
1229→        if let Ok(c_str) = CString::new(json) {
1230→            // SAFETY: `c_str` is a valid NUL-terminated C string, `user_data`
1231→            // is retained by the Swift caller, and the callback copies the
1232→            // string contents before returning. We drop `c_str` afterwards.
1233→            unsafe {
1234→                (self.callback)(c_str.as_ptr(), self.user_data);
1235→            }
1236→        }
1237→    }
1238→}
1239→
1240→/// Start a streaming LLM chat. Events are delivered via `callback`. The
1241→/// function returns immediately; the stream runs on the bridge's tokio
1242→/// runtime. The caller must keep `user_data` alive until a terminal event
1243→/// (done or error) is delivered.
1244→///
1245→/// # Safety
1246→///
1247→/// * `request_json` must be a valid NUL-terminated C string.
1248→/// * `callback` must be a valid function pointer that remains valid for the
1249→///   lifetime of the stream.
1250→/// * `user_data` must remain valid until the callback receives a terminal
1251→///   event (done or error).
1252→#[allow(unsafe_code)]
1253→#[unsafe(no_mangle)]
1254→pub unsafe extern "C" fn moltis_chat_stream(
1255→    request_json: *const c_char,
1256→    callback: StreamCallback,
1257→    user_data: *mut c_void,
1258→) {
1259→    record_call("moltis_chat_stream");
1260→    trace_call("moltis_chat_stream");
1261→
1262→    // Helper to send an error event before `ctx` is constructed.
1263→    let send_error = |msg: String| {
1264→        let event = BridgeStreamEvent::Error { message: msg };
1265→        let json = encode_json(&event);
1266→        if let Ok(c_str) = CString::new(json) {
1267→            // SAFETY: caller guarantees valid callback + user_data.
1268→            unsafe {
1269→                callback(c_str.as_ptr(), user_data);
1270→            }
1271→        }
1272→    };
1273→
1274→    // Parse request synchronously on the calling thread so errors are
1275→    // reported immediately via callback (no need to spawn).
1276→    let raw = match read_c_string(request_json) {
1277→        Ok(value) => value,
1278→        Err(message) => {
1279→            record_error("moltis_chat_stream", "null_pointer_or_invalid_utf8");
1280→            send_error(message);
1281→            return;
1282→        },
1283→    };
1284→
1285→    let request = match serde_json::from_str::<ChatRequest>(&raw) {
1286→        Ok(request) => request,
1287→        Err(error) => {
1288→            record_error("moltis_chat_stream", "invalid_json");
1289→            send_error(error.to_string());
1290→            return;
1291→        },
1292→    };
1293→
1294→    let provider = match resolve_provider(&request) {
1295→        Some(p) => p,
1296→        None => {
1297→            send_error("No LLM provider configured".to_owned());
1298→            return;
1299→        },
1300→    };
1301→
1302→    let model_id = provider.id().to_string();
1303→    let provider_name = provider.name().to_string();
1304→    let messages = vec![AgentChatMessage::User {
1305→        content: UserContent::text(&request.message),
1306→    }];
1307→
1308→    let ctx = StreamCallbackCtx {
1309→        callback,
1310→        user_data,
1311→    };
1312→
1313→    emit_log(
1314→        "INFO",
1315→        "bridge.stream",
1316→        &format!("Starting stream: {}/{}", provider_name, model_id),
1317→    );
1318→
1319→    BRIDGE.runtime.spawn(async move {
1320→        let start = std::time::Instant::now();
1321→
1322→        let result = catch_unwind(AssertUnwindSafe(|| provider.stream(messages)));
1323→
1324→        let mut stream = match result {
1325→            Ok(s) => s,
1326→            Err(_) => {
1327→                emit_log("ERROR", "bridge.stream", "Panic during stream creation");
1328→                ctx.send(&BridgeStreamEvent::Error {
1329→                    message: "panic during stream creation".to_owned(),
1330→                });
1331→                return;
1332→            },
1333→        };
1334→
1335→        let mut usage = Usage::default();
1336→        let mut delta_count: u32 = 0;
1337→
1338→        while let Some(event) = stream.next().await {
1339→            match event {
1340→                StreamEvent::Delta(text) => {
1341→                    delta_count += 1;
1342→                    ctx.send(&BridgeStreamEvent::Delta { text });
1343→                },
1344→                StreamEvent::Done(u) => {
1345→                    usage = u;
1346→                    break;
1347→                },
1348→                StreamEvent::Error(message) => {
1349→                    emit_log(
1350→                        "ERROR",
1351→                        "bridge.stream",
1352→                        &format!("Stream error: {message}"),
1353→                    );
1354→                    ctx.send(&BridgeStreamEvent::Error { message });
1355→                    return;
1356→                },
1357→                // Ignore tool-call and reasoning events for chat UI.
1358→                _ => {},
1359→            }
1360→        }
1361→
1362→        let elapsed = start.elapsed().as_millis() as u64;
1363→        emit_log(
1364→            "INFO",
1365→            "bridge.stream",
1366→            &format!(
1367→                "Stream done: {}ms deltas={} in={} out={} provider={}",
1368→                elapsed, delta_count, usage.input_tokens, usage.output_tokens, provider_name
1369→            ),
1370→        );
1371→        ctx.send(&BridgeStreamEvent::Done {
1372→            input_tokens: usage.input_tokens,
1373→            output_tokens: usage.output_tokens,
1374→            duration_ms: elapsed,
1375→            model: Some(model_id),
1376→            provider: Some(provider_name),
1377→        });
1378→    });
1379→}
