1569→    /// Check if the raw (un-namespaced) model ID is registered under any provider.
1570→    fn has_model_any_provider(&self, model_id: &str) -> bool {
1571→        let raw = raw_model_id(model_id);
1572→        self.models.iter().any(|m| raw_model_id(&m.id) == raw)
1573→    }
