1575→    fn resolve_registry_model_id(
1576→        &self,
1577→        model_id: &str,
1578→        provider_hint: Option<&str>,
1579→    ) -> Option<String> {
1580→        if self.providers.contains_key(model_id) {
1581→            return Some(model_id.to_string());
1582→        }
1583→
1584→        let raw = raw_model_id(model_id);
1585→        self.models
1586→            .iter()
1587→            .enumerate()
1588→            .filter(|(_, m)| raw_model_id(&m.id) == raw)
1589→            .filter(|(_, m)| provider_hint.is_none_or(|hint| m.provider == hint))
1590→            .min_by_key(|(idx, m)| (subscription_preference_rank(&m.provider), *idx))
1591→            .map(|(_, m)| m.id.clone())
1592→    }
