1620→    fn register_dynamic_source_models(
1621→        &mut self,
1622→        source: &dyn DynamicModelDiscovery,
1623→        config: &ProvidersConfig,
1624→        catalog: Vec<DiscoveredModel>,
1625→    ) {
1626→        let Some(models) = Self::desired_models_for_dynamic_source(source, config, catalog) else {
1627→            return;
1628→        };
1629→
1630→        for model in models {
1631→            if self.has_provider_model(source.provider_name(), &model.id) {
1632→                continue;
1633→            }
1634→            let provider = source.build_provider(model.id.clone(), config);
1635→            self.register(
1636→                ModelInfo {
1637→                    id: model.id.clone(),
1638→                    provider: source.provider_name().to_string(),
1639→                    display_name: source.display_name(&model.id, &model.display_name),
1640→                    created_at: model.created_at,
1641→                    recommended: model.recommended,
1642→                    capabilities: model
1643→                        .capabilities
1644→                        .unwrap_or_else(|| ModelCapabilities::infer(&model.id)),
1645→                },
1646→                provider,
1647→            );
1648→        }
1649→    }
