1651→    #[cfg(any(feature = "provider-openai-codex", feature = "provider-github-copilot"))]
1652→    fn refresh_dynamic_source_models(
1653→        &mut self,
1654→        source: &dyn DynamicModelDiscovery,
1655→        config: &ProvidersConfig,
1656→    ) -> bool {
1657→        if !source.is_enabled_and_authenticated(config) {
1658→            return false;
1659→        }
1660→        if !source.should_fetch_models(config) {
1661→            return false;
1662→        }
1663→
1664→        let live_catalog = match source.live_models() {
1665→            Ok(models) => models,
1666→            Err(err) => {
1667→                tracing::warn!(
1668→                    provider = source.provider_name(),
1669→                    error = %err,
1670→                    "skipping dynamic model refresh because live fetch failed"
1671→                );
1672→                return false;
1673→            },
1674→        };
1675→
1676→        let Some(next_models) =
1677→            Self::desired_models_for_dynamic_source(source, config, live_catalog)
1678→        else {
1679→            return false;
1680→        };
1681→
1682→        let new_entries: Vec<(ModelInfo, Arc<dyn LlmProvider>)> = next_models
1683→            .into_iter()
1684→            .map(|model| {
1685→                let caps = model
1686→                    .capabilities
1687→                    .unwrap_or_else(|| ModelCapabilities::infer(&model.id));
1688→                (
1689→                    ModelInfo {
1690→                        id: model.id.clone(),
1691→                        provider: source.provider_name().to_string(),
1692→                        display_name: source.display_name(&model.id, &model.display_name),
1693→                        created_at: model.created_at,
1694→                        recommended: model.recommended,
1695→                        capabilities: caps,
1696→                    },
1697→                    source.build_provider(model.id, config),
1698→                )
1699→            })
1700→            .collect();
1701→
1702→        // Replace stale provider entries atomically only after successful fetch.
1703→        let stale_ids: Vec<String> = self
1704→            .models
1705→            .iter()
1706→            .filter(|m| m.provider == source.provider_name())
1707→            .map(|m| m.id.clone())
1708→            .collect();
1709→        for model_id in &stale_ids {
1710→            self.providers.remove(model_id);
1711→        }
1712→        self.models.retain(|m| m.provider != source.provider_name());
1713→        for (info, provider) in new_entries {
1714→            self.register(info, provider);
1715→        }
1716→
1717→        true
1718→    }
