1798→                let caps = model
1799→                    .capabilities
1800→                    .unwrap_or_else(|| ModelCapabilities::infer(&model.id));
1801→                let provider = Arc::new(
1802→                    anthropic::AnthropicProvider::with_alias(
1803→                        key.clone(),
1804→                        model.id.clone(),
1805→                        base_url.to_string(),
1806→                        alias.clone(),
1807→                    )
1808→                    .with_cache_retention(cache_retention),
1809→                );
1810→                (
1811→                    ModelInfo {
1812→                        id: model.id,
1813→                        provider: provider_label.to_string(),
1814→                        display_name: model.display_name,
1815→                        created_at: model.created_at,
1816→                        recommended: model.recommended,
1817→                        capabilities: caps,
1818→                    },
1819→                    provider as Arc<dyn LlmProvider>,
1820→                )
1821→            })
1822→            .collect();
1823→
1824→        let previous_ids: HashSet<String> = self
1825→            .models
1826→            .iter()
1827→            .filter(|m| m.provider == provider_label)
1828→            .map(|m| m.id.clone())
1829→            .collect();
1830→
1831→        self.models.retain(|m| m.provider != provider_label);
1832→        self.providers.retain(|id, _| !previous_ids.contains(id));
1833→
1834→        let next_ids: HashSet<String> = new_entries
1835→            .iter()
1836→            .map(|(info, _)| namespaced_model_id(provider_label, raw_model_id(&info.id)))
1837→            .collect();
1838→
1839→        for (info, provider) in new_entries {
1840→            self.register(info, provider);
1841→        }
1842→
1843→        next_ids.difference(&previous_ids).count()
1844→    }
