1846→    /// Register a provider manually.
1847→    pub fn register(&mut self, mut info: ModelInfo, provider: Arc<dyn LlmProvider>) {
1848→        let model_id = raw_model_id(&info.id).to_string();
1849→        let registry_model_id = namespaced_model_id(&info.provider, &model_id);
1850→        info.id = registry_model_id.clone();
1851→        let wrapped: Arc<dyn LlmProvider> = Arc::new(RegistryModelProvider {
1852→            model_id: registry_model_id.clone(),
1853→            inner: provider,
1854→        });
1855→        self.providers.insert(registry_model_id, wrapped);
1856→        self.models.push(info);
1857→    }
