1859→    /// Unregister a provider by model ID. Returns true if it was removed.
1860→    pub fn unregister(&mut self, model_id: &str) -> bool {
1861→        let resolved_id = self.resolve_registry_model_id(model_id, None);
1862→        let removed = resolved_id
1863→            .as_deref()
1864→            .and_then(|id| self.providers.remove(id))
1865→            .is_some();
1866→        if removed && let Some(id) = resolved_id {
1867→            self.models.retain(|m| m.id != id);
1868→        }
1869→        removed
1870→    }
