1134→fn ui_offered_provider_order(config: &ProvidersConfig) -> Vec<String> {
1135→    let mut ordered = Vec::new();
1136→    for name in &config.offered {
1137→        let normalized = normalize_provider_name(name);
1138→        if normalized.is_empty() || ordered.iter().any(|existing| existing == &normalized) {
1139→            continue;
1140→        }
1141→        ordered.push(normalized);
1142→    }
1143→    ordered
1144→}
