1232→        }
1233→        if home_key_store
1234→            .as_ref()
1235→            .is_some_and(|(store, _)| store.load(provider.name).is_some())
1236→            && let Some((_, path)) = home_key_store.as_ref()
1237→        {
1238→            sources.push(format!("file:{}", path.display()));
1239→        }
1240→
1241→        if (provider.auth_type == AuthType::Oauth || provider.name == "kimi-code")
