1668→                        );
1669→                    },
1670→                    Err(tokio::sync::broadcast::error::RecvError::Closed) => break,
1671→                }
1672→            }
1673→        });
1674→        emit_log("INFO", "bridge", "Session event callback registered");
1675→    }
