1695→/// Starts the embedded HTTP server with the full Moltis gateway.
1696→/// Returns JSON with `{"running": true, "addr": "..."}`.
1697→/// If already running, returns the current status without restarting.
1698→#[allow(unsafe_code)]
1699→#[unsafe(no_mangle)]
1700→pub extern "C" fn moltis_start_httpd(request_json: *const c_char) -> *mut c_char {
1701→    record_call("moltis_start_httpd");
1702→    trace_call("moltis_start_httpd");
1703→
1704→    with_ffi_boundary(|| {
1705→        let request: StartHttpdRequest = if request_json.is_null() {
1706→            StartHttpdRequest {
1707→                host: default_httpd_host(),
1708→                port: default_httpd_port(),
1709→                config_dir: None,
1710→                data_dir: None,
1711→            }
1712→        } else {
1713→            match read_c_string(request_json) {
1714→                Ok(raw) => match serde_json::from_str(&raw) {
1715→                    Ok(r) => r,
1716→                    Err(e) => return encode_error("invalid_json", &e.to_string()),
1717→                },
1718→                Err(msg) => return encode_error("null_pointer_or_invalid_utf8", &msg),
1719→            }
1720→        };
1721→
1722→        let mut guard = HTTPD.lock().unwrap_or_else(|e| e.into_inner());
1723→
1724→        // Already running — return current status.
1725→        if let Some(handle) = guard.as_ref() {
1726→            emit_log(
1727→                "INFO",
1728→                "bridge.httpd",
1729→                &format!("Server already running on {}", handle.addr),
1730→            );
1731→            return encode_json(&HttpdStatusResponse {
1732→                running: true,
1733→                addr: Some(handle.addr.to_string()),
1734→            });
1735→        }
1736→
1737→        let bind_addr = format!("{}:{}", request.host, request.port);
1738→        emit_log(
1739→            "INFO",
1740→            "bridge.httpd",
1741→            &format!("Starting full gateway on {bind_addr}"),
1742→        );
1743→
1744→        // Prepare the full gateway (config, DB migrations, service wiring,
1745→        // background tasks). This runs on the bridge runtime via block_on —
1746→        // valid because this is an extern "C" fn, not async.
1747→        let prepared = match BRIDGE
1748→            .runtime
1749→            .block_on(moltis_httpd::prepare_httpd_embedded(
1750→                &request.host,
1751→                request.port,
1752→                true, // no_tls — the macOS app manages its own TLS if needed
1753→                None, // log_buffer
1754→                request.config_dir.map(std::path::PathBuf::from),
1755→                request.data_dir.map(std::path::PathBuf::from),
1756→                Some(moltis_web::web_routes), // full web UI
1757→                BRIDGE.session_metadata.event_bus().cloned(), // share bus with gateway
1758→            )) {
1759→            Ok(p) => p,
1760→            Err(e) => {
1761→                emit_log(
1762→                    "ERROR",
1763→                    "bridge.httpd",
1764→                    &format!("Gateway init failed: {e}"),
1765→                );
1766→                return encode_error("gateway_init_failed", &e.to_string());
1767→            },
1768→        };
1769→
1770→        let gateway_state = prepared.state;
1771→
1772→        // Bind the TCP listener synchronously so we can report errors immediately.
1773→        let listener = match BRIDGE
1774→            .runtime
1775→            .block_on(tokio::net::TcpListener::bind(&bind_addr))
1776→        {
1777→            Ok(l) => l,
1778→            Err(e) => {
1779→                emit_log("ERROR", "bridge.httpd", &format!("Bind failed: {e}"));
1780→                return encode_error("bind_failed", &e.to_string());
1781→            },
1782→        };
1783→
1784→        let addr = match listener.local_addr() {
1785→            Ok(a) => a,
1786→            Err(e) => return encode_error("addr_error", &e.to_string()),
1787→        };
1788→
1789→        // Subscribe to the network audit broadcast (if the proxy is active)
1790→        // and forward entries to Swift via the registered callback.
1791→        #[cfg(feature = "trusted-network")]
1792→        if let Some(ref audit_buf) = prepared.audit_buffer {
1793→            let mut audit_rx = audit_buf.subscribe();
1794→            BRIDGE.runtime.spawn(async move {
1795→                loop {
1796→                    match audit_rx.recv().await {
1797→                        Ok(entry) => emit_network_audit(&entry),
1798→                        Err(tokio::sync::broadcast::error::RecvError::Lagged(_)) => continue,
1799→                        Err(_) => break,
1800→                    }
1801→                }
1802→            });
1803→            emit_log("INFO", "bridge.httpd", "Network audit bridge subscribed");
1804→        }
1805→
1806→        let (shutdown_tx, shutdown_rx) = tokio::sync::oneshot::channel::<()>();
1807→        let app = prepared.app;
1808→        // Keep the proxy shutdown sender alive for the server's full lifetime;
1809→        // dropping it closes the watch channel and terminates the proxy.
1810→        #[cfg(feature = "trusted-network")]
1811→        let _proxy_shutdown_tx = prepared._proxy_shutdown_tx;
1812→
1813→        let server_task = BRIDGE.runtime.spawn(async move {
1814→            // Hold the proxy sender inside the spawn so it lives as long as the server.
1815→            #[cfg(feature = "trusted-network")]
1816→            let _keep_proxy = _proxy_shutdown_tx;
1817→            let server = axum::serve(
1818→                listener,
1819→                app.into_make_service_with_connect_info::<std::net::SocketAddr>(),
1820→            )
1821→            .with_graceful_shutdown(async {
1822→                let _ = shutdown_rx.await;
1823→            });
1824→            if let Err(e) = server.await {
1825→                emit_log("ERROR", "bridge.httpd", &format!("Server error: {e}"));
1826→            }
1827→            emit_log("INFO", "bridge.httpd", "Server stopped");
1828→        });
1829→
1830→        emit_log(
1831→            "INFO",
1832→            "bridge.httpd",
1833→            &format!("Gateway listening on {addr}"),
1834→        );
1835→        *guard = Some(HttpdHandle {
1836→            shutdown_tx,
1837→            server_task,
1838→            addr,
1839→            state: gateway_state,
1840→        });
1841→
1842→        encode_json(&HttpdStatusResponse {
1843→            running: true,
1844→            addr: Some(addr.to_string()),
1845→        })
1846→    })
1847→}
