1922→        match BRIDGE
1923→            .runtime
1924→            .block_on(async { state.chat().await.abort(params).await })
1925→        {
1926→            Ok(res) => encode_json(&res),
1927→            Err(e) => encode_error("abort_failed", &e.to_string()),
1928→        }
1929→    })
