2129→    /// Drain all pending discovery receivers (blocking on each `recv()`).
2130→    ///
2131→    /// Returns a map from provider name to discovered models.
2132→    pub fn collect_discoveries(
2133→        pending: PendingDiscoveries,
2134→    ) -> HashMap<String, Vec<DiscoveredModel>> {
2135→        let mut results: HashMap<String, Vec<DiscoveredModel>> = HashMap::new();
2136→        for (key, rx) in pending {
2137→            match rx.recv() {
2138→                Ok(Ok(models)) => {
2139→                    tracing::debug!(
2140→                        provider = %key,
2141→                        model_count = models.len(),
2142→                        "parallel model discovery succeeded"
2143→                    );
2144→                    results.insert(key, models);
2145→                },
2146→                Ok(Err(err)) => {
2147→                    let msg = err.to_string();
2148→                    if msg.contains("not logged in")
2149→                        || msg.contains("tokens not found")
2150→                        || msg.contains("not configured")
2151→                    {
2152→                        tracing::debug!(
2153→                            provider = %key,
2154→                            error = %err,
2155→                            "provider not configured, skipping model discovery"
2156→                        );
2157→                    } else {
2158→                        tracing::warn!(
2159→                            provider = %key,
2160→                            error = %err,
2161→                            "parallel model discovery failed"
2162→                        );
2163→                    }
2164→                },
2165→                Err(err) => {
2166→                    tracing::warn!(
2167→                        provider = %key,
2168→                        error = %err,
2169→                        "parallel model discovery worker crashed"
2170→                    );
2171→                },
2172→            }
2173→        }
2174→        results
2175→    }
