1402→    fn queue_registry_rebuild(&self, provider_name: &str, reason: &'static str) {
1403→        let rebuild_seq = self.registry_rebuild_seq.fetch_add(1, Ordering::SeqCst) + 1;
1404→        let latest_seq = Arc::clone(&self.registry_rebuild_seq);
1405→        let registry = Arc::clone(&self.registry);
1406→        let config = Arc::clone(&self.config);
1407→        let key_store = self.key_store.clone();
1408→        let env_overrides = self.env_overrides.clone();
1409→        let provider_name = provider_name.to_string();
1410→
1411→        tokio::spawn(async move {
1412→            let started = std::time::Instant::now();
1413→            info!(
1414→                provider = %provider_name,
1415→                reason,
1416→                rebuild_seq,
1417→                "provider registry async rebuild started"
1418→            );
1419→
1420→            let effective = {
1421→                let base = config.lock().unwrap_or_else(|e| e.into_inner()).clone();
1422→                config_with_saved_keys(&base, &key_store, &[])
1423→            };
1424→
1425→            let new_registry = match tokio::task::spawn_blocking(move || {
1426→                ProviderRegistry::from_env_with_config_and_overrides(&effective, &env_overrides)
1427→            })
1428→            .await
1429→            {
1430→                Ok(registry) => registry,
1431→                Err(error) => {
1432→                    warn!(
1433→                        provider = %provider_name,
1434→                        reason,
1435→                        rebuild_seq,
1436→                        error = %error,
1437→                        "provider registry async rebuild worker failed"
1438→                    );
1439→                    return;
1440→                },
1441→            };
1442→
1443→            let current_seq = latest_seq.load(Ordering::Acquire);
1444→            if rebuild_seq != current_seq {
1445→                info!(
1446→                    provider = %provider_name,
1447→                    reason,
1448→                    rebuild_seq,
1449→                    latest_seq = current_seq,
1450→                    elapsed_ms = started.elapsed().as_millis(),
1451→                    "provider registry async rebuild skipped as stale"
1452→                );
1453→                return;
1454→            }
1455→
1456→            let provider_summary = new_registry.provider_summary();
1457→            let model_count = new_registry.list_models().len();
1458→            let mut reg = registry.write().await;
1459→            *reg = new_registry;
1460→            info!(
1461→                provider = %provider_name,
1462→                reason,
1463→                rebuild_seq,
1464→                provider_summary = %provider_summary,
1465→                models = model_count,
1466→                elapsed_ms = started.elapsed().as_millis(),
1467→                "provider registry async rebuild finished"
1468→            );
1469→        });
1470→    }
