1487→    fn is_provider_configured(
1488→        &self,
1489→        provider: &KnownProvider,
1490→        active_config: &ProvidersConfig,
1491→    ) -> bool {
1492→        // Disabled providers (by offered allowlist or explicit enabled=false)
1493→        // should not show as configured, except subscription-backed OAuth
1494→        // providers with valid local tokens.
1495→        if !active_config.is_enabled(provider.name) {
1496→            let subscription_with_tokens =
1497→                matches!(provider.name, "openai-codex" | "github-copilot")
1498→                    && active_config
1499→                        .get(provider.name)
1500→                        .is_none_or(|entry| entry.enabled)
1501→                    && self.has_oauth_tokens(provider.name);
1502→            if !subscription_with_tokens {
1503→                return false;
1504→            }
1505→        }
1506→
1507→        // Check if the provider has an API key set via env
1508→        if let Some(env_key) = provider.env_key
1509→            && env_value_with_overrides(&self.env_overrides, env_key).is_some()
1510→        {
1511→            return true;
1512→        }
1513→        if provider.auth_type == AuthType::ApiKey
1514→            && moltis_config::generic_provider_api_key_from_env(provider.name, &self.env_overrides)
1515→                .is_some()
1516→        {
1517→            return true;
1518→        }
1519→        // Check config file
1520→        if let Some(entry) = active_config.get(provider.name)
1521→            && entry
1522→                .api_key
1523→                .as_ref()
1524→                .is_some_and(|k| !k.expose_secret().is_empty())
1525→        {
1526→            return true;
1527→        }
1528→        // Check home/global config file as fallback when using custom config dir.
1529→        if home_provider_config()
1530→            .as_ref()
1531→            .and_then(|(cfg, _)| cfg.get(provider.name))
1532→            .and_then(|entry| entry.api_key.as_ref())
1533→            .is_some_and(|k| !k.expose_secret().is_empty())
1534→        {
1535→            return true;
1536→        }
1537→        // Check persisted key store
1538→        if self.key_store.load(provider.name).is_some() {
1539→            return true;
1540→        }
1541→        // Check persisted key store in user-global config dir.
1542→        if home_key_store()
1543→            .as_ref()
1544→            .is_some_and(|(store, _)| store.load(provider.name).is_some())
1545→        {
1546→            return true;
1547→        }
1548→        // For OAuth providers, check token store
1549→        if provider.auth_type == AuthType::Oauth || provider.name == "kimi-code" {
1550→            if self.token_store.load(provider.name).is_some() {
1551→                return true;
1552→            }
1553→            if home_token_store()
1554→                .as_ref()
1555→                .is_some_and(|(store, _)| store.load(provider.name).is_some())
1556→            {
1557→                return true;
1558→            }
1559→            // Match provider-registry behavior: openai-codex may be inferred from
1560→            // Codex CLI auth at ~/.codex/auth.json.
1561→            if provider.name == "openai-codex"
1562→                && codex_cli_auth_path()
1563→                    .as_deref()
1564→                    .is_some_and(codex_cli_auth_has_access_token)
1565→            {
1566→                return true;
1567→            }
1568→            return false;
1569→        }
1570→        // For local providers, check if model is configured in local_llm config
1571→        #[cfg(feature = "local-llm")]
1572→        if provider.auth_type == AuthType::Local && provider.name == "local-llm" {
1573→            // Check if local-llm model config file exists
1574→            if let Some(config_dir) = moltis_config::config_dir() {
1575→                let config_path = config_dir.join("local-llm.json");
1576→                return config_path.exists();
1577→            }
1578→        }
1579→        false
1580→    }
