4420→
4421→/// Marker string that must be present in an up-to-date seeded `handler.sh`.
4422→///
4423→/// If the on-disk handler is missing this marker it predates the PATH-fix
4424→/// in #626 and must be rewritten — otherwise existing installs silently
4425→/// keep the broken handler while the startup log reports the guard as
4426→/// active. Matching on `export PATH=` is enough because the stale handler
4427→/// never contained any `export` statement.
4428→const DCG_GUARD_HANDLER_FINGERPRINT: &str = "export PATH=";
4429→
4430→/// Marker string that must be present in an up-to-date seeded `HOOK.md`.
4431→///
4432→/// Older installs shipped `cargo install dcg`, which never worked. We
4433→/// refresh `HOOK.md` in place whenever the new upstream install command
4434→/// is missing, so users reading the seeded docs don't get stale advice.
4435→const DCG_GUARD_HOOK_MD_FINGERPRINT: &str = "uv tool install destructive-command-guard";
4436→
4437→/// Seed the `dcg-guard` hook into `~/.moltis/hooks/dcg-guard/` on first run,
4438→/// and refresh on-disk files that predate the PATH-fix in #626.
4439→///
4440→/// Writes both `HOOK.md` and `handler.sh`. The handler gracefully no-ops
4441→/// (fail-open) when `dcg` is not installed, so the hook is always eligible.
4442→///
4443→/// Existing installs affected by the original bug already have `HOOK.md`
4444→/// on disk, so a naive `if !hook_md.exists()` guard would leave the stale
4445→/// handler in place and the startup log would lie about the guard being
4446→/// active. We instead fingerprint both files and rewrite them in place
4447→/// when the marker is missing.
4448→///
4449→/// After (re)seeding, probes for `dcg` on the same augmented `PATH` the
4450→/// handler will use and emits exactly one log line so operators can tell
4451→/// at boot whether the guard is active or inert.
4452→async fn seed_dcg_guard_hook() {
4453→    let hook_dir = moltis_config::data_dir().join("hooks/dcg-guard");
4454→    let hook_md = hook_dir.join("HOOK.md");
4455→    let handler = hook_dir.join("handler.sh");
4456→
4457→    // We always want the startup status log to fire, even if the hook dir
4458→    // could not be created — operators need to know the guard state on
4459→    // every boot. So treat directory creation failure as "skip the file
4460→    // writes but still log the status" rather than an early return.
4461→    let dir_ok = match std::fs::create_dir_all(&hook_dir) {
4462→        Ok(()) => true,
4463→        Err(e) => {
4464→            tracing::debug!("could not create dcg-guard hook dir: {e}");
4465→            false
4466→        },
4467→    };
4468→
4469→    if dir_ok {
4470→        // Refresh HOOK.md if missing or fingerprint missing (stale install).
4471→        let hook_md_needs_write = match std::fs::read_to_string(&hook_md) {
4472→            Ok(existing) => !existing.contains(DCG_GUARD_HOOK_MD_FINGERPRINT),
4473→            Err(_) => true,
4474→        };
4475→        if hook_md_needs_write && let Err(e) = std::fs::write(&hook_md, DCG_GUARD_HOOK_MD) {
4476→            tracing::debug!("could not write dcg-guard HOOK.md: {e}");
4477→        }
4478→
4479→        // Refresh handler.sh if missing or fingerprint missing (stale install).
4480→        let handler_needs_write = match std::fs::read_to_string(&handler) {
4481→            Ok(existing) => !existing.contains(DCG_GUARD_HANDLER_FINGERPRINT),
4482→            Err(_) => true,
4483→        };
4484→        if handler_needs_write {
4485→            if let Err(e) = std::fs::write(&handler, DCG_GUARD_HANDLER_SH) {
4486→                tracing::debug!("could not write dcg-guard handler.sh: {e}");
4487→            }
4488→            #[cfg(unix)]
4489→            {
4490→                use std::os::unix::fs::PermissionsExt;
4491→                let _ = std::fs::set_permissions(&handler, std::fs::Permissions::from_mode(0o755));
4492→            }
4493→            if !hook_md_needs_write {
4494→                // Handler was stale but HOOK.md was already current — this
4495→                // is exactly the #626 repro. Make it visible in the log.
4496→                tracing::info!(
4497→                    "dcg-guard: refreshed stale handler.sh to apply PATH augmentation fix"
4498→                );
4499→            }
4500→        }
4501→    }
4502→
4503→    log_dcg_guard_status().await;
4504→}
4505→
4506→/// PATH augmentation prepended by the dcg-guard handler script. Kept in sync
4507→/// with `DCG_GUARD_HANDLER_SH` so the startup check resolves `dcg` the same
4508→/// way the handler will at invocation time.
4509→const DCG_GUARD_EXTRA_PATH_DIRS: &[&str] = &[".local/bin", "/usr/local/bin", "/opt/homebrew/bin"];
4510→
4511→/// Fallback `$HOME` used by `resolve_dcg_binary` when the environment has
4512→/// no `HOME` set. Must match the `${HOME:-/root}` fallback in
4513→/// `DCG_GUARD_HANDLER_SH` so the Rust startup probe and the shell handler
4514→/// agree on which paths are searched.
4515→const DCG_GUARD_HOME_FALLBACK: &str = "/root";
4516→
4517→/// Resolve `dcg` using the same augmented `PATH` as the handler script.
4518→/// Returns the absolute path to the binary if found.
4519→fn resolve_dcg_binary() -> Option<PathBuf> {
4520→    let mut dirs: Vec<PathBuf> = Vec::new();
4521→
4522→    // Mirror the shell handler's `${HOME:-/root}` behaviour so the Rust
4523→    // startup probe and the handler agree on which paths are searched.
4524→    // If `HOME` is unset we must still try `$FALLBACK/.local/bin` — skipping
4525→    // HOME-relative entries outright was inconsistent with the handler.
4526→    let home_path = std::env::var("HOME")
4527→        .map(PathBuf::from)
4528→        .unwrap_or_else(|_| PathBuf::from(DCG_GUARD_HOME_FALLBACK));
4529→    for rel in DCG_GUARD_EXTRA_PATH_DIRS {
4530→        if rel.starts_with('/') {
4531→            dirs.push(PathBuf::from(rel));
4532→        } else {
4533→            dirs.push(home_path.join(rel));
4534→        }
4535→    }
4536→
4537→    // Existing `$PATH`, falling back to a sane default matching the handler.
4538→    let existing = std::env::var("PATH").unwrap_or_else(|_| "/usr/bin:/bin".to_string());
4539→    for entry in existing.split(':').filter(|s| !s.is_empty()) {
4540→        dirs.push(PathBuf::from(entry));
4541→    }
4542→
4543→    for dir in dirs {
4544→        let candidate = dir.join("dcg");
4545→        if candidate.is_file() {
4546→            #[cfg(unix)]
4547→            {
4548→                use std::os::unix::fs::PermissionsExt;
4549→                if let Ok(meta) = std::fs::metadata(&candidate)
4550→                    && meta.permissions().mode() & 0o111 != 0
4551→                {
4552→                    return Some(candidate);
4553→                }
4554→                continue;
4555→            }
4556→            #[cfg(not(unix))]
4557→            {
4558→                return Some(candidate);
4559→            }
4560→        }
4561→    }
4562→
4563→    None
4564→}
