4566→/// Emit a single startup log line describing whether the dcg-guard is
4567→/// active. Uses `tokio::process::Command` for the `--version` probe so we
4568→/// do not stall the async executor at startup.
4569→async fn log_dcg_guard_status() {
4570→    let Some(path) = resolve_dcg_binary() else {
4571→        tracing::warn!(
4572→            "dcg-guard: 'dcg' not found on PATH; destructive command guard is INACTIVE. \
4573→             Install dcg from https://github.com/Dicklesworthstone/destructive_command_guard"
4574→        );
4575→        return;
4576→    };
4577→
4578→    let version = tokio::process::Command::new(&path)
4579→        .arg("--version")
4580→        .output()
4581→        .await
4582→        .ok()
4583→        .and_then(|out| {
4584→            if out.status.success() {
4585→                Some(String::from_utf8_lossy(&out.stdout).trim().to_string())
4586→            } else {
4587→                None
4588→            }
4589→        })
4590→        .filter(|s| !s.is_empty())
4591→        .unwrap_or_else(|| "unknown version".to_string());
4592→
4593→    tracing::info!(
4594→        dcg_path = %path.display(),
4595→        "dcg-guard: dcg {version} detected, guard active"
4596→    );
4597→}
