4660→fn warn_on_workspace_prompt_file_truncation() {
4661→    let limit_chars = moltis_config::discover_and_load()
4662→        .chat
4663→        .workspace_file_max_chars;
4664→    let data_dir = moltis_config::data_dir();
4665→    let mut paths = vec![data_dir.join("AGENTS.md"), data_dir.join("TOOLS.md")];
4666→    let agents_dir = data_dir.join("agents");
4667→    if let Ok(entries) = std::fs::read_dir(&agents_dir) {
4668→        for entry in entries.flatten() {
4669→            let path = entry.path();
4670→            if !path.is_dir() {
4671→                continue;
4672→            }
4673→            paths.push(path.join("AGENTS.md"));
4674→            paths.push(path.join("TOOLS.md"));
4675→        }
4676→    }
4677→
4678→    for path in paths {
4679→        let Ok(content) = std::fs::read_to_string(&path) else {
4680→            continue;
4681→        };
4682→        let Some(normalized) = moltis_config::normalize_workspace_markdown_content(&content) else {
4683→            continue;
4684→        };
4685→        let char_count = normalized.chars().count();
4686→        if char_count <= limit_chars {
4687→            continue;
4688→        }
4689→        tracing::warn!(
4690→            path = %path.display(),
4691→            char_count,
4692→            limit_chars,
4693→            truncated_chars = char_count.saturating_sub(limit_chars),
4694→            "workspace prompt file exceeds configured prompt cap and will be truncated"
4695→        );
4696→    }
4697→}
