2095→/// Streaming chat within a session. Persists user message before streaming,
2096→/// persists assistant message when done. Events delivered via callback.
2097→///
2098→/// # Safety
2099→///
2100→/// Same requirements as `moltis_chat_stream`.
2101→#[allow(unsafe_code)]
2102→#[unsafe(no_mangle)]
2103→pub unsafe extern "C" fn moltis_session_chat_stream(
2104→    request_json: *const c_char,
2105→    callback: StreamCallback,
2106→    user_data: *mut c_void,
2107→) {
2108→    record_call("moltis_session_chat_stream");
2109→    trace_call("moltis_session_chat_stream");
2110→
2111→    let send_error = |msg: String| {
2112→        let event = BridgeStreamEvent::Error { message: msg };
2113→        let json = encode_json(&event);
2114→        if let Ok(c_str) = CString::new(json) {
2115→            unsafe {
2116→                callback(c_str.as_ptr(), user_data);
2117→            }
2118→        }
2119→    };
2120→
2121→    let raw = match read_c_string(request_json) {
2122→        Ok(value) => value,
2123→        Err(message) => {
2124→            send_error(message);
2125→            return;
2126→        },
2127→    };
2128→
2129→    let request = match serde_json::from_str::<SessionChatRequest>(&raw) {
2130→        Ok(r) => r,
2131→        Err(e) => {
2132→            send_error(e.to_string());
2133→            return;
2134→        },
2135→    };
2136→
2137→    let provider = match resolve_provider_for_model(request.model.as_deref()) {
2138→        Some(p) => p,
2139→        None => {
2140→            send_error("No LLM provider configured".to_owned());
2141→            return;
2142→        },
2143→    };
2144→
2145→    let session_key = request.session_key.clone();
2146→
2147→    // Persist user message.
2148→    let user_msg = PersistedMessage::user(&request.message);
2149→    let user_value = user_msg.to_value();
2150→    if let Err(e) = BRIDGE
2151→        .runtime
2152→        .block_on(BRIDGE.session_store.append(&session_key, &user_value))
2153→    {
2154→        emit_log(
2155→            "WARN",
2156→            "bridge.session_chat",
2157→            &format!("Failed to persist user message: {e}"),
2158→        );
2159→    }
2160→
2161→    // Update metadata.
2162→    BRIDGE.runtime.block_on(async {
2163→        let _ = BRIDGE.session_metadata.upsert(&session_key, None).await;
2164→        let msg_count = BRIDGE
2165→            .session_store
2166→            .read(&session_key)
2167→            .await
2168→            .map(|m| m.len() as u32)
2169→            .unwrap_or(0);
2170→        BRIDGE.session_metadata.touch(&session_key, msg_count).await;
2171→    });
2172→
2173→    let model_id = provider.id().to_string();
2174→    let provider_name = provider.name().to_string();
2175→    let messages = vec![AgentChatMessage::User {
2176→        content: UserContent::text(&request.message),
2177→    }];
2178→
2179→    let ctx = StreamCallbackCtx {
2180→        callback,
2181→        user_data,
2182→    };
2183→
2184→    emit_log(
2185→        "INFO",
2186→        "bridge.session_chat",
2187→        &format!(
2188→            "Starting session stream: session={} provider={}/{}",
2189→            session_key, provider_name, model_id
2190→        ),
2191→    );
2192→
2193→    BRIDGE.runtime.spawn(async move {
2194→        let start = std::time::Instant::now();
2195→        let result = catch_unwind(AssertUnwindSafe(|| provider.stream(messages)));
2196→
2197→        let mut stream = match result {
2198→            Ok(s) => s,
2199→            Err(_) => {
2200→                ctx.send(&BridgeStreamEvent::Error {
2201→                    message: "panic during stream creation".to_owned(),
2202→                });
2203→                return;
2204→            },
2205→        };
2206→
2207→        let mut usage = Usage::default();
2208→        let mut full_text = String::new();
2209→
2210→        while let Some(event) = stream.next().await {
2211→            match event {
2212→                StreamEvent::Delta(text) => {
2213→                    full_text.push_str(&text);
2214→                    ctx.send(&BridgeStreamEvent::Delta { text });
2215→                },
2216→                StreamEvent::Done(u) => {
2217→                    usage = u;
2218→                    break;
2219→                },
2220→                StreamEvent::Error(message) => {
2221→                    ctx.send(&BridgeStreamEvent::Error { message });
2222→                    return;
2223→                },
2224→                _ => {},
2225→            }
2226→        }
2227→
2228→        let elapsed = start.elapsed().as_millis() as u64;
2229→
2230→        // Persist assistant message.
2231→        let assistant_msg = PersistedMessage::assistant(
2232→            &full_text,
2233→            &model_id,
2234→            &provider_name,
2235→            usage.input_tokens,
2236→            usage.output_tokens,
2237→            None, // audio
2238→        );
2239→        let assistant_value = assistant_msg.to_value();
2240→        if let Err(e) = BRIDGE
2241→            .session_store
2242→            .append(&session_key, &assistant_value)
2243→            .await
2244→        {
2245→            emit_log(
2246→                "WARN",
2247→                "bridge.session_chat",
2248→                &format!("Failed to persist assistant message: {e}"),
2249→            );
2250→        }
2251→
2252→        // Update metadata in SQLite.
2253→        let msg_count = BRIDGE
2254→            .session_store
2255→            .read(&session_key)
2256→            .await
2257→            .map(|m| m.len() as u32)
2258→            .unwrap_or(0);
2259→        BRIDGE.session_metadata.touch(&session_key, msg_count).await;
2260→        BRIDGE
2261→            .session_metadata
2262→            .set_model(&session_key, Some(model_id.clone()))
2263→            .await;
2264→
2265→        ctx.send(&BridgeStreamEvent::Done {
2266→            input_tokens: usage.input_tokens,
2267→            output_tokens: usage.output_tokens,
2268→            duration_ms: elapsed,
2269→            model: Some(model_id),
2270→            provider: Some(provider_name),
2271→        });
2272→    });
2273→}
