2343→
2344→        let config = moltis_config::discover_and_load();
2345→        let embedding_model = config
2346→            .memory
2347→            .model
2348→            .clone()
2349→            .unwrap_or_else(|| "none".to_owned());
2350→        let has_embeddings = !config.memory.disable_rag;
2351→
2352→        let db_path = moltis_config::data_dir().join("memory.db");
2353→        let db_size = std::fs::metadata(&db_path).map(|m| m.len()).unwrap_or(0);
2354→
2355→        if !db_path.exists() {
2356→            let response = MemoryStatusResponse {
2357→                available: false,
2358→                total_files: 0,
2359→                total_chunks: 0,
2360→                db_size,
2361→                db_size_display: format_bytes(db_size),
2362→                embedding_model,
2363→                has_embeddings,
2364→                error: Some("memory.db not found".to_owned()),
2365→            };
2366→            return encode_json(&response);
2367→        }
2368→
2369→        let options = match SqliteConnectOptions::from_str(&format!("sqlite:{}", db_path.display()))
2370→        {
2371→            Ok(opts) => opts.create_if_missing(false).read_only(true),
2372→            Err(error) => {
2373→                let response = MemoryStatusResponse {
2374→                    available: false,
2375→                    total_files: 0,
2376→                    total_chunks: 0,
2377→                    db_size,
2378→                    db_size_display: format_bytes(db_size),
2379→                    embedding_model,
2380→                    has_embeddings,
2381→                    error: Some(format!("invalid sqlite path: {error}")),
2382→                };
2383→                return encode_json(&response);
2384→            },
2385→        };
2386→
2387→        let pool = match BRIDGE
2388→            .runtime
2389→            .block_on(sqlx::SqlitePool::connect_with(options))
2390→        {
2391→            Ok(pool) => pool,
2392→            Err(error) => {
2393→                let response = MemoryStatusResponse {
2394→                    available: false,
2395→                    total_files: 0,
2396→                    total_chunks: 0,
2397→                    db_size,
2398→                    db_size_display: format_bytes(db_size),
2399→                    embedding_model,
2400→                    has_embeddings,
2401→                    error: Some(format!("failed to open memory.db: {error}")),
2402→                };
2403→                return encode_json(&response);
2404→            },
2405→        };
2406→
2407→        let (total_files, total_chunks) = BRIDGE.runtime.block_on(async {
2408→            let has_files_table: i64 = sqlx::query_scalar(
2409→                "SELECT COUNT(*) FROM sqlite_master WHERE type = 'table' AND name = 'files'",
2410→            )
2411→            .fetch_one(&pool)
2412→            .await
2413→            .unwrap_or(0);
2414→            let has_chunks_table: i64 = sqlx::query_scalar(
2415→                "SELECT COUNT(*) FROM sqlite_master WHERE type = 'table' AND name = 'chunks'",
2416→            )
2417→            .fetch_one(&pool)
2418→            .await
2419→            .unwrap_or(0);
2420→
2421→            let files: i64 = if has_files_table > 0 {
2422→                sqlx::query_scalar("SELECT COUNT(*) FROM files")
2423→                    .fetch_one(&pool)
2424→                    .await
2425→                    .unwrap_or(0)
2426→            } else {
2427→                0
2428→            };
2429→            let chunks: i64 = if has_chunks_table > 0 {
2430→                sqlx::query_scalar("SELECT COUNT(*) FROM chunks")
2431→                    .fetch_one(&pool)
2432→                    .await
2433→                    .unwrap_or(0)
2434→            } else {
2435→                0
2436→            };
