2529→    record_call("moltis_memory_config_update");
2530→    trace_call("moltis_memory_config_update");
2531→
2532→    with_ffi_boundary(|| {
2533→        let request = match parse_ffi_request::<MemoryConfigUpdateRequest>(
2534→            "moltis_memory_config_update",
2535→            request_json,
2536→        ) {
2537→            Ok(request) => request,
2538→            Err(e) => return e,
2539→        };
2540→
2541→        let current_config = moltis_config::discover_and_load();
2542→        let current = current_config.memory;
2543→        let current_chat = current_config.chat;
2544→        let style = request.style.unwrap_or_else(|| match current.style {
2545→            moltis_config::MemoryStyle::Hybrid => "hybrid".to_owned(),
2546→            moltis_config::MemoryStyle::PromptOnly => "prompt-only".to_owned(),
2547→            moltis_config::MemoryStyle::SearchOnly => "search-only".to_owned(),
2548→            moltis_config::MemoryStyle::Off => "off".to_owned(),
2549→        });
2550→        let agent_write_mode =
2551→            request
2552→                .agent_write_mode
2553→                .unwrap_or_else(|| match current.agent_write_mode {
2554→                    moltis_config::AgentMemoryWriteMode::Hybrid => "hybrid".to_owned(),
2555→                    moltis_config::AgentMemoryWriteMode::PromptOnly => "prompt-only".to_owned(),
2556→                    moltis_config::AgentMemoryWriteMode::SearchOnly => "search-only".to_owned(),
2557→                    moltis_config::AgentMemoryWriteMode::Off => "off".to_owned(),
2558→                });
2559→        let user_profile_write_mode = request.user_profile_write_mode.unwrap_or_else(|| {
2560→            match current.user_profile_write_mode {
2561→                moltis_config::UserProfileWriteMode::ExplicitAndAuto => {
2562→                    "explicit-and-auto".to_owned()
2563→                },
2564→                moltis_config::UserProfileWriteMode::ExplicitOnly => "explicit-only".to_owned(),
2565→                moltis_config::UserProfileWriteMode::Off => "off".to_owned(),
2566→            }
2567→        });
2568→        let backend = request.backend.unwrap_or_else(|| match current.backend {
