2572→        let provider = request.provider.unwrap_or_else(|| match current.provider {
2573→            Some(moltis_config::MemoryProvider::Local) => "local".to_owned(),
2574→            Some(moltis_config::MemoryProvider::Ollama) => "ollama".to_owned(),
2575→            Some(moltis_config::MemoryProvider::OpenAi) => "openai".to_owned(),
2576→            Some(moltis_config::MemoryProvider::Custom) => "custom".to_owned(),
2577→            None => "auto".to_owned(),
2578→        });
2579→        let citations = request
2580→            .citations
2581→            .unwrap_or_else(|| match current.citations {
2582→                moltis_config::MemoryCitationsMode::On => "on".to_owned(),
2583→                moltis_config::MemoryCitationsMode::Off => "off".to_owned(),
2584→                moltis_config::MemoryCitationsMode::Auto => "auto".to_owned(),
2585→            });
2586→        let llm_reranking = request.llm_reranking.unwrap_or(current.llm_reranking);
2587→        let search_merge_strategy = request
2588→            .search_merge_strategy
2589→            .unwrap_or_else(|| match current.search_merge_strategy {
2590→                moltis_config::MemorySearchMergeStrategy::Rrf => "rrf".to_owned(),
