2704→/// Returns QMD availability (binary detection + optional version).
2705→#[unsafe(no_mangle)]
2706→pub extern "C" fn moltis_memory_qmd_status() -> *mut c_char {
2707→    record_call("moltis_memory_qmd_status");
2708→    trace_call("moltis_memory_qmd_status");
2709→
2710→    with_ffi_boundary(|| {
2711→        if !cfg!(feature = "qmd") {
2712→            let response = MemoryQmdStatusResponse {
2713→                feature_enabled: false,
2714→                available: false,
2715→                version: None,
2716→                error: Some("QMD feature is disabled in this build".to_owned()),
2717→            };
2718→            return encode_json(&response);
2719→        }
2720→
2721→        let command = moltis_config::discover_and_load()
2722→            .memory
2723→            .qmd
2724→            .command
2725→            .unwrap_or_else(|| "qmd".to_owned());
2726→
2727→        let output = std::process::Command::new(&command)
2728→            .arg("--version")
2729→            .output();
2730→
2731→        let response = match output {
2732→            Ok(out) if out.status.success() => {
2733→                let version = String::from_utf8_lossy(&out.stdout).trim().to_owned();
2734→                let resolved_version = if version.is_empty() {
2735→                    None
2736→                } else {
2737→                    Some(version)
2738→                };
2739→                MemoryQmdStatusResponse {
2740→                    feature_enabled: true,
2741→                    available: true,
2742→                    version: resolved_version,
2743→                    error: None,
2744→                }
2745→            },
2746→            Ok(out) => {
2747→                let stderr = String::from_utf8_lossy(&out.stderr).trim().to_owned();
2748→                let detail = if stderr.is_empty() {
2749→                    format!("{command} --version exited with status {}", out.status)
2750→                } else {
2751→                    stderr
2752→                };
2753→                MemoryQmdStatusResponse {
2754→                    feature_enabled: true,
2755→                    available: false,
2756→                    version: None,
2757→                    error: Some(detail),
2758→                }
2759→            },
2760→            Err(error) => MemoryQmdStatusResponse {
2761→                feature_enabled: true,
2762→                available: false,
2763→                version: None,
2764→                error: Some(error.to_string()),
2765→            },
2766→        };
2767→
2768→        encode_json(&response)
2769→    })
2770→}
