1709→/// Some providers require visiting a URL that already embeds the user_code.
1710→/// Prefer provider-returned `verification_uri_complete`; otherwise synthesize
1711→/// one for known providers.
1712→fn build_verification_uri_complete(
1713→    provider: &str,
1714→    verification_uri: &str,
1715→    user_code: &str,
1716→    provided_complete: Option<String>,
1717→) -> Option<String> {
