1720→    {
1721→        return Some(complete);
1722→    }
1723→
1724→    if provider == "kimi-code" {
1725→        let sep = if verification_uri.contains('?') {
1726→            "&"
1727→        } else {
1728→            "?"
1729→        };
1730→        return Some(format!("{verification_uri}{sep}user_code={user_code}"));
1731→    }
1732→
1733→    None
1734→}
