1736→#[async_trait]
1737→impl ProviderSetupService for LiveProviderSetupService {
1738→    async fn available(&self) -> ServiceResult {
1739→        let is_cloud = self.deploy_platform.is_some();
1740→        let active_config = self.config_snapshot();
1741→        let offered_order = ui_offered_provider_order(&active_config);
1742→        let offered = ui_offered_provider_set(&offered_order);
1743→        let offered_rank: HashMap<String, usize> = offered_order
1744→            .iter()
1745→            .enumerate()
1746→            .map(|(idx, provider)| (provider.clone(), idx))
1747→            .collect();
1748→
1749→        let mut providers: Vec<(Option<usize>, usize, Value)> = known_providers()
1750→            .iter()
1751→            .enumerate()
1752→            .filter_map(|(known_idx, provider)| {
1753→                // Hide local-only providers on cloud deployments.
1754→                if is_cloud && provider.is_local_only() {
1755→                    return None;
1756→                }
1757→
1758→                let configured = self.is_provider_configured(provider, &active_config);
1759→                let normalized_name = normalize_provider_name(provider.name);
1760→                if let Some(allowed) = offered.as_ref()
1761→                    && !allowed.contains(&normalized_name)
1762→                    && !configured
1763→                {
1764→                    return None;
1765→                }
1766→
1767→                // Get saved config for this provider (baseUrl, preferred models)
1768→                let saved_config = self.key_store.load_config(provider.name);
1769→                let base_url = saved_config.as_ref().and_then(|c| c.base_url.clone());
1770→                let models = saved_config
1771→                    .map(|c| normalize_model_list(c.models))
1772→                    .unwrap_or_default();
1773→                let model = models.first().cloned();
1774→
1775→                Some((
1776→                    offered_rank.get(&normalized_name).copied(),
1777→                    known_idx,
1778→                    serde_json::json!({
1779→                        "name": provider.name,
1780→                        "displayName": provider.display_name,
1781→                        "authType": provider.auth_type.as_str(),
1782→                        "configured": configured,
1783→                        "defaultBaseUrl": provider.default_base_url,
1784→                        "baseUrl": base_url,
1785→                        "models": models,
1786→                        "model": model,
1787→                        "requiresModel": provider.requires_model,
1788→                        "keyOptional": provider.key_optional,
1789→                    }),
1790→                ))
1791→            })
1792→            .collect();
1793→
1794→        // Append custom providers from the key store.
1795→        let known_count = providers.len();
1796→        for (name, config) in self.key_store.load_all_configs() {
1797→            if !is_custom_provider(&name) {
1798→                continue;
1799→            }
1800→            if active_config.get(&name).is_some_and(|entry| !entry.enabled) {
1801→                continue;
1802→            }
1803→            let display_name = config.display_name.clone().unwrap_or_else(|| name.clone());
1804→            let base_url = config.base_url.clone();
1805→            let models = normalize_model_list(config.models.clone());
1806→            let model = models.first().cloned();
1807→
1808→            providers.push((
1809→                None,
1810→                known_count, // sort after all known providers
1811→                serde_json::json!({
1812→                    "name": name,
1813→                    "displayName": display_name,
1814→                    "authType": "api-key",
1815→                    "configured": true,
1816→                    "defaultBaseUrl": base_url,
1817→                    "baseUrl": base_url,
1818→                    "models": models,
1819→                    "model": model,
1820→                    "requiresModel": true,
1821→                    "keyOptional": false,
1822→                    "isCustom": true,
1823→                }),
1824→            ));
1825→        }
1826→
1827→        providers.sort_by(
1828→            |(a_offered, a_known, a_value), (b_offered, b_known, b_value)| {
1829→                let offered_cmp = match (a_offered, b_offered) {
1830→                    (Some(a), Some(b)) => a.cmp(b),
1831→                    (Some(_), None) => std::cmp::Ordering::Less,
1832→                    (None, Some(_)) => std::cmp::Ordering::Greater,
1833→                    (None, None) => std::cmp::Ordering::Equal,
1834→                };
1835→                if offered_cmp != std::cmp::Ordering::Equal {
1836→                    return offered_cmp;
1837→                }
1838→
1839→                let known_cmp = a_known.cmp(b_known);
1840→                if known_cmp != std::cmp::Ordering::Equal {
1841→                    return known_cmp;
1842→                }
1843→
1844→                let a_name = a_value
1845→                    .get("displayName")
1846→                    .and_then(|v| v.as_str())
1847→                    .unwrap_or_default();
1848→                let b_name = b_value
1849→                    .get("displayName")
1850→                    .and_then(|v| v.as_str())
1851→                    .unwrap_or_default();
1852→                a_name.cmp(b_name)
1853→            },
1854→        );
1855→
1856→        let providers: Vec<Value> = providers
1857→            .into_iter()
1858→            .enumerate()
1859→            .map(|(idx, (_, _, mut value))| {
1860→                if let Some(obj) = value.as_object_mut() {
1861→                    obj.insert("uiOrder".into(), serde_json::json!(idx));
1862→                }
1863→                value
1864→            })
1865→            .collect();
1866→
1867→        Ok(Value::Array(providers))
1868→    }
