1870→    async fn save_key(&self, params: Value) -> ServiceResult {
1871→        let _timing = ProviderSetupTiming::start(
1872→            "providers.save_key",
1873→            params.get("provider").and_then(Value::as_str),
1874→        );
1875→        let provider_name = params
1876→            .get("provider")
1877→            .and_then(|v| v.as_str())
1878→            .ok_or_else(|| "missing 'provider' parameter".to_string())?;
1879→
1880→        // API key is optional for some providers (e.g., Ollama)
1881→        let api_key = params.get("apiKey").and_then(|v| v.as_str());
1882→        let base_url = params.get("baseUrl").and_then(|v| v.as_str());
1883→        let models = parse_models_param(&params);
1884→
1885→        // Custom providers bypass known_providers() validation.
1886→        let is_custom = is_custom_provider(provider_name);
1887→        if !is_custom {
1888→            // Validate provider name - allow both api-key and local providers
1889→            let known = known_providers();
1890→            let provider = known
1891→                .iter()
1892→                .find(|p| {
1893→                    p.name == provider_name
1894→                        && (p.auth_type == AuthType::ApiKey || p.auth_type == AuthType::Local)
1895→                })
1896→                .ok_or_else(|| format!("unknown provider: {provider_name}"))?;
1897→
1898→            // API key is required for api-key providers unless the provider
1899→            // marks the key as optional (Ollama, LM Studio).
1900→            if provider.auth_type == AuthType::ApiKey && !provider.key_optional && api_key.is_none()
1901→            {
1902→                return Err("missing 'apiKey' parameter".into());
1903→            }
1904→        } else if api_key.is_none() {
1905→            return Err("missing 'apiKey' parameter".into());
1906→        }
1907→
1908→        let normalized_base_url = if provider_name == "ollama" {
1909→            base_url.map(|url| normalize_ollama_openai_base_url(Some(url)))
1910→        } else {
1911→            base_url.map(String::from)
1912→        };
1913→
1914→        let key_store_path = self.key_store.path();
1915→        info!(
1916→            provider = provider_name,
1917→            has_api_key = api_key.is_some(),
1918→            has_base_url = normalized_base_url
1919→                .as_ref()
1920→                .is_some_and(|url| !url.trim().is_empty()),
1921→            models = models.len(),
1922→            key_store_path = %key_store_path.display(),
1923→            "saving provider config"
1924→        );
1925→
1926→        // Persist full config to disk
1927→        if let Err(error) = self.key_store.save_config(
1928→            provider_name,
1929→            api_key.map(String::from),
1930→            normalized_base_url,
1931→            (!models.is_empty()).then_some(models),
1932→        ) {
1933→            warn!(
1934→                provider = provider_name,
1935→                key_store_path = %key_store_path.display(),
1936→                error = %error,
1937→                "failed to persist provider config"
1938→            );
1939→            return Err(ServiceError::message(error));
1940→        }
1941→        set_provider_enabled_in_config(provider_name, true)?;
1942→        self.set_provider_enabled_in_memory(provider_name, true);
1943→
1944→        // Rebuild the provider registry with saved keys merged into config.
1945→        let effective = self.effective_config();
1946→        let new_registry = self.build_registry(&effective);
1947→        let provider_summary = new_registry.provider_summary();
1948→        let model_count = new_registry.list_models().len();
1949→        let mut reg = self.registry.write().await;
1950→        *reg = new_registry;
1951→
1952→        info!(
1953→            provider = provider_name,
1954→            provider_summary = %provider_summary,
1955→            models = model_count,
1956→            "saved provider config to disk and rebuilt provider registry"
1957→        );
1958→
1959→        Ok(serde_json::json!({ "ok": true }))
1960→    }
