1962→    async fn oauth_start(&self, params: Value) -> ServiceResult {
1963→        let provider_name = params
1964→            .get("provider")
1965→            .and_then(|v| v.as_str())
1966→            .ok_or_else(|| "missing 'provider' parameter".to_string())?
1967→            .to_string();
1968→
1969→        // RFC 8252 §7.3/§8.3: loopback redirect URIs must use `http`.
1970→        // The UI sends `${window.location.origin}/auth/callback`, which is
1971→        // `https://localhost:<port>/auth/callback` on TLS-enabled
1972→        // deployments. Rewrite loopback origins to `http` so strict
1973→        // authorization servers accept them; the TLS listener's HTTP peek
1974→        // redirect bounces the callback back onto the HTTPS handler.
1975→        let redirect_uri = params
1976→            .get("redirectUri")
1977→            .and_then(|v| v.as_str())
1978→            .map(str::trim)
1979→            .filter(|v| !v.is_empty())
1980→            .map(normalize_loopback_redirect);
1981→
1982→        let mut oauth_config = load_oauth_config(&provider_name)
1983→            .ok_or_else(|| format!("no OAuth config for provider: {provider_name}"))?;
1984→
1985→        // Normalize any loopback `redirect_uri` loaded from the user
1986→        // config file (`~/.config/moltis/oauth_providers.json`) or
1987→        // `MOLTIS_OAUTH_{PROVIDER}_REDIRECT_URI`. See
1988→        // `normalize_loaded_redirect_uri` for the full rationale.
1989→        normalize_loaded_redirect_uri(&mut oauth_config);
1990→
1991→        // User explicitly initiated OAuth for this provider; ensure it is enabled.
1992→        set_provider_enabled_in_config(&provider_name, true)?;
1993→        self.set_provider_enabled_in_memory(&provider_name, true);
1994→
1995→        // If tokens already exist (for example imported from the main/home config),
1996→        // skip launching a fresh OAuth flow and rebuild the registry immediately.
1997→        if self.has_oauth_tokens(&provider_name) {
1998→            let effective = self.effective_config();
1999→            let new_registry = self.build_registry(&effective);
2000→            let provider_summary = new_registry.provider_summary();
2001→            let model_count = new_registry.list_models().len();
2002→            let mut reg = self.registry.write().await;
2003→            *reg = new_registry;
2004→            info!(
2005→                provider = %provider_name,
2006→                provider_summary = %provider_summary,
2007→                models = model_count,
2008→                "oauth start skipped because provider already has tokens; rebuilt provider registry"
2009→            );
2010→            return Ok(serde_json::json!({
2011→                "alreadyAuthenticated": true,
2012→            }));
2013→        }
2014→
2015→        if oauth_config.device_flow {
2016→            return self
2017→                .oauth_start_device_flow(provider_name, oauth_config)
2018→                .await;
2019→        }
2020→
2021→        // Providers with a pre-registered redirect_uri (e.g. openai-codex
2022→        // registered as http://localhost:1455/auth/callback with OpenAI)
2023→        // must always use that URI in the authorization request.
2024→        // Overriding it with the gateway URL causes OAuth providers to
2025→        // reject the request with "unknown_error".
2026→        // For these providers we always use the local callback server.
2027→        //
2028→        // The pre-registered URI has already been loopback-normalized
2029→        // above, so strict authorization servers accept it even if the
2030→        // user's custom config file used the `https://` form.
2031→        let has_registered_redirect = !oauth_config.redirect_uri.is_empty();
2032→        let use_server_callback = redirect_uri.is_some() && !has_registered_redirect;
2033→        if !has_registered_redirect && let Some(uri) = redirect_uri {
2034→            oauth_config.redirect_uri = uri;
2035→        }
2036→
2037→        let port = callback_port(&oauth_config);
2038→        let oauth_config_for_pending = oauth_config.clone();
2039→        let flow = OAuthFlow::new(oauth_config);
2040→        let auth_req = flow.start().map_err(ServiceError::message)?;
2041→
2042→        let auth_url = auth_req.url.clone();
2043→        let verifier = auth_req.pkce.verifier.clone();
2044→        let expected_state = auth_req.state.clone();
2045→
2046→        let pending = PendingOAuthFlow {
2047→            provider_name: provider_name.clone(),
2048→            oauth_config: oauth_config_for_pending,
2049→            verifier: verifier.clone(),
2050→        };
2051→        self.pending_oauth
2052→            .write()
2053→            .await
2054→            .insert(expected_state.clone(), pending);
2055→
2056→        // Browser/server callback mode: callback lands on this gateway instance,
2057→        // then `/auth/callback` completes the exchange with `oauth_complete`.
2058→        if use_server_callback {
2059→            return Ok(serde_json::json!({
2060→                "authUrl": auth_url,
2061→            }));
2062→        }
2063→
2064→        // Spawn background task to wait for the callback and exchange the code
2065→        let token_store = self.token_store.clone();
2066→        let registry = Arc::clone(&self.registry);
2067→        let config = self.effective_config();
2068→        let env_overrides = self.env_overrides.clone();
2069→        let bind_addr = self.callback_bind_addr.clone();
2070→        let pending_oauth = Arc::clone(&self.pending_oauth);
2071→        let callback_state = expected_state.clone();
2072→        tokio::spawn(async move {
2073→            match CallbackServer::wait_for_code(port, callback_state, &bind_addr).await {
2074→                Ok(code) => {
2075→                    // If a manual pasted callback already completed this flow,
2076→                    // skip duplicate exchange.
2077→                    let state_is_pending = pending_oauth
2078→                        .write()
2079→                        .await
2080→                        .remove(&expected_state)
2081→                        .is_some();
2082→                    if !state_is_pending {
2083→                        tracing::debug!(
2084→                            provider = %provider_name,
2085→                            "OAuth callback received after flow was already completed manually"
2086→                        );
2087→                        return;
2088→                    }
2089→
2090→                    match flow.exchange(&code, &verifier).await {
2091→                        Ok(tokens) => {
2092→                            if let Err(e) = token_store.save(&provider_name, &tokens) {
2093→                                tracing::error!(
2094→                                    provider = %provider_name,
2095→                                    error = %e,
2096→                                    "failed to save OAuth tokens"
2097→                                );
2098→                                return;
2099→                            }

2500→
2501→        let base_url = config
2502→            .get("openai")
2503→            .and_then(|e| e.base_url.clone())
2504→            .or_else(|| env_value(env_overrides, "OPENAI_BASE_URL"))
2505→            .unwrap_or_else(|| "https://api.openai.com/v1".into());
2506→
2507→        let model_id = configured_models_for_provider(config, "openai")
2508→            .into_iter()
2509→            .next()
2510→            .unwrap_or_else(|| "gpt-4o".to_string());
2511→
2512→        // Get alias if configured (for metrics differentiation).
2513→        let alias = config.get("openai").and_then(|e| e.alias.clone());
2514→        let provider_label = alias.clone().unwrap_or_else(|| "async-openai".into());
2515→        if self.has_model_any_provider(&model_id) {
2516→            return;
2517→        }
2518→
2519→        let provider = Arc::new(async_openai_provider::AsyncOpenAiProvider::with_alias(
2520→            key,
2521→            model_id.clone(),
2522→            base_url,
2523→            alias,
2524→        ));
2525→        self.register(
2526→            ModelInfo {
2527→                id: model_id.clone(),
2528→                provider: provider_label,
2529→                display_name: "GPT-4o (async-openai)".into(),
2530→                created_at: None,
2531→                recommended: false,
2532→                capabilities: ModelCapabilities::infer(&model_id),
2533→            },
2534→            provider,
2535→        );
2536→    }
