5999→        // Regression guard: the warning must be emitted *before* stdin is
6000→        // drained. The old silent no-op form `cat >/dev/null; exit 0` ran
6001→        // without any prior stderr write, so the warning echo must precede
6002→        // the `cat >/dev/null` inside the missing-dcg branch.
6003→        let warn_idx = DCG_GUARD_HANDLER_SH
6004→            .find("NOT scanned")
6005→            .expect("handler must contain the NOT scanned warning");
6006→        let drain_idx = DCG_GUARD_HANDLER_SH
6007→            .find("cat >/dev/null")
6008→            .expect("handler still drains stdin in the missing-dcg branch");
6009→        assert!(
6010→            warn_idx < drain_idx,
6011→            "warning must be printed before stdin is drained"
