6123→    #[test]
6124→    fn dcg_guard_extra_path_dirs_match_handler_script() {
6125→        // Parity guard: every directory in DCG_GUARD_EXTRA_PATH_DIRS must
6126→        // appear literally in the handler's `export PATH=` line. If
6127→        // someone edits one list without the other, the Rust startup
6128→        // probe and the shell handler will disagree on which directories
6129→        // are searched — exactly the class of bug #626 was about. Pin
6130→        // them together with an explicit assertion.
6131→        for rel in DCG_GUARD_EXTRA_PATH_DIRS {
6132→            let needle = if rel.starts_with('/') {
6133→                (*rel).to_string()
6134→            } else {
6135→                format!("/{rel}")
6136→            };
6137→            assert!(
6138→                DCG_GUARD_HANDLER_SH.contains(&needle),
6139→                "handler script missing PATH entry for {rel:?} (needle={needle:?})"
6140→            );
6141→        }
6142→        // Also pin the absolute form of the $HOME-relative entry so the
6143→        // fallback path (${{HOME:-/root}}/.local/bin) stays in sync with
6144→        // the Rust probe's DCG_GUARD_HOME_FALLBACK.
6145→        assert!(
6146→            DCG_GUARD_HANDLER_SH
6147→                .contains(&format!("${{HOME:-{DCG_GUARD_HOME_FALLBACK}}}/.local/bin")),
