3049→/// Adds or changes the authentication password.
3050→///
3051→/// Accepts JSON:
3052→/// - `{"new_password":"..."}` to set the first password.
3053→/// - `{"current_password":"...","new_password":"..."}` to rotate.
3054→#[unsafe(no_mangle)]
3055→pub extern "C" fn moltis_auth_password_change(request_json: *const c_char) -> *mut c_char {
3056→    record_call("moltis_auth_password_change");
3057→    trace_call("moltis_auth_password_change");
3058→
3059→    with_ffi_boundary(|| {
3060→        let request = match parse_ffi_request::<AuthPasswordChangeRequest>(
3061→            "moltis_auth_password_change",
3062→            request_json,
3063→        ) {
3064→            Ok(r) => r,
3065→            Err(e) => return e,
3066→        };
3067→
3068→        if request.new_password.expose_secret().len() < 8 {
3069→            record_error("moltis_auth_password_change", "AUTH_PASSWORD_TOO_SHORT");
3070→            return encode_error(
3071→                "AUTH_PASSWORD_TOO_SHORT",
3072→                "new password must be at least 8 characters",
3073→            );
3074→        }
3075→
3076→        let has_password = match BRIDGE
3077→            .runtime
3078→            .block_on(BRIDGE.credential_store.has_password())
3079→        {
3080→            Ok(value) => value,
3081→            Err(error) => {
3082→                record_error("moltis_auth_password_change", "AUTH_STATUS_FAILED");
3083→                return encode_error("AUTH_STATUS_FAILED", &error.to_string());
3084→            },
3085→        };
3086→
3087→        let mut recovery_key: Option<String> = None;
3088→
3089→        let new_password = request.new_password.expose_secret();
3090→
3091→        if has_password {
3092→            let current_password = request
3093→                .current_password
3094→                .as_ref()
3095→                .map(|s| s.expose_secret().as_str())
3096→                .unwrap_or("");
3097→            if let Err(error) = BRIDGE.runtime.block_on(
3098→                BRIDGE
3099→                    .credential_store
3100→                    .change_password(current_password, new_password),
3101→            ) {
3102→                let message = error.to_string();
3103→                if message.contains("incorrect") {
3104→                    record_error(
3105→                        "moltis_auth_password_change",
3106→                        "AUTH_INVALID_CURRENT_PASSWORD",
3107→                    );
3108→                    return encode_error("AUTH_INVALID_CURRENT_PASSWORD", &message);
3109→                }
3110→                record_error("moltis_auth_password_change", "AUTH_PASSWORD_CHANGE_FAILED");
3111→                return encode_error("AUTH_PASSWORD_CHANGE_FAILED", &message);
3112→            }
3113→
3114→            if let Some(vault) = BRIDGE.credential_store.vault()
3115→                && let Err(error) = BRIDGE
3116→                    .runtime
3117→                    .block_on(vault.change_password(current_password, new_password))
3118→            {
3119→                emit_log(
3120→                    "WARN",
3121→                    "bridge.auth",
3122→                    &format!("Vault password rotation failed: {error}"),
3123→                );
3124→            }
3125→        } else if let Err(error) = BRIDGE
3126→            .runtime
3127→            .block_on(BRIDGE.credential_store.add_password(new_password))
3128→        {
3129→            record_error("moltis_auth_password_change", "AUTH_PASSWORD_SET_FAILED");
3130→            return encode_error("AUTH_PASSWORD_SET_FAILED", &error.to_string());
3131→        } else if let Some(vault) = BRIDGE.credential_store.vault() {
3132→            match BRIDGE.runtime.block_on(vault.initialize(new_password)) {
3133→                Ok(key) => {
3134→                    recovery_key = Some(key.phrase().to_owned());
3135→                },
3136→                Err(moltis_gateway::auth::moltis_vault::VaultError::AlreadyInitialized) => {
3137→                    if let Err(error) = BRIDGE.runtime.block_on(vault.unseal(new_password)) {
3138→                        emit_log(
3139→                            "WARN",
3140→                            "bridge.auth",
3141→                            &format!("Vault unseal failed after password set: {error}"),
3142→                        );
3143→                    }
3144→                },
3145→                Err(error) => {
3146→                    emit_log(
3147→                        "WARN",
3148→                        "bridge.auth",
3149→                        &format!("Vault initialization failed after password set: {error}"),
3150→                    );
3151→                },
3152→            }
3153→        }
3154→
3155→        encode_json(&AuthPasswordChangeResponse {
3156→            ok: true,
3157→            recovery_key,
3158→        })
3159→    })
3160→}
