3422→            return encode_json(&SandboxCheckPackagesResponse {
3423→                found: HashMap::new(),
3424→            });
3425→        }
3426→
3427→        if !is_valid_image_ref(&base) {
3428→            record_error("moltis_sandbox_check_packages", SANDBOX_BASE_IMAGE_INVALID);
3429→            return encode_error(
3430→                SANDBOX_BASE_IMAGE_INVALID,
3431→                "base image contains invalid characters",
3432→            );
3433→        }
3434→
3435→        if let Some(bad) = packages.iter().find(|p| !is_valid_package_name(p)) {
3436→            record_error(
3437→                "moltis_sandbox_check_packages",
3438→                SANDBOX_PACKAGE_NAME_INVALID,
3439→            );
3440→            return encode_error(
3441→                SANDBOX_PACKAGE_NAME_INVALID,
3442→                &format!("invalid package name: {bad}"),
3443→            );
3444→        }
3445→
3446→        let checks: Vec<String> = packages
3447→            .iter()
3448→            .map(|pkg| {
3449→                format!(
3450→                    r#"if dpkg -s '{pkg}' >/dev/null 2>&1 || command -v '{pkg}' >/dev/null 2>&1; then echo "FOUND:{pkg}"; fi"#
3451→                )
3452→            })
3453→            .collect();
3454→        let script = checks.join("\n");
3455→
3456→        let cli = moltis_tools::sandbox::container_cli();
3457→        let output = BRIDGE.runtime.block_on(async {
3458→            tokio::process::Command::new(cli)
3459→                .args(["run", "--rm", "--entrypoint", "sh", &base, "-c", &script])
3460→                .stdout(std::process::Stdio::piped())
3461→                .stderr(std::process::Stdio::piped())
3462→                .output()
3463→                .await
3464→        });
3465→
3466→        match output {
3467→            Ok(output) => {
3468→                let stdout = String::from_utf8_lossy(&output.stdout);
3469→                let mut found = HashMap::new();
3470→                for pkg in packages {
3471→                    let present = stdout
3472→                        .lines()
3473→                        .any(|line| line.trim() == format!("FOUND:{pkg}"));
3474→                    found.insert(pkg, present);
3475→                }
3476→                encode_json(&SandboxCheckPackagesResponse { found })
3477→            },
3478→            Err(error) => {
3479→                record_error(
3480→                    "moltis_sandbox_check_packages",
3481→                    SANDBOX_CHECK_PACKAGES_FAILED,
3482→                );
3483→                encode_error(SANDBOX_CHECK_PACKAGES_FAILED, &error.to_string())
3484→            },
3485→        }
3486→    })
3487→}
