3051→    /// Register custom OpenAI-compatible providers (names starting with `custom-`).
3052→    /// These are user-added endpoints that may support model discovery via `/v1/models`.
3053→    fn register_custom_providers(
3054→        &mut self,
3055→        config: &ProvidersConfig,
3056→        prefetched: &HashMap<String, Vec<DiscoveredModel>>,
3057→    ) {
3058→        for (name, entry) in &config.providers {
3059→            if !name.starts_with("custom-") || !entry.enabled {
3060→                continue;
3061→            }
3062→
3063→            let Some(api_key) = entry
3064→                .api_key
3065→                .as_ref()
3066→                .filter(|k| !k.expose_secret().is_empty())
3067→            else {
3068→                continue;
3069→            };
3070→
3071→            let Some(base_url) = entry.base_url.as_ref().filter(|u| !u.trim().is_empty()) else {
3072→                continue;
3073→            };
3074→
3075→            let preferred = configured_models_for_provider(config, name);
3076→
3077→            // Use pre-fetched results from parallel discovery.
3078→            let discovered = if should_fetch_models(config, name) {
3079→                match prefetched.get(name.as_str()) {
3080→                    Some(models) => models.clone(),
3081→                    None => Vec::new(),
3082→                }
3083→            } else {
3084→                Vec::new()
3085→            };
3086→
3087→            let models = merge_preferred_and_discovered_models(preferred, discovered);
3088→            if models.is_empty() {
3089→                tracing::debug!(
3090→                    provider = %name,
3091→                    "custom provider has no models — skipping registration"
3092→                );
3093→                continue;
3094→            }
3095→
3096→            let custom_tool_mode = entry.tool_mode;
3097→            for model in models {
3098→                let caps = model
3099→                    .capabilities
3100→                    .unwrap_or_else(|| ModelCapabilities::infer(&model.id));
3101→                let (model_id, display_name, created_at, recommended) = (
3102→                    model.id,
3103→                    model.display_name,
3104→                    model.created_at,
3105→                    model.recommended,
3106→                );
3107→                if self.has_provider_model(name, &model_id) {
3108→                    continue;
3109→                }
3110→                let mut oai = openai::OpenAiProvider::new_with_name(
3111→                    api_key.clone(),
3112→                    model_id.clone(),
3113→                    base_url.clone(),
3114→                    name.clone(),
3115→                )
3116→                .with_stream_transport(entry.stream_transport)
3117→                .with_cache_retention(entry.cache_retention);
3118→                if !matches!(entry.wire_api, moltis_config::WireApi::ChatCompletions) {
3119→                    oai = oai.with_wire_api(entry.wire_api);
3120→                }
3121→                if !matches!(custom_tool_mode, moltis_config::ToolMode::Auto) {
3122→                    oai = oai.with_tool_mode(custom_tool_mode);
3123→                }
3124→                let provider = Arc::new(oai);
3125→                self.register(
3126→                    ModelInfo {
3127→                        id: model_id,
3128→                        provider: name.clone(),
3129→                        display_name,
3130→                        created_at,
3131→                        recommended,
3132→                        capabilities: caps,
3133→                    },
3134→                    provider,
3135→                );
3136→            }
3137→
3138→            tracing::info!(
3139→                provider = %name,
3140→                "registered custom OpenAI-compatible provider"
3141→            );
3142→        }
3143→    }
