3145→    pub fn get(&self, model_id: &str) -> Option<Arc<dyn LlmProvider>> {
3146→        let (base_id, reasoning) = split_reasoning_suffix(model_id);
3147→        let provider = self
3148→            .resolve_registry_model_id(base_id, None)
3149→            .as_deref()
3150→            .and_then(|id| self.providers.get(id))
3151→            .cloned()?;
3152→        if let Some(effort) = reasoning {
3153→            let new_provider = Arc::clone(&provider).with_reasoning_effort(effort);
3154→            if new_provider.is_none() {
3155→                tracing::warn!(
3156→                    model_id,
3157→                    ?effort,
3158→                    "provider does not support reasoning effort; ignoring suffix"
3159→                );
3160→            }
3161→            Some(new_provider.unwrap_or(provider))
3162→        } else {
3163→            Some(provider)
3164→        }
3165→    }
