3169→            .iter()
3170→            .enumerate()
3171→            .min_by_key(|(idx, m)| (subscription_preference_rank(&m.provider), *idx))
3172→            .map(|(_, m)| m)
3173→            .and_then(|m| self.providers.get(&m.id))
3174→            .cloned()
