3177→    /// Return the first provider that supports tool calling,
3178→    /// falling back to the first provider overall.
3179→    pub fn first_with_tools(&self) -> Option<Arc<dyn LlmProvider>> {
3180→        self.models
3181→            .iter()
3182→            .enumerate()
3183→            .filter_map(|(idx, m)| self.providers.get(&m.id).map(|p| (idx, m, p)))
3184→            .filter(|(_, _, p)| p.supports_tools())
3185→            .min_by_key(|(idx, m, _)| (subscription_preference_rank(&m.provider), *idx))
3186→            .map(|(_, _, p)| Arc::clone(p))
3187→            .or_else(|| self.first())
3188→    }
