3194→    /// Return the base model list plus reasoning-effort variants for supported models.
3195→    ///
3196→    /// For each model that supports extended thinking, three additional entries
3197→    /// are appended: `<id>@reasoning-low`, `<id>@reasoning-medium`, `<id>@reasoning-high`.
3198→    /// These virtual IDs are resolved by `get()` back to the base provider with
3199→    /// the corresponding reasoning effort applied.
3200→    #[must_use]
3201→    pub fn list_models_with_reasoning_variants(&self) -> Vec<ModelInfo> {
3202→        let mut result = Vec::with_capacity(self.models.len() * 4);
3203→        for m in &self.models {
3204→            result.push(m.clone());
3205→            if m.capabilities.reasoning {
3206→                for &(suffix, _) in REASONING_SUFFIXES {
3207→                    let label = suffix.strip_prefix("reasoning-").unwrap_or(suffix);
3208→                    result.push(ModelInfo {
3209→                        id: format!("{}{REASONING_SUFFIX_SEP}{suffix}", m.id),
3210→                        provider: m.provider.clone(),
3211→                        display_name: format!("{} ({label} reasoning)", m.display_name),
3212→                        created_at: m.created_at,
3213→                        recommended: false,
3214→                        capabilities: ModelCapabilities {
3215→                            reasoning: true,
3216→                            ..m.capabilities
3217→                        },
3218→                    });
3219→                }
3220→            }
3221→        }
3222→        result
3223→    }
