3246→    /// Return fallback providers ordered by affinity to the given primary:
3247→    ///
3248→    /// 1. Same model ID on a different provider backend (e.g. `gpt-4o` via openrouter)
3249→    /// 2. Subscription providers (`openai-codex`, `github-copilot`)
3250→    /// 3. Other models from the same provider (e.g. `claude-opus-4` when primary is `claude-sonnet-4`)
3251→    /// 4. Models from other providers
3252→    ///
3253→    /// The primary itself is excluded from the result.
3254→    pub fn fallback_providers_for(
3255→        &self,
3256→        primary_model_id: &str,
3257→        primary_provider_name: &str,
3258→    ) -> Vec<Arc<dyn LlmProvider>> {
3259→        let primary_raw_model_id = raw_model_id(primary_model_id);
3260→        let mut ranked: Vec<(u8, usize, usize, Arc<dyn LlmProvider>)> = Vec::new();
3261→
3262→        for (idx, info) in self.models.iter().enumerate() {
3263→            if info.id == primary_model_id && info.provider == primary_provider_name {
3264→                continue; // skip the primary itself
3265→            }
3266→            let Some(p) = self.providers.get(&info.id).cloned() else {
3267→                continue;
3268→            };
3269→            let provider_rank = subscription_preference_rank(&info.provider);
3270→            let bucket = if raw_model_id(&info.id) == primary_raw_model_id {
3271→                0
3272→            } else if provider_rank == 0 {
3273→                1
3274→            } else if info.provider == primary_provider_name {
3275→                2
3276→            } else {
3277→                3
3278→            };
3279→            ranked.push((bucket, provider_rank, idx, p));
3280→        }
3281→
3282→        ranked.sort_by_key(|(bucket, provider_rank, idx, _)| (*bucket, *provider_rank, *idx));
3283→        ranked.into_iter().map(|(_, _, _, p)| p).collect()
3284→    }
