2149→    async fn oauth_complete(&self, params: Value) -> ServiceResult {
2150→        let parsed_callback = params
2151→            .get("callback")
2152→            .and_then(Value::as_str)
2153→            .map(str::trim)
2154→            .filter(|value| !value.is_empty())
2155→            .map(parse_callback_input)
2156→            .transpose()
2157→            .map_err(ServiceError::message)?;
2158→
2159→        let code = params
2160→            .get("code")
2161→            .and_then(|v| v.as_str())
2162→            .map(str::trim)
2163→            .filter(|value| !value.is_empty())
2164→            .map(ToOwned::to_owned)
2165→            .or_else(|| parsed_callback.as_ref().map(|parsed| parsed.code.clone()))
2166→            .ok_or_else(|| "missing 'code' parameter".to_string())?;
2167→        let state = params
2168→            .get("state")
2169→            .and_then(|v| v.as_str())
2170→            .map(str::trim)
2171→            .filter(|value| !value.is_empty())
2172→            .map(ToOwned::to_owned)
2173→            .or_else(|| parsed_callback.as_ref().map(|parsed| parsed.state.clone()))
2174→            .ok_or_else(|| "missing 'state' parameter".to_string())?;
2175→        let requested_provider = params
2176→            .get("provider")
2177→            .and_then(Value::as_str)
2178→            .map(str::trim)
2179→            .filter(|value| !value.is_empty())
2180→            .map(ToOwned::to_owned);
2181→
2182→        let pending = {
2183→            let mut pending_oauth = self.pending_oauth.write().await;
2184→            let pending = pending_oauth
2185→                .get(&state)
2186→                .cloned()
2187→                .ok_or_else(|| "unknown or expired OAuth state".to_string())?;
2188→
2189→            if let Some(provider) = requested_provider.as_deref()
2190→                && provider != pending.provider_name
2191→            {
2192→                return Err(ServiceError::message(format!(
2193→                    "provider mismatch for OAuth state: expected '{}', got '{}'",
2194→                    pending.provider_name, provider
2195→                )));
2196→            }
2197→
2198→            pending_oauth
2199→                .remove(&state)
2200→                .ok_or_else(|| "unknown or expired OAuth state".to_string())?
2201→        };
2202→
2203→        let flow = OAuthFlow::new(pending.oauth_config);
2204→        let tokens = flow
2205→            .exchange(&code, &pending.verifier)
2206→            .await
2207→            .map_err(ServiceError::message)?;
2208→
2209→        self.token_store
2210→            .save(&pending.provider_name, &tokens)
2211→            .map_err(ServiceError::message)?;
2212→        set_provider_enabled_in_config(&pending.provider_name, true)?;
2213→        self.set_provider_enabled_in_memory(&pending.provider_name, true);
2214→
2215→        let effective = self.effective_config();
2216→        let new_registry = self.build_registry(&effective);
2217→        let provider_summary = new_registry.provider_summary();
2218→        let model_count = new_registry.list_models().len();
2219→        let mut reg = self.registry.write().await;
2220→        *reg = new_registry;
2221→
2222→        info!(
2223→            provider = %pending.provider_name,
2224→            provider_summary = %provider_summary,
2225→            models = model_count,
2226→            "OAuth callback complete, rebuilt provider registry"
2227→        );
2228→
2229→        Ok(serde_json::json!({
2230→            "ok": true,
2231→            "provider": pending.provider_name,
2232→        }))
2233→    }
