6583→fn is_valid_agent_memory_leaf_name(name: &str) -> bool {
6584→    if name.is_empty() || name.contains('/') || !name.ends_with(".md") {
6585→        return false;
6586→    }
6587→    if name.chars().any(char::is_whitespace) {
6588→        return false;
6589→    }
6590→    let stem = &name[..name.len() - 3];
6591→    !(stem.is_empty() || stem.starts_with('.'))
6592→}
