6594→fn resolve_agent_memory_target_path(agent_id: &str, file: &str) -> anyhow::Result<PathBuf> {
6595→    let trimmed = file.trim();
6596→    if trimmed.is_empty() {
6597→        anyhow::bail!("memory path cannot be empty");
6598→    }
6599→
6600→    let workspace = moltis_config::agent_workspace_dir(agent_id);
6601→    if trimmed == "MEMORY.md" || trimmed == "memory.md" {
6602→        return Ok(workspace.join("MEMORY.md"));
6603→    }
6604→
6605→    let Some(name) = trimmed.strip_prefix("memory/") else {
6606→        anyhow::bail!(
6607→            "invalid memory path '{trimmed}': allowed targets are MEMORY.md, memory.md, or memory/<name>.md"
6608→        );
6609→    };
6610→    if !is_valid_agent_memory_leaf_name(name) {
6611→        anyhow::bail!(
6612→            "invalid memory path '{trimmed}': allowed targets are MEMORY.md, memory.md, or memory/<name>.md"
6613→        );
6614→    }
6615→    Ok(workspace.join("memory").join(name))
6616→}
