6618→fn is_path_in_agent_memory_scope(path: &Path, agent_id: &str) -> bool {
6619→    let workspace = moltis_config::agent_workspace_dir(agent_id);
6620→    let workspace_memory_dir = workspace.join("memory");
6621→    if path == workspace.join("MEMORY.md")
6622→        || path == workspace.join("memory.md")
6623→        || path.starts_with(&workspace_memory_dir)
6624→    {
6625→        return true;
6626→    }
6627→
6628→    if agent_id != "main" {
6629→        return false;
6630→    }
6631→
6632→    let data_dir = moltis_config::data_dir();
6633→    let root_memory_dir = data_dir.join("memory");
6634→    path == data_dir.join("MEMORY.md")
6635→        || path == data_dir.join("memory.md")
6636→        || path.starts_with(&root_memory_dir)
6637→}
