8059→/// [`ProviderRequired`]: compaction_run::CompactionRunError::ProviderRequired
8060→async fn compact_session(
8061→    store: &Arc<SessionStore>,
8062→    session_key: &str,
8063→    config: &moltis_config::CompactionConfig,
8064→    provider: Option<&dyn moltis_agents::model::LlmProvider>,
8065→) -> error::Result<compaction_run::CompactionOutcome> {
8066→    let history = store
8067→        .read(session_key)
8068→        .await
8069→        .map_err(|source| error::Error::external("failed to read session history", source))?;
8070→
8071→    let mut outcome = compaction_run::run_compaction(&history, config, provider)
8072→        .await
8073→        .map_err(|e| error::Error::message(e.to_string()))?;
8074→
8075→    // Enforce summary budget discipline on the compacted history.
8076→    outcome.history = compress_summary_in_history(outcome.history);
8077→
8078→    store
8079→        .replace_history(session_key, outcome.history.clone())
8080→        .await
8081→        .map_err(|source| error::Error::external("failed to replace compacted history", source))?;
8082→
8083→    Ok(outcome)
8084→}
