8087→const STREAM_RETRYABLE_SERVER_PATTERNS: &[&str] = &[
8088→    "http 500",
8089→    "http 502",
8090→    "http 503",
8091→    "http 504",
8092→    "internal server error",
8093→    "service unavailable",
8094→    "gateway timeout",
8095→    "temporarily unavailable",
8096→    "overloaded",
8097→    "timeout",
8098→    "connection reset",
8099→];
8100→const STREAM_SERVER_RETRY_DELAY_MS: u64 = 2_000;
8101→const STREAM_SERVER_MAX_RETRIES: u8 = 1;
8102→const STREAM_RATE_LIMIT_INITIAL_RETRY_MS: u64 = 2_000;
8103→const STREAM_RATE_LIMIT_MAX_RETRY_MS: u64 = 60_000;
8104→const STREAM_RATE_LIMIT_MAX_RETRIES: u8 = 10;
8105→
8106→fn is_retryable_stream_server_error(msg: &str) -> bool {
8107→    let lower = msg.to_ascii_lowercase();
8108→    STREAM_RETRYABLE_SERVER_PATTERNS
8109→        .iter()
8110→        .any(|pattern| lower.contains(pattern))
8111→}
8112→
8113→fn next_stream_rate_limit_retry_ms(previous_ms: Option<u64>) -> u64 {
8114→    previous_ms
8115→        .map(|ms| ms.saturating_mul(2))
8116→        .unwrap_or(STREAM_RATE_LIMIT_INITIAL_RETRY_MS)
8117→        .clamp(
8118→            STREAM_RATE_LIMIT_INITIAL_RETRY_MS,
8119→            STREAM_RATE_LIMIT_MAX_RETRY_MS,
8120→        )
8121→}
8122→
8123→fn next_stream_retry_delay_ms(
8124→    raw_error: &str,
8125→    error_obj: &Value,
8126→    server_retries_remaining: &mut u8,
8127→    rate_limit_retries_remaining: &mut u8,
8128→    rate_limit_backoff_ms: &mut Option<u64>,
8129→) -> Option<u64> {
8130→    if error_obj.get("type").and_then(Value::as_str) == Some("rate_limit_exceeded") {
8131→        if *rate_limit_retries_remaining == 0 {
8132→            return None;
8133→        }
8134→        *rate_limit_retries_remaining -= 1;
8135→
8136→        let current_backoff = *rate_limit_backoff_ms;
8137→        *rate_limit_backoff_ms = Some(next_stream_rate_limit_retry_ms(current_backoff));
8138→
8139→        let hinted_ms = error_obj.get("retryAfterMs").and_then(Value::as_u64);
8140→        let delay_ms = hinted_ms
8141→            .or(*rate_limit_backoff_ms)
8142→            .unwrap_or(STREAM_RATE_LIMIT_INITIAL_RETRY_MS);
8143→        return Some(delay_ms.clamp(1, STREAM_RATE_LIMIT_MAX_RETRY_MS));
8144→    }
8145→
8146→    if is_retryable_stream_server_error(raw_error) {
8147→        if *server_retries_remaining == 0 {
8148→            return None;
8149→        }
8150→        *server_retries_remaining -= 1;
8151→        return Some(STREAM_SERVER_RETRY_DELAY_MS);
8152→    }
8153→
8154→    None
8155→}
