2538→                api_key: api_key.map(|k| Secret::new(k.to_string())),
2539→                base_url: normalized_base_url,
2540→                models: preferred_models,
2541→                ..Default::default()
2542→            },
2543→        );
2544→
2545→        // Build a temporary registry from the temp config.
2546→        let temp_registry = self.build_registry(&temp_config);
2547→
2548→        // Filter models for this provider.
2549→        let models: Vec<_> = temp_registry
2550→            .list_models()
2551→            .iter()
2552→            .filter(|m| {
2553→                normalize_provider_name(&m.provider)
2554→                    == normalize_provider_name(&validation_provider_name)
2555→            })
2556→            .cloned()
2557→            .collect();
2558→
2559→        if models.is_empty() {
2560→            let error =
2561→                "No models available for this provider. Check your credentials and try again.";
2562→            self.emit_validation_progress(
2563→                &validation_provider_name,
2564→                request_id.as_deref(),
2565→                "error",
2566→                progress_payload(serde_json::json!({
2567→                    "message": error,
2568→                })),
2569→            )
2570→            .await;
2571→            return Ok(serde_json::json!({
2572→                "valid": false,
2573→                "error": error,
2574→            }));
2575→        }
2576→
2577→        info!(
2578→            provider = %validation_provider_name,
2579→            model_count = models.len(),
2580→            "provider validation discovered candidate models"
2581→        );
2582→
2583→        // Skip probing — the model list endpoint already proves the endpoint
2584→        // is reachable and any API key is valid.  Probing each model via a
2585→        // chat completion forces local LLM servers (Ollama, LemonadeSDK, …)
2586→        // to load/unload every model, causing enormous I/O for large model
2587→        // sets.  Errors will surface at chat time with actionable messages.
2588→        // Users can manually test individual models from the Providers page.
2589→        let model_list: Vec<Value> = models
2590→            .iter()
2591→            .filter(|m| moltis_providers::is_chat_capable_model(&m.id))
2592→            .map(|m| {
2593→                let supports_tools = temp_registry.get(&m.id).is_some_and(|p| p.supports_tools());
2594→                serde_json::json!({
2595→                    "id": m.id,
2596→                    "displayName": m.display_name,
2597→                    "provider": m.provider,
2598→                    "supportsTools": supports_tools,
2599→                })
2600→            })
2601→            .collect();
2602→
2603→        self.emit_validation_progress(
2604→            &validation_provider_name,
2605→            request_id.as_deref(),
2606→            "complete",
2607→            progress_payload(serde_json::json!({
2608→                "message": "Validation complete.",
2609→                "modelCount": model_list.len(),
2610→            })),
2611→        )
2612→        .await;
2613→        Ok(serde_json::json!({
2614→            "valid": true,
2615→            "models": model_list,
2616→        }))
2617→    }
