2619→    async fn save_model(&self, params: Value) -> ServiceResult {
2620→        let provider_name = params
2621→            .get("provider")
2622→            .and_then(|v| v.as_str())
2623→            .ok_or_else(|| "missing 'provider' parameter".to_string())?;
2624→
2625→        let model = params
2626→            .get("model")
2627→            .and_then(|v| v.as_str())
2628→            .ok_or_else(|| "missing 'model' parameter".to_string())?;
2629→
2630→        // Validate provider exists (known or custom).
2631→        if !is_custom_provider(provider_name) {
2632→            let known = known_providers();
2633→            if !known.iter().any(|p| p.name == provider_name) {
2634→                return Err(format!("unknown provider: {provider_name}").into());
2635→            }
2636→        }
2637→
2638→        // Prepend chosen model to existing saved models so it appears first,
2639→        // while preserving any previously chosen models.
2640→        let mut models = vec![model.to_string()];
2641→        if let Some(existing) = self.key_store.load_config(provider_name) {
2642→            models.extend(existing.models);
2643→        }
2644→
2645→        self.key_store
2646→            .save_config(provider_name, None, None, Some(models))
2647→            .map_err(ServiceError::message)?;
2648→
2649→        // Update the cross-provider priority list so the dropdown puts
2650→        // the chosen model at the top immediately.
2651→        if let Some(ref priority) = self.priority_models {
2652→            let mut list = priority.write().await;
2653→            // Remove any existing occurrence and prepend.
2654→            let normalized = model.to_string();
2655→            list.retain(|m| m != &normalized);
2656→            list.insert(0, normalized);
2657→        }
2658→
2659→        info!(
2660→            provider = provider_name,
2661→            model, "saved model preference and queued async registry rebuild"
2662→        );
2663→        self.queue_registry_rebuild(provider_name, "save_model");
2664→        Ok(serde_json::json!({ "ok": true }))
2665→    }
