2667→    async fn save_models(&self, params: Value) -> ServiceResult {
2668→        let _timing = ProviderSetupTiming::start(
2669→            "providers.save_models",
2670→            params.get("provider").and_then(Value::as_str),
2671→        );
2672→        let provider_name = params
2673→            .get("provider")
2674→            .and_then(|v| v.as_str())
2675→            .ok_or_else(|| "missing 'provider' parameter".to_string())?;
2676→
2677→        let models: Vec<String> = params
2678→            .get("models")
2679→            .and_then(|v| v.as_array())
2680→            .ok_or_else(|| "missing 'models' array parameter".to_string())?
2681→            .iter()
2682→            .filter_map(|v| v.as_str().map(String::from))
2683→            .collect();
2684→
2685→        // Validate provider exists (known or custom).
2686→        if !is_custom_provider(provider_name) {
2687→            let known = known_providers();
2688→            if !known.iter().any(|p| p.name == provider_name) {
2689→                return Err(format!("unknown provider: {provider_name}").into());
2690→            }
2691→        }
2692→
2693→        self.key_store
2694→            .save_config(provider_name, None, None, Some(models.clone()))
2695→            .map_err(ServiceError::message)?;
2696→
2697→        // Update the cross-provider priority list.
2698→        if let Some(ref priority) = self.priority_models {
2699→            let mut list = priority.write().await;
2700→            // Prepend all selected models in order, removing any existing
2701→            // occurrences to avoid duplicates.
2702→            for m in models.iter().rev() {
2703→                list.retain(|existing| existing != m);
2704→                list.insert(0, m.clone());
2705→            }
2706→        }
2707→
2708→        info!(
2709→            provider = provider_name,
2710→            count = models.len(),
2711→            models = ?models,
2712→            "saved model preferences and queued async registry rebuild"
2713→        );
2714→        self.queue_registry_rebuild(provider_name, "save_models");
2715→        Ok(serde_json::json!({ "ok": true }))
2716→    }
