2718→    async fn add_custom(&self, params: Value) -> ServiceResult {
2719→        let _timing = ProviderSetupTiming::start("providers.add_custom", None);
2720→
2721→        let base_url = params
2722→            .get("baseUrl")
2723→            .and_then(|v| v.as_str())
2724→            .filter(|s| !s.trim().is_empty())
2725→            .ok_or_else(|| "missing 'baseUrl' parameter".to_string())?;
2726→
2727→        let api_key = params
2728→            .get("apiKey")
2729→            .and_then(|v| v.as_str())
2730→            .filter(|s| !s.trim().is_empty())
2731→            .ok_or_else(|| "missing 'apiKey' parameter".to_string())?;
2732→
2733→        let model = params
2734→            .get("model")
2735→            .and_then(|v| v.as_str())
2736→            .filter(|s| !s.trim().is_empty());
2737→
2738→        let base_name = derive_provider_name_from_url(base_url)
2739→            .ok_or_else(|| "could not parse endpoint URL".to_string())?;
2740→
2741→        let existing = self.key_store.load_all_configs();
2742→        let provider_name = existing_custom_provider_for_base_url(base_url, &existing)
2743→            .unwrap_or_else(|| make_unique_provider_name(&base_name, &existing));
2744→        let reused_existing_provider = existing.contains_key(&provider_name);
2745→        let display_name = base_url_to_display_name(base_url);
2746→
2747→        let models = model.map(|m| vec![m.to_string()]);
2748→
2749→        self.key_store
2750→            .save_config_with_display_name(
2751→                &provider_name,
2752→                Some(api_key.to_string()),
2753→                Some(base_url.to_string()),
2754→                models,
2755→                Some(display_name.clone()),
2756→            )
2757→            .map_err(ServiceError::message)?;
2758→
2759→        set_provider_enabled_in_config(&provider_name, true)?;
2760→        self.set_provider_enabled_in_memory(&provider_name, true);
2761→
2762→        // Rebuild synchronously so the just-added custom provider is immediately
2763→        // available for model probing in the same UI flow.
2764→        let effective = self.effective_config();
2765→        let new_registry = self.build_registry(&effective);
2766→        let provider_summary = new_registry.provider_summary();
2767→        let model_count = new_registry.list_models().len();
2768→        let mut reg = self.registry.write().await;
2769→        *reg = new_registry;
2770→
2771→        info!(
2772→            provider = %provider_name,
2773→            display_name = %display_name,
2774→            reused = reused_existing_provider,
2775→            provider_summary = %provider_summary,
2776→            models = model_count,
2777→            "saved custom OpenAI-compatible provider and rebuilt provider registry"
2778→        );
2779→
2780→        Ok(serde_json::json!({
2781→            "ok": true,
2782→            "providerName": provider_name,
2783→            "displayName": display_name,
2784→        }))
2785→    }
