4169→    #[test]
4170→    #[serial_test::serial]
4171→    fn chat_stream_sends_error_for_no_provider() {
4172→        use std::sync::{Arc, Mutex};
4173→
4174→        // Force a no-provider environment so this test exercises the
4175→        // synchronous error callback path deterministically.
4176→        let original_registry = {
4177→            let mut guard = BRIDGE.registry.write().unwrap_or_else(|e| e.into_inner());
4178→            std::mem::replace(&mut *guard, ProviderRegistry::empty())
4179→        };
4180→        struct RestoreRegistry(Option<ProviderRegistry>);
4181→        impl Drop for RestoreRegistry {
4182→            fn drop(&mut self) {
4183→                if let Some(registry) = self.0.take() {
4184→                    let mut guard = BRIDGE.registry.write().unwrap_or_else(|e| e.into_inner());
4185→                    *guard = registry;
4186→                }
4187→            }
4188→        }
4189→        let _restore_registry = RestoreRegistry(Some(original_registry));
4190→
4191→        let events: Arc<Mutex<Vec<String>>> = Arc::new(Mutex::new(Vec::new()));
4192→        let events_clone = Arc::clone(&events);
4193→        let user_data = Arc::into_raw(events_clone) as *mut c_void;
4194→
4195→        unsafe extern "C" fn test_callback(event_json: *const c_char, user_data: *mut c_void) {
4196→            // SAFETY: event_json is a valid NUL-terminated C string from
4197→            // send_stream_event; user_data is our Arc<Mutex<Vec<String>>>.
4198→            unsafe {
4199→                let json = CStr::from_ptr(event_json).to_string_lossy().to_string();
4200→                let events = &*(user_data as *const Mutex<Vec<String>>);
4201→                events.lock().unwrap_or_else(|e| e.into_inner()).push(json);
4202→            }
4203→        }
4204→
4205→        // With an empty registry, this must error synchronously.
4206→        let request = r#"{"message":"test","model":"nonexistent-model-xyz"}"#;
4207→        let c_request = CString::new(request).unwrap_or_else(|e| panic!("{e}"));
4208→
4209→        // SAFETY: valid C string, valid callback, valid user_data.
4210→        unsafe {
4211→            moltis_chat_stream(c_request.as_ptr(), test_callback, user_data);
4212→        }
4213→
4214→        let events = unsafe { Arc::from_raw(user_data as *const Mutex<Vec<String>>) };
4215→        let received = events.lock().unwrap_or_else(|e| e.into_inner());
4216→
4217→        assert!(
4218→            !received.is_empty(),
4219→            "should receive at least one stream event"
4220→        );
4221→        let parsed: Value =
4222→            serde_json::from_str(&received[0]).unwrap_or_else(|e| panic!("bad json: {e}"));
4223→        assert_eq!(
4224→            parsed.get("type").and_then(Value::as_str),
4225→            Some("error"),
4226→            "expected an error event when no provider is available"
4227→        );
4228→    }
