4268→    #[test]
4269→    fn fallback_providers_ordering() {
4270→        // Build a registry with:
4271→        // - gpt-4o on "openai"
4272→        // - gpt-4o on "openrouter" (same model, different provider)
4273→        // - claude-sonnet on "anthropic" (different model, different provider)
4274→        // - gpt-4o-mini on "openai" (different model, same provider)
4275→        let mut reg = ProviderRegistry {
4276→            providers: HashMap::new(),
4277→            models: Vec::new(),
4278→        };
4279→
4280→        // Register in arbitrary order.
4281→        let mk = |id: &str, prov: &str| {
4282→            (
4283→                ModelInfo {
4284→                    id: id.into(),
4285→                    provider: prov.into(),
4286→                    display_name: id.into(),
4287→                    created_at: None,
4288→                    recommended: false,
4289→                    capabilities: ModelCapabilities::infer(id),
4290→                },
4291→                Arc::new(openai::OpenAiProvider::new_with_name(
4292→                    secret("k"),
4293→                    id.into(),
4294→                    "u".into(),
4295→                    prov.into(),
4296→                )) as Arc<dyn LlmProvider>,
4297→            )
4298→        };
4299→
4300→        let (info, prov) = mk("gpt-4o", "openai");
4301→        reg.register(info, prov);
4302→        let (info, prov) = mk("gpt-4o-mini", "openai");
4303→        reg.register(info, prov);
4304→        let (info, prov) = mk("claude-sonnet", "anthropic");
4305→        reg.register(info, prov);
4306→        // Simulate same model on different provider (openrouter).
4307→        // The registry key is model_id so we need a distinct key; use a composite.
4308→        // In practice the registry is keyed by model ID, so same model from
4309→        // different provider would need a different registration approach.
4310→        // For this test, use a unique key but same model info pattern.
4311→        let provider_or = Arc::new(openai::OpenAiProvider::new_with_name(
4312→            secret("k"),
4313→            "gpt-4o".into(),
4314→            "u".into(),
4315→            "openrouter".into(),
4316→        ));
4317→        // We can't register same model ID twice, so test the ordering
4318→        // with what we have: primary is gpt-4o/openai.
4319→        let fallbacks = reg.fallback_providers_for("openai::gpt-4o", "openai");
4320→        let ids: Vec<&str> = fallbacks.iter().map(|p| p.id()).collect();
4321→
4322→        // gpt-4o-mini (same provider) should come before claude-sonnet (other provider).
4323→        assert_eq!(ids, vec!["openai::gpt-4o-mini", "anthropic::claude-sonnet"]);
4324→
4325→        // Now test with primary being claude-sonnet/anthropic — both openai models should follow.
4326→        let fallbacks = reg.fallback_providers_for("anthropic::claude-sonnet", "anthropic");
4327→        let ids: Vec<&str> = fallbacks.iter().map(|p| p.id()).collect();
4328→        assert_eq!(ids, vec!["openai::gpt-4o", "openai::gpt-4o-mini"]);
4329→
4330→        // Verify we don't use the openrouter provider we created (not registered).
4331→        drop(provider_or);
4332→    }
