5774→    /// Native streaming provider that emits XML-like function text instead of
5775→    /// structured tool events on the first pass.
5776→    struct NativeTextFunctionStreamProvider {
5777→        call_count: std::sync::atomic::AtomicUsize,
5778→    }
5779→
5780→    #[async_trait]
5781→    impl LlmProvider for NativeTextFunctionStreamProvider {
5782→        fn name(&self) -> &str {
5783→            "mock-native-function-stream"
5784→        }
5785→
5786→        fn id(&self) -> &str {
5787→            "mock-native-function-stream"
5788→        }
5789→
5790→        fn supports_tools(&self) -> bool {
5791→            true
5792→        }
5793→
5794→        async fn complete(
5795→            &self,
5796→            _messages: &[ChatMessage],
5797→            _tools: &[serde_json::Value],
5798→        ) -> Result<CompletionResponse> {
5799→            Ok(CompletionResponse {
5800→                text: Some("fallback".into()),
5801→                tool_calls: vec![],
5802→                usage: Usage::default(),
5803→            })
5804→        }
5805→
5806→        fn stream(
5807→            &self,
5808→            messages: Vec<ChatMessage>,
5809→        ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
5810→            self.stream_with_tools(messages, vec![])
5811→        }
5812→
5813→        fn stream_with_tools(
5814→            &self,
5815→            messages: Vec<ChatMessage>,
5816→            _tools: Vec<serde_json::Value>,
5817→        ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
5818→            let count = self
5819→                .call_count
5820→                .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
5821→            if count == 0 {
5822→                Box::pin(tokio_stream::iter(vec![
5823→                    StreamEvent::Delta(
5824→                        "<function=process>\n<parameter=action>\nstart\n</parameter>\n<parameter=command>\npwd\n</parameter>\n</function>\n</tool_call>"
5825→                            .into(),
5826→                    ),
5827→                    StreamEvent::Done(Usage {
5828→                        input_tokens: 10,
5829→                        output_tokens: 15,
5830→                        ..Default::default()
5831→                    }),
5832→                ]))
5833→            } else {
5834→                let tool_content = messages
5835→                    .iter()
5836→                    .find_map(|m| {
5837→                        if let ChatMessage::Tool { content, .. } = m {
5838→                            Some(content.as_str())
5839→                        } else {
5840→                            None
5841→                        }
5842→                    })
5843→                    .unwrap_or("");
5844→                assert!(
5845→                    tool_content.contains("\"action\":\"start\""),
5846→                    "tool result should include action=start, got: {tool_content}"
5847→                );
5848→                assert!(
5849→                    tool_content.contains("\"command\":\"pwd\""),
5850→                    "tool result should include command=pwd, got: {tool_content}"
5851→                );
5852→                Box::pin(tokio_stream::iter(vec![
5853→                    StreamEvent::Delta("Process executed in fallback mode".into()),
5854→                    StreamEvent::Done(Usage {
5855→                        input_tokens: 5,
5856→                        output_tokens: 5,
5857→                        ..Default::default()
5858→                    }),
5859→                ]))
5860→            }
5861→        }
5862→    }
