7297→    /// Provider that makes 3 tool calls (one per iteration), then stops with
7298→    /// text repeatedly. Used to test that auto-continue nudges the model and
7299→    /// caps at the configured limit. The default threshold for auto-continue
7300→    /// is `agent_auto_continue_min_tool_calls = 3`, so we need at least 3 tool calls.
7301→    struct AutoContinueProvider {
7302→        call_count: std::sync::atomic::AtomicUsize,
7303→    }
