7305→    #[async_trait]
7306→    impl LlmProvider for AutoContinueProvider {
7307→        fn name(&self) -> &str {
7308→            "mock"
7309→        }
7310→
7311→        fn id(&self) -> &str {
7312→            "mock-model"
7313→        }
7314→
7315→        fn supports_tools(&self) -> bool {
7316→            true
7317→        }
7318→
7319→        async fn complete(
7320→            &self,
7321→            _messages: &[ChatMessage],
7322→            _tools: &[serde_json::Value],
7323→        ) -> Result<CompletionResponse> {
7324→            let count = self
7325→                .call_count
7326→                .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
7327→            if count < 3 {
7328→                // First 3 calls: make a tool call each time.
7329→                Ok(CompletionResponse {
7330→                    text: None,
7331→                    tool_calls: vec![ToolCall {
7332→                        id: format!("call_{}", count + 1),
7333→                        name: "echo_tool".into(),
7334→                        arguments: serde_json::json!({"text": format!("step {}", count + 1)}),
7335→                    }],
7336→                    usage: Usage {
7337→                        input_tokens: 10,
7338→                        output_tokens: 5,
7339→                        ..Default::default()
7340→                    },
7341→                })
7342→            } else {
7343→                // Subsequent calls: always return text without tool calls.
7344→                // This forces auto-continue to fire (until capped).
7345→                Ok(CompletionResponse {
7346→                    text: Some(format!("Partial result {count}")),
7347→                    tool_calls: vec![],
7348→                    usage: Usage {
7349→                        input_tokens: 10,
7350→                        output_tokens: 5,
7351→                        ..Default::default()
7352→                    },
7353→                })
7354→            }
7355→        }
7356→
7357→        fn stream(
7358→            &self,
7359→            _messages: Vec<ChatMessage>,
7360→        ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
7361→            Box::pin(tokio_stream::empty())
7362→        }
7363→    }
