7762→            Arc::new(std::sync::Mutex::new(Vec::new()));
7763→        let events_clone = Arc::clone(&events);
7764→        let on_event: OnEvent = Box::new(move |e| {
7765→            events_clone
7766→                .lock()
7767→                .unwrap_or_else(|e| e.into_inner())
7768→                .push(e);
