7778→            None,
7779→            None,
7780→            None,
7781→        )
7782→        .await
7783→        .unwrap();
7784→
7785→        let events = events.lock().unwrap_or_else(|e| e.into_inner());
7786→        let auto_continue_events: Vec<_> = events
7787→            .iter()
7788→            .filter(|e| matches!(e, RunnerEvent::AutoContinue { .. }))
7789→            .collect();
