8579→async fn deliver_channel_replies(
8580→    state: &Arc<dyn ChatRuntime>,
8581→    session_key: &str,
8582→    text: &str,
8583→    desired_reply_medium: ReplyMedium,
8584→    streamed_target_keys: &HashSet<ChannelReplyTargetKey>,
8585→) {
8586→    let drained_targets = state.drain_channel_replies(session_key).await;
8587→    let mut targets = Vec::with_capacity(drained_targets.len());
8588→    let mut streamed_targets = Vec::new();
8589→    // When the reply medium is voice we must still deliver TTS audio even if
8590→    // the text was already streamed — skip the stream dedupe entirely.
8591→    if desired_reply_medium != ReplyMedium::Voice && !streamed_target_keys.is_empty() {
8592→        for target in drained_targets {
8593→            let key = ChannelReplyTargetKey::from(&target);
8594→            if streamed_target_keys.contains(&key) {
8595→                streamed_targets.push(target);
8596→            } else {
8597→                targets.push(target);
8598→            }
8599→        }
8600→    } else {
8601→        targets = drained_targets;
8602→    }
8603→    let is_channel_session = session_key.starts_with("telegram:")
8604→        || session_key.starts_with("msteams:")
8605→        || session_key.starts_with("discord:");
8606→    if targets.is_empty() && streamed_targets.is_empty() {
8607→        let _ = state.drain_channel_status_log(session_key).await;
8608→        if is_channel_session {
8609→            info!(
8610→                session_key,
8611→                text_len = text.len(),
8612→                streamed_count = streamed_target_keys.len(),
8613→                "channel reply delivery skipped: no pending targets after stream dedupe"
8614→            );
8615→        }
8616→        return;
8617→    }
8618→    if text.is_empty() {
8619→        let _ = state.drain_channel_status_log(session_key).await;
8620→        if is_channel_session {
8621→            info!(
8622→                session_key,
8623→                target_count = targets.len() + streamed_targets.len(),
8624→                "channel reply delivery skipped: empty response text"
8625→            );
8626→        }
8627→        return;
8628→    }
8629→    if is_channel_session {
8630→        info!(
8631→            session_key,
8632→            target_count = targets.len(),
8633→            text_len = text.len(),
8634→            reply_medium = ?desired_reply_medium,
8635→            "channel reply delivery starting"
8636→        );
8637→    }
8638→    let outbound = match state.channel_outbound() {
8639→        Some(o) => o,
8640→        None => {
8641→            if is_channel_session {
8642→                info!(
8643→                    session_key,
8644→                    target_count = targets.len(),
8645→                    "channel reply delivery skipped: outbound unavailable"
8646→                );
8647→            }
8648→            return;
8649→        },
8650→    };
8651→    // Drain buffered status log entries to build a logbook suffix.
8652→    let status_log = state.drain_channel_status_log(session_key).await;
8653→    let logbook_html = format_logbook_html(&status_log);
8654→    if !streamed_targets.is_empty() && !logbook_html.is_empty() {
8655→        send_channel_logbook_follow_up_to_targets(
8656→            Arc::clone(&outbound),
8657→            streamed_targets,
8658→            &logbook_html,
8659→        )
8660→        .await;
8661→    }
8662→    if targets.is_empty() {
8663→        if is_channel_session {
8664→            info!(
8665→                session_key,
8666→                text_len = text.len(),
8667→                streamed_count = streamed_target_keys.len(),
8668→                "channel reply delivery completed via stream-only targets"
8669→            );
8670→        }
8671→        return;
8672→    }
8673→    deliver_channel_replies_to_targets(
8674→        outbound,
8675→        targets,
8676→        session_key,
8677→        text,
8678→        Arc::clone(state),
8679→        desired_reply_medium,
8680→        status_log,
8681→        streamed_target_keys,
8682→    )
8683→    .await;
8684→}
