8686→/// Format buffered status log entries into a Telegram expandable blockquote HTML.
8687→/// Returns an empty string if there are no entries.
8688→fn format_logbook_html(entries: &[String]) -> String {
8689→    if entries.is_empty() {
8690→        return String::new();
8691→    }
8692→    let mut html = String::from("<blockquote expandable>\n\u{1f4cb} <b>Activity log</b>\n");
8693→    for entry in entries {
8694→        // Escape HTML entities in the entry text.
8695→        let escaped = entry
8696→            .replace('&', "&amp;")
8697→            .replace('<', "&lt;")
8698→            .replace('>', "&gt;");
8699→        html.push_str(&format!("\u{2022} {escaped}\n"));
8700→    }
8701→    html.push_str("</blockquote>");
8702→    html
8703→}
