8742→fn format_channel_retry_message(error_obj: &Value, retry_after: Duration) -> String {
8743→    let retry_secs = ((retry_after.as_millis() as u64).saturating_add(999) / 1_000).max(1);
8744→    if error_obj.get("type").and_then(|v| v.as_str()) == Some("rate_limit_exceeded") {
8745→        format!("⏳ Provider rate limited. Retrying in {retry_secs}s.")
