8759→        .unwrap_or("Request failed");
8760→    let detail = error_obj
8761→        .get("detail")
8762→        .and_then(|v| v.as_str())
8763→        .or_else(|| error_obj.get("message").and_then(|v| v.as_str()))
8764→        .unwrap_or("Please try again.");
