8768→/// Format a user-facing notice announcing that a session was compacted.
8769→///
8770→/// Shown verbatim to channel users (Telegram, Discord, WhatsApp, etc.) and
8771→/// kept short so small mobile clients don't wrap the whole thing.
8772→///
8773→/// When `include_settings_hint` is false, the "Change chat.compaction.mode…"
8774→/// footer is omitted so users who have set
8775→/// `chat.compaction.show_settings_hint = false` don't see the repetitive
8776→/// hint on every compaction. Mode + token lines are always included.
8777→/// The LLM retry path never sees this text regardless.
8778→fn format_channel_compaction_notice(
8779→    outcome: &compaction_run::CompactionOutcome,
8780→    include_settings_hint: bool,
8781→) -> String {
8782→    let mode_label = match outcome.effective_mode {
8783→        moltis_config::CompactionMode::Deterministic => "Deterministic",
8784→        moltis_config::CompactionMode::RecencyPreserving => "Recency preserving",
8785→        moltis_config::CompactionMode::Structured => "Structured",
8786→        moltis_config::CompactionMode::LlmReplace => "LLM replace",
8787→    };
8788→    let total = outcome.total_tokens();
8789→    let token_line = if total == 0 {
8790→        // Any strategy that made no LLM calls ends up here: Deterministic,
8791→        // RecencyPreserving, or a Structured run that fell back to
8792→        // recency_preserving before the LLM call landed. Report the
8793→        // actual effective mode so users don't see "deterministic
8794→        // strategy" when they picked recency_preserving.
8795→        format!(
8796→            "No LLM tokens used ({} strategy)",
8797→            mode_label.to_lowercase()
8798→        )
8799→    } else {
8800→        format!(
8801→            "Used {total} tokens ({input} in + {output} out)",
8802→            total = total,
8803→            input = outcome.input_tokens,
8804→            output = outcome.output_tokens,
8805→        )
8806→    };
8807→    let body = format!(
8808→        "🧹 Conversation compacted\n\
8809→         Mode: {mode_label}\n\
8810→         {token_line}",
8811→    );
8812→    if include_settings_hint {
8813→        format!("{body}\n{hint}", hint = compaction_run::SETTINGS_HINT)
8814→    } else {
8815→        body
8816→    }
8817→}
