use std::sync::Arc;

use crate::state::GatewayState;

/// Gateway implementation of [`moltis_tools::location::LocationRequester`].
///
/// Uses the `PendingInvoke` + oneshot pattern to request the user's browser
/// geolocation and waits for `location.result` RPC to resolve it.
pub(crate) struct GatewayLocationRequester {
    pub(crate) state: Arc<GatewayState>,
}

#[async_trait::async_trait]
impl moltis_tools::location::LocationRequester for GatewayLocationRequester {
    async fn request_location(
        &self,
        conn_id: &str,
        precision: moltis_tools::location::LocationPrecision,
    ) -> moltis_tools::Result<moltis_tools::location::LocationResult> {
        use moltis_tools::location::{LocationError, LocationResult};

        let request_id = uuid::Uuid::new_v4().to_string();

        // Send a location.request event to the browser client, including
        // the requested precision so JS can adjust geolocation options.
        let event = moltis_protocol::EventFrame::new(
            "location.request",
            serde_json::json!({ "requestId": request_id, "precision": precision }),
            self.state.next_seq(),
        );
        let event_json = serde_json::to_string(&event)?;

        {
            let inner = self.state.inner.read().await;
            let clients = &inner.clients;
            let client = clients.get(conn_id).ok_or_else(|| {
                moltis_tools::Error::message(format!("no client connection for conn_id {conn_id}"))
            })?;
            if !client.send(&event_json) {
                return Err(moltis_tools::Error::message(format!(
                    "failed to send location request to client {conn_id}"
                )));
            }
        }

        // Set up a oneshot for the result with timeout.
        let (tx, rx) = tokio::sync::oneshot::channel();
        {
            let mut inner_w = self.state.inner.write().await;
            let invokes = &mut inner_w.pending_invokes;
            invokes.insert(request_id.clone(), crate::state::PendingInvoke {
                request_id: request_id.clone(),
                sender: tx,
                created_at: std::time::Instant::now(),
            });
        }

        // Wait up to 30 seconds for the user to grant/deny permission.
        let result = match tokio::time::timeout(std::time::Duration::from_secs(30), rx).await {
            Ok(Ok(value)) => value,
            Ok(Err(_)) => {
                // Sender dropped — clean up.
                self.state
                    .inner
                    .write()
                    .await
                    .pending_invokes
                    .remove(&request_id);
                return Ok(LocationResult {
                    location: None,
                    error: Some(LocationError::Timeout),
                });
            },
            Err(_) => {
                // Timeout — clean up.
                self.state
                    .inner
                    .write()
                    .await
                    .pending_invokes
                    .remove(&request_id);
                return Ok(LocationResult {
                    location: None,
                    error: Some(LocationError::Timeout),
                });
            },
        };

        // Parse the result from the browser.
        if let Some(loc) = result.get("location") {
            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
            Ok(LocationResult {
                location: Some(moltis_tools::location::BrowserLocation {
                    latitude: lat,
                    longitude: lon,
                    accuracy,
                }),
                error: None,
            })
        } else if let Some(err) = result.get("error") {
            let code = err.get("code").and_then(|v| v.as_u64()).unwrap_or(0);
            let error = match code {
                1 => LocationError::PermissionDenied,
                2 => LocationError::PositionUnavailable,
                3 => LocationError::Timeout,
                _ => LocationError::NotSupported,
            };
            Ok(LocationResult {
                location: None,
                error: Some(error),
            })
        } else {
            Ok(LocationResult {
                location: None,
                error: Some(LocationError::PositionUnavailable),
            })
        }
    }

    fn cached_location(&self) -> Option<moltis_config::GeoLocation> {
        self.state.inner.try_read().ok()?.cached_location.clone()
    }

    async fn request_channel_location(
        &self,
        session_key: &str,
    ) -> moltis_tools::Result<moltis_tools::location::LocationResult> {
        use moltis_tools::location::{LocationError, LocationResult};

        // Look up channel binding from session metadata.
        let session_meta = self
            .state
            .services
            .session_metadata
            .as_ref()
            .ok_or_else(|| moltis_tools::Error::message("session metadata not available"))?;
        let entry = session_meta.get(session_key).await.ok_or_else(|| {
            moltis_tools::Error::message(format!("no session metadata for key {session_key}"))
        })?;
        let binding_json = entry.channel_binding.ok_or_else(|| {
            moltis_tools::Error::message(format!("no channel binding for session {session_key}"))
        })?;
        let reply_target: moltis_channels::ChannelReplyTarget =
            serde_json::from_str(&binding_json)?;

        // Send a message asking the user to share their location.
        let outbound = self
            .state
            .services
            .channel_outbound_arc()
            .ok_or_else(|| moltis_tools::Error::message("no channel outbound available"))?;
        outbound
            .send_text(
                &reply_target.account_id,
                &reply_target.outbound_to(),
                "Please share your location in this chat, or paste a geo: link / map pin.",
                None,
            )
            .await
            .map_err(|e| moltis_tools::Error::external("send location request", e))?;

        // Create a pending invoke keyed by session.
        let pending_key = format!("channel_location:{session_key}");
        let (tx, rx) = tokio::sync::oneshot::channel();
        {
            let mut inner = self.state.inner.write().await;
            inner
                .pending_invokes
                .insert(pending_key.clone(), crate::state::PendingInvoke {
                    request_id: pending_key.clone(),
                    sender: tx,
                    created_at: std::time::Instant::now(),
                });
        }

        // Wait up to 60 seconds — user needs to navigate Telegram's UI.
        let result = match tokio::time::timeout(std::time::Duration::from_secs(60), rx).await {
            Ok(Ok(value)) => value,
            Ok(Err(_)) => {
                self.state
                    .inner
                    .write()
                    .await
                    .pending_invokes
                    .remove(&pending_key);
                return Ok(LocationResult {
                    location: None,
                    error: Some(LocationError::Timeout),
                });
            },
            Err(_) => {
                self.state
                    .inner
                    .write()
                    .await
                    .pending_invokes
                    .remove(&pending_key);
                return Ok(LocationResult {
                    location: None,
                    error: Some(LocationError::Timeout),
                });
            },
        };

        // Parse the result (same format as update_location sends).
        if let Some(loc) = result.get("location") {
            let lat = loc.get("latitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
            let lon = loc.get("longitude").and_then(|v| v.as_f64()).unwrap_or(0.0);
            let accuracy = loc.get("accuracy").and_then(|v| v.as_f64()).unwrap_or(0.0);
            Ok(LocationResult {
                location: Some(moltis_tools::location::BrowserLocation {
                    latitude: lat,
                    longitude: lon,
                    accuracy,
                }),
                error: None,
            })
        } else {
            Ok(LocationResult {
                location: None,
                error: Some(LocationError::PositionUnavailable),
            })
        }
    }
}

use std::{
    collections::HashMap,
    path::PathBuf,
    sync::{Arc, Mutex},
};

use {
    serde_json::Value,
    tracing::warn,
};

use moltis_providers::raw_model_id;

// ── Model normalization helpers ────────────────────────────────────────────

pub(crate) fn normalize_model_list(models: impl IntoIterator<Item = String>) -> Vec<String> {
    let mut out = Vec::new();
    for model in models {
        let trimmed = model.trim();
        if trimmed.is_empty() {
            continue;
        }
        // Persist raw IDs so provider-local preferences don't collide with
        // another provider's namespace (e.g. "openai::gpt-5.2").
        let normalized = raw_model_id(trimmed).trim().to_string();
        if normalized.is_empty() {
            continue;
        }
        if out.iter().any(|existing: &String| existing == &normalized) {
            continue;
        }
        out.push(normalized);
    }
    out
}

pub(crate) fn parse_models_param(params: &Value) -> Vec<String> {
    let from_array = params
        .get("models")
        .and_then(Value::as_array)
        .map(|values| {
            values
                .iter()
                .filter_map(Value::as_str)
                .map(ToString::to_string)
                .collect::<Vec<String>>()
        })
        .unwrap_or_default();

    let mut models = normalize_model_list(from_array);
    if models.is_empty()
        && let Some(model) = params.get("model").and_then(Value::as_str)
    {
        models = normalize_model_list([model.to_string()]);
    }
    models
}

// ── ProviderConfig ─────────────────────────────────────────────────────────

/// Per-provider stored configuration (API key, base URL, preferred models).
#[derive(Debug, Clone, Default, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct ProviderConfig {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub api_key: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub base_url: Option<String>,
    #[serde(
        default,
        alias = "model",
        deserialize_with = "deserialize_provider_models",
        skip_serializing_if = "Vec::is_empty"
    )]
    pub models: Vec<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub display_name: Option<String>,
}

fn deserialize_provider_models<'de, D>(deserializer: D) -> Result<Vec<String>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    let value: Value = serde::Deserialize::deserialize(deserializer)?;
    let normalized = match value {
        Value::Null => Vec::new(),
        Value::String(model) => vec![model],
        Value::Array(values) => values
            .into_iter()
            .filter_map(|value| value.as_str().map(ToString::to_string))
            .collect(),
        _ => {
            return Err(serde::de::Error::custom(
                "models must be a string or string array",
            ));
        },
    };

    Ok(normalize_model_list(normalized))
}

// ── KeyStore ───────────────────────────────────────────────────────────────

/// File-based provider config storage at `~/.config/moltis/provider_keys.json`.
/// Stores per-provider configuration including API keys, base URLs, and models.
#[derive(Debug, Clone)]
pub struct KeyStore {
    inner: Arc<Mutex<KeyStoreInner>>,
}

#[derive(Debug)]
struct KeyStoreInner {
    path: PathBuf,
}

impl Default for KeyStore {
    fn default() -> Self {
        Self::new()
    }
}

impl KeyStore {
    pub fn new() -> Self {
        let path = moltis_config::config_dir()
            .unwrap_or_else(|| PathBuf::from(".config/moltis"))
            .join("provider_keys.json");
        Self {
            inner: Arc::new(Mutex::new(KeyStoreInner { path })),
        }
    }

    pub(crate) fn with_path(path: PathBuf) -> Self {
        Self {
            inner: Arc::new(Mutex::new(KeyStoreInner { path })),
        }
    }

    fn lock(&self) -> std::sync::MutexGuard<'_, KeyStoreInner> {
        self.inner.lock().unwrap_or_else(|e| e.into_inner())
    }

    pub(crate) fn path(&self) -> PathBuf {
        self.lock().path.clone()
    }

    /// Load all provider configs. Handles migration from old format (string values).
    fn load_all_configs_from_path(path: &PathBuf) -> HashMap<String, ProviderConfig> {
        let content = match std::fs::read_to_string(path) {
            Ok(c) => c,
            Err(error) => {
                if error.kind() != std::io::ErrorKind::NotFound {
                    warn!(
                        path = %path.display(),
                        error = %error,
                        "failed to read provider key store"
                    );
                }
                return HashMap::new();
            },
        };

        // Try parsing as new format first
        if let Ok(configs) = serde_json::from_str::<HashMap<String, ProviderConfig>>(&content) {
            return configs;
        }

        // Fall back to old format migration: { "provider": "api-key-string" }
        if let Ok(old_format) = serde_json::from_str::<HashMap<String, String>>(&content) {
            return old_format
                .into_iter()
                .map(|(k, v)| {
                    (k, ProviderConfig {
                        api_key: Some(v),
                        base_url: None,
                        models: Vec::new(),
                        display_name: None,
                    })
                })
                .collect();
        }

        warn!(
            path = %path.display(),
            "provider key store is invalid JSON and will be ignored"
        );
        HashMap::new()
    }

    pub fn load_all_configs(&self) -> HashMap<String, ProviderConfig> {
        let guard = self.lock();
        Self::load_all_configs_from_path(&guard.path)
    }

    /// Save all provider configs to disk.
    fn save_all_configs_to_path(
        path: &PathBuf,
        configs: &HashMap<String, ProviderConfig>,
    ) -> crate::error::Result<()> {
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent).map_err(|error| {
                warn!(
                    path = %parent.display(),
                    error = %error,
                    "failed to create provider key store directory"
                );
                crate::error::Error::external("failed to create provider key store directory", error)
            })?;
        }
        let data = serde_json::to_string_pretty(configs).map_err(|error| {
            warn!(error = %error, "failed to serialize provider key store");
            error
        })?;

        // Write atomically via temp file + rename so readers never observe
        // partially-written JSON.
        let nanos = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_nanos())
            .unwrap_or(0);
        let temp_path = path.with_extension(format!("json.tmp.{nanos}"));
        std::fs::write(&temp_path, &data).map_err(|error| {
            warn!(
                path = %temp_path.display(),
                error = %error,
                "failed to write provider key store temp file"
            );
            crate::error::Error::external("failed to write provider key store temp file", error)
        })?;
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let _ = std::fs::set_permissions(&temp_path, std::fs::Permissions::from_mode(0o600));
        }

        std::fs::rename(&temp_path, path).map_err(|error| {
            warn!(
                temp_path = %temp_path.display(),
                path = %path.display(),
                error = %error,
                "failed to atomically replace provider key store"
            );
            crate::error::Error::external("failed to atomically replace provider key store", error)
        })?;

        Ok(())
    }

    /// Load all API keys (used in tests).
    #[cfg_attr(not(test), allow(dead_code))]
    pub(crate) fn load_all(&self) -> HashMap<String, String> {
        self.load_all_configs()
            .into_iter()
            .filter_map(|(k, v)| v.api_key.map(|key| (k, key)))
            .collect()
    }

    /// Load a provider's API key.
    pub(crate) fn load(&self, provider: &str) -> Option<String> {
        self.load_all_configs()
            .get(provider)
            .and_then(|c| c.api_key.clone())
    }

    /// Load a provider's full config.
    pub fn load_config(&self, provider: &str) -> Option<ProviderConfig> {
        self.load_all_configs().get(provider).cloned()
    }

    /// Remove a provider's configuration.
    pub(crate) fn remove(&self, provider: &str) -> crate::error::Result<()> {
        let guard = self.lock();
        let mut configs = Self::load_all_configs_from_path(&guard.path);
        configs.remove(provider);
        Self::save_all_configs_to_path(&guard.path, &configs)
    }

    /// Save a provider's API key (simple interface, used in tests).
    #[cfg_attr(not(test), allow(dead_code))]
    pub(crate) fn save(&self, provider: &str, api_key: &str) -> crate::error::Result<()> {
        self.save_config(
            provider,
            Some(api_key.to_string()),
            None, // preserve existing base_url
            None, // preserve existing models
        )
    }

    /// Save a provider's full configuration.
    pub fn save_config(
        &self,
        provider: &str,
        api_key: Option<String>,
        base_url: Option<String>,
        models: Option<Vec<String>>,
    ) -> crate::error::Result<()> {
        self.save_config_with_display_name(provider, api_key, base_url, models, None)
    }

    /// Save a provider's full configuration, including an optional display name.
    pub(crate) fn save_config_with_display_name(
        &self,
        provider: &str,
        api_key: Option<String>,
        base_url: Option<String>,
        models: Option<Vec<String>>,
        display_name: Option<String>,
    ) -> crate::error::Result<()> {
        let guard = self.lock();
        let mut configs = Self::load_all_configs_from_path(&guard.path);
        let entry = configs.entry(provider.to_string()).or_default();

        // Only update fields that are provided (Some), preserve existing for None
        if let Some(key) = api_key {
            entry.api_key = Some(key);
        }
        if let Some(url) = base_url {
            entry.base_url = if url.is_empty() {
                None
            } else {
                Some(url)
            };
        }
        if let Some(models) = models {
            entry.models = normalize_model_list(models);
        }
        if let Some(name) = display_name {
            entry.display_name = Some(name);
        }

        Self::save_all_configs_to_path(&guard.path, &configs)
    }
}

#[allow(clippy::unwrap_used, clippy::expect_used)]
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn key_store_save_and_load() {
        let dir = tempfile::tempdir().unwrap();
        let store = KeyStore::with_path(dir.path().join("keys.json"));
        assert!(store.load("anthropic").is_none());
        store.save("anthropic", "sk-test-123").unwrap();
        assert_eq!(store.load("anthropic").unwrap(), "sk-test-123");
        // Overwrite
        store.save("anthropic", "sk-new").unwrap();
        assert_eq!(store.load("anthropic").unwrap(), "sk-new");
        // Multiple providers
        store.save("openai", "sk-openai").unwrap();
