//! Error classification and retry delay logic for transient provider failures.

use tracing::warn;

/// Error patterns that indicate the context window has been exceeded.
const CONTEXT_WINDOW_PATTERNS: &[&str] = &[
    "context_length_exceeded",
    "context_window_exceeded",
    "context_window_exceeded",
    "max_tokens",
    "too many tokens",
    "request too large",
    "maximum context length",
    "context window",
    "token limit",
    "input too long",
    "input_too_long",
    "content_too_large",
    "request_too_large",
];

/// Check if an error message indicates a context window overflow.
pub(crate) fn is_context_window_error(msg: &str) -> bool {
    let lower = msg.to_lowercase();
    CONTEXT_WINDOW_PATTERNS.iter().any(|p| lower.contains(p))
}

/// Error patterns that indicate a transient server error worth retrying.
const RETRYABLE_SERVER_PATTERNS: &[&str] = &[
    "http 500",
    "http 502",
    "http 503",
    "http 529",
    "server_error",
    "internal server error",
    "overloaded",
    "bad gateway",
    "service unavailable",
    "the server had an error processing your request",
];

/// Check if an error looks like a transient provider failure that may
/// succeed on retry (5xx, overloaded, etc.).
pub(crate) fn is_retryable_server_error(msg: &str) -> bool {
    let lower = msg.to_ascii_lowercase();
    RETRYABLE_SERVER_PATTERNS.iter().any(|p| lower.contains(p))
}

/// Error patterns that indicate provider-side rate limiting.
const RATE_LIMIT_PATTERNS: &[&str] = &[
    "http 429",
    "status=429",
    "status 429",
    "status: 429",
    "too many requests",
    "rate limit",
    "rate_limit",
];

pub(crate) fn is_rate_limit_error(msg: &str) -> bool {
    let lower = msg.to_ascii_lowercase();
    RATE_LIMIT_PATTERNS.iter().any(|p| lower.contains(p))
}

/// Error patterns that indicate the account is out of credits/quota.
/// These are not retryable in the short term and should surface directly.
const BILLING_QUOTA_PATTERNS: &[&str] = &[
    "insufficient_quota",
    "quota exceeded",
    "current quota",
    "billing details",
    "billing limit",
    "credit balance",
];

pub(crate) fn is_billing_quota_error(msg: &str) -> bool {
    let lower = msg.to_ascii_lowercase();
    BILLING_QUOTA_PATTERNS.iter().any(|p| lower.contains(p))
}

/// Base delay for non-rate-limit transient retries.
pub(crate) const SERVER_RETRY_DELAY: std::time::Duration = std::time::Duration::from_secs(2);

/// Rate-limit retries use exponential backoff with a cap.
pub(crate) const RATE_LIMIT_INITIAL_RETRY_MS: u64 = 2_000;
pub(crate) const RATE_LIMIT_MAX_RETRY_MS: u64 = 60_000;
pub(crate) const RATE_LIMIT_MAX_RETRIES: u8 = 10;

pub(crate) fn next_rate_limit_retry_ms(previous_ms: Option<u64>) -> u64 {
    previous_ms
        .map(|ms| ms.saturating_mul(2))
        .unwrap_or(RATE_LIMIT_INITIAL_RETRY_MS)
        .clamp(RATE_LIMIT_INITIAL_RETRY_MS, RATE_LIMIT_MAX_RETRY_MS)
}

fn parse_retry_delay_ms_from_fragment(
    fragment: &str,
    unit_default_ms: bool,
    max_ms: u64,
) -> Option<u64> {
    let start = fragment.find(|c: char| c.is_ascii_digit())?;
    let tail = &fragment[start..];
    let digits_len = tail.chars().take_while(|c| c.is_ascii_digit()).count();
    if digits_len == 0 {
        return None;
    }
    let amount = tail[..digits_len].parse::<u64>().ok()?;
    let unit = tail[digits_len..].trim_start();

    let ms = if unit.starts_with("ms") || unit.starts_with("millisecond") {
        amount
    } else if unit.starts_with("sec") || unit.starts_with("second") || unit.starts_with('s') {
        amount.saturating_mul(1_000)
    } else if unit.starts_with("min") || unit.starts_with("minute") || unit.starts_with('m') {
        amount.saturating_mul(60_000)
    } else if unit_default_ms {
        amount
    } else {
        amount.saturating_mul(1_000)
    };

    Some(ms.clamp(1, max_ms))
}

/// Extract retry delay hints embedded in provider error messages.
///
/// Supports patterns like:
/// - `retry_after_ms=1234`
/// - `Retry-After: 30`
/// - `retry after 30s`
/// - `retry in 45 seconds`
pub(crate) fn extract_retry_after_ms(msg: &str, max_ms: u64) -> Option<u64> {
    let lower = msg.to_ascii_lowercase();
    for (needle, default_ms) in [
        ("retry_after_ms=", true),
        ("retry-after-ms=", true),
        ("retry_after=", false),
        ("retry-after:", false),
        ("retry after ", false),
        ("retry in ", false),
    ] {
        if let Some(idx) = lower.find(needle) {
            let fragment = &lower[idx + needle.len()..];
            if let Some(ms) = parse_retry_delay_ms_from_fragment(fragment, default_ms, max_ms) {
                return Some(ms);
            }
        }
    }
    None
}

pub(crate) fn next_retry_delay_ms(
    msg: &str,
    server_retries_remaining: &mut u8,
    rate_limit_retries_remaining: &mut u8,
    rate_limit_backoff_ms: &mut Option<u64>,
) -> Option<u64> {
    // Account/billing quota exhaustion is not transient; don't auto-retry.
    if is_billing_quota_error(msg) {
        return None;
    }

    if is_rate_limit_error(msg) {
        if *rate_limit_retries_remaining == 0 {
            return None;
        }
        *rate_limit_retries_remaining -= 1;

        // Keep exponential state advancing even when the provider gives a
        // Retry-After hint, so future retries remain bounded and predictable.
        let current_backoff = *rate_limit_backoff_ms;
        *rate_limit_backoff_ms = Some(next_rate_limit_retry_ms(current_backoff));

        let hinted_ms = extract_retry_after_ms(msg, RATE_LIMIT_MAX_RETRY_MS);
        let delay_ms = hinted_ms
            .or(*rate_limit_backoff_ms)
            .unwrap_or(RATE_LIMIT_INITIAL_RETRY_MS);
        return Some(delay_ms.clamp(1, RATE_LIMIT_MAX_RETRY_MS));
    }

    if is_retryable_server_error(msg) {
        if *server_retries_remaining == 0 {
            return None;
        }
        *server_retries_remaining -= 1;
        return Some(SERVER_RETRY_DELAY.as_millis() as u64);
    }

    None
}

/// Fallback loop limit when config is missing or invalid.
pub(crate) const DEFAULT_AGENT_MAX_ITERATIONS: usize = 25;

pub(crate) fn resolve_agent_max_iterations(configured: usize) -> usize {
    if configured == 0 {
        warn!(
            default = DEFAULT_AGENT_MAX_ITERATIONS,
            "tools.agent_max_iterations was 0; falling back to default"
        );
        return DEFAULT_AGENT_MAX_ITERATIONS;
    }
    configured
}

//! Global bridge state: tokio runtime, provider registry, session stores, and HTTP server handle.

use std::{
    net::SocketAddr,
    sync::{Arc, LazyLock, Mutex, RwLock},
};

use {
    moltis_providers::ProviderRegistry,
    moltis_sessions::{
        metadata::SqliteSessionMetadata,
        session_events::SessionEventBus,
        store::SessionStore,
    },
};

use crate::callbacks::emit_log;

// ── Global bridge state ──────────────────────────────────────────────────

pub(crate) struct BridgeState {
    pub runtime: tokio::runtime::Runtime,
    pub registry: RwLock<ProviderRegistry>,
    pub session_store: SessionStore,
    pub session_metadata: SqliteSessionMetadata,
    pub credential_store: Arc<moltis_gateway::auth::CredentialStore>,
    pub sandbox_default_image_override: RwLock<Option<String>>,
}

impl BridgeState {
    fn new() -> Self {
        #[cfg(test)]
        init_swift_bridge_test_dirs();

        emit_log(
            "INFO",
            "bridge",
            "Initializing Rust bridge (tokio runtime + registry)",
        );
        let runtime = tokio::runtime::Builder::new_multi_thread()
            .worker_threads(2)
            .enable_all()
            .build()
            .unwrap_or_else(|e| panic!("failed to create tokio runtime: {e}"));

        let registry = build_registry();

        // Initialize persistent session storage (JSONL message files).
        let data_dir = moltis_config::data_dir();
        let sessions_dir = data_dir.join("sessions");
        if let Err(e) = std::fs::create_dir_all(&sessions_dir) {
            emit_log(
                "ERROR",
                "bridge",
                &format!("Failed to create sessions dir: {e}"),
            );
        }
        let session_store = SessionStore::new(sessions_dir);

        // Open the shared SQLite database (same moltis.db used by the gateway).
        // WAL mode + synchronous=NORMAL avoids multi-second write contention.
        let db_path = data_dir.join("moltis.db");
        let db_pool = runtime.block_on(async {
            use {
                sqlx::sqlite::{SqliteConnectOptions, SqliteJournalMode, SqliteSynchronous},
                std::str::FromStr,
            };
            let opts = SqliteConnectOptions::from_str(&format!("sqlite:{}", db_path.display()))
                .expect("invalid moltis.db path")
                .create_if_missing(true)
                .journal_mode(SqliteJournalMode::Wal)
                .synchronous(SqliteSynchronous::Normal);
            let pool = sqlx::SqlitePool::connect_with(opts)
                .await
                .unwrap_or_else(|e| panic!("failed to open moltis.db: {e}"));
            // Run migrations so the sessions table exists even if the gateway
            // hasn't been started yet. Order: projects first (FK dependency).
            if let Err(e) = moltis_projects::run_migrations(&pool).await {
                emit_log("WARN", "bridge", &format!("projects migration: {e}"));
            }
            if let Err(e) = moltis_sessions::run_migrations(&pool).await {
                emit_log("WARN", "bridge", &format!("sessions migration: {e}"));
            }
            if let Err(e) = moltis_gateway::run_migrations(&pool).await {
                emit_log("WARN", "bridge", &format!("gateway migration: {e}"));
            }
            pool
        });
        let event_bus = SessionEventBus::new();
        let session_metadata = SqliteSessionMetadata::with_event_bus(db_pool.clone(), event_bus);
        let credential_store = runtime.block_on(async {
            // Keep vault metadata up to date so env var encryption status works
            // even when the full gateway server is not running.
            if let Err(e) = moltis_gateway::auth::moltis_vault::run_migrations(&db_pool).await {
                emit_log("WARN", "bridge", &format!("vault migration: {e}"));
            }

            let vault = match moltis_gateway::auth::moltis_vault::Vault::new(db_pool.clone()).await
            {
                Ok(vault) => Some(Arc::new(vault)),
                Err(e) => {
                    emit_log("WARN", "bridge", &format!("vault init failed: {e}"));
                    None
                },
            };

            match moltis_gateway::auth::CredentialStore::with_vault(
                db_pool.clone(),
                &moltis_config::discover_and_load().auth,
                vault,
            )
            .await
            {
                Ok(store) => Arc::new(store),
                Err(e) => panic!("failed to init credential store: {e}"),
            }
        });

        emit_log("INFO", "bridge", "Bridge initialized successfully");
        Self {
            runtime,
            registry: RwLock::new(registry),
            session_store,
            session_metadata,
            credential_store,
            sandbox_default_image_override: RwLock::new(None),
        }
    }
}

#[cfg(test)]
fn init_swift_bridge_test_dirs() {
    static TEST_DIRS_INIT: std::sync::OnceLock<()> = std::sync::OnceLock::new();

    TEST_DIRS_INIT.get_or_init(|| {
        let base = std::env::temp_dir().join(format!(
            "moltis-swift-bridge-tests-{}-{}",
            std::process::id(),
            uuid::Uuid::new_v4().simple()
        ));
        let config_dir = base.join("config");
        let data_dir = base.join("data");

        if let Err(error) = std::fs::create_dir_all(&config_dir) {
            panic!("failed to create swift-bridge test config dir: {error}");
        }
        if let Err(error) = std::fs::create_dir_all(&data_dir) {
            panic!("failed to create swift-bridge test data dir: {error}");
        }

        moltis_config::set_config_dir(config_dir);
        moltis_config::set_data_dir(data_dir);
    });
}

pub(crate) fn build_registry() -> ProviderRegistry {
    let config = moltis_config::discover_and_load();
    let env_overrides = config.env.clone();
    let key_store = moltis_provider_setup::KeyStore::new();
    let effective =
        moltis_provider_setup::config_with_saved_keys(&config.providers, &key_store, &[]);
    #[cfg(test)]
    {
        ProviderRegistry::from_config_with_static_catalogs(&effective, &env_overrides)
    }
    #[cfg(not(test))]
    {
        ProviderRegistry::from_env_with_config_and_overrides(&effective, &env_overrides)
    }
}

pub(crate) static BRIDGE: LazyLock<BridgeState> = LazyLock::new(BridgeState::new);

// ── HTTP Server handle ───────────────────────────────────────────────────

/// Handle to a running httpd server, used to shut it down.
pub(crate) struct HttpdHandle {
    pub shutdown_tx: tokio::sync::oneshot::Sender<()>,
    pub server_task: tokio::task::JoinHandle<()>,
    pub addr: SocketAddr,
    /// Gateway state -- used for abort/peek FFI calls and kept alive while
    /// the server is running.
    pub state: std::sync::Arc<moltis_gateway::state::GatewayState>,
}

/// Global server handle -- `None` when stopped, `Some` when running.
pub(crate) static HTTPD: Mutex<Option<HttpdHandle>> = Mutex::new(None);

pub(crate) fn stop_httpd_handle(handle: HttpdHandle, log_target: &str, stop_message: &str) {
    emit_log("INFO", log_target, stop_message);
    let _ = handle.shutdown_tx.send(());
    BRIDGE.runtime.block_on(async {
        if let Err(error) = handle.server_task.await {
            emit_log(
                "WARN",
                log_target,
                &format!("httpd task join failed during shutdown: {error}"),
            );
        }
    });
}

//! Log, session event, and network audit callbacks for the Swift FFI layer.

use std::{
    collections::HashMap,
    ffi::{CString, c_char},
    sync::OnceLock,
};

use {
    moltis_sessions::session_events::SessionEvent,
    serde::Serialize,
};

// ── Log callback for Swift ───────────────────────────────────────────────

/// Callback type for forwarding log events to Swift. Rust owns the
/// `log_json` pointer -- the callback must copy the data before returning.
#[allow(unsafe_code)]
pub(crate) type LogCallback = unsafe extern "C" fn(log_json: *const c_char);

pub(crate) static LOG_CALLBACK: OnceLock<LogCallback> = OnceLock::new();

/// JSON-serializable log event sent to Swift.
#[derive(Debug, Serialize)]
struct BridgeLogEvent<'a> {
    level: &'a str,
    target: &'a str,
    message: &'a str,
    #[serde(skip_serializing_if = "Option::is_none")]
    fields: Option<&'a HashMap<&'a str, String>>,
}

pub(crate) fn emit_log(level: &str, target: &str, message: &str) {
    emit_log_with_fields(level, target, message, None);
}

#[allow(unsafe_code)]
pub(crate) fn emit_log_with_fields(
    level: &str,
    target: &str,
    message: &str,
    fields: Option<&HashMap<&str, String>>,
) {
    if let Some(callback) = LOG_CALLBACK.get() {
        let event = BridgeLogEvent {
            level,
            target,
            message,
            fields,
        };
        if let Ok(json) = serde_json::to_string(&event)
            && let Ok(c_str) = CString::new(json)
        {
            // SAFETY: c_str is valid NUL-terminated, callback copies
