    mode: AgentMemoryWriteMode,
    file: &str,
) -> anyhow::Result<()> {
    match mode {
        AgentMemoryWriteMode::Hybrid => Ok(()),
        AgentMemoryWriteMode::PromptOnly => {
            if is_prompt_memory_file(file) {
                Ok(())
            } else {
                anyhow::bail!(
