pub(crate) const PROMPT_MEMORY_NAMESPACE: &str = "__prompt_memory";

pub(crate) fn prompt_memory_snapshot_key(agent_id: &str) -> String {
    format!("snapshot:{agent_id}")
}

pub(crate) async fn clear_prompt_memory_snapshot(
    session_key: &str,
    agent_id: &str,
    state_store: Option<&SessionStateStore>,
) -> bool {
    let Some(store) = state_store else {
        return false;
    };
    let key = prompt_memory_snapshot_key(agent_id);
    match store
        .delete(session_key, PROMPT_MEMORY_NAMESPACE, &key)
        .await
    {
        Ok(deleted) => deleted,
        Err(error) => {
            warn!(
                session = %session_key,
                agent_id,
                error = %error,
                "failed to clear prompt memory snapshot"
            );
            false
        },
    }
}

pub(crate) fn prompt_memory_status(
    style: MemoryStyle,
    mode: PromptMemoryMode,
    write_mode: AgentMemoryWriteMode,
    snapshot_active: bool,
    memory: Option<&LoadedWorkspaceMarkdown>,
) -> PromptMemoryStatus {
    PromptMemoryStatus {
        style,
        mode,
        write_mode,
        snapshot_active,
        present: memory.is_some(),
        chars: memory.map_or(0, |entry| entry.content.chars().count()),
        path: memory.map(|entry| entry.path.to_string_lossy().into_owned()),
        file_source: memory.map(|entry| entry.source),
    }
}

pub(crate) fn resolve_prompt_agent_id(session_entry: Option<&SessionEntry>) -> String {
    let Some(entry) = session_entry else {
        return "main".to_string();
    };
    let Some(agent_id) = entry
        .agent_id
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    else {
        return "main".to_string();
    };
    if agent_id == "main" {
        return "main".to_string();
    }
    if moltis_config::agent_workspace_dir(agent_id).exists() {
        return agent_id.to_string();
    }
    warn!(
        session = %entry.key,
        agent_id,
        "session references unknown agent workspace, falling back to main prompt persona"
    );
    "main".to_string()
}

/// Load identity, user profile, soul, and workspace text for one agent.
pub(crate) fn load_prompt_persona_base_for_agent(agent_id: &str) -> PromptPersona {
    let config = moltis_config::discover_and_load();
    let prompt_memory_mode = config.chat.prompt_memory_mode;
    let agent_write_mode = config.memory.agent_write_mode;
    let memory_style = config.memory.style;
    let mut identity = config.identity.clone();
    if let Some(file_identity) = moltis_config::load_identity_for_agent(agent_id) {
        if file_identity.name.is_some() {
            identity.name = file_identity.name;
        }
        if file_identity.emoji.is_some() {
            identity.emoji = file_identity.emoji;
        }
        if file_identity.theme.is_some() {
            identity.theme = file_identity.theme;
        }
    }
    let user = moltis_config::resolve_user_profile_from_config(&config);
    PromptPersona {
        config,
        identity,
        user,
        soul_text: moltis_config::load_soul_for_agent(agent_id),
        boot_text: moltis_config::load_boot_md_for_agent(agent_id),
        agents_text: moltis_config::load_agents_md_for_agent(agent_id),
        tools_text: moltis_config::load_tools_md_for_agent(agent_id),
        memory_text: None,
        memory_status: prompt_memory_status(
            memory_style,
            prompt_memory_mode,
            agent_write_mode,
            false,
            None,
        ),
    }
}

pub(crate) fn load_prompt_persona_for_agent(agent_id: &str) -> PromptPersona {
    let mut persona = load_prompt_persona_base_for_agent(agent_id);
    let style = persona.config.memory.style;
    let mode = persona.config.chat.prompt_memory_mode;
    let write_mode = persona.config.memory.agent_write_mode;
    let memory = if memory_style_allows_prompt(style) {
        moltis_config::load_memory_md_for_agent_with_source(agent_id)
    } else {
        None
    };
    persona.memory_text = memory.as_ref().map(|entry| entry.content.clone());
    persona.memory_status = prompt_memory_status(style, mode, write_mode, false, memory.as_ref());
    persona
}

pub(crate) async fn load_prompt_memory_for_session(
    session_key: &str,
    agent_id: &str,
    mode: PromptMemoryMode,
    state_store: Option<&SessionStateStore>,
) -> (Option<LoadedWorkspaceMarkdown>, bool) {
    let live_memory = || moltis_config::load_memory_md_for_agent_with_source(agent_id);

    if !matches!(mode, PromptMemoryMode::FrozenAtSessionStart) {
        return (live_memory(), false);
    }

    let Some(store) = state_store else {
        return (live_memory(), false);
    };

    let key = prompt_memory_snapshot_key(agent_id);
    match store.get(session_key, PROMPT_MEMORY_NAMESPACE, &key).await {
        Ok(Some(raw)) => match serde_json::from_str::<Option<LoadedWorkspaceMarkdown>>(&raw) {
            Ok(snapshot) => return (snapshot, true),
            Err(error) => warn!(
                session = %session_key,
                agent_id,
                error = %error,
                "failed to deserialize prompt memory snapshot, rebuilding"
            ),
        },
        Ok(None) => {},
        Err(error) => warn!(
            session = %session_key,
            agent_id,
            error = %error,
            "failed to read prompt memory snapshot, falling back to live memory"
        ),
    }

    let memory = live_memory();
    match serde_json::to_string(&memory) {
        Ok(serialized) => {
            if let Err(error) = store
                .set(session_key, PROMPT_MEMORY_NAMESPACE, &key, &serialized)
                .await
            {
                warn!(
                    session = %session_key,
                    agent_id,
                    error = %error,
                    "failed to persist prompt memory snapshot"
                );
                return (memory, false);
            }
            (memory, true)
        },
        Err(error) => {
            warn!(
                session = %session_key,
                agent_id,
                error = %error,
                "failed to serialize prompt memory snapshot"
            );
            (memory, false)
        },
    }
}

pub(crate) async fn load_prompt_persona_for_session(
    session_key: &str,
    session_entry: Option<&SessionEntry>,
    state_store: Option<&SessionStateStore>,
) -> PromptPersona {
    let agent_id = resolve_prompt_agent_id(session_entry);
    let mut persona = load_prompt_persona_base_for_agent(&agent_id);
    let style = persona.config.memory.style;
    let mode = persona.config.chat.prompt_memory_mode;
    let write_mode = persona.config.memory.agent_write_mode;
    let (memory, snapshot_active) = if memory_style_allows_prompt(style) {
        load_prompt_memory_for_session(session_key, &agent_id, mode, state_store).await
    } else {
        (None, false)
    };
    persona.memory_text = memory.as_ref().map(|entry| entry.content.clone());
    persona.memory_status =
        prompt_memory_status(style, mode, write_mode, snapshot_active, memory.as_ref());
    persona
}

pub(crate) fn prompt_build_limits_from_config(
    config: &moltis_config::MoltisConfig,
) -> PromptBuildLimits {
    PromptBuildLimits {
        workspace_file_max_chars: config.chat.workspace_file_max_chars,
    }
}

/// Discover skills from the default filesystem paths, honoring `[skills] enabled`.
///
/// Returns an empty list when `config.skills.enabled` is `false`, so callers can
/// unconditionally feed the result into prompt building / tool filtering without
/// injecting skills into the LLM context when the operator has disabled them.
pub(crate) async fn discover_skills_if_enabled(
    config: &moltis_config::MoltisConfig,
) -> Vec<moltis_skills::types::SkillMetadata> {
    if !config.skills.enabled {
        return Vec::new();
    }
    let search_paths = moltis_skills::discover::FsSkillDiscoverer::default_paths();
    let discoverer = moltis_skills::discover::FsSkillDiscoverer::new(search_paths);
    match discoverer.discover().await {
        Ok(skills) => skills,
        Err(e) => {
            warn!("failed to discover skills: {e}");
            Vec::new()
        },
    }
}

pub(crate) fn resolve_channel_runtime_context(
    session_key: &str,
    session_entry: Option<&SessionEntry>,
) -> moltis_common::hooks::ChannelBinding {
    match moltis_channels::resolve_session_channel_binding(
        session_key,
        session_entry.and_then(|entry| entry.channel_binding.as_deref()),
    ) {
        Ok(binding) => binding,
        Err(error) => {
            warn!(
                error = %error,
                session = %session_key,
                "failed to parse channel_binding JSON; falling back to web"
            );
            moltis_channels::web_session_channel_binding()
        },
    }
}

pub(crate) fn channel_binding_from_runtime_context(
    runtime_context: Option<&PromptRuntimeContext>,
) -> Option<moltis_common::hooks::ChannelBinding> {
    let host = &runtime_context?.host;
    let binding = moltis_common::hooks::ChannelBinding {
        surface: host.surface.clone(),
        session_kind: host.session_kind.clone(),
        channel_type: host.channel_type.clone(),
        account_id: host.channel_account_id.clone(),
        chat_id: host.channel_chat_id.clone(),
        chat_type: host.channel_chat_type.clone(),
        sender_id: host.channel_sender_id.clone(),
    };
    (!binding.is_empty()).then_some(binding)
}

pub(crate) fn build_tool_context(
    session_key: &str,
    accept_language: Option<&str>,
    conn_id: Option<&str>,
    runtime_context: Option<&PromptRuntimeContext>,
) -> Value {
    let mut tool_context = serde_json::json!({
        "_session_key": session_key,
    });
    if let Some(channel_binding) = channel_binding_from_runtime_context(runtime_context)
        && let Ok(channel_value) = serde_json::to_value(channel_binding)
    {
        tool_context["_channel"] = channel_value;
    }
    if let Some(lang) = accept_language {
        tool_context["_accept_language"] = serde_json::json!(lang);
    }
    if let Some(cid) = conn_id {
        tool_context["_conn_id"] = serde_json::json!(cid);
    }
    tool_context
}

pub(crate) async fn build_prompt_runtime_context(
    state: &Arc<dyn ChatRuntime>,
    provider: &Arc<dyn moltis_agents::model::LlmProvider>,
    session_key: &str,
    session_entry: Option<&SessionEntry>,
) -> PromptRuntimeContext {
    let data_dir = moltis_config::data_dir();
    let data_dir_display = data_dir.display().to_string();

    let sudo_fut = detect_host_sudo_access();
    let sandbox_fut = async {
        if let Some(router) = state.sandbox_router() {
            let is_sandboxed = router.is_sandboxed(session_key).await;
            // Only include sandbox context when sandbox is actually enabled for
            // this session.  When disabled, omitting it prevents the LLM from
            // hallucinating sandbox usage (see #360).  This intentionally
            // discards `session_override` — its only consumer is the prompt
            // line we are omitting, and no other code reads it from
            // `PromptSandboxRuntimeContext`.
            if !is_sandboxed {
                return None;
            }
            let config = router.config();
            let backend_name = router.backend_name();
            let workspace_mount = config.workspace_mount.to_string();
            let workspace_path = (workspace_mount != "none").then(|| data_dir_display.clone());
            Some(PromptSandboxRuntimeContext {
                exec_sandboxed: true,
                mode: Some(config.mode.to_string()),
                backend: Some(backend_name.to_string()),
                scope: Some(config.scope.to_string()),
                image: Some(router.resolve_image(session_key, None).await),
                home: Some("/home/sandbox".to_string()),
                workspace_mount: Some(workspace_mount),
                workspace_path,
                no_network: prompt_sandbox_no_network_state(backend_name, config.no_network),
                session_override: session_entry.and_then(|entry| entry.sandbox_enabled),
            })
        } else {
            None
        }
    };

    let ((sudo_non_interactive, sudo_status), sandbox_ctx) = tokio::join!(sudo_fut, sandbox_fut);

    let configured_timezone = state
        .sandbox_router()
        .and_then(|r| r.config().timezone.clone());
    let timezone = Some(server_prompt_timezone(configured_timezone.as_deref()));

    let location = state
        .cached_location()
        .await
        .as_ref()
        .map(|loc| loc.to_string());
    let channel_context = resolve_channel_runtime_context(session_key, session_entry);

    let mut host_ctx = PromptHostRuntimeContext {
        host: Some(state.hostname().to_string()),
        os: Some(std::env::consts::OS.to_string()),
        arch: Some(std::env::consts::ARCH.to_string()),
        shell: detect_runtime_shell(),
        time: None,
        provider: Some(provider.name().to_string()),
        model: Some(provider.id().to_string()),
        session_key: Some(session_key.to_string()),
        surface: channel_context.surface,
        session_kind: channel_context.session_kind,
        channel_type: channel_context.channel_type,
        channel_account_id: channel_context.account_id,
        channel_chat_id: channel_context.chat_id,
        channel_chat_type: channel_context.chat_type,
        data_dir: Some(data_dir_display),
        sudo_non_interactive,
        sudo_status,
        timezone,
        location,
        ..Default::default()
    };
    refresh_runtime_prompt_time(&mut host_ctx);

    // Build nodes context from connected remote nodes.
    let connected = state.connected_nodes().await;
    let nodes_ctx = if connected.is_empty() {
        None
    } else {
        let default_node_id = session_entry.and_then(|e| e.node_id.clone());
        Some(PromptNodesRuntimeContext {
            nodes: connected
                .into_iter()
                .map(|n| PromptNodeInfo {
                    node_id: n.node_id,
                    display_name: n.display_name,
                    platform: n.platform,
                    capabilities: n.capabilities,
                    cpu_count: n.cpu_count,
                    mem_total: n.mem_total,
                    runtimes: n.runtimes,
                    providers: n.providers,
                })
                .collect(),
            default_node_id,
        })
    };

    PromptRuntimeContext {
        host: host_ctx,
        sandbox: sandbox_ctx,
        nodes: nodes_ctx,
    }
}

pub(crate) fn apply_request_runtime_context(
    host: &mut PromptHostRuntimeContext,
    params: &Value,
) {
    host.accept_language = params
        .get("_accept_language")
        .and_then(|v| v.as_str())
        .map(String::from);
    host.remote_ip = params
        .get("_remote_ip")
        .and_then(|v| v.as_str())
        .map(String::from);

    // Extract sender_id from channel metadata (set by channel handlers).
    if host.channel_sender_id.is_none() {
        host.channel_sender_id = params
            .get("channel")
            .and_then(|ch| ch.get("sender_id"))
            .and_then(|v| v.as_str())
            .map(String::from);
    }

    if let Some(timezone) =
        normalized_iana_timezone(params.get("_timezone").and_then(|v| v.as_str()))
            .or_else(default_user_prompt_timezone)
    {
        host.timezone = Some(timezone);
    }

    refresh_runtime_prompt_time(host);
}

pub(crate) fn apply_runtime_tool_filters(
    base: &moltis_agents::tool_registry::ToolRegistry,
    config: &moltis_config::MoltisConfig,
    _skills: &[moltis_skills::types::SkillMetadata],
    mcp_disabled: bool,
    policy_context: &PolicyContext,
) -> moltis_agents::tool_registry::ToolRegistry {
    let base_registry = if mcp_disabled {
        base.clone_without_mcp()
    } else {
        base.clone_without(&[])
    };

    let policy = resolve_effective_policy(config, policy_context);
    // NOTE: Do not globally restrict tools by discovered skill `allowed_tools`.
    // Skills are always discovered for prompt injection; applying those lists at
    // runtime can unintentionally remove unrelated tools (for example, leaving
    // only `web_fetch` and preventing `create_skill` from being called).
    // Tool availability here is controlled by configured runtime policy.
    base_registry.clone_allowed_by(|name| policy.is_allowed(name))
}

/// Build a `PolicyContext` from runtime context and request parameters.
pub(crate) fn build_policy_context(
    agent_id: &str,
    runtime_context: Option<&PromptRuntimeContext>,
    params: Option<&Value>,
) -> PolicyContext {
    let host = runtime_context.map(|rc| &rc.host);
    // sender_id: prefer params["channel"]["sender_id"] (fresh from channel
    // dispatch), fall back to host.channel_sender_id (set by
    // apply_request_runtime_context earlier in the call chain).
    let sender_id = params
        .and_then(|p| p.get("channel"))
        .and_then(|ch| ch.get("sender_id"))
        .and_then(|v| v.as_str())
        .map(String::from)
        .or_else(|| host.and_then(|h| h.channel_sender_id.clone()));
    PolicyContext {
        agent_id: agent_id.to_string(),
        provider: host.and_then(|h| h.provider.clone()),
        channel: host.and_then(|h| h.channel_type.clone()),
        channel_account_id: host.and_then(|h| h.channel_account_id.clone()),
        group_id: host.and_then(|h| h.channel_chat_type.clone()),
        sender_id,
        sandboxed: runtime_context
            .and_then(|rc| rc.sandbox.as_ref())
            .is_some_and(|s| s.exec_sandboxed),
    }
}

//! Session FFI exports: list, create, switch, and session-scoped streaming chat.

use std::{
    ffi::{CString, c_char, c_void},
    panic::{AssertUnwindSafe, catch_unwind},
};

use {
    moltis_agents::model::{
        ChatMessage as AgentChatMessage, LlmProvider, StreamEvent, Usage, UserContent,
    },
    moltis_sessions::message::PersistedMessage,
    tokio_stream::StreamExt,
};

use crate::{
    callbacks::emit_log,
    chat::{
        BridgeStreamEvent, StreamCallback, StreamCallbackCtx, resolve_provider_for_model,
    },
    helpers::{
        encode_error, encode_json, parse_ffi_request, read_c_string, record_call, record_error,
        trace_call, with_ffi_boundary,
    },
    state::BRIDGE,
    types::{
        BridgeSessionEntry, BridgeSessionHistory, CreateSessionRequest, SessionChatRequest,
        SwitchSessionRequest,
    },
};

// ── Session FFI exports ──────────────────────────────────────────────────

/// Returns JSON array of all session entries (sorted by created_at ASC, matching web UI).
#[allow(unsafe_code)]
#[unsafe(no_mangle)]
pub extern "C" fn moltis_list_sessions() -> *mut c_char {
    record_call("moltis_list_sessions");
    trace_call("moltis_list_sessions");

    with_ffi_boundary(|| {
        let all = BRIDGE.runtime.block_on(BRIDGE.session_metadata.list());
        let entries: Vec<BridgeSessionEntry> = all.iter().map(BridgeSessionEntry::from).collect();
        emit_log(
            "DEBUG",
            "bridge.sessions",
            &format!("Listed {} sessions", entries.len()),
        );
        encode_json(&entries)
    })
}

/// Switches to a session by key. Returns entry + message history.
/// If the session doesn't exist yet, it will be created.
#[allow(unsafe_code)]
#[unsafe(no_mangle)]
pub extern "C" fn moltis_switch_session(request_json: *const c_char) -> *mut c_char {
    record_call("moltis_switch_session");
    trace_call("moltis_switch_session");

    with_ffi_boundary(|| {
        let request = match parse_ffi_request::<SwitchSessionRequest>(
            "moltis_switch_session",
            request_json,
        ) {
            Ok(r) => r,
            Err(e) => return e,
        };

        // Ensure metadata entry exists.
        if let Err(e) = BRIDGE
            .runtime
            .block_on(BRIDGE.session_metadata.upsert(&request.key, None))
        {
            emit_log(
                "WARN",
                "bridge.sessions",
                &format!("Failed to upsert metadata: {e}"),
            );
        }

        // Read message history from JSONL.
        let messages = match BRIDGE
            .runtime
            .block_on(BRIDGE.session_store.read(&request.key))
        {
            Ok(msgs) => msgs,
            Err(e) => {
                emit_log(
                    "WARN",
                    "bridge.sessions",
                    &format!("Failed to read session: {e}"),
                );
                vec![]
            },
        };

        let entry = BRIDGE
            .runtime
            .block_on(BRIDGE.session_metadata.get(&request.key))
            .map(|e| BridgeSessionEntry::from(&e));

        match entry {
            Some(entry) => {
                emit_log(
                    "INFO",
                    "bridge.sessions",
                    &format!(
                        "Switched to session '{}' ({} messages)",
                        request.key,
                        messages.len()
                    ),
                );
                encode_json(&BridgeSessionHistory { entry, messages })
            },
            None => encode_error(
                "session_not_found",
                &format!("Session '{}' not found", request.key),
            ),
        }
    })
}

/// Creates a new session with an optional label. Returns the entry.
#[allow(unsafe_code)]
#[unsafe(no_mangle)]
pub extern "C" fn moltis_create_session(request_json: *const c_char) -> *mut c_char {
    record_call("moltis_create_session");
    trace_call("moltis_create_session");

    with_ffi_boundary(|| {
        let request: CreateSessionRequest = if request_json.is_null() {
            CreateSessionRequest { label: None }
        } else {
            match read_c_string(request_json) {
                Ok(raw) => match serde_json::from_str(&raw) {
                    Ok(r) => r,
                    Err(e) => return encode_error("invalid_json", &e.to_string()),
                },
                Err(msg) => return encode_error("null_pointer_or_invalid_utf8", &msg),
            }
        };

        let key = format!("session:{}", uuid::Uuid::new_v4());
        let label = request.label.unwrap_or_else(|| "New Session".to_owned());

        match BRIDGE
            .runtime
            .block_on(BRIDGE.session_metadata.upsert(&key, Some(label)))
        {
            Ok(entry) => {
                emit_log(
                    "INFO",
                    "bridge.sessions",
                    &format!("Created session '{}'", key),
                );
                encode_json(&BridgeSessionEntry::from(&entry))
            },
            Err(e) => encode_error("create_failed", &format!("Failed to create session: {e}")),
        }
    })
}

/// Streaming chat within a session. Persists user message before streaming,
/// persists assistant message when done. Events delivered via callback.
///
/// # Safety
///
/// Same requirements as `moltis_chat_stream`.
#[allow(unsafe_code)]
#[unsafe(no_mangle)]
pub unsafe extern "C" fn moltis_session_chat_stream(
    request_json: *const c_char,
    callback: StreamCallback,
    user_data: *mut c_void,
) {
    record_call("moltis_session_chat_stream");
    trace_call("moltis_session_chat_stream");

    let send_error = |msg: String| {
        let event = BridgeStreamEvent::Error { message: msg };
        let json = encode_json(&event);
        if let Ok(c_str) = CString::new(json) {
            unsafe {
                callback(c_str.as_ptr(), user_data);
            }
        }
    };

    let raw = match read_c_string(request_json) {
        Ok(value) => value,
        Err(message) => {
            send_error(message);
            return;
        },
    };

    let request = match serde_json::from_str::<SessionChatRequest>(&raw) {
        Ok(r) => r,
        Err(e) => {
            send_error(e.to_string());
            return;
        },
    };

    let provider = match resolve_provider_for_model(request.model.as_deref()) {
        Some(p) => p,
        None => {
            send_error("No LLM provider configured".to_owned());
            return;
        },
    };

    let session_key = request.session_key.clone();

    // Persist user message.
    let user_msg = PersistedMessage::user(&request.message);
    let user_value = user_msg.to_value();
    if let Err(e) = BRIDGE
        .runtime
        .block_on(BRIDGE.session_store.append(&session_key, &user_value))
    {
        emit_log(
            "WARN",
            "bridge.session_chat",
            &format!("Failed to persist user message: {e}"),
        );
    }

    // Update metadata.
    BRIDGE.runtime.block_on(async {
        let _ = BRIDGE.session_metadata.upsert(&session_key, None).await;
        let msg_count = BRIDGE
            .session_store
            .read(&session_key)
            .await
            .map(|m| m.len() as u32)
            .unwrap_or(0);
        BRIDGE.session_metadata.touch(&session_key, msg_count).await;
    });

    let model_id = provider.id().to_string();
    let provider_name = provider.name().to_string();
    let messages = vec![AgentChatMessage::User {
        content: UserContent::text(&request.message),
    }];

    let ctx = StreamCallbackCtx {
        callback,
        user_data,
    };

    emit_log(
        "INFO",
        "bridge.session_chat",
        &format!(
            "Starting session stream: session={} provider={}/{}",
            session_key, provider_name, model_id
        ),
    );

    BRIDGE.runtime.spawn(async move {
        let start = std::time::Instant::now();
        let result = catch_unwind(AssertUnwindSafe(|| provider.stream(messages)));

        let mut stream = match result {
            Ok(s) => s,
            Err(_) => {
                ctx.send(&BridgeStreamEvent::Error {
                    message: "panic during stream creation".to_owned(),
                });
                return;
            },
        };

        let mut usage = Usage::default();
        let mut full_text = String::new();

        while let Some(event) = stream.next().await {
            match event {
                StreamEvent::Delta(text) => {
                    full_text.push_str(&text);
                    ctx.send(&BridgeStreamEvent::Delta { text });
                },
                StreamEvent::Done(u) => {
                    usage = u;
                    break;
                },
                StreamEvent::Error(message) => {
                    ctx.send(&BridgeStreamEvent::Error { message });
                    return;
                },
                _ => {},
            }
        }

        let elapsed = start.elapsed().as_millis() as u64;

        // Persist assistant message.
        let assistant_msg = PersistedMessage::assistant(
            &full_text,
            &model_id,
            &provider_name,
            usage.input_tokens,
            usage.output_tokens,
            None, // audio
        );
        let assistant_value = assistant_msg.to_value();
        if let Err(e) = BRIDGE
            .session_store
            .append(&session_key, &assistant_value)
            .await
        {
            emit_log(
                "WARN",
                "bridge.session_chat",
                &format!("Failed to persist assistant message: {e}"),
            );
        }

        // Update metadata in SQLite.
        let msg_count = BRIDGE
            .session_store
            .read(&session_key)
            .await
            .map(|m| m.len() as u32)
            .unwrap_or(0);
        BRIDGE.session_metadata.touch(&session_key, msg_count).await;
        BRIDGE
            .session_metadata
            .set_model(&session_key, Some(model_id.clone()))
            .await;

        ctx.send(&BridgeStreamEvent::Done {
            input_tokens: usage.input_tokens,
            output_tokens: usage.output_tokens,
            duration_ms: elapsed,
            model: Some(model_id),
            provider: Some(provider_name),
        });
    });
}

// ── Tests ────────────────────────────────────────────────────────────────

#[allow(unsafe_code)]
#[cfg(test)]
mod tests {
    use std::ffi::{CString, c_char};

    use serde_json::Value;

    use super::*;

    fn text_from_ptr(ptr: *mut c_char) -> String {
        assert!(!ptr.is_null(), "ffi returned null pointer");
        let owned = unsafe { CString::from_raw(ptr) };
        match owned.into_string() {
            Ok(text) => text,
            Err(error) => panic!("failed to decode UTF-8 from ffi pointer: {error}"),
        }
    }

    fn json_from_ptr(ptr: *mut c_char) -> Value {
        let text = text_from_ptr(ptr);
        match serde_json::from_str::<Value>(&text) {
            Ok(value) => value,
            Err(error) => panic!("failed to parse ffi json payload: {error}; payload={text}"),
        }
    }

    #[test]
    fn list_sessions_returns_array() {
        let payload = json_from_ptr(moltis_list_sessions());
        assert!(
            payload.as_array().is_some(),
            "list_sessions should return a JSON array"
        );
    }

    #[test]
    fn create_and_switch_session() {
        // Create a session with a label.
        let request = r#"{"label":"Test Session"}"#;
        let c_request = CString::new(request).unwrap_or_else(|e| panic!("{e}"));
        let payload = json_from_ptr(moltis_create_session(c_request.as_ptr()));

        let key = payload
            .get("key")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(
            key.starts_with("session:"),
            "created session key should start with 'session:'"
        );
        assert_eq!(
            payload.get("label").and_then(Value::as_str),
            Some("Test Session"),
        );

        // Switch to the created session.
        let switch_request = serde_json::json!({"key": key}).to_string();
        let c_switch = CString::new(switch_request).unwrap_or_else(|e| panic!("{e}"));
        let history = json_from_ptr(moltis_switch_session(c_switch.as_ptr()));

        assert!(history.get("entry").is_some(), "switch should return entry");
        assert!(
            history.get("messages").and_then(Value::as_array).is_some(),
            "switch should return messages array"
        );
    }

    #[test]
    fn create_session_with_null_uses_defaults() {
        let payload = json_from_ptr(moltis_create_session(std::ptr::null()));

        let key = payload
            .get("key")
            .and_then(Value::as_str)
            .unwrap_or_default();
        assert!(
            key.starts_with("session:"),
            "session key should start with 'session:'"
        );
        assert_eq!(
            payload.get("label").and_then(Value::as_str),
            Some("New Session"),
        );
    }
}

//! Streaming variant of the agent loop.

use std::sync::Arc;

use {
    anyhow::Result,
    tracing::{debug, info, trace, warn},
};

#[cfg(feature = "metrics")]
use moltis_metrics::{counter, histogram, labels, llm as llm_metrics};

use futures::StreamExt;

use moltis_common::hooks::{HookAction, HookPayload, HookRegistry};

use crate::{
    model::{ChatMessage, LlmProvider, StreamEvent, ToolCall, Usage, UserContent},
    response_sanitizer::recover_tool_calls_from_content,
    tool_arg_validator::validate_tool_args,
    tool_loop_detector::ToolCallFingerprint,
    tool_parsing::{looks_like_failed_tool_call, new_synthetic_tool_call_id, parse_tool_calls_from_text},
    tool_registry::ToolRegistry,
};

use super::{
    AgentRunError, AgentRunResult, OnEvent, RunnerEvent,
    apply_loop_detector_intervention,
    channel_binding_from_tool_context,
    empty_tool_name_retry_prompt,
    explicit_shell_command_from_user_content,
    find_empty_tool_name_call,
    has_named_tool_call,
    is_substantive_answer_text,
    sanitize_tool_name,
    streaming_tool_call_message_content,
    tool_result::sanitize_tool_result,
    retry::{
        RATE_LIMIT_MAX_RETRIES,
        is_context_window_error,
        next_retry_delay_ms,
        resolve_agent_max_iterations,
    },
    AUTO_CONTINUE_NUDGE,
    MALFORMED_TOOL_RETRY_PROMPT,
};

use crate::{
    response_sanitizer::clean_response,
    tool_loop_detector::ToolLoopDetector,
};

/// Streaming variant of the agent loop.
///
/// Unlike `run_agent_loop_with_context`, this function uses streaming to send
/// text deltas to the UI as they arrive, providing a much better UX.
///
/// Tool calls are accumulated from the stream and executed after the stream
/// completes, then the loop continues with the next iteration.
pub async fn run_agent_loop_streaming(
    provider: Arc<dyn LlmProvider>,
    tools: &ToolRegistry,
    system_prompt: &str,
    user_content: &UserContent,
    on_event: Option<&OnEvent>,
    history: Option<Vec<ChatMessage>>,
    tool_context: Option<serde_json::Value>,
    hook_registry: Option<Arc<HookRegistry>>,
) -> Result<AgentRunResult, AgentRunError> {
    let native_tools = provider.supports_tools();
    let config = moltis_config::discover_and_load();
    let max_tool_result_bytes = config.tools.max_tool_result_bytes;
    let max_auto_continues = config.tools.agent_max_auto_continues;
    let auto_continue_min_tool_calls = config.tools.agent_auto_continue_min_tool_calls;
    let base_max_iterations = resolve_agent_max_iterations(config.tools.agent_max_iterations);
    // Lazy mode needs extra iterations for tool_search discovery round-trips.
    let max_iterations = if config.tools.registry_mode == moltis_config::ToolRegistryMode::Lazy {
        base_max_iterations * 3
    } else {
        base_max_iterations
    };

    let is_multimodal = matches!(user_content, UserContent::Multimodal(_));
    info!(
        provider = provider.name(),
        model = provider.id(),
        native_tools,
        tools_count = tools.list_names().len(),
        is_multimodal,
        "starting streaming agent loop"
    );

    let mut messages: Vec<ChatMessage> = vec![ChatMessage::system(system_prompt)];

    // Insert conversation history before the current user message.
    if let Some(hist) = history {
        messages.extend(hist);
    }

    messages.push(ChatMessage::User {
        content: user_content.clone(),
    });
    let explicit_shell_command = explicit_shell_command_from_user_content(user_content);

    // Extract session key once for hook payloads.
    let session_key_for_hooks = tool_context
        .as_ref()
        .and_then(|ctx| ctx.get("_session_key"))
        .and_then(|v| v.as_str())
        .unwrap_or("")
        .to_string();
    let channel_for_hooks =
        channel_binding_from_tool_context(&session_key_for_hooks, tool_context.as_ref());

    let mut iterations = 0;
    let mut total_tool_calls = 0;
    let mut total_input_tokens: u32 = 0;
    let mut total_output_tokens: u32 = 0;
    let mut server_retries_remaining: u8 = 1;
    let mut rate_limit_retries_remaining: u8 = RATE_LIMIT_MAX_RETRIES;
    let mut rate_limit_backoff_ms: Option<u64> = None;
    let mut raw_llm_responses: Vec<serde_json::Value> = Vec::new();
    // Track answer text from iterations that also contained tool calls.
    // When the final iteration is empty (e.g. model stop after browser close),
    // this is used as the final response text instead of returning silent.
    let mut last_answer_text = String::new();
    let mut malformed_retry_count: u8 = 0;
    let mut empty_tool_name_retry_count: u8 = 0;
    let mut auto_continue_count: usize = 0;
    let mut loop_detector = ToolLoopDetector::new(
        config.tools.agent_loop_detector_window,
        config.tools.agent_loop_detector_strip_tools_on_second_fire,
    );
    let mut strip_tools_next_iter = false;

    loop {
        iterations += 1;
        if iterations > max_iterations {
            warn!(
                "streaming agent loop exceeded max iterations ({})",
                max_iterations
            );
            return Err(AgentRunError::Other(anyhow::anyhow!(
                "agent loop exceeded max iterations ({})",
                max_iterations
            )));
        }

        // Re-compute schemas each iteration so activated tools appear immediately.
        // When the loop detector has escalated to stage 2, pass an empty tool
        // list for this single turn so the model is forced to respond in text
        // (issue #658).
        let schemas_for_api = if native_tools && !strip_tools_next_iter {
            tools.list_schemas()
        } else {
            vec![]
        };
        if strip_tools_next_iter {
            strip_tools_next_iter = false;
            loop_detector.clear_strip_tools();
        }

        super::enforce_tool_result_context_budget(
            &mut messages,
            &schemas_for_api,
            provider.context_window(),
        )?;

        if let Some(cb) = on_event {
            cb(RunnerEvent::Iteration(iterations));
        }

        info!(
            iteration = iterations,
            messages_count = messages.len(),
            "calling LLM (streaming)"
        );
        trace!(iteration = iterations, messages = ?messages, "LLM request messages");

        // Dispatch BeforeLLMCall hook — may block the LLM call.
        if let Some(ref hooks) = hook_registry {
            let msgs_json: Vec<serde_json::Value> =
                messages.iter().map(|m| m.to_openai_value()).collect();
            let payload = HookPayload::BeforeLLMCall {
                session_key: session_key_for_hooks.clone(),
                provider: provider.name().to_string(),
                model: provider.id().to_string(),
                messages: serde_json::Value::Array(msgs_json),
                tool_count: schemas_for_api.len(),
                iteration: iterations,
            };
            match hooks.dispatch(&payload).await {
                Ok(HookAction::Block(reason)) => {
                    warn!(reason = %reason, "LLM call blocked by BeforeLLMCall hook");
                    return Err(AgentRunError::Other(anyhow::anyhow!(
                        "blocked by BeforeLLMCall hook: {reason}"
                    )));
                },
                Ok(HookAction::ModifyPayload(_)) => {
                    debug!("BeforeLLMCall ModifyPayload ignored (messages are typed)");
                },
                Ok(HookAction::Continue) => {},
                Err(e) => {
                    warn!(error = %e, "BeforeLLMCall hook dispatch failed");
                },
            }
        }

        if let Some(cb) = on_event {
            cb(RunnerEvent::Thinking);
        }

        // Use streaming API.
        #[cfg(feature = "metrics")]
        let iter_start = std::time::Instant::now();
        let mut stream = provider.stream_with_tools(messages.clone(), schemas_for_api.clone());

        // Accumulate answer text, reasoning text, and tool calls from the stream.
        let mut accumulated_text = String::new();
        let mut accumulated_reasoning = String::new();
        let mut tool_calls: Vec<ToolCall> = Vec::new();
        // Map streaming index -> accumulated JSON args string.
        let mut tool_call_args: std::collections::HashMap<usize, String> =
            std::collections::HashMap::new();
        // Map streaming index -> position in the `tool_calls` vec.
        // The streaming index may not start at 0 (e.g. Copilot proxying
        // Anthropic uses the content-block index, so a text block at index 0
        // pushes the tool_use to index 1).
        let mut stream_idx_to_vec_pos: std::collections::HashMap<usize, usize> =
            std::collections::HashMap::new();
        let mut input_tokens: u32 = 0;
        let mut output_tokens: u32 = 0;
        let mut stream_error: Option<String> = None;

        while let Some(event) = stream.next().await {
            match event {
                StreamEvent::Delta(text) => {
                    accumulated_text.push_str(&text);
                    if let Some(cb) = on_event {
                        cb(RunnerEvent::TextDelta(text));
                    }
                },
                StreamEvent::ProviderRaw(raw) => {
                    if raw_llm_responses.len() < 256 {
                        raw_llm_responses.push(raw);
                    }
                },
                StreamEvent::ReasoningDelta(text) => {
                    accumulated_reasoning.push_str(&text);
                    if let Some(cb) = on_event {
                        cb(RunnerEvent::ThinkingText(accumulated_reasoning.clone()));
                    }
                },
                StreamEvent::ToolCallStart { id, name, index } => {
                    let vec_pos = tool_calls.len();
                    debug!(tool = %name, id = %id, stream_index = index, vec_pos, "tool call started in stream");
                    tool_calls.push(ToolCall {
                        id,
                        name,
                        arguments: serde_json::json!({}),
                    });
                    stream_idx_to_vec_pos.insert(index, vec_pos);
                    tool_call_args.insert(index, String::new());
                },
                StreamEvent::ToolCallArgumentsDelta { index, delta } => {
                    if let Some(args) = tool_call_args.get_mut(&index) {
                        args.push_str(&delta);
                    }
                },
                StreamEvent::ToolCallComplete { index } => {
                    // Arguments are finalized after stream completes.
                    // Just log for now - we'll parse accumulated args later.
                    debug!(index, "tool call arguments complete");
                },
                StreamEvent::Done(usage) => {
                    input_tokens = usage.input_tokens;
                    output_tokens = usage.output_tokens;
                    debug!(input_tokens, output_tokens, "stream done");

                    #[cfg(feature = "metrics")]
                    {
                        let provider_name = provider.name().to_string();
                        let model_id = provider.id().to_string();
                        let duration = iter_start.elapsed().as_secs_f64();
                        counter!(
                            llm_metrics::COMPLETIONS_TOTAL,
                            labels::PROVIDER => provider_name.clone(),
                            labels::MODEL => model_id.clone()
                        )
                        .increment(1);
                        counter!(
                            llm_metrics::INPUT_TOKENS_TOTAL,
                            labels::PROVIDER => provider_name.clone(),
                            labels::MODEL => model_id.clone()
                        )
                        .increment(u64::from(usage.input_tokens));
                        counter!(
                            llm_metrics::OUTPUT_TOKENS_TOTAL,
                            labels::PROVIDER => provider_name.clone(),
                            labels::MODEL => model_id.clone()
                        )
                        .increment(u64::from(usage.output_tokens));
                        counter!(
                            llm_metrics::CACHE_READ_TOKENS_TOTAL,
                            labels::PROVIDER => provider_name.clone(),
                            labels::MODEL => model_id.clone()
                        )
                        .increment(u64::from(usage.cache_read_tokens));
                        counter!(
                            llm_metrics::CACHE_WRITE_TOKENS_TOTAL,
                            labels::PROVIDER => provider_name.clone(),
                            labels::MODEL => model_id.clone()
                        )
                        .increment(u64::from(usage.cache_write_tokens));
                        histogram!(
                            llm_metrics::COMPLETION_DURATION_SECONDS,
                            labels::PROVIDER => provider_name,
                            labels::MODEL => model_id
                        )
                        .record(duration);
                    }
                },
                StreamEvent::Error(msg) => {
                    stream_error = Some(msg);
                    break;
                },
            }
        }

        if let Some(cb) = on_event {
            cb(RunnerEvent::ThinkingDone);
        }

        // Handle stream errors — retry on transient failures/rate limits.
        if let Some(err) = stream_error {
            if is_context_window_error(&err) {
                return Err(AgentRunError::ContextWindowExceeded(err));
            }
            if let Some(delay_ms) = next_retry_delay_ms(
                &err,
                &mut server_retries_remaining,
                &mut rate_limit_retries_remaining,
                &mut rate_limit_backoff_ms,
            ) {
                // Don't count the failed attempt as an iteration.
                iterations -= 1;
                warn!(
                    error = %err,
                    delay_ms,
                    server_retries_remaining,
                    rate_limit_retries_remaining,
                    "transient LLM error, retrying after delay"
                );
                if let Some(cb) = on_event {
                    cb(RunnerEvent::RetryingAfterError {
                        error: err,
                        delay_ms,
                    });
                }
                tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;
                continue;
            }
            return Err(AgentRunError::Other(anyhow::anyhow!(err)));
        }

        total_input_tokens = total_input_tokens.saturating_add(input_tokens);
        total_output_tokens = total_output_tokens.saturating_add(output_tokens);

        // Finalize tool call arguments from accumulated strings.
        // Use stream_idx_to_vec_pos to map streaming indices (which may not
        // start at 0) to the actual position in the tool_calls vec.
        for (stream_idx, args_str) in &tool_call_args {
            // Emit raw accumulated string at debug level so future variants of
            // "default to {} because no deltas arrived" can be diagnosed
            // without a repro (issue #658).
            debug!(
                stream_idx,
                args_str = %args_str,
                "finalizing tool call args"
            );
            if let Some(&vec_pos) = stream_idx_to_vec_pos.get(stream_idx)
                && vec_pos < tool_calls.len()
                && !args_str.is_empty()
                && let Ok(args) = serde_json::from_str::<serde_json::Value>(args_str)
            {
                tool_calls[vec_pos].arguments = args;
            }
        }

        info!(
            iteration = iterations,
            has_text = !accumulated_text.is_empty(),
            tool_calls_count = tool_calls.len(),
            input_tokens,
            output_tokens,
            "streaming LLM response complete"
        );

        // Fallback: parse tool calls from model text if the provider returned
        // no structured tool calls (some providers/models emit text-based calls).
        if tool_calls.is_empty() && !accumulated_text.is_empty() {
            let (parsed, remaining) = parse_tool_calls_from_text(&accumulated_text);
            if !parsed.is_empty() {
                info!(
                    native_tools,
                    count = parsed.len(),
                    first_tool = %parsed[0].name,
                    "parsed tool call(s) from text fallback"
                );
                accumulated_text = remaining.unwrap_or_default();
                tool_calls = parsed;
            }
        }

        // One-shot retry for malformed tool calls in streaming mode.
        if tool_calls.is_empty()
            && looks_like_failed_tool_call(&Some(accumulated_text.clone()))
            && malformed_retry_count == 0
        {
            malformed_retry_count += 1;
            info!("detected malformed tool call in stream, requesting retry");
            messages.push(ChatMessage::assistant(&accumulated_text));
            messages.push(ChatMessage::user(MALFORMED_TOOL_RETRY_PROMPT));
            continue;
        }

        // Fallback: recover tool calls from XML blocks (<function_call>, <tool_call>).
        if !native_tools && tool_calls.is_empty() && !accumulated_text.is_empty() {
            let (cleaned, recovered) = recover_tool_calls_from_content(&accumulated_text);
            if !recovered.is_empty() {
                info!(
                    count = recovered.len(),
                    "recovered tool calls from XML blocks in streamed text"
                );
                accumulated_text = cleaned;
                tool_calls = recovered;
            }
        }

        // Final fallback: if the user turn is an explicit `/sh ...` command and
        // the model returned plain text, force one exec tool call so this path
        // is deterministic in the UI.
        if tool_calls.is_empty()
            && iterations == 1
            && total_tool_calls == 0
            && let Some(command) = explicit_shell_command.as_ref()
            && tools.get("exec").is_some()
        {
            info!(command = %command, "forcing exec tool call from explicit /sh command");
            // Preserve streamed reasoning/planning text on the assistant tool
            // message so providers that validate thinking history accept the
            // next iteration.
            tool_calls = vec![ToolCall {
                id: new_synthetic_tool_call_id("forced"),
                name: "exec".to_string(),
                arguments: serde_json::json!({ "command": command }),
            }];
        }

        if let Some(tc) = find_empty_tool_name_call(&tool_calls) {
            if has_named_tool_call(&tool_calls) {
                warn!(
                    tool_call_id = %tc.id,
                    "streamed tool call batch contains both empty and valid tool names; preserving valid sibling tool calls and falling back to normal tool error handling"
                );
            } else if empty_tool_name_retry_count == 0 {
                empty_tool_name_retry_count += 1;
                info!(tool_call_id = %tc.id, "detected structured tool call with empty name in stream, requesting retry");
                let retry_text = streaming_tool_call_message_content(
                    &mut last_answer_text,
                    &accumulated_text,
                    &accumulated_reasoning,
                );
                messages.push(ChatMessage::assistant(retry_text.unwrap_or_default()));
                messages.push(ChatMessage::user(empty_tool_name_retry_prompt(tc)));
                continue;
            }
            warn!(
                tool_call_id = %tc.id,
                "structured tool call in stream still has empty name after retry; falling back to normal tool error handling"
            );
        }

        // Dispatch AfterLLMCall hook — may block tool execution.
        if let Some(ref hooks) = hook_registry {
            let tc_json: Vec<serde_json::Value> = tool_calls
                .iter()
                .map(|tc| {
                    serde_json::json!({
                        "id": tc.id,
                        "name": tc.name,
                        "arguments": tc.arguments,
                    })
                })
                .collect();
            let payload = HookPayload::AfterLLMCall {
                session_key: session_key_for_hooks.clone(),
                provider: provider.name().to_string(),
                model: provider.id().to_string(),
                text: if accumulated_text.is_empty() {
                    None
                } else {
                    Some(accumulated_text.clone())
                },
                tool_calls: tc_json,
                input_tokens,
                output_tokens,
                iteration: iterations,
            };
            match hooks.dispatch(&payload).await {
                Ok(HookAction::Block(reason)) => {
                    warn!(reason = %reason, "LLM response blocked by AfterLLMCall hook");
                    return Err(AgentRunError::Other(anyhow::anyhow!(
                        "blocked by AfterLLMCall hook: {reason}"
                    )));
                },
                Ok(HookAction::ModifyPayload(_)) => {
                    debug!("AfterLLMCall ModifyPayload ignored (response is typed)");
                },
                Ok(HookAction::Continue) => {},
                Err(e) => {
                    warn!(error = %e, "AfterLLMCall hook dispatch failed");
                },
            }
        }

        // If no tool calls, auto-continue or return the text response.
        if tool_calls.is_empty() {
            // Auto-continue: if the model made tool calls earlier in this run
            // and we haven't exhausted nudges, ask it to keep going. Suppress
            // the nudge when the model already produced a substantive final
            // answer — nudging in that case risks losing the answer (GH #628).
            if !is_substantive_answer_text(&accumulated_text)
                && total_tool_calls > 0
                && total_tool_calls >= auto_continue_min_tool_calls
                && auto_continue_count < max_auto_continues
            {
                auto_continue_count += 1;
                info!(
                    iterations,
                    auto_continue_count, "model stopped without tool calls, auto-continuing"
                );
                if let Some(cb) = on_event {
                    cb(RunnerEvent::AutoContinue {
                        iteration: iterations,
                        max_iterations,
                    });
                }
                if !accumulated_text.is_empty() {
                    messages.push(ChatMessage::assistant(&accumulated_text));
                }
                messages.push(ChatMessage::user(AUTO_CONTINUE_NUDGE));
                continue;
            }

            // When the final iteration produced no text but a previous iteration
            // streamed answer text alongside tool calls, use that as the response.
            let final_text = if accumulated_text.is_empty() && !last_answer_text.is_empty() {
                std::mem::take(&mut last_answer_text)
            } else {
                accumulated_text
            };
            info!(
                iterations,
                tool_calls = total_tool_calls,
                "streaming agent loop complete — returning text"
            );
            return Ok(AgentRunResult {
                text: clean_response(&final_text),
                iterations,
                tool_calls_made: total_tool_calls,
                usage: Usage {
                    input_tokens: total_input_tokens,
                    output_tokens: total_output_tokens,
                    ..Default::default()
                },
                request_usage: Usage {
                    input_tokens,
                    output_tokens,
                    ..Default::default()
                },
                raw_llm_responses,
            });
        }

        // Append assistant message with tool calls.
        //
        // When the model emits explicit reasoning (extended thinking), use
        // that as the planning text and emit it as ThinkingText for the UI.
        // When there is only regular text alongside tool calls (no separate
        // reasoning), preserve it on the message for history but do NOT emit
        // it as ThinkingText — it was already streamed as TextDelta and is
        // likely the actual answer (e.g. a search result table produced
        // before a `browser close` cleanup call).
        let (text_for_msg, is_actual_reasoning) = if !accumulated_reasoning.is_empty() {
            (Some(accumulated_reasoning), true)
        } else if !accumulated_text.is_empty() {
            last_answer_text.clone_from(&accumulated_text);
            (Some(accumulated_text), false)
        } else {
            (None, false)
        };
        if let Some(ref text) = text_for_msg
            && is_actual_reasoning
            && let Some(cb) = on_event
        {
            cb(RunnerEvent::ThinkingText(text.clone()));
        }
        messages.push(ChatMessage::assistant_with_tools(
            text_for_msg,
            tool_calls.clone(),
        ));

        // Execute tool calls concurrently.
        total_tool_calls += tool_calls.len();

        // Build futures for all tool calls (executed concurrently).
        //
        // Pre-dispatch schema validation runs synchronously against each
        // tool's declared `parameters_schema`. Calls that fail validation
        // are short-circuited to a directive error response without invoking
        // `execute`, and the UI receives `ToolCallRejected` instead of the
        // misleading "executing" status (issue #658).
        let tool_futures: Vec<_> = tool_calls
            .iter()
            .map(|tc| {
                let sanitized = sanitize_tool_name(&tc.name);
                if *sanitized != tc.name {
                    debug!(original = %tc.name, sanitized = %sanitized, "sanitized mangled tool name");
                }
                let tool = tools.get(&sanitized);
                let mut args = tc.arguments.clone();

                let hook_registry = hook_registry.clone();
                let session_key = session_key_for_hooks.clone();
                let channel_for_hooks = channel_for_hooks.clone();
                let tc_name = sanitized.to_string();

                if let Some(ref ctx) = tool_context
                    && let (Some(args_obj), Some(ctx_obj)) = (args.as_object_mut(), ctx.as_object())
                {
                    for (k, v) in ctx_obj {
                        args_obj.insert(k.clone(), v.clone());
                    }
                }

                // Pre-dispatch validation against the tool's schema.
                let validation_error: Option<String> = if let Some(ref t) = tool {
                    let schema = t.parameters_schema();
                    match validate_tool_args(&schema, &args) {
                        Ok(()) => None,
                        Err(e) => {
                            warn!(
                                tool = %tc_name,
                                summary = %e.short_summary(),
                                "tool call rejected by pre-dispatch schema validation"
                            );
                            Some(e.to_llm_error_message(&tc_name))
                        },
                    }
                } else {
                    None
                };

                if validation_error.is_none() {
                    if let Some(cb) = on_event {
                        cb(RunnerEvent::ToolCallStart {
                            id: tc.id.clone(),
                            name: tc.name.clone(),
                            arguments: args.clone(),
                        });
                    }
                    info!(tool = %tc_name, id = %tc.id, args = %args, "executing tool");
                }

                async move {
                    if let Some(err_msg) = validation_error {
                        return (
                            false,
                            serde_json::json!({ "error": err_msg.clone() }),
                            Some(err_msg),
                            true,
                        );
                    }
                    // Run BeforeToolCall hook.
                    if let Some(ref hooks) = hook_registry {
                        let payload = HookPayload::BeforeToolCall {
                            session_key: session_key.clone(),
                            tool_name: tc_name.clone(),
                            arguments: args.clone(),
                            channel: channel_for_hooks.clone(),
                        };
                        match hooks.dispatch(&payload).await {
                            Ok(HookAction::Block(reason)) => {
                                warn!(tool = %tc_name, reason = %reason, "tool call blocked by hook");
                                let err_str = format!("blocked by hook: {reason}");
                                return (
                                    false,
                                    serde_json::json!({ "error": err_str }),
                                    Some(err_str),
                                    false,
                                );
                            }
                            Ok(HookAction::ModifyPayload(v)) => {
                                args = v;
                            }
                            Ok(HookAction::Continue) => {}
                            Err(e) => {
                                warn!(tool = %tc_name, error = %e, "BeforeToolCall hook dispatch failed");
                            }
                        }
                    }

                    if let Some(tool) = tool {
                        match tool.execute(args).await {
                            Ok(val) => {
                                // Check if the result indicates a logical failure
                                // (e.g., BrowserResponse with success: false)
                                let has_error = val.get("error").is_some()
                                    || val.get("success") == Some(&serde_json::json!(false));
                                let error_msg = if has_error {
                                    val.get("error")
                                        .and_then(|e| e.as_str())
                                        .map(String::from)
                                } else {
                                    None
                                };

                                if let Some(ref hooks) = hook_registry {
                                    let payload = HookPayload::AfterToolCall {
                                        session_key: session_key.clone(),
                                        tool_name: tc_name.clone(),
                                        success: !has_error,
                                        result: Some(val.clone()),
                                        channel: channel_for_hooks.clone(),
                                    };
                                    if let Err(e) = hooks.dispatch(&payload).await {
                                        warn!(tool = %tc_name, error = %e, "AfterToolCall hook dispatch failed");
                                    }
                                }

                                if has_error {
                                    (false, serde_json::json!({ "result": val }), error_msg, false)
                                } else {
                                    (true, serde_json::json!({ "result": val }), None, false)
                                }
                            }
                            Err(e) => {
                                let err_str = e.to_string();
                                if let Some(ref hooks) = hook_registry {
                                    let payload = HookPayload::AfterToolCall {
                                        session_key: session_key.clone(),
                                        tool_name: tc_name.clone(),
                                        success: false,
                                        result: None,
                                        channel: channel_for_hooks.clone(),
                                    };
                                    if let Err(e) = hooks.dispatch(&payload).await {
                                        warn!(tool = %tc_name, error = %e, "AfterToolCall hook dispatch failed");
                                    }
                                }
                                (
                                    false,
                                    serde_json::json!({ "error": err_str }),
                                    Some(err_str),
                                    false,
                                )
                            }
                        }
                    } else {
                        let err_str = format!("unknown tool: {tc_name}");
                        (
                            false,
                            serde_json::json!({ "error": err_str }),
                            Some(err_str),
                            false,
                        )
                    }
                }
            })
            .collect();

        // Execute all tools concurrently and collect results in order.
        let results = futures::future::join_all(tool_futures).await;

        // Process results in original order: emit events, append messages.
        // Intervention is derived from the detector's post-batch state
        // via `consume_pending_action()` below — see the non-streaming
        // path for the rationale (issue #658).
        for (tc, (success, mut result, error, rejected)) in tool_calls.iter().zip(results) {
            if success {
                info!(tool = %tc.name, id = %tc.id, "tool execution succeeded");
                trace!(tool = %tc.name, result = %result, "tool result");
            } else if rejected {
                warn!(
                    tool = %tc.name,
                    id = %tc.id,
                    "tool call rejected before execution by pre-dispatch validation"
                );
            } else {
                warn!(tool = %tc.name, id = %tc.id, error = %error.as_deref().unwrap_or(""), "tool execution failed");
            }

            // Record outcome in the loop detector (issue #658).
            if loop_detector.is_enabled() {
                let fp = if success {
                    ToolCallFingerprint::success(&tc.name, &tc.arguments)
                } else {
                    ToolCallFingerprint::failure(&tc.name, &tc.arguments, error.as_deref())
                };
                let _ = loop_detector.record(fp);
            }

            if let Some(cb) = on_event {
                if rejected {
                    cb(RunnerEvent::ToolCallRejected {
                        id: tc.id.clone(),
                        name: tc.name.clone(),
                        arguments: tc.arguments.clone(),
                        error: error.clone().unwrap_or_default(),
                    });
                } else {
                    cb(RunnerEvent::ToolCallEnd {
                        id: tc.id.clone(),
                        name: tc.name.clone(),
                        success,
                        error,
                        result: if success {
                            result.get("result").cloned()
                        } else {
                            None
                        },
                    });
                }
            }

            // Dispatch ToolResultPersist hook — the last opportunity for a handler
            // to sanitize, redact, or block attacker-controlled tool output before
            // it enters the messages array and is reasoned on by the next LLM
            // iteration. Block substitutes an error marker instead of aborting the
            // run, so a single hostile tool result cannot kill a long-running
            // autonomous agent.
            if let Some(ref hooks) = hook_registry {
                let payload = HookPayload::ToolResultPersist {
                    session_key: session_key_for_hooks.clone(),
                    tool_name: sanitize_tool_name(&tc.name).into_owned(),
                    result: result.clone(),
                    channel: channel_for_hooks.clone(),
                };
                match hooks.dispatch(&payload).await {
                    Ok(HookAction::ModifyPayload(v)) => {
                        debug!(tool = %tc.name, "ToolResultPersist replaced tool result");
                        result = v;
                    },
                    Ok(HookAction::Block(reason)) => {
                        warn!(tool = %tc.name, reason = %reason, "ToolResultPersist blocked result — substituting error marker");
                        result = serde_json::json!({
                            "error": format!("blocked by hook: {reason}")
                        });
                    },
                    Ok(HookAction::Continue) => {},
                    Err(e) => {
                        warn!(tool = %tc.name, error = %e, "ToolResultPersist hook dispatch failed");
                    },
                }
            }

            // Always sanitize tool results as strings - most LLM APIs don't support
            // multimodal content in tool results. Images are stripped but the UI
            // still receives them via ToolCallEnd event.
            let tool_result_str = sanitize_tool_result(&result.to_string(), max_tool_result_bytes);
            debug!(
                tool = %tc.name,
                id = %tc.id,
                result_len = tool_result_str.len(),
                "appending tool result to messages"
            );
            trace!(tool = %tc.name, content = %tool_result_str, "tool result message content");

            messages.push(ChatMessage::tool(&tc.id, &tool_result_str));
        }

        // Apply loop-detector intervention if one fired during this batch.
        apply_loop_detector_intervention(
            &mut loop_detector,
            &mut messages,
            &mut strip_tools_next_iter,
            on_event,
        );
    }
}

