// ── Probe infrastructure ────────────────────────────────────────────────────

pub(crate) const PROBE_RATE_LIMIT_INITIAL_BACKOFF_MS: u64 = 1_000;
pub(crate) const PROBE_RATE_LIMIT_MAX_BACKOFF_MS: u64 = 30_000;

#[derive(Debug, Clone, Copy)]
struct ProbeRateLimitState {
    backoff_ms: u64,
    until: Instant,
}

#[derive(Debug, Default)]
struct ProbeRateLimiter {
    by_provider: Mutex<HashMap<String, ProbeRateLimitState>>,
}

impl ProbeRateLimiter {
    async fn remaining_backoff(&self, provider: &str) -> Option<Duration> {
        let map = self.by_provider.lock().await;
        map.get(provider).and_then(|state| {
            let now = Instant::now();
            (state.until > now).then_some(state.until - now)
        })
    }

    async fn mark_rate_limited(&self, provider: &str) -> Duration {
        let mut map = self.by_provider.lock().await;
        let next_backoff_ms =
            next_probe_rate_limit_backoff_ms(map.get(provider).map(|s| s.backoff_ms));
        let delay = Duration::from_millis(next_backoff_ms);
        let state = ProbeRateLimitState {
            backoff_ms: next_backoff_ms,
            until: Instant::now() + delay,
        };
        let _ = map.insert(provider.to_string(), state);
        delay
    }

    async fn clear(&self, provider: &str) {
        let mut map = self.by_provider.lock().await;
        let _ = map.remove(provider);
    }
}

pub(crate) fn next_probe_rate_limit_backoff_ms(previous_ms: Option<u64>) -> u64 {
    previous_ms
        .map(|ms| ms.saturating_mul(2))
        .unwrap_or(PROBE_RATE_LIMIT_INITIAL_BACKOFF_MS)
        .clamp(
            PROBE_RATE_LIMIT_INITIAL_BACKOFF_MS,
            PROBE_RATE_LIMIT_MAX_BACKOFF_MS,
        )
}

pub(crate) fn is_probe_rate_limited_error(error_obj: &Value, error_text: &str) -> bool {
    if error_obj.get("type").and_then(|v| v.as_str()) == Some("rate_limit_exceeded") {
        return true;
    }

    let lower = error_text.to_ascii_lowercase();
    lower.contains("status=429")
        || lower.contains("http 429")
        || lower.contains("too many requests")
        || lower.contains("rate limit")
        || lower.contains("quota exceeded")
}

#[derive(Debug)]
struct ProbeProviderLimiter {
    permits_per_provider: usize,
    by_provider: Mutex<HashMap<String, Arc<Semaphore>>>,
}

impl ProbeProviderLimiter {
    fn new(permits_per_provider: usize) -> Self {
        Self {
            permits_per_provider,
            by_provider: Mutex::new(HashMap::new()),
        }
    }

    async fn acquire(
        &self,
        provider: &str,
    ) -> Result<OwnedSemaphorePermit, tokio::sync::AcquireError> {
        let provider_sem = {
            let mut map = self.by_provider.lock().await;
            Arc::clone(
                map.entry(provider.to_string())
                    .or_insert_with(|| Arc::new(Semaphore::new(self.permits_per_provider))),
            )
        };

        provider_sem.acquire_owned().await
    }
}

#[derive(Debug)]
enum ProbeStatus {
    Supported,
    Unsupported { detail: String, provider: String },
    Error { message: String },
}

#[derive(Debug)]
struct ProbeOutcome {
    model_id: String,
    display_name: String,
    provider_name: String,
    status: ProbeStatus,
}

/// Run a single model probe: acquire concurrency permits, respect rate-limit
/// backoff, send a "ping" completion, and classify the result.
async fn run_single_probe(
    model_id: String,
    display_name: String,
    provider_name: String,
    provider: Arc<dyn moltis_agents::model::LlmProvider>,
    limiter: Arc<Semaphore>,
    provider_limiter: Arc<ProbeProviderLimiter>,
    rate_limiter: Arc<ProbeRateLimiter>,
) -> ProbeOutcome {
    let _permit = match limiter.acquire_owned().await {
        Ok(permit) => permit,
        Err(_) => {
            return ProbeOutcome {
                model_id,
                display_name,
                provider_name,
                status: ProbeStatus::Error {
                    message: "probe limiter closed".to_string(),
                },
            };
        },
    };
    let _provider_permit = match provider_limiter.acquire(&provider_name).await {
        Ok(permit) => permit,
        Err(_) => {
            return ProbeOutcome {
                model_id,
                display_name,
                provider_name,
                status: ProbeStatus::Error {
                    message: "provider probe limiter closed".to_string(),
                },
            };
        },
    };

    if let Some(wait_for) = rate_limiter.remaining_backoff(&provider_name).await {
        debug!(
            provider = %provider_name,
            model = %model_id,
            wait_ms = wait_for.as_millis() as u64,
            "skipping model probe while provider is in rate-limit backoff"
        );
        return ProbeOutcome {
            model_id,
            display_name,
            provider_name,
            status: ProbeStatus::Error {
                message: format!(
                    "probe skipped due provider backoff ({}ms remaining)",
                    wait_for.as_millis()
                ),
            },
        };
    }

    let completion = tokio::time::timeout(Duration::from_secs(20), provider.probe()).await;

    match completion {
        Ok(Ok(_)) => {
            rate_limiter.clear(&provider_name).await;
            ProbeOutcome {
                model_id,
                display_name,
                provider_name,
                status: ProbeStatus::Supported,
            }
        },
        Ok(Err(err)) => {
            let error_text = err.to_string();
            let error_obj = parse_chat_error(&error_text, Some(provider_name.as_str()));
            if is_probe_rate_limited_error(&error_obj, &error_text) {
                let backoff = rate_limiter.mark_rate_limited(&provider_name).await;
                let detail = error_obj
                    .get("detail")
                    .and_then(|v| v.as_str())
                    .unwrap_or("Too many requests while probing model support");
                warn!(
                    provider = %provider_name,
                    model = %model_id,
                    backoff_ms = backoff.as_millis() as u64,
                    "model probe rate limited, applying provider backoff"
                );
                return ProbeOutcome {
                    model_id,
                    display_name,
                    provider_name,
                    status: ProbeStatus::Error {
                        message: format!("{detail} (probe backoff {}ms)", backoff.as_millis()),
                    },
                };
            }

            rate_limiter.clear(&provider_name).await;
            let is_unsupported =
                error_obj.get("type").and_then(|v| v.as_str()) == Some("unsupported_model");

            if is_unsupported {
                let detail = error_obj
                    .get("detail")
                    .and_then(|v| v.as_str())
                    .unwrap_or("Model is not supported for this account/provider")
                    .to_string();
                let parsed_provider = error_obj
                    .get("provider")
                    .and_then(|v| v.as_str())
                    .unwrap_or(provider_name.as_str())
                    .to_string();
                ProbeOutcome {
                    model_id,
                    display_name,
                    provider_name,
                    status: ProbeStatus::Unsupported {
                        detail,
                        provider: parsed_provider,
                    },
                }
            } else {
                ProbeOutcome {
                    model_id,
                    display_name,
                    provider_name,
                    status: ProbeStatus::Error {
                        message: error_text,
                    },
                }
            }
        },
        Err(_) => ProbeOutcome {
            model_id,
            display_name,
            provider_name,
            status: ProbeStatus::Error {
                message: "probe timeout after 20s".to_string(),
            },
        },
    }
}

// ── Disabled Models Store ────────────────────────────────────────────────────

/// Persistent store for disabled model IDs.
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct DisabledModelsStore {
    #[serde(default)]
    pub disabled: HashSet<String>,
    #[serde(default)]
    pub unsupported: HashMap<String, UnsupportedModelInfo>,
}

/// Metadata for a model that failed at runtime due to provider support/account limits.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UnsupportedModelInfo {
    pub detail: String,
    pub provider: Option<String>,
    pub updated_at_ms: u64,
}

impl DisabledModelsStore {
    fn config_path() -> Option<PathBuf> {
        moltis_config::config_dir().map(|d| d.join("disabled-models.json"))
    }

    /// Load disabled models from config file.
    pub fn load() -> Self {
        Self::config_path()
            .and_then(|p| std::fs::read_to_string(p).ok())
            .and_then(|content| serde_json::from_str(&content).ok())
            .unwrap_or_default()
    }

    /// Save disabled models to config file.
    pub fn save(&self) -> crate::error::Result<()> {
        let path = Self::config_path().ok_or(crate::error::Error::NoConfigDirectory)?;
        let content = serde_json::to_string_pretty(self)?;
        std::fs::write(path, content)?;
        Ok(())
    }

    /// Disable a model by ID.
    pub fn disable(&mut self, model_id: &str) -> bool {
        self.disabled.insert(model_id.to_string())
    }

    /// Enable a model by ID (remove from disabled set).
    pub fn enable(&mut self, model_id: &str) -> bool {
        self.disabled.remove(model_id)
    }

    /// Check if a model is disabled.
    pub fn is_disabled(&self, model_id: &str) -> bool {
        self.disabled.contains(model_id)
    }

    /// Mark a model as unsupported with a human-readable reason.
    pub fn mark_unsupported(
        &mut self,
        model_id: &str,
        detail: &str,
        provider: Option<&str>,
    ) -> bool {
        let next = UnsupportedModelInfo {
            detail: detail.to_string(),
            provider: provider.map(ToString::to_string),
            updated_at_ms: now_ms(),
        };
        let should_update = self
            .unsupported
            .get(model_id)
            .map(|existing| existing.detail != next.detail || existing.provider != next.provider)
            .unwrap_or(true);

        if should_update {
            self.unsupported.insert(model_id.to_string(), next);
            true
        } else {
            false
        }
    }

    /// Clear unsupported status when a model succeeds again.
    pub fn clear_unsupported(&mut self, model_id: &str) -> bool {
        self.unsupported.remove(model_id).is_some()
    }

    /// Get unsupported metadata for a model.
    pub fn unsupported_info(&self, model_id: &str) -> Option<&UnsupportedModelInfo> {
        self.unsupported.get(model_id)
    }
}

// ── LiveModelService ────────────────────────────────────────────────────────

pub struct LiveModelService {
    providers: Arc<RwLock<ProviderRegistry>>,
    disabled: Arc<RwLock<DisabledModelsStore>>,
    state: Arc<OnceCell<Arc<dyn ChatRuntime>>>,
    detect_gate: Arc<Semaphore>,
    /// Token used to cancel an in-flight `detect_supported` run.
    detect_cancel: Arc<RwLock<Option<CancellationToken>>>,
    priority_models: Arc<RwLock<Vec<String>>>,
    show_legacy_models: bool,
    /// Provider config for runtime model rediscovery.
    providers_config: moltis_config::schema::ProvidersConfig,
    /// Environment variable overrides for runtime model rediscovery.
    /// Shared so the gateway can update it after loading UI-stored keys.
    env_overrides: Arc<RwLock<HashMap<String, String>>>,
}

impl LiveModelService {
    pub fn new(
        providers: Arc<RwLock<ProviderRegistry>>,
        disabled: Arc<RwLock<DisabledModelsStore>>,
        priority_models: Vec<String>,
    ) -> Self {
        Self {
            providers,
            disabled,
            state: Arc::new(OnceCell::new()),
            detect_gate: Arc::new(Semaphore::new(1)),
            detect_cancel: Arc::new(RwLock::new(None)),
            priority_models: Arc::new(RwLock::new(priority_models)),
            show_legacy_models: false,
            providers_config: moltis_config::schema::ProvidersConfig::default(),
            env_overrides: Arc::new(RwLock::new(HashMap::new())),
        }
    }

    pub fn with_show_legacy_models(mut self, show: bool) -> Self {
        self.show_legacy_models = show;
        self
    }

    /// Set the provider config and initial env overrides used for runtime
    /// model rediscovery when "Detect All Models" is triggered.
    pub fn with_discovery_config(
        mut self,
        providers_config: moltis_config::schema::ProvidersConfig,
        env_overrides: HashMap<String, String>,
    ) -> Self {
        self.providers_config = providers_config;
        self.env_overrides = Arc::new(RwLock::new(env_overrides));
        self
    }

    /// Shared handle to the env overrides. Pass this to code that needs to
    /// update the overrides after construction (e.g. when runtime UI-stored
    /// API keys are loaded from the credential store).
    pub fn env_overrides_handle(&self) -> Arc<RwLock<HashMap<String, String>>> {
        Arc::clone(&self.env_overrides)
    }

    /// Shared handle to the priority models list. Pass this to services
    /// that need to update model ordering at runtime (e.g. `save_model`).
    pub fn priority_models_handle(&self) -> Arc<RwLock<Vec<String>>> {
        Arc::clone(&self.priority_models)
    }

    fn build_priority_order(models: &[String]) -> HashMap<String, usize> {
        let mut order = HashMap::new();
        for (idx, model) in models.iter().enumerate() {
            let key = normalize_model_key(model);
            if !key.is_empty() {
                let _ = order.entry(key).or_insert(idx);
            }
        }
        order
    }

    fn priority_rank(order: &HashMap<String, usize>, model: &moltis_providers::ModelInfo) -> usize {
        let full = normalize_model_key(&model.id);
        if let Some(rank) = order.get(&full) {
            return *rank;
        }
        let raw = normalize_model_key(raw_model_id(&model.id));
        if let Some(rank) = order.get(&raw) {
            return *rank;
        }
        let display = normalize_model_key(&model.display_name);
        if let Some(rank) = order.get(&display) {
            return *rank;
        }
        usize::MAX
    }

    fn prioritize_models<'a>(
        order: &HashMap<String, usize>,
        models: impl Iterator<Item = &'a moltis_providers::ModelInfo>,
    ) -> Vec<&'a moltis_providers::ModelInfo> {
        let mut ordered: Vec<(usize, &'a moltis_providers::ModelInfo)> =
            models.enumerate().collect();
        ordered.sort_by(|(idx_a, a), (idx_b, b)| {
            let rank_a = Self::priority_rank(order, a);
            let rank_b = Self::priority_rank(order, b);
            // Preferred (rank != MAX) first, then non-preferred
            let bucket_a = if rank_a == usize::MAX {
                1u8
            } else {
                0
            };
            let bucket_b = if rank_b == usize::MAX {
                1u8
            } else {
                0
            };
            bucket_a
                .cmp(&bucket_b)
                .then_with(|| {
                    if bucket_a == 0 {
                        rank_a.cmp(&rank_b)
                    } else {
                        Ordering::Equal
                    }
                })
                .then_with(|| {
                    a.display_name
                        .to_lowercase()
                        .cmp(&b.display_name.to_lowercase())
                })
                .then_with(|| {
                    subscription_provider_rank(&a.provider)
                        .cmp(&subscription_provider_rank(&b.provider))
                })
                .then_with(|| idx_a.cmp(idx_b))
        });
        ordered.into_iter().map(|(_, model)| model).collect()
    }

    async fn priority_order(&self) -> HashMap<String, usize> {
        let list = self.priority_models.read().await;
        Self::build_priority_order(&list)
    }

    /// Set the gateway state reference for broadcasting model updates.
    pub fn set_state(&self, state: Arc<dyn ChatRuntime>) {
        let _ = self.state.set(state);
    }

    async fn broadcast_model_visibility_update(&self, model_id: &str, disabled: bool) {
        if let Some(state) = self.state.get() {
            broadcast(
                state,
                "models.updated",
                serde_json::json!({
                    "modelId": model_id,
                    "disabled": disabled,
                }),
                BroadcastOpts::default(),
            )
            .await;
        }
    }
}

#[async_trait]
impl ModelService for LiveModelService {
    async fn list(&self) -> ServiceResult {
        let reg = self.providers.read().await;
        let disabled = self.disabled.read().await;
        let order = self.priority_order().await;
        let all_models = reg.list_models_with_reasoning_variants();

        // Hide models older than 1 year from the chat selector unless the
        // user opted in via `providers.show_legacy_models`.  Preferred models
        // and models without a timestamp are never hidden.
        let legacy_cutoff: Option<i64> = if self.show_legacy_models {
            None
        } else {
            let one_year_ago = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap_or_default()
                .as_secs() as i64
                - 365 * 24 * 60 * 60;
            Some(one_year_ago)
        };

        let prioritized = Self::prioritize_models(
            &order,
            all_models
                .iter()
                .filter(|m| moltis_providers::is_chat_capable_model(&m.id))
                .filter(|m| !disabled.is_disabled(&m.id))
                .filter(|m| disabled.unsupported_info(&m.id).is_none()),
        );
        debug!(model_count = prioritized.len(), "models.list response");
        let models: Vec<_> = prioritized
            .iter()
            .copied()
            .filter(|m| {
                let preferred = Self::priority_rank(&order, m) != usize::MAX;
                if preferred {
                    return true;
                }
                match (legacy_cutoff, m.created_at) {
                    (Some(cutoff), Some(ts)) => ts >= cutoff,
                    _ => true, // no cutoff or no timestamp -> keep
                }
            })
            .map(|m| {
                let preferred = Self::priority_rank(&order, m) != usize::MAX;
                serde_json::json!({
                    "id": m.id,
                    "provider": m.provider,
                    "displayName": m.display_name,
                    "supportsTools": m.capabilities.tools,
                    "supportsVision": m.capabilities.vision,
                    "supportsReasoning": m.capabilities.reasoning,
                    "preferred": preferred,
                    "recommended": m.recommended,
                    "createdAt": m.created_at,
                    "unsupported": false,
                    "unsupportedReason": Value::Null,
                    "unsupportedProvider": Value::Null,
                    "unsupportedUpdatedAt": Value::Null,
                })
            })
            .collect();
        Ok(serde_json::json!(models))
    }

    async fn list_all(&self) -> ServiceResult {
        let reg = self.providers.read().await;
        let disabled = self.disabled.read().await;
        let order = self.priority_order().await;
        let all_models = reg.list_models_with_reasoning_variants();
        let prioritized = Self::prioritize_models(
            &order,
            all_models
                .iter()
                .filter(|m| moltis_providers::is_chat_capable_model(&m.id)),
        );
        info!(model_count = prioritized.len(), "models.list_all response");
        let models: Vec<_> = prioritized
            .iter()
            .copied()
            .map(|m| {
                let preferred = Self::priority_rank(&order, m) != usize::MAX;
                let unsupported = disabled.unsupported_info(&m.id);
                serde_json::json!({
                    "id": m.id,
                    "provider": m.provider,
                    "displayName": m.display_name,
                    "supportsTools": m.capabilities.tools,
                    "supportsVision": m.capabilities.vision,
                    "supportsReasoning": m.capabilities.reasoning,
                    "preferred": preferred,
                    "recommended": m.recommended,
                    "createdAt": m.created_at,
                    "disabled": disabled.is_disabled(&m.id),
                    "unsupported": unsupported.is_some(),
                    "unsupportedReason": unsupported.map(|u| u.detail.clone()),
                    "unsupportedProvider": unsupported.and_then(|u| u.provider.clone()),
                    "unsupportedUpdatedAt": unsupported.map(|u| u.updated_at_ms),
                })
            })
            .collect();
        Ok(serde_json::json!(models))
    }

    async fn disable(&self, params: Value) -> ServiceResult {
        let model_id = params
            .get("modelId")
            .and_then(|v| v.as_str())
            .ok_or_else(|| "missing 'modelId' parameter".to_string())?;

        info!(model = %model_id, "disabling model");

        let mut disabled = self.disabled.write().await;
        disabled.disable(model_id);
        disabled
            .save()
            .map_err(|e| format!("failed to save: {e}"))?;
        drop(disabled);

        self.broadcast_model_visibility_update(model_id, true).await;

        Ok(serde_json::json!({
            "ok": true,
            "modelId": model_id,
        }))
    }

    async fn enable(&self, params: Value) -> ServiceResult {
        let model_id = params
            .get("modelId")
            .and_then(|v| v.as_str())
            .ok_or_else(|| "missing 'modelId' parameter".to_string())?;

        info!(model = %model_id, "enabling model");

        let mut disabled = self.disabled.write().await;
        disabled.enable(model_id);
        disabled
            .save()
            .map_err(|e| format!("failed to save: {e}"))?;
        drop(disabled);

        self.broadcast_model_visibility_update(model_id, false)
            .await;

        Ok(serde_json::json!({
            "ok": true,
            "modelId": model_id,
        }))
    }

    async fn detect_supported(&self, params: Value) -> ServiceResult {
        let background = params
            .get("background")
            .and_then(|v| v.as_bool())
            .unwrap_or(false);
        let reason = params
            .get("reason")
            .and_then(|v| v.as_str())
            .unwrap_or("manual")
            .to_string();
        let max_parallel = params
            .get("maxParallel")
            .and_then(|v| v.as_u64())
            .map(|v| v.clamp(1, 32) as usize)
            .unwrap_or(8);
        let max_parallel_per_provider = probe_max_parallel_per_provider(&params);
        let provider_filter = provider_filter_from_params(&params);

        let _run_permit: OwnedSemaphorePermit = if background {
            match Arc::clone(&self.detect_gate).try_acquire_owned() {
                Ok(permit) => permit,
                Err(_) => {
                    return Ok(serde_json::json!({
                        "ok": true,
                        "background": true,
                        "reason": reason,
                        "skipped": true,
                        "message": "model probe already running",
                    }));
                },
            }
        } else {
            Arc::clone(&self.detect_gate)
                .acquire_owned()
                .await
                .map_err(|_| ServiceError::message("model probe gate closed"))?
        };

        // Install a cancellation token for this run so cancel_detect() can stop it.
        let cancel_token = CancellationToken::new();
        {
            let mut guard = self.detect_cancel.write().await;
            *guard = Some(cancel_token.clone());
        }

        let state = self.state.get().cloned();

        // Phase 0: re-discover models from provider APIs so that newly
        // added models (e.g. a model loaded into llama.cpp after startup)
        // are found before probing.
        {
            let env_snapshot = self.env_overrides.read().await.clone();
            let result = moltis_providers::fetch_discoverable_models(
                &self.providers_config,
                &env_snapshot,
                provider_filter.as_deref(),
            )
            .await;
            if !result.is_empty() {
                let mut reg = self.providers.write().await;
                let new_count = reg.register_rediscovered_models(
                    &self.providers_config,
                    &env_snapshot,
                    &result,
                );
                if new_count > 0 {
                    tracing::info!(
                        new_models = new_count,
                        "rediscovery registered new models before probe"
                    );
                }
            }
        }

        // Phase 1: notify clients to refresh and show the full current model list first.
        if let Some(state) = state.as_ref() {
            broadcast(
                state,
                "models.updated",
                serde_json::json!({
                    "phase": "catalog",
                    "background": background,
                    "reason": reason,
                    "provider": provider_filter.as_deref(),
                }),
                BroadcastOpts::default(),
            )
            .await;
        }

        let checks = {
            let reg = self.providers.read().await;
            let disabled = self.disabled.read().await;
            reg.list_models()
                .iter()
                .filter(|m| !disabled.is_disabled(&m.id))
                .filter(|m| provider_matches_filter(&m.provider, provider_filter.as_deref()))
                .filter_map(|m| {
                    reg.get(&m.id).map(|provider| {
                        (
                            m.id.clone(),
                            m.display_name.clone(),
                            provider.name().to_string(),
                            provider,
                        )
                    })
                })
                .collect::<Vec<_>>()
        };

        let total = checks.len();
        if let Some(state) = state.as_ref() {
            broadcast(
                state,
                "models.updated",
                serde_json::json!({
                    "phase": "start",
                    "background": background,
                    "reason": reason,
                    "provider": provider_filter.as_deref(),
                    "maxParallelPerProvider": max_parallel_per_provider,
                    "total": total,
                    "checked": 0,
                    "supported": 0,
                    "unsupported": 0,
                    "errors": 0,
                }),
                BroadcastOpts::default(),
            )
            .await;
        }

        let limiter = Arc::new(Semaphore::new(max_parallel));
        let provider_limiter = Arc::new(ProbeProviderLimiter::new(max_parallel_per_provider));
        let rate_limiter = Arc::new(ProbeRateLimiter::default());
        let mut tasks = tokio::task::JoinSet::new();
        for (model_id, display_name, provider_name, provider) in checks {
            let limiter = Arc::clone(&limiter);
            let provider_limiter = Arc::clone(&provider_limiter);
            let rate_limiter = Arc::clone(&rate_limiter);
            tasks.spawn(run_single_probe(
                model_id,
                display_name,
                provider_name,
                provider,
                limiter,
                provider_limiter,
                rate_limiter,
            ));
        }

        let mut results = Vec::with_capacity(total);
        let mut checked = 0usize;
        let mut supported = 0usize;
        let mut unsupported = 0usize;
        let mut flagged = 0usize;
        let mut cleared = 0usize;
        let mut errors = 0usize;
        let mut supported_by_provider: BTreeMap<String, Vec<Value>> = BTreeMap::new();
        let mut unsupported_by_provider: BTreeMap<String, Vec<Value>> = BTreeMap::new();
        let mut errors_by_provider: BTreeMap<String, Vec<Value>> = BTreeMap::new();

        let mut cancelled = false;
        loop {
            let joined = tokio::select! {
                biased;
                () = cancel_token.cancelled() => {
                    tasks.abort_all();
                    cancelled = true;
                    break;
                }
                next = tasks.join_next() => match next {
                    Some(joined) => joined,
                    None => break,
                },
            };
            checked += 1;
            let outcome = match joined {
                Ok(outcome) => outcome,
                Err(err) => {
                    errors += 1;
                    results.push(serde_json::json!({
                        "modelId": "",
                        "displayName": "",
                        "provider": "",
                        "status": "error",
                        "error": format!("probe task failed: {err}"),
                    }));
                    if let Some(state) = state.as_ref() {
                        broadcast(
                            state,
                            "models.updated",
                            serde_json::json!({
                                "phase": "progress",
                                "background": background,
                                "reason": reason,
                                "provider": provider_filter.as_deref(),
                                "total": total,
                                "checked": checked,
                                "supported": supported,
                                "unsupported": unsupported,
                                "errors": errors,
                            }),
                            BroadcastOpts::default(),
                        )
                        .await;
                    }
                    continue;
                },
            };

            match outcome.status {
                ProbeStatus::Supported => {
                    supported += 1;
                    push_provider_model(
                        &mut supported_by_provider,
                        &outcome.provider_name,
                        &outcome.model_id,
                        &outcome.display_name,
                    );
                    let mut changed = false;
                    {
                        let mut store = self.disabled.write().await;
                        if store.clear_unsupported(&outcome.model_id) {
                            changed = true;
                            if let Err(err) = store.save() {
                                warn!(
                                    model = %outcome.model_id,
                                    error = %err,
                                    "failed to persist unsupported model clear"
                                );
                            }
                        }
                    }
                    if changed {
                        cleared += 1;
                        if let Some(state) = state.as_ref() {
                            broadcast(
                                state,
                                "models.updated",
                                serde_json::json!({
                                    "modelId": outcome.model_id,
                                    "unsupported": false,
                                }),
                                BroadcastOpts::default(),
                            )
                            .await;
                        }
                    }

                    results.push(serde_json::json!({
                        "modelId": outcome.model_id,
                        "displayName": outcome.display_name,
                        "provider": outcome.provider_name,
                        "status": "supported",
                    }));
                },
                ProbeStatus::Unsupported { detail, provider } => {
                    unsupported += 1;
                    push_provider_model(
                        &mut unsupported_by_provider,
                        &outcome.provider_name,
                        &outcome.model_id,
                        &outcome.display_name,
                    );
                    let mut changed = false;
                    let mut updated_at_ms = now_ms();
                    {
                        let mut store = self.disabled.write().await;
                        if store.mark_unsupported(&outcome.model_id, &detail, Some(&provider)) {
                            changed = true;
                            if let Some(info) = store.unsupported_info(&outcome.model_id) {
                                updated_at_ms = info.updated_at_ms;
                            }
                            if let Err(save_err) = store.save() {
                                warn!(
                                    model = %outcome.model_id,
                                    provider = provider,
                                    error = %save_err,
                                    "failed to persist unsupported model flag"
                                );
                            }
                        }
                    }
                    if changed {
                        flagged += 1;
                        if let Some(state) = state.as_ref() {
                            broadcast(
                                state,
                                "models.updated",
                                serde_json::json!({
                                    "modelId": outcome.model_id,
                                    "unsupported": true,
                                    "unsupportedReason": detail,
                                    "unsupportedProvider": provider,
                                    "unsupportedUpdatedAt": updated_at_ms,
                                }),
                                BroadcastOpts::default(),
                            )
                            .await;
                        }
                    }

                    results.push(serde_json::json!({
                        "modelId": outcome.model_id,
                        "displayName": outcome.display_name,
                        "provider": outcome.provider_name,
                        "status": "unsupported",
                        "error": detail,
                    }));
                },
                ProbeStatus::Error { message } => {
                    errors += 1;
                    push_provider_model(
                        &mut errors_by_provider,
                        &outcome.provider_name,
                        &outcome.model_id,
                        &outcome.display_name,
                    );
                    results.push(serde_json::json!({
                        "modelId": outcome.model_id,
                        "displayName": outcome.display_name,
                        "provider": outcome.provider_name,
                        "status": "error",
                        "error": message,
                    }));
                },
            }

            if let Some(state) = state.as_ref() {
                broadcast(
                    state,
                    "models.updated",
                    serde_json::json!({
                        "phase": "progress",
                        "background": background,
                        "reason": reason,
                        "provider": provider_filter.as_deref(),
                        "total": total,
                        "checked": checked,
                        "supported": supported,
                        "unsupported": unsupported,
                        "errors": errors,
                    }),
                    BroadcastOpts::default(),
                )
                .await;
            }
        }

        // Clear the cancellation token now that the loop has exited.
        {
            let mut guard = self.detect_cancel.write().await;
            *guard = None;
        }

        let phase = if cancelled {
            "cancelled"
        } else {
            "complete"
        };
        let summary = serde_json::json!({
            "ok": true,
            "cancelled": cancelled,
            "probeWord": "ping",
            "background": background,
            "reason": reason,
            "provider": provider_filter.as_deref(),
            "maxParallel": max_parallel,
            "maxParallelPerProvider": max_parallel_per_provider,
            "total": total,
            "checked": checked,
            "supported": supported,
            "unsupported": unsupported,
            "flagged": flagged,
            "cleared": cleared,
            "errors": errors,
            "supportedByProvider": supported_by_provider,
            "unsupportedByProvider": unsupported_by_provider,
            "errorsByProvider": errors_by_provider,
            "results": results,
        });

        // Final refresh event to ensure clients are in sync after the full pass.
        if let Some(state) = state.as_ref() {
            broadcast(
                state,
                "models.updated",
                serde_json::json!({
                    "phase": phase,
                    "background": background,
                    "reason": reason,
                    "provider": provider_filter.as_deref(),
                    "summary": summary,
                }),
                BroadcastOpts::default(),
            )
            .await;
        }

        Ok(summary)
    }

    async fn cancel_detect(&self) -> ServiceResult {
        let token = self.detect_cancel.read().await.clone();
        let cancelled = if let Some(token) = token {
            token.cancel();
            true
        } else {
            false
        };
        Ok(serde_json::json!({ "ok": true, "cancelled": cancelled }))
    }

    async fn test(&self, params: Value) -> ServiceResult {
        let model_id = params
            .get("modelId")
            .and_then(|v| v.as_str())
            .ok_or_else(|| "missing 'modelId' parameter".to_string())?;

        let provider = {
            let reg = self.providers.read().await;
            if let Some(provider) = reg.get(model_id) {
                provider
            } else {
                let available_model_ids: Vec<String> =
                    reg.list_models().iter().map(|m| m.id.clone()).collect();
                let suggestions = suggest_model_ids(model_id, &available_model_ids, 5);
                warn!(
                    model_id,
                    available_model_count = available_model_ids.len(),
                    available_model_ids = ?available_model_ids,
                    suggested_model_ids = ?suggestions,
                    "models.test received unknown model id"
                );
                let suggestion_hint = if suggestions.is_empty() {
                    String::new()
                } else {
                    format!(". did you mean: {}", suggestions.join(", "))
                };
                return Err(format!("unknown model: {model_id}{suggestion_hint}").into());
            }
        };
        let started = Instant::now();
        info!(model_id, provider = provider.name(), "model probe started");

        match provider.probe().await {
            Ok(()) => {
                info!(
                    model_id,
                    provider = provider.name(),
                    elapsed_ms = started.elapsed().as_millis(),
                    "model probe succeeded"
                );
                Ok(serde_json::json!({
                    "ok": true,
                    "modelId": model_id,
                }))
            },
            Err(err) => {
                let error_text = err.to_string();
                let error_obj = parse_chat_error(&error_text, Some(provider.name()));
                let detail = error_obj
                    .get("detail")
                    .and_then(|v| v.as_str())
                    .unwrap_or(&error_text)
                    .to_string();

                warn!(
                    model_id,
                    provider = provider.name(),
                    elapsed_ms = started.elapsed().as_millis(),
                    error = %detail,
                    "model probe failed"
                );
                Err(detail.into())
            },
        }
    }
}

//! Agent runner: LLM call loop with tool execution, retry, and streaming support.

mod non_streaming;
pub mod retry;
mod streaming;
pub mod tool_result;

#[cfg(test)]
mod tests;

use std::borrow::Cow;

use tracing::{info, warn};

use moltis_common::hooks::ChannelBinding;

use crate::{
    model::{ChatMessage, ToolCall, Usage, UserContent},
    tool_loop_detector::{
        LoopDetectorAction, ToolLoopDetector, format_intervention_message,
        format_strip_tools_message,
    },
};

// ── Re-exports (preserve public API) ────────────────────────────────────

pub use non_streaming::{run_agent, run_agent_loop, run_agent_loop_with_context};
pub use streaming::run_agent_loop_streaming;
pub use tool_result::{ExtractedImage, sanitize_tool_result, tool_result_to_content};

// ── Constants ───────────────────────────────────────────────────────────

const TOOL_RESULT_COMPACTION_RATIO_PERCENT: usize = 75;
const PREEMPTIVE_OVERFLOW_RATIO_PERCENT: usize = 90;
const TOOL_RESULT_COMPACTION_PLACEHOLDER: &str =
    "[tool result compacted to preserve context budget]";
const TOOL_RESULT_COMPACTION_MIN_BYTES: usize = 200;

const MALFORMED_TOOL_RETRY_PROMPT: &str = "Your tool call was malformed. Retry with exact format:\n\
     ```tool_call\n{\"tool\": \"name\", \"arguments\": {...}}\n```";
const EMPTY_TOOL_NAME_RETRY_PROMPT: &str = "Your structured tool call had an empty tool name. Retry the same tool call using the intended tool's exact name and the same arguments.";

/// Nudge sent to the model when auto-continue fires after it stopped mid-task
/// without emitting a substantive final answer.
///
/// Deliberately avoids phrasing like "provide a brief final answer" because
/// that invites the model to overwrite an already-emitted long response with
/// a terse summary (see GH #628).
const AUTO_CONTINUE_NUDGE: &str = "Your previous response ended without tool calls and without a final answer. \
     If there are still steps to run, continue executing them. \
     Otherwise reply with exactly: done";

/// Minimum character count (after trimming) that qualifies an assistant text
/// response as a "substantive final answer" — at or above this length the
/// auto-continue nudge is suppressed because the model has clearly finished
/// talking and nudging it risks losing the answer (GH #628).
const AUTO_CONTINUE_SUBSTANTIVE_TEXT_THRESHOLD: usize = 40;

// ── Typed errors and result ─────────────────────────────────────────────

/// Typed errors from the agent loop.
#[derive(Debug, thiserror::Error)]
pub enum AgentRunError {
    /// The provider reported that the context window / token limit was exceeded.
    #[error("context window exceeded: {0}")]
    ContextWindowExceeded(String),
    /// Any other error.
    #[error(transparent)]
    Other(#[from] anyhow::Error),
}

/// Result of running the agent loop.
#[derive(Debug)]
pub struct AgentRunResult {
    pub text: String,
    pub iterations: usize,
    pub tool_calls_made: usize,
    /// Sum of usage across all LLM requests in this run.
    pub usage: Usage,
    /// Usage for the final LLM request in this run.
    pub request_usage: Usage,
    pub raw_llm_responses: Vec<serde_json::Value>,
}

/// Callback for streaming events out of the runner.
pub type OnEvent = Box<dyn Fn(RunnerEvent) + Send + Sync>;

/// Events emitted during the agent run.
#[derive(Debug, Clone)]
pub enum RunnerEvent {
    /// LLM is processing (show a "thinking" indicator).
    Thinking,
    /// LLM finished thinking (hide the indicator).
    ThinkingDone,
    ToolCallStart {
        id: String,
        name: String,
        arguments: serde_json::Value,
    },
    ToolCallEnd {
        id: String,
        name: String,
        success: bool,
        error: Option<String>,
        result: Option<serde_json::Value>,
    },
    /// LLM returned reasoning/status text alongside tool calls.
    ThinkingText(String),
    TextDelta(String),
    Iteration(usize),
    SubAgentStart {
        task: String,
        model: String,
        depth: u64,
    },
    SubAgentEnd {
        task: String,
        model: String,
        depth: u64,
        iterations: usize,
        tool_calls_made: usize,
    },
    /// A transient LLM error occurred and the runner will retry.
    RetryingAfterError {
        error: String,
        delay_ms: u64,
    },
    /// The model stopped without tool calls but iteration budget remains;
    /// the runner is automatically re-prompting.
    AutoContinue {
        iteration: usize,
        max_iterations: usize,
    },
    /// A tool call was rejected by pre-dispatch schema validation before the
    /// tool's `execute` method ran. Used in place of the usual
    /// `ToolCallStart`/`ToolCallEnd` pair for rejected calls so the UI does
    /// not render a misleading "executing" status for a call that never
    /// actually executed.
    ToolCallRejected {
        id: String,
        name: String,
        arguments: serde_json::Value,
        error: String,
    },
    /// The loop detector fired after observing repeated identical tool-call
    /// failures. `stage` is 1 for the nudge/directive intervention and 2 for
    /// the stronger tool-stripping escalation (see issue #658).
    LoopInterventionFired {
        stage: u8,
        tool_name: String,
    },
}

// ── Shared helper functions ─────────────────────────────────────────────

/// Sanitize a tool name from model output.
///
/// Handles quirks from various LLM providers:
/// 1. Trims whitespace
/// 2. Strips surrounding double quotes (some models quote tool names)
/// 3. Strips `functions_` prefix (OpenAI legacy artifact from some models)
/// 4. Strips trailing `_\d+` suffix (parallel-call indexing from some models,
///    e.g. Kimi K2.5 via OpenRouter sends `exec_2`, `browser_4`)
fn sanitize_tool_name(name: &str) -> Cow<'_, str> {
    let trimmed = name.trim();
    let unquoted = trimmed
        .strip_prefix('"')
        .and_then(|s| s.strip_suffix('"'))
        .unwrap_or(trimmed);

    // Strip `functions_` prefix (OpenAI legacy artifact from some models).
    // INVARIANT: no registered tool name starts with "functions_".
    let without_prefix = unquoted.strip_prefix("functions_").unwrap_or(unquoted);

    // Strip trailing `_\d+` suffix (parallel-call indexing from some models).
    // INVARIANT: no registered tool name ends with `_\d+` (a purely numeric segment after the last underscore).
    let cleaned = without_prefix
        .rfind('_')
        .and_then(|pos| {
            let suffix = &without_prefix[pos + 1..];
            if !suffix.is_empty() && suffix.bytes().all(|b| b.is_ascii_digit()) && pos > 0 {
                Some(&without_prefix[..pos])
            } else {
                None
            }
        })
        .unwrap_or(without_prefix);

    if cleaned == name {
        Cow::Borrowed(name)
    } else {
        Cow::Owned(cleaned.to_string())
    }
}

/// Detect an explicit shell command in the latest user turn.
///
/// Only `/sh ...` commands are treated as explicit shell execution requests.
/// This keeps normal chat turns (`hey`, `hello`, etc.) out of the forced-exec path.
///
/// Supported forms:
/// - `/sh pwd`
/// - `/sh@mybot uname -a`
fn explicit_shell_command_from_user_content(user_content: &UserContent) -> Option<String> {
    let text = match user_content {
        UserContent::Text(text) => text.trim(),
        UserContent::Multimodal(_) => return None,
    };

    if text.is_empty() || text.len() > 4096 || text.contains('\n') || text.contains('\r') {
        return None;
    }

    let rest = text.strip_prefix('/')?;
    let split_idx = rest.find(char::is_whitespace)?;
    let head = &rest[..split_idx];
    let command = rest[split_idx..].trim_start();
    if command.is_empty() {
        return None;
    }

    let head_lower = head.to_ascii_lowercase();
    let is_sh_prefix = if head_lower == "sh" {
        true
    } else {
        head_lower
            .strip_prefix("sh@")
            .is_some_and(|mention| !mention.is_empty())
    };

    if !is_sh_prefix {
        return None;
    }

    Some(command.to_string())
}

/// Returns `true` if `text` (trimmed) is long enough to be considered a real
/// final answer rather than an empty/terse pause.
#[must_use]
fn is_substantive_answer_text(text: &str) -> bool {
    text.trim().chars().count() >= AUTO_CONTINUE_SUBSTANTIVE_TEXT_THRESHOLD
}

fn find_empty_tool_name_call(tool_calls: &[ToolCall]) -> Option<&ToolCall> {
    tool_calls
        .iter()
        .find(|tc| sanitize_tool_name(&tc.name).is_empty())
}

fn has_named_tool_call(tool_calls: &[ToolCall]) -> bool {
    tool_calls
        .iter()
        .any(|tc| !sanitize_tool_name(&tc.name).is_empty())
}

fn empty_tool_name_retry_prompt(tool_call: &ToolCall) -> String {
    format!(
        "{EMPTY_TOOL_NAME_RETRY_PROMPT}\nExact arguments JSON:\n{}",
        tool_call.arguments
    )
}

fn record_answer_text(last_answer_text: &mut String, text: &Option<String>) {
    if let Some(text) = text.as_ref()
        && !text.is_empty()
    {
        last_answer_text.clone_from(text);
    }
}

fn streaming_tool_call_message_content(
    last_answer_text: &mut String,
    accumulated_text: &str,
    accumulated_reasoning: &str,
) -> Option<String> {
    if !accumulated_reasoning.is_empty() {
        Some(accumulated_reasoning.to_string())
    } else if !accumulated_text.is_empty() {
        last_answer_text.clear();
        last_answer_text.push_str(accumulated_text);
        Some(accumulated_text.to_string())
    } else {
        None
    }
}

#[must_use]
fn estimate_prompt_text_tokens(text: &str) -> usize {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return 0;
    }
    trimmed.len().div_ceil(4).max(1)
}

#[must_use]
fn estimate_message_tokens(message: &ChatMessage) -> usize {
    estimate_prompt_text_tokens(&message.to_openai_value().to_string())
}

#[must_use]
fn estimate_prompt_tokens(messages: &[ChatMessage], tool_schemas: &[serde_json::Value]) -> usize {
    let message_tokens: usize = messages.iter().map(estimate_message_tokens).sum();
    let tool_tokens: usize = tool_schemas
        .iter()
        .map(|schema| estimate_prompt_text_tokens(&schema.to_string()))
        .sum();
    message_tokens.saturating_add(tool_tokens)
}

#[must_use]
fn has_tool_result_messages(messages: &[ChatMessage]) -> bool {
    messages
        .iter()
        .any(|message| matches!(message, ChatMessage::Tool { .. }))
}

fn compact_tool_results_newest_first_in_place(
    messages: &mut [ChatMessage],
    tokens_needed: usize,
) -> usize {
    if tokens_needed == 0 {
        return 0;
    }

    let mut reduced = 0;
    for message in messages.iter_mut().rev() {
        if reduced >= tokens_needed {
            break;
        }

        let ChatMessage::Tool {
            tool_call_id,
            content,
        } = message
        else {
            continue;
        };
        if content == TOOL_RESULT_COMPACTION_PLACEHOLDER
            || content.len() < TOOL_RESULT_COMPACTION_MIN_BYTES
        {
            continue;
        }

        let tool_call_id = tool_call_id.clone();
        let original = content.clone();
        let before = estimate_message_tokens(&ChatMessage::tool(&tool_call_id, &original));
        *content = TOOL_RESULT_COMPACTION_PLACEHOLDER.to_string();
        let after = estimate_message_tokens(&ChatMessage::tool(
            &tool_call_id,
            TOOL_RESULT_COMPACTION_PLACEHOLDER,
        ));
        let saved = before.saturating_sub(after);
        if saved == 0 {
            *content = original;
            continue;
        }

        reduced = reduced.saturating_add(saved);
    }

    reduced
}

fn enforce_tool_result_context_budget(
    messages: &mut [ChatMessage],
    tool_schemas: &[serde_json::Value],
    context_window: u32,
) -> Result<(), AgentRunError> {
    let context_window = context_window as usize;
    if context_window == 0 || !has_tool_result_messages(messages) {
        return Ok(());
    }

    let compaction_budget =
        context_window.saturating_mul(TOOL_RESULT_COMPACTION_RATIO_PERCENT) / 100;
    let overflow_budget = context_window.saturating_mul(PREEMPTIVE_OVERFLOW_RATIO_PERCENT) / 100;
    let current_tokens = estimate_prompt_tokens(messages, tool_schemas);

    if current_tokens > compaction_budget {
        let needed = current_tokens.saturating_sub(compaction_budget);
        let reduced = compact_tool_results_newest_first_in_place(messages, needed);
        tracing::debug!(
            current_tokens,
            compaction_budget,
            overflow_budget,
            needed,
            reduced,
            "compacted newest tool results to preserve prompt budget"
        );
    }

    let post_compaction_tokens = estimate_prompt_tokens(messages, tool_schemas);
    if post_compaction_tokens > overflow_budget {
        return Err(AgentRunError::ContextWindowExceeded(format!(
            "preemptive context overflow: estimated prompt size {post_compaction_tokens} tokens exceeds {overflow_budget} token budget after tool-result compaction"
        )));
    }

    Ok(())
}

fn channel_binding_from_tool_context(
    session_key: &str,
    tool_context: Option<&serde_json::Value>,
) -> Option<ChannelBinding> {
    let channel_value = tool_context.and_then(|ctx| ctx.get("_channel"))?;
    match serde_json::from_value(channel_value.clone()) {
        Ok(binding) => Some(binding),
        Err(error) => {
            warn!(
                error = %error,
                session = %session_key,
                "failed to parse _channel tool context for hooks; ignoring channel provenance"
            );
            None
        },
    }
}

/// Consume the detector's post-batch action (if any) and apply it to the
/// runner state: push the directive user message into `messages`, emit the
/// `LoopInterventionFired` UI event, and set `strip_tools_next_iter` when
/// stage 2 fires. Shared by the streaming and non-streaming loops (issue
/// #658).
fn apply_loop_detector_intervention(
    loop_detector: &mut ToolLoopDetector,
    messages: &mut Vec<ChatMessage>,
    strip_tools_next_iter: &mut bool,
    on_event: Option<&OnEvent>,
) {
    if !loop_detector.is_enabled() {
        return;
    }
    match loop_detector.consume_pending_action() {
        LoopDetectorAction::None => {},
        LoopDetectorAction::InjectNudge => {
            let window = loop_detector.window_snapshot();
            let stuck_tool = window
                .first()
                .map(|fp| fp.tool_name.clone())
                .unwrap_or_default();
            let intervention = format_intervention_message(&window);
            info!(
                tool = %stuck_tool,
                "loop detector fired (stage 1): injecting directive intervention"
            );
            if let Some(cb) = on_event {
                cb(RunnerEvent::LoopInterventionFired {
                    stage: 1,
                    tool_name: stuck_tool,
                });
            }
            messages.push(ChatMessage::user(intervention));
        },
        LoopDetectorAction::StripTools => {
            let stuck_tool = loop_detector
                .window_snapshot()
                .first()
                .map(|fp| fp.tool_name.clone())
                .unwrap_or_default();
            info!(
                tool = %stuck_tool,
                "loop detector fired (stage 2): stripping tools for next iteration"
            );
            if let Some(cb) = on_event {
                cb(RunnerEvent::LoopInterventionFired {
                    stage: 2,
                    tool_name: stuck_tool,
                });
            }
            messages.push(ChatMessage::user(format_strip_tools_message()));
            *strip_tools_next_iter = true;
        },
    }
}

//! Config, identity, soul, memory, and environment variable FFI exports.

use std::ffi::c_char;

use secrecy::ExposeSecret;

use crate::{
    callbacks::emit_log,
    helpers::{
        config_dir_string, data_dir_string, encode_error, encode_json, format_bytes,
        parse_ffi_request, record_call, record_error, trace_call, vault_status_string,
        with_ffi_boundary,
    },
    state::BRIDGE,
    types::*,
};

// ── Config FFI ───────────────────────────────────────────────────────────

/// Returns the full `MoltisConfig` as JSON together with `config_dir` and
/// `data_dir` paths. Swift uses this to populate all settings panels.
#[unsafe(no_mangle)]
pub extern "C" fn moltis_get_config() -> *mut c_char {
    record_call("moltis_get_config");
    trace_call("moltis_get_config");

    with_ffi_boundary(|| {
        emit_log("DEBUG", "bridge", "moltis_get_config called");
        let config = moltis_config::discover_and_load();
        let config_value = match serde_json::to_value(&config) {
            Ok(v) => v,
            Err(e) => return encode_error("serialization_error", &e.to_string()),
        };
        let response = GetConfigResponse {
            config: config_value,
            config_dir: config_dir_string(),
            data_dir: data_dir_string(),
        };
        emit_log("INFO", "bridge", "Config loaded for settings");
        encode_json(&response)
    })
}

/// Accepts a full `MoltisConfig` JSON and saves it via `save_config()`.
/// The TOML writer preserves existing comments in the config file.
#[unsafe(no_mangle)]
pub extern "C" fn moltis_save_config(request_json: *const c_char) -> *mut c_char {
    record_call("moltis_save_config");
    trace_call("moltis_save_config");

    with_ffi_boundary(|| {
        let config = match parse_ffi_request::<moltis_config::MoltisConfig>(
            "moltis_save_config",
            request_json,
        ) {
            Ok(c) => c,
            Err(e) => return e,
        };

        emit_log("INFO", "bridge.config", "Saving full config from settings");
        match moltis_config::save_config(&config) {
            Ok(path) => {
                emit_log(
                    "INFO",
                    "bridge.config",
                    &format!("Config saved to {}", path.display()),
                );
                encode_json(&OkResponse { ok: true })
            },
            Err(e) => {
                emit_log("ERROR", "bridge.config", &format!("Save failed: {e}"));
                encode_error("save_failed", &e.to_string())
            },
        }
    })
}

// ── Memory FFI ───────────────────────────────────────────────────────────

/// Returns memory status (counts + db size) for the settings panel.
#[unsafe(no_mangle)]
pub extern "C" fn moltis_memory_status() -> *mut c_char {
    record_call("moltis_memory_status");
    trace_call("moltis_memory_status");

    with_ffi_boundary(|| {
        use {sqlx::sqlite::SqliteConnectOptions, std::str::FromStr};

        let config = moltis_config::discover_and_load();
        let embedding_model = config
            .memory
            .model
            .clone()
            .unwrap_or_else(|| "none".to_owned());
        let has_embeddings = !config.memory.disable_rag;

        let db_path = moltis_config::data_dir().join("memory.db");
        let db_size = std::fs::metadata(&db_path).map(|m| m.len()).unwrap_or(0);

        if !db_path.exists() {
            let response = MemoryStatusResponse {
                available: false,
                total_files: 0,
                total_chunks: 0,
                db_size,
                db_size_display: format_bytes(db_size),
                embedding_model,
                has_embeddings,
                error: Some("memory.db not found".to_owned()),
            };
            return encode_json(&response);
        }

        let options = match SqliteConnectOptions::from_str(&format!("sqlite:{}", db_path.display()))
        {
            Ok(opts) => opts.create_if_missing(false).read_only(true),
            Err(error) => {
                let response = MemoryStatusResponse {
                    available: false,
                    total_files: 0,
                    total_chunks: 0,
                    db_size,
                    db_size_display: format_bytes(db_size),
                    embedding_model,
                    has_embeddings,
                    error: Some(format!("invalid sqlite path: {error}")),
                };
                return encode_json(&response);
            },
        };

        let pool = match BRIDGE
            .runtime
            .block_on(sqlx::SqlitePool::connect_with(options))
        {
            Ok(pool) => pool,
            Err(error) => {
                let response = MemoryStatusResponse {
                    available: false,
                    total_files: 0,
                    total_chunks: 0,
                    db_size,
                    db_size_display: format_bytes(db_size),
                    embedding_model,
                    has_embeddings,
                    error: Some(format!("failed to open memory.db: {error}")),
                };
                return encode_json(&response);
            },
        };

        let (total_files, total_chunks) = BRIDGE.runtime.block_on(async {
            let has_files_table: i64 = sqlx::query_scalar(
                "SELECT COUNT(*) FROM sqlite_master WHERE type = 'table' AND name = 'files'",
            )
            .fetch_one(&pool)
            .await
            .unwrap_or(0);
            let has_chunks_table: i64 = sqlx::query_scalar(
                "SELECT COUNT(*) FROM sqlite_master WHERE type = 'table' AND name = 'chunks'",
            )
            .fetch_one(&pool)
            .await
            .unwrap_or(0);

            let files: i64 = if has_files_table > 0 {
                sqlx::query_scalar("SELECT COUNT(*) FROM files")
                    .fetch_one(&pool)
                    .await
                    .unwrap_or(0)
            } else {
                0
            };
            let chunks: i64 = if has_chunks_table > 0 {
                sqlx::query_scalar("SELECT COUNT(*) FROM chunks")
                    .fetch_one(&pool)
                    .await
                    .unwrap_or(0)
            } else {
                0
            };

            let files_count: usize = files.max(0).try_into().unwrap_or(0);
            let chunk_count: usize = chunks.max(0).try_into().unwrap_or(0);
            (files_count, chunk_count)
        });
        BRIDGE.runtime.block_on(pool.close());

        let response = MemoryStatusResponse {
            available: true,
            total_files,
            total_chunks,
            db_size,
            db_size_display: format_bytes(db_size),
            embedding_model,
            has_embeddings,
            error: None,
        };
        encode_json(&response)
    })
}

/// Returns memory configuration fields used by the settings panel.
#[unsafe(no_mangle)]
pub extern "C" fn moltis_memory_config_get() -> *mut c_char {
    record_call("moltis_memory_config_get");
    trace_call("moltis_memory_config_get");

    with_ffi_boundary(|| {
        let config = moltis_config::discover_and_load();
        let memory = config.memory;
        let chat = config.chat;
        let response = MemoryConfigResponse {
            style: match memory.style {
                moltis_config::MemoryStyle::Hybrid => "hybrid".to_owned(),
                moltis_config::MemoryStyle::PromptOnly => "prompt-only".to_owned(),
                moltis_config::MemoryStyle::SearchOnly => "search-only".to_owned(),
                moltis_config::MemoryStyle::Off => "off".to_owned(),
            },
            agent_write_mode: match memory.agent_write_mode {
                moltis_config::AgentMemoryWriteMode::Hybrid => "hybrid".to_owned(),
                moltis_config::AgentMemoryWriteMode::PromptOnly => "prompt-only".to_owned(),
                moltis_config::AgentMemoryWriteMode::SearchOnly => "search-only".to_owned(),
                moltis_config::AgentMemoryWriteMode::Off => "off".to_owned(),
            },
            user_profile_write_mode: match memory.user_profile_write_mode {
                moltis_config::UserProfileWriteMode::ExplicitAndAuto => {
                    "explicit-and-auto".to_owned()
                },
                moltis_config::UserProfileWriteMode::ExplicitOnly => "explicit-only".to_owned(),
                moltis_config::UserProfileWriteMode::Off => "off".to_owned(),
            },
            backend: match memory.backend {
                moltis_config::MemoryBackend::Builtin => "builtin".to_owned(),
                moltis_config::MemoryBackend::Qmd => "qmd".to_owned(),
            },
            provider: match memory.provider {
                Some(moltis_config::MemoryProvider::Local) => "local".to_owned(),
                Some(moltis_config::MemoryProvider::Ollama) => "ollama".to_owned(),
                Some(moltis_config::MemoryProvider::OpenAi) => "openai".to_owned(),
                Some(moltis_config::MemoryProvider::Custom) => "custom".to_owned(),
                None => "auto".to_owned(),
            },
            citations: match memory.citations {
                moltis_config::MemoryCitationsMode::On => "on".to_owned(),
                moltis_config::MemoryCitationsMode::Off => "off".to_owned(),
                moltis_config::MemoryCitationsMode::Auto => "auto".to_owned(),
            },
            disable_rag: memory.disable_rag,
            llm_reranking: memory.llm_reranking,
            search_merge_strategy: match memory.search_merge_strategy {
                moltis_config::MemorySearchMergeStrategy::Rrf => "rrf".to_owned(),
                moltis_config::MemorySearchMergeStrategy::Linear => "linear".to_owned(),
            },
            session_export: match memory.session_export {
                moltis_config::SessionExportMode::Off => "off".to_owned(),
                moltis_config::SessionExportMode::OnNewOrReset => "on-new-or-reset".to_owned(),
            },
            prompt_memory_mode: match chat.prompt_memory_mode {
                moltis_config::PromptMemoryMode::LiveReload => "live-reload".to_owned(),
                moltis_config::PromptMemoryMode::FrozenAtSessionStart => {
                    "frozen-at-session-start".to_owned()
                },
            },
            qmd_feature_enabled: cfg!(feature = "qmd"),
        };
        encode_json(&response)
    })
}

/// Updates memory configuration fields used by the settings panel.
#[unsafe(no_mangle)]
pub extern "C" fn moltis_memory_config_update(request_json: *const c_char) -> *mut c_char {
    record_call("moltis_memory_config_update");
    trace_call("moltis_memory_config_update");

    with_ffi_boundary(|| {
        let request = match parse_ffi_request::<MemoryConfigUpdateRequest>(
            "moltis_memory_config_update",
            request_json,
        ) {
            Ok(request) => request,
            Err(e) => return e,
        };

        let current_config = moltis_config::discover_and_load();
        let current = current_config.memory;
        let current_chat = current_config.chat;
        let style = request.style.unwrap_or_else(|| match current.style {
            moltis_config::MemoryStyle::Hybrid => "hybrid".to_owned(),
            moltis_config::MemoryStyle::PromptOnly => "prompt-only".to_owned(),
            moltis_config::MemoryStyle::SearchOnly => "search-only".to_owned(),
            moltis_config::MemoryStyle::Off => "off".to_owned(),
        });
        let agent_write_mode =
            request
                .agent_write_mode
                .unwrap_or_else(|| match current.agent_write_mode {
                    moltis_config::AgentMemoryWriteMode::Hybrid => "hybrid".to_owned(),
                    moltis_config::AgentMemoryWriteMode::PromptOnly => "prompt-only".to_owned(),
                    moltis_config::AgentMemoryWriteMode::SearchOnly => "search-only".to_owned(),
                    moltis_config::AgentMemoryWriteMode::Off => "off".to_owned(),
                });
        let user_profile_write_mode = request.user_profile_write_mode.unwrap_or_else(|| {
            match current.user_profile_write_mode {
                moltis_config::UserProfileWriteMode::ExplicitAndAuto => {
                    "explicit-and-auto".to_owned()
                },
                moltis_config::UserProfileWriteMode::ExplicitOnly => "explicit-only".to_owned(),
                moltis_config::UserProfileWriteMode::Off => "off".to_owned(),
            }
        });
        let backend = request.backend.unwrap_or_else(|| match current.backend {
            moltis_config::MemoryBackend::Builtin => "builtin".to_owned(),
            moltis_config::MemoryBackend::Qmd => "qmd".to_owned(),
        });
        let provider = request.provider.unwrap_or_else(|| match current.provider {
            Some(moltis_config::MemoryProvider::Local) => "local".to_owned(),
            Some(moltis_config::MemoryProvider::Ollama) => "ollama".to_owned(),
            Some(moltis_config::MemoryProvider::OpenAi) => "openai".to_owned(),
            Some(moltis_config::MemoryProvider::Custom) => "custom".to_owned(),
            None => "auto".to_owned(),
        });
        let citations = request
            .citations
            .unwrap_or_else(|| match current.citations {
                moltis_config::MemoryCitationsMode::On => "on".to_owned(),
                moltis_config::MemoryCitationsMode::Off => "off".to_owned(),
                moltis_config::MemoryCitationsMode::Auto => "auto".to_owned(),
            });
        let llm_reranking = request.llm_reranking.unwrap_or(current.llm_reranking);
        let search_merge_strategy = request
            .search_merge_strategy
            .unwrap_or_else(|| match current.search_merge_strategy {
                moltis_config::MemorySearchMergeStrategy::Rrf => "rrf".to_owned(),
                moltis_config::MemorySearchMergeStrategy::Linear => "linear".to_owned(),
            });
        let session_export = request.session_export.map_or_else(
            || match current.session_export {
                moltis_config::SessionExportMode::Off => "off".to_owned(),
                moltis_config::SessionExportMode::OnNewOrReset => "on-new-or-reset".to_owned(),
            },
            |value| match value {
                SessionExportUpdateValue::Mode(mode) => mode,
                SessionExportUpdateValue::LegacyBool(enabled) => {
                    if enabled {
                        "on-new-or-reset".to_owned()
                    } else {
                        "off".to_owned()
                    }
                },
            },
        );
        let prompt_memory_mode =
            request
                .prompt_memory_mode
                .unwrap_or_else(|| match current_chat.prompt_memory_mode {
                    moltis_config::PromptMemoryMode::LiveReload => "live-reload".to_owned(),
                    moltis_config::PromptMemoryMode::FrozenAtSessionStart => {
                        "frozen-at-session-start".to_owned()
                    },
                });
        let mut disable_rag = current.disable_rag;

        let style_value = match style.as_str() {
            "prompt-only" => moltis_config::MemoryStyle::PromptOnly,
            "search-only" => moltis_config::MemoryStyle::SearchOnly,
            "off" => moltis_config::MemoryStyle::Off,
            _ => moltis_config::MemoryStyle::Hybrid,
        };
        let agent_write_mode_value = match agent_write_mode.as_str() {
            "prompt-only" => moltis_config::AgentMemoryWriteMode::PromptOnly,
            "search-only" => moltis_config::AgentMemoryWriteMode::SearchOnly,
            "off" => moltis_config::AgentMemoryWriteMode::Off,
            _ => moltis_config::AgentMemoryWriteMode::Hybrid,
        };
        let user_profile_write_mode_value = match user_profile_write_mode.as_str() {
            "explicit-only" => moltis_config::UserProfileWriteMode::ExplicitOnly,
            "off" => moltis_config::UserProfileWriteMode::Off,
            _ => moltis_config::UserProfileWriteMode::ExplicitAndAuto,
        };
        let backend_value = match backend.as_str() {
            "qmd" => moltis_config::MemoryBackend::Qmd,
            _ => moltis_config::MemoryBackend::Builtin,
        };
        let provider_value = match provider.as_str() {
            "local" => Some(moltis_config::MemoryProvider::Local),
            "ollama" => Some(moltis_config::MemoryProvider::Ollama),
            "openai" => Some(moltis_config::MemoryProvider::OpenAi),
            "custom" => Some(moltis_config::MemoryProvider::Custom),
            _ => None,
        };
        let citations_value = match citations.as_str() {
            "on" => moltis_config::MemoryCitationsMode::On,
            "off" => moltis_config::MemoryCitationsMode::Off,
            _ => moltis_config::MemoryCitationsMode::Auto,
        };
        let search_merge_strategy_value = match search_merge_strategy.as_str() {
            "linear" => moltis_config::MemorySearchMergeStrategy::Linear,
            _ => moltis_config::MemorySearchMergeStrategy::Rrf,
        };
        let session_export_value = match session_export.as_str() {
            "off" => moltis_config::SessionExportMode::Off,
            _ => moltis_config::SessionExportMode::OnNewOrReset,
        };
        let prompt_memory_mode_value = match prompt_memory_mode.as_str() {
            "frozen-at-session-start" => moltis_config::PromptMemoryMode::FrozenAtSessionStart,
            _ => moltis_config::PromptMemoryMode::LiveReload,
        };

        if let Err(error) = moltis_config::update_config(|cfg| {
            cfg.memory.style = style_value;
            cfg.memory.agent_write_mode = agent_write_mode_value;
            cfg.memory.user_profile_write_mode = user_profile_write_mode_value;
            cfg.memory.backend = backend_value;
            cfg.memory.provider = provider_value;
            cfg.memory.citations = citations_value;
            cfg.memory.llm_reranking = llm_reranking;
            cfg.memory.search_merge_strategy = search_merge_strategy_value;
            if let Some(value) = request.disable_rag {
                cfg.memory.disable_rag = value;
            }
            cfg.memory.session_export = session_export_value;
            cfg.chat.prompt_memory_mode = prompt_memory_mode_value;
            disable_rag = cfg.memory.disable_rag;
        }) {
            record_error("moltis_memory_config_update", "save_failed");
            return encode_error("save_failed", &error.to_string());
        }

        let response = MemoryConfigResponse {
            style,
            agent_write_mode,
            user_profile_write_mode,
            backend,
            provider,
            citations,
            disable_rag,
            llm_reranking,
            search_merge_strategy,
            session_export,
            prompt_memory_mode,
            qmd_feature_enabled: cfg!(feature = "qmd"),
        };
        encode_json(&response)
    })
}

/// Returns QMD availability (binary detection + optional version).
#[unsafe(no_mangle)]
pub extern "C" fn moltis_memory_qmd_status() -> *mut c_char {
    record_call("moltis_memory_qmd_status");
    trace_call("moltis_memory_qmd_status");

    with_ffi_boundary(|| {
        if !cfg!(feature = "qmd") {
            let response = MemoryQmdStatusResponse {
                feature_enabled: false,
                available: false,
                version: None,
                error: Some("QMD feature is disabled in this build".to_owned()),
            };
            return encode_json(&response);
        }

        let command = moltis_config::discover_and_load()
            .memory
            .qmd
            .command
            .unwrap_or_else(|| "qmd".to_owned());

        let output = std::process::Command::new(&command)
            .arg("--version")
            .output();

        let response = match output {
            Ok(out) if out.status.success() => {
                let version = String::from_utf8_lossy(&out.stdout).trim().to_owned();
                let resolved_version = if version.is_empty() {
                    None
                } else {
                    Some(version)
                };
                MemoryQmdStatusResponse {
                    feature_enabled: true,
                    available: true,
                    version: resolved_version,
                    error: None,
                }
            },
            Ok(out) => {
                let stderr = String::from_utf8_lossy(&out.stderr).trim().to_owned();
                let detail = if stderr.is_empty() {
                    format!("{command} --version exited with status {}", out.status)
                } else {
                    stderr
                };
                MemoryQmdStatusResponse {
                    feature_enabled: true,
                    available: false,
                    version: None,
                    error: Some(detail),
                }
            },
            Err(error) => MemoryQmdStatusResponse {
                feature_enabled: true,
                available: false,
                version: None,
                error: Some(error.to_string()),
            },
        };

        encode_json(&response)
    })
}

