                        .as_ref()
                        .map(|value| value.display().to_string())
                        .unwrap_or_else(|| "moltis.toml only".to_string());
                    emit_log(
                        "INFO",
                        "bridge.config",
                        &format!("User profile saved to {destination}"),
                    );
                    encode_json(&OkResponse { ok: true })
                },
                Err(e) => {
                    emit_log(
                        "ERROR",
                        "bridge.config",
