6988→        Some(ToolMode::Off) => ToolMode::Off,
6989→        Some(ToolMode::Auto) | None => {
6990→            if provider.supports_tools() {
6991→                ToolMode::Native
6992→            } else {
6993→                ToolMode::Text
6994→            }
6995→        },
6996→    }
