                tool_calls: vec![],
                usage: Usage {
                    input_tokens: 10,
                    output_tokens: 10,
                    ..Default::default()
                },
            })
        } else {
            let assistant_tool_text = messages
                .iter()
                .find_map(|m| {
                    if let ChatMessage::Assistant {
                        content,
                        tool_calls,
                    } = m
                    {
                        if tool_calls.is_empty() {
                            return None;
                        }
                        return content.as_deref();
                    }
                    None
                })
                .unwrap_or("");
            assert!(
                !assistant_tool_text.is_empty(),
                "forced exec should preserve assistant reasoning text"
            );
            let tool_content = messages
                .iter()
                .find_map(|m| {
                    if let ChatMessage::Tool { content, .. } = m {
                        Some(content.as_str())
                    } else {
                        None
                    }
                })
                .unwrap_or("");
            assert!(
                !tool_content.is_empty(),
                "forced exec should append a tool result message"
            );
            Ok(CompletionResponse {
                text: Some("done".into()),
                tool_calls: vec![],
                usage: Usage {
                    input_tokens: 10,
                    output_tokens: 5,
                    ..Default::default()
                },
            })
        }
    }

    fn stream(
        &self,
        _messages: Vec<ChatMessage>,
    ) -> Pin<Box<dyn Stream<Item = StreamEvent> + Send + '_>> {
        Box::pin(tokio_stream::empty())
    }
}

